-- [6] 000 BOZZA ORDER TEMPLATE NAPA
SELECT "" AS IMAGES, "Footwear" AS MAINGROUP, "6AE2" AS PRODUCTGROUP, "NP_FT_" & [product_Shoe_" & [Item.Product Family] AS COLLECTION, "10" AS SUBDIVISION, "Footwear" AS SUBLINE, Left$([Item.Product Sex],1) AS Gender, Left$([item.model item no_],1) & "P0" & Right$([item.model item no_],8) & "1" AS STYLE, [Item_1.Description 2] & " " & [variable code.description] & " " & " xxx sistemare [item.Variable Code]" AS DESCRIPTION
FROM ((((([Purchase Line] INNER JOIN Item ON [Purchase Line].No_ = Item.No_) LEFT JOIN UPCCodes ON Item.No_ = UPCCodes.[Item No_]) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_) INNER JOIN [Purchase Line] AS [Purchase Line_1] ON ([Purchase Line].[Document No_] = [Purchase Line_1].[Document No_]) AND ([Purchase Line].[Original Line No_] = [Purchase Line_1].[Line No_])) INNER JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_
WHERE ((([Purchase Header].No_)="ODA-19-00006"));

GO

-- [7] 000 movimenti carico venezia
SELECT Item.[Trademark Code], Item.[Season Code], Item.[Model Item No_], Val([quantity]) AS qty, [Item Ledger Entry].*, [Item Ledger Entry].[Location Code]
FROM [Item Ledger Entry] INNER JOIN Item ON [Item Ledger Entry].[Item No_] = Item.No_
WHERE ((([Item Ledger Entry].[Location Code])="venezia"));

GO

-- [8] 000_allocazioni blac
SELECT [DDT_Picking Header].No_, [DDT_Picking Header].[Bill-to Name], [DDT_Picking Line].[model item no_] AS Article, [DDT_Picking Line].[Variable Code 01] AS Color, [DDT_Picking Line].[Variable Code 02] AS [Size], Val([quantity]) AS qty, AllocazioniBlac.FILA
FROM ([DDT_Picking Header] LEFT JOIN [DDT_Picking Line] ON ([DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) AND ([DDT_Picking Header].[Document Type] = [DDT_Picking Line].[Document Type])) LEFT JOIN AllocazioniBlac ON ([DDT_Picking Line].[Variable Code 01] = AllocazioniBlac.ColorCode) AND ([DDT_Picking Line].[Model Item No_] = AllocazioniBlac.No_)
WHERE ((([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Line].Type)=2) AND (([DDT_Picking Header].STATUS)=1) AND (([DDT_Picking Header].[Shortcut Dimension 2 Code])="BLAC"))
ORDER BY [DDT_Picking Header].No_, AllocazioniBlac.FILA;

GO

-- [9] 000_Apepazza Per Mapcite_v1
SELECT Customer.Name, Customer.Address, Customer.[Address 2], Customer.City, Customer.County, Format$([Post Code],"00000") AS pc, Customer.[Country_Region Code], Sum(Val([no_ of pairs])) AS qty, [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[selling season code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_
GROUP BY Customer.Name, Customer.Address, Customer.[Address 2], Customer.City, Customer.County, Format$([Post Code],"00000"), Customer.[Country_Region Code], [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[selling season code], [Sales Line].Type, [Sales Header].[order type], [Sales Line].[delete reason], Customer.[Geographical Zone 2]
HAVING ((([Sales Header].[Shortcut Dimension 2 Code])="AP") AND (([Sales Line].[selling season code])="E24") AND (([Sales Line].Type)=20) AND (([Sales Header].[order type])=0) AND (([Sales Line].[delete reason])="") AND ((Customer.[Geographical Zone 2])="33"));

GO

-- [10] 000_Apepazza Per Mapcite_v2
SELECT Customer.City, Customer.County, Format$([Post Code],"00000") AS pc, Sum(Val([no_ of pairs])) AS qty, [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[selling season code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_
GROUP BY Customer.City, Customer.County, Format$([Post Code],"00000"), Customer.[Country_Region Code], [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[selling season code], [Sales Line].Type, [Sales Header].[order type], [Sales Line].[delete reason], Customer.[Geographical Zone 2]
HAVING (((Customer.[Country_Region Code])="IT") AND (([Sales Header].[Shortcut Dimension 2 Code])="AP") AND (([Sales Line].Type)=20) AND (([Sales Header].[order type])=0) AND (([Sales Line].[delete reason])="") AND ((Customer.[Geographical Zone 2])="33"));

GO

-- [11] 000_BOZZA ANALISI NOTE CREDITO QUALUTA CONTO CG
SELECT [Sales Cr_Memo Line].[Document No_], [Sales Cr_Memo Line].No_, [Sales Cr_Memo Line].Description, [Sales Cr_Memo Header].[Shortcut Dimension 2 Code], [Sales Cr_Memo Line].Type, [Sales Cr_Memo Header].[Posting Date], Val([AMOUNT]) AS VALORE
FROM [Sales Cr_Memo Line] INNER JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_
WHERE ((([Sales Cr_Memo Line].No_)="R0100200") AND (([Sales Cr_Memo Header].[Shortcut Dimension 2 Code])="NAPA") AND (([Sales Cr_Memo Line].Type)=1) AND (([Sales Cr_Memo Header].[Posting Date]) Between #10/1/2021# And #3/21/2022#));

GO

-- [12] 000_check magazzino fine anno ad assortimento _2_assortim
SELECT [Assortment Ledger Entry].[Document No_], [Assortment Ledger Entry].[Entry No_], [Assortment Ledger Entry].[Posting Date], [Assortment Ledger Entry].[Model Item No_], [Assortment Ledger Entry].[CONSTANT VARIABLE CODE], [Assortment Ledger Entry].[Assortment Code], [Assortment Ledger Entry].[Location Code], (Val([QUANTITY])) AS QTY, [Assortment Ledger Entry].[Entry Type]
FROM [Assortment Ledger Entry]
WHERE ((([Assortment Ledger Entry].[Model Item No_])="NP0A4FKTCX") AND (([Assortment Ledger Entry].[CONSTANT VARIABLE CODE])="02U") AND (([Assortment Ledger Entry].[Location Code])="SPMAG") AND (([Assortment Ledger Entry].[Entry Type])=3))
ORDER BY [Assortment Ledger Entry].[Posting Date];

GO

-- [13] 000_check magazzino fine anno ad assortimento _3_assortim paia
SELECT [Assortment Ledger Entry Item].[Assortment Ledger Entry No_], [Assortment Ledger Entry Item].*
FROM [Assortment Ledger Entry Item]
WHERE ((([Assortment Ledger Entry Item].[Assortment Ledger Entry No_])=517352 Or ([Assortment Ledger Entry Item].[Assortment Ledger Entry No_])=517717));

GO

-- [14] 000_check magazzino fine anno ad assortimento_1_trova problemi
SELECT [Assortment Ledger Entry].[Model Item No_], [Assortment Ledger Entry].[CONSTANT VARIABLE CODE], [Assortment Ledger Entry].[Assortment Code], [Assortment Ledger Entry].[Location Code], Sum(Val([QUANTITY])) AS QTY
FROM [Assortment Ledger Entry]
WHERE ((([Assortment Ledger Entry].[Posting Date])<=[Forms]![principale]![datafinale]))
GROUP BY [Assortment Ledger Entry].[Model Item No_], [Assortment Ledger Entry].[CONSTANT VARIABLE CODE], [Assortment Ledger Entry].[Assortment Code], [Assortment Ledger Entry].[Location Code]
HAVING (((Sum(Val([QUANTITY])))<0));

