-- [26] 000_dam_analisi pesi e colli spedizioni
SELECT [DDT_Picking Header].[Document Type], [DDT_Picking Line].[Document No_], [DDT_Picking Header].[posted date], [DDT_Picking Line].type, Sum(Val([ddt_picking line.quantity])) AS boxes, First(Val([ddt_picking header.gross weight])) AS pesolordo, First(Val([added boxes])) AS boxAggiunti, [DDT_Picking Header].[selling season code], [Sales Header].[Shortcut Dimension 1 Code], [DDT_Picking Header].[Bill-to Country_Region Code], [DDT_Picking Header].[Shipping Agent Code], First(Val([ddt_picking header.Total Volume])) AS VolumeTotale
FROM (([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) INNER JOIN [Sales Line] ON ([DDT_Picking Line].[Order Line No_] = [Sales Line].[Line No_]) AND ([DDT_Picking Line].[Order No_] = [Sales Line].[Document No_])) INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])
GROUP BY [DDT_Picking Header].[Document Type], [DDT_Picking Line].[Document No_], [DDT_Picking Header].[posted date], [DDT_Picking Line].type, [DDT_Picking Header].[selling season code], [Sales Header].[Shortcut Dimension 1 Code], [DDT_Picking Header].[Bill-to Country_Region Code], [DDT_Picking Header].[Shipping Agent Code]
HAVING ((([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Header].[posted date]) Between #1/1/2021# And #12/31/2021#) AND (([DDT_Picking Line].type)=20) AND (([DDT_Picking Header].[selling season code])="E21" Or ([DDT_Picking Header].[selling season code])="I21") AND (([Sales Header].[Shortcut Dimension 1 Code])="A-PF") AND (([DDT_Picking Header].[Bill-to Country_Region Code])="DE") AND (([DDT_Picking Header].[Shipping Agent Code])="1"));

GO

