GO

-- [28] 000_dam_analisi trasferimenti magazzino transito errato_MOD_RIC
UPDATE [Transfer Line] INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_ SET [Transfer Line].[Transfer-from Code] = "1CN_DBG", [Transfer Line].[Transfer-to Code] = "DBG"
WHERE ((([Transfer Line].[Transfer-from Code])="1CN_PMAG") AND (([Transfer Line].[Transfer-to Code])="PMAG") AND (([Transfer Header].No_)="TRO-23/00627") AND ((Val([quantity shipped]))=0));

GO

-- [29] 000_dam_analisi trasferimenti magazzino transito errato_MOD_SPED
UPDATE [Transfer Line] INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_ SET [Transfer Header].[In-Transit Code] = "1CN_DBG", [Transfer Line].[In-Transit Code] = "1CN_DBG", [Transfer Header].[Transfer-to Code] = "DBG", [Transfer Line].[Transfer-to Code] = "DBG"
WHERE ((([Transfer Header].[In-Transit Code])="1CN_PMAG") AND (([Transfer Line].[In-Transit Code])="1CN_PMAG") AND (([Transfer Header].[Transfer-to Code])="PMAG") AND (([Transfer Line].[Transfer-to Code])="PMAG") AND (([Transfer Header].No_)="TRO-23/00627") AND ((Val([quantity shipped]))>0));

GO

-- [30] 000_dam_analisi trasferimenti magazzino transito errato_VERIFICA
SELECT [Transfer Header].No_, [Transfer Header].[Transfer-from Code], [Transfer Header].[In-Transit Code], [Transfer Header].[Transfer-to Code], [Transfer Line].[Item No_], [Transfer Line].[Transfer-from Code], [Transfer Line].[In-Transit Code], [Transfer Line].[Transfer-to Code], [Transfer Line].[Line Type], [Transfer Line].[Item Type], Val([Quantity]) AS qty, Val([Quantity Shipped]) AS qtyshp
FROM [Transfer Line] INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_
WHERE ((([Transfer Header].No_)="TRO-23/00730" Or ([Transfer Header].No_)="TRO-23/00694" Or ([Transfer Header].No_)="TRO-23/00627"));

GO

