-- [32] 000_dam_AnalisiArriviMerceN_step0_Acquisti_Direct
SELECT [Purch_ Rcpt_ Line].[Document No_], [Purch_ Rcpt_ Line].Type, [Purch_ Rcpt_ Line].No_, [Purch_ Rcpt_ Line].[Constant Variable Code], [Purch_ Rcpt_ Line].[season code], [Purch_ Rcpt_ Line].[Posting Date] AS PurchaseOrderReceiptDate, Sum(Val([NO_ OF PAIRS])) AS QTY, [Purch_ Rcpt_ Line].[Order No_], [Purch_ Rcpt_ Line].[Order Line No_]
FROM [Purch_ Rcpt_ Line] INNER JOIN [Purch_ Rcpt_ Header] ON [Purch_ Rcpt_ Line].[Document No_] = [Purch_ Rcpt_ Header].No_
WHERE ((([Purch_ Rcpt_ Header].[location code])="PMAG" Or ([Purch_ Rcpt_ Header].[location code])="SPMAG" Or ([Purch_ Rcpt_ Header].[location code])="DBG"))
GROUP BY [Purch_ Rcpt_ Line].[Document No_], [Purch_ Rcpt_ Line].Type, [Purch_ Rcpt_ Line].No_, [Purch_ Rcpt_ Line].[Constant Variable Code], [Purch_ Rcpt_ Line].[season code], [Purch_ Rcpt_ Line].[Posting Date], [Purch_ Rcpt_ Line].[Order No_], [Purch_ Rcpt_ Line].[Order Line No_]
HAVING ((([Purch_ Rcpt_ Line].Type)=19 Or ([Purch_ Rcpt_ Line].Type)=20) AND (([Purch_ Rcpt_ Line].[season code])=[CODICE STAGIONE]) AND ((Sum(Val([NO_ OF PAIRS])))>0));

GO

-- [33] 000_dam_AnalisiArriviMerceN_step0_Acquisti_Split
SELECT [Purch_ Rcpt_ Line].[Document No_], [Purch_ Rcpt_ Line].Type, [Purch_ Rcpt_ Line].No_, [Purch_ Rcpt_ Line].[Constant Variable Code], [Purch_ Rcpt_ Line].[season code], [Purch_ Rcpt_ Line].[Posting Date] AS PurchaseOrderReceiptDate, Sum(Val([NO_ OF PAIRS])) AS QTY, [Purch_ Rcpt_ Line].[Order No_], [Purch_ Rcpt_ Line].[Order Line No_]
FROM [Purch_ Rcpt_ Line] INNER JOIN [Purch_ Rcpt_ Header] ON [Purch_ Rcpt_ Line].[Document No_] = [Purch_ Rcpt_ Header].No_
WHERE ((([Purch_ Rcpt_ Header].[location code])<>"PMAG" And ([Purch_ Rcpt_ Header].[location code])<>"SPMAG" And ([Purch_ Rcpt_ Header].[location code])<>"DBG"))
GROUP BY [Purch_ Rcpt_ Line].[Document No_], [Purch_ Rcpt_ Line].Type, [Purch_ Rcpt_ Line].No_, [Purch_ Rcpt_ Line].[Constant Variable Code], [Purch_ Rcpt_ Line].[season code], [Purch_ Rcpt_ Line].[Posting Date], [Purch_ Rcpt_ Line].[Order No_], [Purch_ Rcpt_ Line].[Order Line No_]
HAVING ((([Purch_ Rcpt_ Line].Type)=19 Or ([Purch_ Rcpt_ Line].Type)=20) AND (([Purch_ Rcpt_ Line].[season code])=[CODICE STAGIONE]) AND ((Sum(Val([NO_ OF PAIRS])))>0));

GO

-- [34] 000_dam_AnalisiArriviMerceN_step0_TransferReceipt
SELECT [Transfer Receipt Line].[Document No_], [Transfer Receipt Line].[Item Type], [Transfer Receipt Line].[Item No_], [Transfer Receipt Line].[Constant Variable Code], [Transfer Receipt Line].[Season Code], [Transfer Receipt Line].[Receipt Date], Sum(Val([NO_ OF PAIRS])) AS QTY, [Transfer Receipt Line].[Transfer Order No_], [Transfer Receipt Line].Description, [Transfer Receipt Header].Note, [Transfer Receipt Header].Typification
FROM [Transfer Receipt Line] INNER JOIN [Transfer Receipt Header] ON [Transfer Receipt Line].[Document No_] = [Transfer Receipt Header].No_
WHERE ((([Transfer Receipt Line].[Transfer-to Code])="PMAG" Or ([Transfer Receipt Line].[Transfer-to Code])="SPMAG" Or ([Transfer Receipt Line].[Transfer-to Code])="DBG"))
GROUP BY [Transfer Receipt Line].[Document No_], [Transfer Receipt Line].[Item Type], [Transfer Receipt Line].[Item No_], [Transfer Receipt Line].[Constant Variable Code], [Transfer Receipt Line].[Season Code], [Transfer Receipt Line].[Receipt Date], [Transfer Receipt Line].[Transfer Order No_], [Transfer Receipt Line].Description, [Transfer Receipt Header].Note, [Transfer Receipt Header].Typification
HAVING ((([Transfer Receipt Line].[Item Type])=19 Or ([Transfer Receipt Line].[Item Type])=20) AND (([Transfer Receipt Line].[Season Code])=[CODICE STAGIONE]) AND (([Transfer Receipt Header].Typification)="PRODUZIONE" Or ([Transfer Receipt Header].Typification)="produzione"));

GO

-- [35] 000_dam_AnalisiArriviMerceN_step0_TransferShipment
