-- [37] 000_dam_AnalisiArriviMerceN_step1_AcquistI_Direct
SELECT [000_dam_AnalisiArriviMerceN_step0_Acquisti_Direct].*, Item.[trademark code], Item.[Line code], Vendor.Name AS Vendor, Vendor_1.Name AS Manufacturer, [Purchase Line].[Requested Receipt Date], [Purchase Line].[Promised Receipt Date], [Purchase Line].[Expected Receipt Date], [Purchase Line].[Planned Receipt Date], DateDiff("d",[Purchase Line.Promised Receipt Date],[PurchaseOrderReceiptDate]) AS DelayReceiptPromised, [qty]*[DelayReceiptPromised] AS QTYxDELAY, [Purchase Header].[Order Date], DateDiff("d",[Purchase Header.Order Date],[PurchaseOrderReceiptDate]) AS ProductionLeadTime, Item.[Inventory Posting Group], [qty]*[ProductionLeadTime] AS QTYxPRODUCTIONLEADTIME, Item.[Country_Region of Origin Code]
FROM ((((Item RIGHT JOIN 000_dam_AnalisiArriviMerceN_step0_Acquisti_Direct ON Item.No_ = [000_dam_AnalisiArriviMerceN_step0_Acquisti_Direct].No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_) LEFT JOIN [Purchase Line] ON ([000_dam_AnalisiArriviMerceN_step0_Acquisti_Direct].[Order Line No_] = [Purchase Line].[Line No_]) AND ([000_dam_AnalisiArriviMerceN_step0_Acquisti_Direct].[Order No_] = [Purchase Line].[Document No_])) LEFT JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_;

GO

