-- [48] 000_dam_check leadtime ddt released posted
SELECT [DDT_Picking Header].[Shortcut Dimension 2 Code] AS Trademark, [DDT_Picking Header].[Selling Season Code], [DDT_Picking Header].[Shortcut Dimension 1 Code], [DDT_Picking Header].No_, [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Posting Date], [DDT_Picking Header].[First Release Date], [DDT_Picking Header].[Posted Date], DateDiff("d",[posting date],[first release date]) AS deltaDateA, DateDiff("d",[first release date],[posted date]) AS deltaDate, IIf([deltadate]<=1,"1-Super",IIf([deltadate]<=3,"2-OK",IIf([deltadate]<=5,"3-Fair",IIf([deltadate]<=7,"4-Acceptable","5-Bad")))) AS RankingDate, DateDiff("d",[posting date],[posted date]) AS deltaDateTot, Sum(Val([no_ of pairs])) AS paia, Sum(Val([quantity])) AS colli, IIf([colli]<=1,"1-Critical",IIf([colli]<=3,"2-Severe",IIf([colli]<=5,"3-Fair","4-Good"))) AS RankingColli, [DDT_Picking Header].[Sell-to Country_Region Code], [DDT_Picking Header].[Ship-to Country_Region Code], [Geographical Zone].Description AS GeographicalZone, [DDT_Picking Line].Type
FROM ([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON [DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) LEFT JOIN [Geographical Zone] ON [DDT_Picking Header].[Geographical Zone] = [Geographical Zone].Code
WHERE ((([DDT_Picking Header].[document type])=0) AND (([DDT_Picking Header].status)=20))
GROUP BY [DDT_Picking Header].[Shortcut Dimension 2 Code], [DDT_Picking Header].[Selling Season Code], [DDT_Picking Header].[Shortcut Dimension 1 Code], [DDT_Picking Header].No_, [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Posting Date], [DDT_Picking Header].[First Release Date], [DDT_Picking Header].[Posted Date], [DDT_Picking Header].[Sell-to Country_Region Code], [DDT_Picking Header].[Ship-to Country_Region Code], [Geographical Zone].Description, [DDT_Picking Line].Type
HAVING ((([DDT_Picking Header].[Selling Season Code])="E24" Or ([DDT_Picking Header].[Selling Season Code])="I24") AND (([DDT_Picking Line].Type)=20));

GO

