-- [294] AnalisiCancellazioniSKU_step0_dativendite
SELECT [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Constant Variable Code] AS ColorCode, [Variable Code].Description AS ColorDescription, Sum(IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs]))) AS PairsSold, [Sales Header].[Selling Season Code] AS [SEASON CODE], [Sales Header].[shortcut dimension 2 code] AS [Trademark code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN [Sales Header Extension] ON ([Sales Header].No_ = [Sales Header Extension].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19) AND (([Sales Header].[Order Type])=0 Or ([Sales Header].[Order Type])=2) AND (([Sales Line].[delete reason])="ART" Or ([Sales Line].[delete reason])=""))
GROUP BY [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Constant Variable Code], [Variable Code].Description, [Sales Header].[Selling Season Code], [Sales Header].[shortcut dimension 2 code], [Sales Line].[Constant Variable Code] AND  ([Season Code]='I25') and ([Trademark Code]='BLAUER');

GO

-- [295] AnalisiCancellazioniSKU_step0_dativendite_NOFILTRI
SELECT [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Constant Variable Code] AS ColorCode, [Variable Code].Description AS ColorDescription, Sum(IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs]))) AS PairsSold, [Sales Header].[Selling Season Code] AS [SEASON CODE], [Sales Header].[shortcut dimension 2 code] AS [Trademark code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])) LEFT JOIN [Sales Header Extension] ON ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type]) AND ([Sales Header].No_ = [Sales Header Extension].[Document No_])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19) AND (([Sales Header].[Order Type])=0 Or ([Sales Header].[Order Type])=2) AND (([Sales Line].[delete reason])="ART" Or ([Sales Line].[delete reason])=""))
GROUP BY [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Constant Variable Code], [Variable Code].Description, [Sales Header].[Selling Season Code], [Sales Header].[shortcut dimension 2 code], [Sales Line].[Constant Variable Code];

GO

-- [296] AnalisiCancellazioniSKUS
SELECT [DatiCarryOverESMU-Completi].[Season Code], [DatiCarryOverESMU-Completi].[Trademark Code], [DatiCarryOverESMU-Completi].[Collection Code], [DatiCarryOverESMU-Completi].[Product Sex], [DatiCarryOverESMU-Completi].[Model Item No_] AS Article, [DatiCarryOverESMU-Completi].[Variable Code 01] AS Color, [Variable Code].Description AS ColorDescription, [DatiCarryOverESMU-Completi].[Sales_Purchase Status - Item], Item.Description, Item.[Description 2], Item.[Line Code], Item.[Season Typology], Item.[Product Family], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Country_Region of Origin Code], AnalisiCancellazioniSKU_step0_dativendite.PairsSold, ListinoVenditaRetailRaggruppato.Listinoretail AS RP
FROM (((AnalisiCancellazioniSKU_step0_dativendite RIGHT JOIN [DatiCarryOverESMU-Completi] ON (AnalisiCancellazioniSKU_step0_dativendite.ColorCode = [DatiCarryOverESMU-Completi].[Variable Code 01]) AND (AnalisiCancellazioniSKU_step0_dativendite.No_ = [DatiCarryOverESMU-Completi].[Model Item No_])) LEFT JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [DatiCarryOverESMU-Completi].[Model Item No_] = Item.No_) LEFT JOIN [Variable Code] ON ([DatiCarryOverESMU-Completi].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([DatiCarryOverESMU-Completi].[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN ListinoVenditaRetailRaggruppato ON ([DatiCarryOverESMU-Completi].[Variable Code 01] = ListinoVenditaRetailRaggruppato.[variable code 01]) AND ([DatiCarryOverESMU-Completi].[Model Item No_] = ListinoVenditaRetailRaggruppato.[model item no_])
WHERE ((([DatiCarryOverESMU-Completi].[Model Item No_]) Not Like "TEMP*") AND (([DatiCarryOverESMU-Completi].[Advertising Material])=0));

GO

-- [297] AnalisiCancellazioniSKUS_GLOBAL MEMO
SELECT [DatiCarryOverESMU-Completi].[Advertising Material], [DatiCarryOverESMU-Completi].[Season Code], [DatiCarryOverESMU-Completi].[Trademark Code], [DatiCarryOverESMU-Completi].[Collection Code], [DatiCarryOverESMU-Completi].[Product Sex], [DatiCarryOverESMU-Completi].[Model Item No_] AS Article, [DatiCarryOverESMU-Completi].[Variable Code 01] AS Color, [Variable Code].Description AS ColorDescription, [DatiCarryOverESMU-Completi].[Sales_Purchase Status - Item], Item.Description, Item.[Description 2], Item.[Line Code], Item.[Season Typology], Item.[Product Family], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Country_Region of Origin Code], AnalisiCancellazioniSKU_step0_dativendite.PairsSold, ListinoVenditaRetailRaggruppato.Listinoretail AS RP
FROM (((AnalisiCancellazioniSKU_step0_dativendite RIGHT JOIN [DatiCarryOverESMU-Completi] ON (AnalisiCancellazioniSKU_step0_dativendite.ColorCode = [DatiCarryOverESMU-Completi].[Variable Code 01]) AND (AnalisiCancellazioniSKU_step0_dativendite.No_ = [DatiCarryOverESMU-Completi].[Model Item No_])) LEFT JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [DatiCarryOverESMU-Completi].[Model Item No_] = Item.No_) LEFT JOIN [Variable Code] ON ([DatiCarryOverESMU-Completi].[Variable Group 01] = [Variable Code].[Variable Group]) AND ([DatiCarryOverESMU-Completi].[Model Item No_] = [Variable Code].[Variable Code])) LEFT JOIN ListinoVenditaRetailRaggruppato ON ([DatiCarryOverESMU-Completi].[Variable Code 01] = ListinoVenditaRetailRaggruppato.[variable code 01]) AND ([DatiCarryOverESMU-Completi].[Model Item No_] = ListinoVenditaRetailRaggruppato.[model item no_])
WHERE ((([DatiCarryOverESMU-Completi].[Advertising Material])=0));

GO

