-- [299] AnalisiCancellazioniSKUS-step0_old
SELECT [qSoloVend-step1].*, Customer.[VAT Registration No_], Customer.[Fiscal Code], Item.Description, Item.[Description 2], Item.[Line Code], [Variable Code].Description AS Color, [Geographical Zone].Description AS GeographicalZoneDescription, Item.[Season Typology], Item.[Product Family], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], [MustBuy-ArticoloColore].[Must Buy], [Geographical Zone_1].Description AS GeographicalZone2Description, Customer.[Name 2], Customer.Address, Customer.City, Customer.Contact, Customer.[Phone No_], Customer.[Country_Region Code], Customer.[Post Code], Customer.County, Customer.[Reservation Priority], Customer.[VAT Registration No_] AS PartitaIva, Item.[Vendor No_], Vendor.Name AS Vendor, Customer.[Current Risk] AS LinceRischioOggi, Customer.[Updated Date] AS LinceAggiornamentoFile, Customer.[Updated Type] AS LinceTipoEvasione, Customer.[Due Date] AS LinceDataEvasione, Customer.[Internal Valuation], Customer.[Valuation Date], Customer.[Business E-Mail], [pairsSold]*Val([standard cost]) AS EstimatedLandeCostOnSold, Item.[Country_Region of Origin Code], Customer.[Fax No_]
FROM (((((([qSoloVend-step1] INNER JOIN Item ON [qSoloVend-step1].Article = Item.No_) INNER JOIN [Variable Code] ON ([qSoloVend-step1].ColorCode = [Variable Code].[Variable Code]) AND (Item.[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])) LEFT JOIN [Geographical Zone] ON [qSoloVend-step1].[Geographical Zone] = [Geographical Zone].[Code]) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON [qSoloVend-step1].[Geographical Zone 2] = [Geographical Zone_1].Code) LEFT JOIN Customer ON [qSoloVend-step1].CustomerCode = Customer.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN [MustBuy-ArticoloColore] ON ([qSoloVend-step1].[Constant Variable Code] = [MustBuy-ArticoloColore].[Variable Code 01]) AND ([qSoloVend-step1].Article = [MustBuy-ArticoloColore].[Model Item No_]);

GO

-- [300] AnalisiCancellazioniSKUS-step1
SELECT [DatiCarryOverESMU-Completi].[Trademark Code] AS [Trademark Code_2], [DatiCarryOverESMU-Completi].[Season Code] AS [Season Code_2], [DatiCarryOverESMU-Completi].[Collection Code], [DatiCarryOverESMU-Completi].[Product Sex], [DatiCarryOverESMU-Completi].Smu, [DatiCarryOverESMU-Completi].[Carry Over], [DatiCarryOverESMU-Completi].[Sold Out], [DatiCarryOverESMU-Completi].[Sold Out Date], [DatiCarryOverESMU-Completi].[Sales_Purchase Status - item], [DatiCarryOverESMU-Completi].[Sales_Purchase Status Date], Item.[Line Code] AS LineCodeByStyle, Vendor.Name AS VendoNameByStyle, [DatiCarryOverESMU-Completi].[Model Item No_], [DatiCarryOverESMU-Completi].[Variable Code 01], [DatiCarryOverESMU-Completi].[Advertising Material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName, [AnalisiCancellazioniSKUS-step0].*
FROM ((([DatiCarryOverESMU-Completi] LEFT JOIN [AnalisiCancellazioniSKUS-step0] ON ([DatiCarryOverESMU-Completi].[Variable Code 01] = [AnalisiCancellazioniSKUS-step0].[Constant Variable Code]) AND ([DatiCarryOverESMU-Completi].[Model Item No_] = [AnalisiCancellazioniSKUS-step0].Article)) LEFT JOIN Item ON [DatiCarryOverESMU-Completi].[Model Item No_] = Item.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_;

GO

-- [301] AnalisiCredito
SELECT [AnalisiCredito-Union].CodiceCliente AS [Codice Cliente], [AnalisiCredito-Union].Name AS [Nome Cliente], [AnalisiCredito-Union].[Name 2] AS [Nome 2], [AnalisiCredito-Union].Address AS Indirizzo, [AnalisiCredito-Union].[Post Code] AS Cap, [AnalisiCredito-Union].City AS Città, [AnalisiCredito-Union].County AS Provincia, [AnalisiCredito-Union].[Country_region Code] AS Paese, [AnalisiCredito-Union].[VAT Registration NO_] AS [Partita Iva], [AnalisiCredito-Union].[Fiscal Code] AS [Cod fiscale], [AnalisiCredito-Union].[Payment Method Code], [AnalisiCredito-Union].[Purchase Group], [AnalisiCredito-Union].[Current Risk], [AnalisiCredito-Union].[Risk Rating], [AnalisiCredito-Union].[PM Failure Assigned Score], [AnalisiCredito-Union].DataAggiornamento, [AnalisiCredito-Union].DataValutazione, [AnalisiCredito-Union].DataScadenza, Val(Format$([AnalisiCredito-Union.datascadenza]-Now(),"#")) AS GiorniScadenza, IIf([AnalisiCredito-Union.Updated Type]=1,"Automatico",IIf([AnalisiCredito-Union.Updated Type]=2,"Manuale","")) AS Aggiornamento, IIf([AnalisiCredito-Union.Skip Credit Info Update]=1,"Sì","No") AS SaltaAggiornamento, IIf([saltaaggiornamento]="No" And Val([giorniscadenza])<Val([forms]![principale]![ControlloNumeroGiorniScadenzaLince]) And ([saldoD]>0 Or [valueoutstandingstagione1]>0 Or [valueoutstandingstagione2]>0),"Sì","No") AS RichiedereControllo, IIf([SaltaAggiornamento]="Sì" And ([saldoD]>0 Or [valueoutstandingstagione1]>0 Or [valueoutstandingstagione2]>0),"Sì","") AS PropostaRipristinoControllo, [AnalisiCredito-Union].SaldoD, [AnalisiCredito-step1-datiSaldoExtraClienti].SaldoDExtra, [SaldoD]+IIf(IsNull([No_])=False,[saldodextra],0) AS SaldoTotale, [AnalisiCredito-Union].[Currency Code], [AnalisiCredito-Union].ValueSoldStagione1, [AnalisiCredito-Union].ValueOutStandingStagione1, [AnalisiCredito-Union].ValueSoldStagione2, [AnalisiCredito-Union].ValueOutStandingStagione2, [AnalisiCredito-Union].ValueReturnStagione1, [AnalisiCredito-Union].ValueReturnStagione2
FROM [AnalisiCredito-Union] LEFT JOIN [AnalisiCredito-step1-datiSaldoExtraClienti] ON [AnalisiCredito-Union].CodiceCliente = [AnalisiCredito-step1-datiSaldoExtraClienti].No_;

GO

-- [302] AnalisiCredito-Both
SELECT [AnalisiCredito-step1-datiSaldoClienti].No_ AS CodiceCliente, [AnalisiCredito-step1-datiSaldoClienti].[Purchase Group], [AnalisiCredito-step1-datiSaldoClienti].Name, [AnalisiCredito-step1-datiSaldoClienti].[Name 2], [AnalisiCredito-step1-datiSaldoClienti].Address, [AnalisiCredito-step1-datiSaldoClienti].[Post Code], [AnalisiCredito-step1-datiSaldoClienti].City, [AnalisiCredito-step1-datiSaldoClienti].County, [AnalisiCredito-step1-datiSaldoClienti].[Country_region Code], [AnalisiCredito-step1-datiSaldoClienti].[VAT Registration No_], [AnalisiCredito-step1-datiSaldoClienti].[Fiscal Code], [AnalisiCredito-step1-datiSaldoClienti].[Payment Method Code], [AnalisiCredito-step1-datiSaldoClienti].[Current Risk], [AnalisiCredito-step1-datiSaldoClienti].[Risk Rating], [AnalisiCredito-step1-datiSaldoClienti].[PM Failure Assigned Score], [AnalisiCredito-step1-datiSaldoClienti].DataAggiornamento, [AnalisiCredito-step1-datiSaldoClienti].DataValutazione, [AnalisiCredito-step1-datiSaldoClienti].DataScadenza, [AnalisiCredito-step1-datiSaldoClienti].[Updated Type], [AnalisiCredito-step1-datiSaldoClienti].[Skip Credit Info Update], [AnalisiCredito-step1-datiSaldoClienti].SaldoD, [AnalisiCredito-step0-datiVendite].[Currency Code], [AnalisiCredito-step0-datiVendite].ValueSoldStagione1, [AnalisiCredito-step0-datiVendite].ValueOutstandingStagione1, [AnalisiCredito-step0-datiVendite].ValueSoldStagione2, [AnalisiCredito-step0-datiVendite].ValueOutstandingStagione2, [AnalisiCredito-step0-datiVendite].ValueReturnStagione1, [AnalisiCredito-step0-datiVendite].ValueReturnStagione2
FROM [AnalisiCredito-step1-datiSaldoClienti] INNER JOIN [AnalisiCredito-step0-datiVendite] ON [AnalisiCredito-step1-datiSaldoClienti].No_ = [AnalisiCredito-step0-datiVendite].[Sell-to Customer No_];

GO

-- [303] AnalisiCredito-RicercaAnomalie
SELECT [Sales Header].[Document Type], [Geographical Zone].[Credit Manager], [Sales Line].[Delete Reason], [Sales Header].No_ AS OrderNo, Customer.[Blocked for Assignments], IIf([Anomalous]=1,"X","") AS Anomalo, IIf([Not Anomalous]=1,"X","") AS NonAnomalo, [Sales Header].[Anomalous Date], IIf([Checked]=1,"X","") AS Verificato, [Sales Header].[Checked Date], IIf([anomalous]=1 And [checked]<>1,"X","") AS DaVerificare, Salesperson_Purchaser.Code AS SalesPersonCode, Salesperson_Purchaser.Name AS SalesPersonName, [Sales Header].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Post Code], Customer.City, Customer.County, Customer.[Country_region Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[purchase group], [Sales Header].[Payment Method Code] AS MetodoPagamentoOrdine, [Sales Header].[Payment Terms Code] AS CondizioniPagamentoOrdine, Customer.[Payment Method Code] AS MetodoPagamentoClienti, Customer.[Payment Terms Code] AS CondizioniPagamentoCliente, Customer.[Current Risk], Val([credit limit]) AS FidoCerved, Customer.[risk rating], Val([creditlimit]) AS FidoCribis, Customer.[Updated Date] AS DataAggiornamento, Customer.[Due Date] AS DataValutazione, [Customer.Due Date]+365 AS DataScadenza, Customer.[Updated Type], Customer.[Skip Credit Info Update], [Sales Line].[Currency Code], Sum(IIf([Sales Header.Selling Season Code]=[forms]![principale]![creditofiltrostagione2] And [Sales Line.Document Type]=1,Val([Line Amount])-Val([Inv_ Discount Amount]),0)) AS ValueSoldStagione2, Sum(IIf([Sales Header.Selling Season Code]=[forms]![principale]![creditofiltrostagione2] And [Sales Line.Document Type]=5,+Val([Line Amount])-Val([Inv_ Discount Amount]),0)) AS ValueReturnStagione2, Sum(IIf([Sales Header.Selling Season Code]=[forms]![principale]![creditofiltrostagione2] And [Sales Line.Document Type]=1,Val([Amount Including VAT]),0)) AS ValueSoldVATStagione2, Sum(IIf([Sales Header.Selling Season Code]=[forms]![principale]![creditofiltrostagione2] And [Sales Line.Document Type]=5,+Val([Amount Including VAT]),0)) AS ValueReturnVATStagione2, Item.[Season Code], [AnalisiCredito-RicercaAnomalie-NoteOrdiniStep2].listacommenti, [AnalisiCredito-RicercaAnomalie-NoteOrdiniCreditoStep2].listacommenti AS CommentiCredito, [AnalisiCredito-RicercaAnomalie-NoteOrdiniCommercialeStep2].listacommenti AS CommentiCommerciale, [AnalisiCredito-RicercaAnomalie-NoteOrdiniAltroStep2].listacommenti AS CommentiAltro, Customer.[Geographical Zone], [Geographical Zone].Description AS [Geographical Zone Description], Customer.[Geographical Zone 2], [Geographical Zone_1].Description AS [Geographical Zone2 Description], [Sales Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Header].[selling season code] AS StagioneOrdine
FROM ((((((((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN Customer ON [Sales Line].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN [AnalisiCredito-RicercaAnomalie-NoteOrdiniStep2] ON [Sales Line].[Document No_] = [AnalisiCredito-RicercaAnomalie-NoteOrdiniStep2].NumeroOrdine) LEFT JOIN [AnalisiCredito-RicercaAnomalie-NoteOrdiniAltroStep2] ON [Sales Line].[Document No_] = [AnalisiCredito-RicercaAnomalie-NoteOrdiniAltroStep2].NumeroOrdine) LEFT JOIN [AnalisiCredito-RicercaAnomalie-NoteOrdiniCommercialeStep2] ON [Sales Line].[Document No_] = [AnalisiCredito-RicercaAnomalie-NoteOrdiniCommercialeStep2].NumeroOrdine) LEFT JOIN [AnalisiCredito-RicercaAnomalie-NoteOrdiniCreditoStep2] ON [Sales Line].[Document No_] = [AnalisiCredito-RicercaAnomalie-NoteOrdiniCreditoStep2].NumeroOrdine) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code
WHERE ((([Sales Line].[Document Type])=1 Or ([Sales Line].[Document Type])=5) AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19) AND ((Item.[advertising material])=0))
GROUP BY [Sales Header].[Document Type], [Geographical Zone].[Credit Manager], [Sales Line].[Delete Reason], [Sales Header].No_, Customer.[Blocked for Assignments], IIf([Anomalous]=1,"X",""), IIf([Not Anomalous]=1,"X",""), [Sales Header].[Anomalous Date], IIf([Checked]=1,"X",""), [Sales Header].[Checked Date], IIf([anomalous]=1 And [checked]<>1,"X",""), Salesperson_Purchaser.Code, Salesperson_Purchaser.Name, [Sales Header].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Post Code], Customer.City, Customer.County, Customer.[Country_region Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[purchase group], [Sales Header].[Payment Method Code], [Sales Header].[Payment Terms Code], Customer.[Payment Method Code], Customer.[Payment Terms Code], Customer.[Current Risk], Val([credit limit]), Customer.[risk rating], Val([creditlimit]), Customer.[Updated Date], Customer.[Due Date], [Customer.Due Date]+365, Customer.[Updated Type], Customer.[Skip Credit Info Update], [Sales Line].[Currency Code], Item.[Season Code], [AnalisiCredito-RicercaAnomalie-NoteOrdiniStep2].listacommenti, [AnalisiCredito-RicercaAnomalie-NoteOrdiniCreditoStep2].listacommenti, [AnalisiCredito-RicercaAnomalie-NoteOrdiniCommercialeStep2].listacommenti, [AnalisiCredito-RicercaAnomalie-NoteOrdiniAltroStep2].listacommenti, Customer.[Geographical Zone], [Geographical Zone].Description, Customer.[Geographical Zone 2], [Geographical Zone_1].Description, [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[selling season code]
HAVING ((([Sales Header].[Document Type])=1) AND (([Sales Line].[Delete Reason])="") AND ((Item.[Season Code])=[forms]![principale]![creditofiltrostagione2]));

GO

