-- [323] AnalisiCredito-step0-datiVendite
SELECT [Sales Line].[Delete Reason], Customer.[Purchase Group], [Sales Header].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Post Code], Customer.City, Customer.County, Customer.[Country_region Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[Payment Method Code], Customer.[Current Risk], Customer.[Risk Rating], Customer.[PM Failure Assigned Score], Customer.[Updated Date] AS DataAggiornamento, Customer.[valuation Date] AS DataValutazione, [Customer.Due Date] AS DataScadenza, Customer.[Updated Type], Customer.[Skip Credit Info Update], [Sales Line].[Currency Code], Sum(IIf([Sales Header.selling Season Code]=[forms]![principale]![creditofiltrostagione1] And [Sales Line.Document Type]=1,Val([Line Amount])-Val([Inv_ Discount Amount]),0)) AS ValueSoldStagione1, Sum(IIf([Sales Header.selling Season Code]=[forms]![principale]![creditofiltrostagione1] And [Sales Line.Document Type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount]))*Val([outstanding quantity])/Val([quantity]),0)) AS ValueOutstandingStagione1, Sum(IIf([Sales Header.selling Season Code]=[forms]![principale]![creditofiltrostagione2] And [Sales Line.Document Type]=1,Val([Line Amount])-Val([Inv_ Discount Amount]),0)) AS ValueSoldStagione2, Sum(IIf([Sales Header.selling Season Code]=[forms]![principale]![creditofiltrostagione2] And [Sales Line.Document Type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount]))*Val([outstanding quantity])/Val([quantity]),0)) AS ValueOutstandingStagione2, Sum(IIf([Sales Header.selling Season Code]=[forms]![principale]![creditofiltrostagione1] And [Sales Line.Document Type]=5,-Val([Line Amount])+Val([Inv_ Discount Amount]),0)) AS ValueReturnStagione1, Sum(IIf([Sales Header.selling Season Code]=[forms]![principale]![creditofiltrostagione2] And [Sales Line.Document Type]=5,+Val([Line Amount])+Val([Inv_ Discount Amount]),0)) AS ValueReturnStagione2
FROM ((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN Customer ON [Sales Line].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_
WHERE ((([Sales Line].[Document Type])=1 Or ([Sales Line].[Document Type])=5) AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19) AND ((Item.[Season Code])=[forms]![principale]![creditofiltrostagione1] Or (Item.[Season Code])=[forms]![principale]![creditofiltrostagione2]) AND ((Item.[ADVERTISING MATERIAL])=0))
GROUP BY [Sales Line].[Delete Reason], Customer.[Purchase Group], [Sales Header].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Post Code], Customer.City, Customer.County, Customer.[Country_region Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[Payment Method Code], Customer.[Current Risk], Customer.[Risk Rating], Customer.[PM Failure Assigned Score], Customer.[Updated Date], Customer.[valuation Date], [Customer.Due Date], Customer.[Updated Type], Customer.[Skip Credit Info Update], [Sales Line].[Currency Code]
HAVING ((([Sales Line].[Delete Reason])=""));

