-- [324] AnalisiCredito-step1-datiSaldoClienti
SELECT Customer.No_, Customer.[Purchase Group], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Post Code], Customer.City, Customer.County, Customer.[Country_region Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[Payment Method Code], Customer.[Risk Rating], Customer.[PM Failure Assigned Score], Customer.[Current Risk], Customer.[Updated Date] AS DataAggiornamento, Customer.[valuation Date] AS DataValutazione, [Customer.Due Date] AS DataScadenza, Customer.[Updated Type], Customer.[Skip Credit Info Update], Sum(Val([Detailed Cust_ Ledg_ Entry.Amount])) AS SaldoD
