-- [340] AnalisiPosizionamento
SELECT Item.[Line Code] AS Linea, [Sales Line].No_ AS Articolo, [Sales Line].[Constant Variable Code] AS CodiceColore, [Variable Code].Description AS Colore, [Sales Line].[Variable Code 02] AS [Size], Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione, Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,Val([quantity]),0)) AS PaiaConfermate, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, IIf(IsNull([AnalisiPosizionamentoWholesalePrice.item no_])=False,[WSPrice],"") AS WholesalePriceC, IIf(IsNull([AnalisiPosizionamentoRetailPrice.item no_])=False,[RetailPrice],"") AS RetailPriceC
FROM (((([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([Sales Line].[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN AnalisiPosizionamentoRetailPrice ON [Sales Line].No_ = AnalisiPosizionamentoRetailPrice.[Item No_]) LEFT JOIN AnalisiPosizionamentoWholeSalePrice ON [Sales Line].No_ = AnalisiPosizionamentoWholeSalePrice.[Item No_]
GROUP BY Item.[Line Code], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Variable Code].Description, [Sales Line].[Variable Code 02], Item.[Trademark Code], Item.[Season Code], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, IIf(IsNull([AnalisiPosizionamentoWholesalePrice.item no_])=False,[WSPrice],""), IIf(IsNull([AnalisiPosizionamentoRetailPrice.item no_])=False,[RetailPrice],"")
HAVING (((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND ((Item.[Season Code])=[Maschere]![principale]![filtroStagione]) AND ((Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,Val([quantity]),0)))<>0))
ORDER BY Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,Val([quantity]),0)) DESC;

