-- [353] BLAUER_covid_1_ValorizzazioneSpeditoAPrezzoStandard
SELECT [Sales Header].[Bill-to Customer No_], [Sales Header].No_, [Sales Header].[Bill-to Name], [Sales Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Header].[selling season code], [Sales Line].type, Sum(IIf(Val([quantity])>0,Val([quantity shipped])*Val([no_ of pairs])/Val([quantity]),0)) AS pairsShipped, Sum(IIf(Val([quantity])>0,Val([quantity shipped])*Val([no_ of pairs])/Val([quantity])*Val([sales price model item.Unit Price]),0)) AS valueshippedAtPriceList, Sum(IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*(Val([Line Amount])-Val([Inv_ Discount Amount])),0)) AS ValueShipped, [Sales Header].[transport reason code], Sum(IIf(Val([quantity])>0,Val([return qty_ received])*Val([no_ of pairs])/Val([quantity]),0)) AS pairsReturned, Sum(IIf(Val([quantity])>0,Val([return qty_ received])*Val([no_ of pairs])/Val([quantity])*Val([sales price model item.Unit Price]),0)) AS valueReturnedAtPriceList, Sum(IIf(Val([quantity])>0,Val([return qty_ received])/Val([quantity])*(Val([Line Amount])-Val([Inv_ Discount Amount])),0)) AS Valuereturned
FROM ([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) INNER JOIN [Sales Price Model Item] ON ([Sales Header].[Customer Price Group] = [Sales Price Model Item].[Sales Code]) AND ([Sales Line].No_ = [Sales Price Model Item].[Model Item No_])
GROUP BY [Sales Header].[Bill-to Customer No_], [Sales Header].No_, [Sales Header].[Bill-to Name], [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[selling season code], [Sales Line].type, [Sales Header].[transport reason code], [Sales Header].[document type]
HAVING ((([Sales Header].[Shortcut Dimension 2 Code])<>"AP GIRL" And ([Sales Header].[Shortcut Dimension 2 Code])<>"BLK") AND (([Sales Header].[selling season code])=[Stagione]) AND (([Sales Line].type)=19 Or ([Sales Line].type)=20) AND ((Sum(IIf(Val([quantity])>0,Val([quantity shipped])*Val([no_ of pairs])/Val([quantity]),0)))>0) AND (([Sales Header].[document type])=1)) OR ((([Sales Header].[Shortcut Dimension 2 Code])<>"AP GIRL" And ([Sales Header].[Shortcut Dimension 2 Code])<>"BLK") AND (([Sales Header].[selling season code])=[Stagione]) AND (([Sales Line].type)=19 Or ([Sales Line].type)=20) AND ((Sum(IIf(Val([quantity])>0,Val([return qty_ received])*Val([no_ of pairs])/Val([quantity]),0)))>0) AND (([Sales Header].[document type])=5));

GO

-- [354] BLAUER_covid_2a_FATTURE
SELECT [Sales Invoice Header].[Bill-to Customer No_], [Sales Invoice Header].[Bill-to Name], Sum(Val([Amount])) AS Importo, [Sales Invoice Header].[selling season code], [Sales Invoice Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Invoice Line].Type, "FATT" AS TIPO
FROM [Sales Invoice Line] INNER JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_
GROUP BY [Sales Invoice Header].[Bill-to Customer No_], [Sales Invoice Header].[Bill-to Name], [Sales Invoice Header].[selling season code], [Sales Invoice Header].[Shortcut Dimension 2 Code], [Sales Invoice Line].Type, "FATT"
HAVING ((([Sales Invoice Header].[selling season code])="E20") AND (([Sales Invoice Header].[Shortcut Dimension 2 Code])="BLAUER") AND (([Sales Invoice Line].Type)=1 Or ([Sales Invoice Line].Type)=2));

GO

-- [355] BLAUER_covid_2b_NDC
SELECT [Sales Cr_Memo Header].[Bill-to Customer No_], [Sales Cr_Memo Header].[Bill-to Name], Sum(Val([Amount])) AS Importo, [Sales Cr_Memo Header].[selling season code], [Sales Cr_Memo Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Cr_Memo Line].Type, "NDC" AS TIPO
FROM [Sales Cr_Memo Line] INNER JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_
GROUP BY [Sales Cr_Memo Header].[Bill-to Customer No_], [Sales Cr_Memo Header].[Bill-to Name], [Sales Cr_Memo Header].[selling season code], [Sales Cr_Memo Header].[Shortcut Dimension 2 Code], [Sales Cr_Memo Line].Type, "NDC"
HAVING ((([Sales Cr_Memo Header].[selling season code])="E20") AND (([Sales Cr_Memo Header].[Shortcut Dimension 2 Code])="BLAUER") AND (([Sales Cr_Memo Line].Type)=1 Or ([Sales Cr_Memo Line].Type)=2));

GO

-- [356] BLAUER_covid_2c_FATTURE E NDC
SELECT [Bill-to Customer No_], [Bill-to Name], Importo, [selling season code], Marchio, TIPO
FROM BLAUER_covid_2a_FATTURE;

UNION ALL SELECT [Bill-to Customer No_], [Bill-to Name], -Importo, [selling season code], Marchio, TIPO
FROM BLAUER_covid_2b_NDC;

GO

-- [357] BLAUER_covid_FATTURE E NDC_NON USARE LORDO IVA
SELECT [Cust_ Ledger Entry].[Customer No_], Round(Sum(IIf([entry type]=1 Or [entry type]=3 Or [entry type]=4 Or [entry type]=5 Or [entry type]=6 Or [entry type]=7 Or [entry type]=8 Or [entry type]=9 Or [entry type]=12 Or [entry type]=13 Or [entry type]=14 Or [entry type]=15 Or [entry type]=16 Or [entry type]=17,Val([Amount]),0))*10000)/10000 AS Importo, Round(Sum(Val([Amount]))*10000)/10000 AS ImportoResiduo
FROM (([Cust_ Ledger Entry] INNER JOIN [Detailed Cust_ Ledg_ Entry] ON [Cust_ Ledger Entry].[Entry No_] = [Detailed Cust_ Ledg_ Entry].[Cust_ Ledger Entry No_]) LEFT JOIN [Sales Invoice Header] ON [Cust_ Ledger Entry].[Document No_] = [Sales Invoice Header].No_) LEFT JOIN [Sales Cr_Memo Header] ON [Cust_ Ledger Entry].[Document No_] = [Sales Cr_Memo Header].No_
WHERE ((([Cust_ Ledger Entry].[Document Type])=2) AND (([Sales Invoice Header].[SELLING SEASON CODE])="E20") AND (([Sales Invoice Header].[Shortcut Dimension 2 Code])="BLAUER")) OR ((([Cust_ Ledger Entry].[Document Type])=3) AND (([Sales Cr_Memo Header].[SELLING SEASON CODE])="E20") AND (([Sales Cr_Memo Header].[Shortcut Dimension 2 Code])="BLAUER"))
GROUP BY [Cust_ Ledger Entry].[Customer No_];

GO

-- [358] BoxBarcodePallet
SELECT LettureSovraccolliTXT.boxbarcode, LettureSovraccolliTXT.pallet, AnagraficheLogimodaE20.Articolo, AnagraficheLogimodaE20.Colore, AnagraficheLogimodaE20.Assortimento, AnagraficheLogimodaE20.Quantita
FROM LettureSovraccolliTXT LEFT JOIN AnagraficheLogimodaE20 ON LettureSovraccolliTXT.boxbarcode = AnagraficheLogimodaE20.Collo;

GO

-- [359] BudgetVend-Both
SELECT [qSoloVend-perBudget].SalesPersonCode AS SalespersonCode, [qSoloVend-perBudget].Salesperson, [qSoloVend-perBudget].CustomerCode, Budget.CustomerName, Budget.Trademark, [qSoloVend-perBudget].SeasonCode, [qSoloVend-perBudget].PairsSold, Budget.PairsBudget, [qSoloVend-perBudget].salesvalue, Budget.ValueBudget, Budget.Doors
FROM Budget INNER JOIN [qSoloVend-perBudget] ON (Budget.Trademark = [qSoloVend-perBudget].Trademark) AND (Budget.SeasonCode = [qSoloVend-perBudget].SeasonCode) AND (Budget.SalespersonCode = [qSoloVend-perBudget].SalesPersonCode) AND (Budget.CustomerCode = [qSoloVend-perBudget].CustomerCode);

GO

-- [360] BudgetVend-SoloBudget
SELECT Budget.SalespersonCode AS SalespersonCode, Budget.SalesPerson, Budget.CustomerCode, Budget.CustomerName, Budget.Trademark, Budget.SeasonCode, [qSoloVend-perBudget].PairsSold, Budget.PairsBudget, [qSoloVend-perBudget].salesvalue, Budget.ValueBudget, Budget.Doors, [qSoloVend-perBudget].SalesPersonCode
FROM Budget LEFT JOIN [qSoloVend-perBudget] ON (Budget.Trademark = [qSoloVend-perBudget].Trademark) AND (Budget.SeasonCode = [qSoloVend-perBudget].SeasonCode) AND (Budget.CustomerCode = [qSoloVend-perBudget].CustomerCode) AND (Budget.SalespersonCode = [qSoloVend-perBudget].SalesPersonCode)
WHERE ((([qSoloVend-perBudget].SalesPersonCode) Is Null));

GO

-- [361] BudgetVend-SoloVend
SELECT [qSoloVend-perBudget].SalesPersonCode AS SalespersonCode, [qSoloVend-perBudget].Salesperson, [qSoloVend-perBudget].CustomerCode, [qSoloVend-perBudget].CustomerName, [qSoloVend-perBudget].Trademark AS Trademark, [qSoloVend-perBudget].SeasonCode, [qSoloVend-perBudget].PairsSold, Budget.PairsBudget, [qSoloVend-perBudget].salesvalue, Budget.ValueBudget, Budget.Doors, Budget.SalespersonCode
FROM Budget RIGHT JOIN [qSoloVend-perBudget] ON (Budget.CustomerCode = [qSoloVend-perBudget].CustomerCode) AND (Budget.SalespersonCode = [qSoloVend-perBudget].SalesPersonCode) AND (Budget.Trademark = [qSoloVend-perBudget].Trademark) AND (Budget.SeasonCode = [qSoloVend-perBudget].SeasonCode)
WHERE (((Budget.SalespersonCode) Is Null));

GO

-- [362] BudgetVend-Union
SELECT SalespersonCode,Salesperson, CustomerCode, CustomerName, Trademark, SeasonCode, PairsSold, PairsBudget, SalesValue,ValueBudget, Doors
FROM [BudgetVend-Both];

union all SELECT SalespersonCode,Salesperson, CustomerCode, CustomerName, Trademark, SeasonCode, 0, PairsBudget, 0,ValueBudget, Doors
FROM [BudgetVend-SoloBudget];

UNION ALL SELECT SalespersonCode,Salesperson, CustomerCode, CustomerName, Trademark, SeasonCode, PairsSold, 0, SalesValue,0, 0
FROM [BudgetVend-SoloVend];

GO

-- [363] CalcoloDisponibilita
SELECT CalcoloDisponibilita_pre.*, IIf([sold out]=1 Or [Potential sold out]=1,1,0) AS VenditaLimitata, IIf([sold out]=1,0,IIf([Potential sold out]=1,IIf([tosellQTY]<=0,-[tosellQTY],0),0)) AS Quantità, IIf([sold out]=1,0,IIf([Potential sold out]=1,IIf([tosellQTY_CrossSeason]<=0,-[tosellQTY_CrossSeason],0),0)) AS Quantità_CrossSeason
FROM CalcoloDisponibilita_pre;

GO

-- [364] CalcoloDisponibilita_Pre
SELECT CalcoloDisponibilita_pre_pre.*, DisponibilitaCrossSeason.InvQTY_CrossSeason, DisponibilitaCrossSeason.InvPairs_CrossSeason, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty]>0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty],0) AS ToBuyQTY_CrossSeason, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[invpairs_crossseason]-[transpairs]>0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[invpairs_crossseason]-[transpairs],0) AS ToBuyPairs_CrossSeason, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty]<0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty],0) AS ToSellQTY_CrossSeason, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[invpairs_crossseason]-[traNSPAIRS]<0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[invpairs_crossseason]-[transPAIRS],0) AS ToSelLPairs_CrossSeason
FROM CalcoloDisponibilita_pre_pre LEFT JOIN DisponibilitaCrossSeason ON CalcoloDisponibilita_pre_pre.[Nr_ Articolo] = DisponibilitaCrossSeason.[Nr_ Articolo];

GO

-- [365] CalcoloDisponibilita_pre_pre
SELECT [CalcoloDisponibilita-step2].*, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty]>0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty],0) AS ToBuyQTY, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[transpairs]>0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[transpairs],0) AS ToBuyPairs, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty]<0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty],0) AS ToSellQTY, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[traNSPAIRS]<0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[transPAIRS],0) AS ToSelLPairs, [article] & "_" & [color] & "_" & [assortment] AS [Nr_ Articolo]
FROM [CalcoloDisponibilita-step2];

GO

-- [366] CalcoloDisponibilitaItem
SELECT Item.[Vendor No_], Vendor.Name, Item.Manufacturer, Vendor_1.Name, CalcoloDisponibilitaItem_pre.*, IIf([CalcoloDisponibilitaItem_pre.sold out]=1 Or [CalcoloDisponibilitaItem_pre.Potential sold out]=1,1,0) AS VenditaLimitata, IIf([CalcoloDisponibilitaItem_pre.sold out]=1,0,IIf([CalcoloDisponibilitaItem_pre.Potential sold out]=1,IIf([tosellQTY]<=0,-[tosellQTY],0),0)) AS Quantità, IIf([CalcoloDisponibilitaItem_pre.sold out]=1,0,IIf([CalcoloDisponibilitaItem_pre.Potential sold out]=1,IIf([tosellQTY_CrossSeason]<=0,-[tosellQTY_CrossSeason],0),0)) AS Quantità_CrossSeason
FROM ((CalcoloDisponibilitaItem_pre LEFT JOIN Item ON CalcoloDisponibilitaItem_pre.Article = Item.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_;

GO

-- [367] CalcoloDisponibilitaItem_Pre
SELECT CalcoloDisponibilitaItem_pre_pre.*, DisponibilitaCrossSeasonItem.InvQTY_CrossSeason, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty]>0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty],0) AS ToBuyQTY_CrossSeason, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty]<0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[invqty_crossseason]-[transqty],0) AS ToSellQTY_CrossSeason
FROM CalcoloDisponibilitaItem_pre_pre LEFT JOIN DisponibilitaCrossSeasonItem ON CalcoloDisponibilitaItem_pre_pre.[Nr_ Articolo] = DisponibilitaCrossSeasonItem.[Nr_ Articolo];

GO

-- [368] CalcoloDisponibilitaItem_pre_pre
SELECT [CalcoloDisponibilitaItem-step2].*, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty]>0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty],0) AS ToBuyQTY, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[transpairs]>0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[transpairs],0) AS ToBuyPairs, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty]<0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty],0) AS ToSellQTY, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[traNSPAIRS]<0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[transPAIRS],0) AS ToSelLPairs, Item.no_ AS [Nr_ Articolo]
FROM [CalcoloDisponibilitaItem-step2] INNER JOIN Item ON ([CalcoloDisponibilitaItem-step2].size = Item.[Variable Code 02]) AND ([CalcoloDisponibilitaItem-step2].Color = Item.[Variable Code 01]) AND ([CalcoloDisponibilitaItem-step2].Article = Item.[Model Item No_]);

GO

-- [369] CalcoloDisponibilitaItemPerStock
SELECT CalcoloDisponibilitaItemPerStock_pre.*, IIf([sold out]=1 Or [Potential sold out]=1,1,0) AS VenditaLimitata, IIf([sold out]=1,0,IIf([Potential sold out]=1,IIf([tosellQTY]<=0,-[tosellQTY],0),0)) AS Quantità
FROM CalcoloDisponibilitaItemPerStock_pre;

GO

-- [370] CalcoloDisponibilitaItemPerStock_pre
SELECT [CalcoloDisponibilitaItemPerStock-step2].*, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty]>0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty],0) AS ToBuyQTY, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[transpairs]>0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[transpairs],0) AS ToBuyPairs, IIf([SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty]<0,[SALESQTY]-[PURCHASEDQTY]-[INVQTY]-[transqty],0) AS ToSellQTY, IIf([SALESpairs]-[PURCHASEdpairs]-[INVpairs]-[traNSPAIRS]<0,[SALESpairs]-[PURCHASEDpairs]-[INVpairs]-[transPAIRS],0) AS ToSelLPairs, Item.no_ AS [Nr_ Articolo]
FROM Item INNER JOIN [CalcoloDisponibilitaItemPerStock-step2] ON (Item.[Variable Code 02] = [CalcoloDisponibilitaItemPerStock-step2].size) AND (Item.[Variable Code 01] = [CalcoloDisponibilitaItemPerStock-step2].Color) AND (Item.[Model Item No_] = [CalcoloDisponibilitaItemPerStock-step2].Article);

GO

-- [371] CalcoloDisponibilitaItemPerStock-step0-GiacenzaItem
SELECT "INV" AS Cat, Item.[Trademark Code] AS Trademark, Item.[Season Code] AS [Selling season code], Item.[LINE CODE], [Item Ledger Entry].[Model Item No_] AS Article, Item.[Description 2], [Item Ledger Entry].[variable code 01] AS Color, [Item Ledger Entry].[variable code 02] AS [size], Sum(Val([Quantity])) AS qty, Sum(0) AS pairs
FROM ([Item Ledger Entry] INNER JOIN Location ON [Item Ledger Entry].[Location Code] = Location.Code) INNER JOIN Item ON [Item Ledger Entry].[Model Item No_] = Item.No_
WHERE (((Item.[ADVERTISING MATERIAL])=0) AND ((Location.[Enable to Purchase Run])=1))
GROUP BY "INV", Item.[Trademark Code], Item.[Season Code], Item.[LINE CODE], [Item Ledger Entry].[Model Item No_], Item.[Description 2], [Item Ledger Entry].[variable code 01], [Item Ledger Entry].[variable code 02]
HAVING (((Item.[Trademark Code])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[Season Code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([Quantity])))<>0));

GO

-- [372] CalcoloDisponibilitaItemPerStock-step0-MasterData
SELECT "MasterData" AS Cat, Item.[trademark code] AS Trademark, Item.[season code] AS [selling season code], Item.[line code], Item.[Model Item No_] AS Article, Item.[Description 2], Item.[Variable code 01] AS Color, Item.[variable code 02] AS [size], 0 AS qty, 0 AS Pairs
FROM Item
WHERE (((Item.[configurator relation])=3) AND ((Item.[advertising material])=0))
GROUP BY Item.[trademark code], Item.[season code], Item.[line code], Item.[Model Item No_], Item.[Description 2], Item.[Variable code 01], Item.[variable code 02]
HAVING (((Item.[trademark code])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[season code])=[forms]![principale]![FiltroStagioneSourcing]));

GO

-- [373] CalcoloDisponibilitaItemPerStock-step0-VenditeNette
SELECT "Sales" AS Cat, [Sales Header].[Shortcut Dimension 2 Code] AS Trademark, [Sales Line].[selling season code], Item.[LINE CODE], [Sales Line].[model item No_] AS Article, Item.[Description 2], [Sales Line].[variable code 01] AS Color, [Sales Line].[variable code 02] AS [size], Sum(Val([outstanding quantity])) AS Qty, Sum(IIf(Val([quantity])>0,Val([no_ of pairs])*Val([outstanding quantity])/Val([QUANTITY]),0)) AS Pairs
FROM ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_
WHERE ((([Sales Header].[Order Type])=3) AND (([Sales Line].[delete reason])="") AND (([Sales Line].Type)=2) AND ((Item.[advertising material])=0))
GROUP BY "Sales", [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[selling season code], Item.[LINE CODE], [Sales Line].[model item No_], Item.[Description 2], [Sales Line].[variable code 01], [Sales Line].[variable code 02]
HAVING ((([Sales Header].[Shortcut Dimension 2 Code])=[forms]![principale]![FiltroMarchioSourcing]) AND (([Sales Line].[selling season code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([outstanding quantity])))>0));

GO

-- [374] CalcoloDisponibilitaItemPerStock-step1
SELECT *
FROM [CalcoloDisponibilitaItemPerStock-step0-VenditeNette];



UNION ALL SELECT *
FROM [CalcoloDisponibilitaItemPerStock-step0-GiacenzaItem];



UNION ALL SELECT *
FROM [CalcoloDisponibilitaItemPerStock-step0-MasterData];

GO

-- [375] CalcoloDisponibilitaItemPerStock-step2
SELECT [CalcoloDisponibilitaItemPerStock-step1].Trademark, [CalcoloDisponibilitaItemPerStock-step1].[selling season code], [CalcoloDisponibilitaItemPerStock-step1].[LINE CODE], [CalcoloDisponibilitaItemPerStock-step1].Article, [CalcoloDisponibilitaItemPerStock-step1].[Description 2], DatiCarryOverESMU.[Sales_Purchase Status - Item], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Potential Sold Out], [CalcoloDisponibilitaItemPerStock-step1].Color, [CalcoloDisponibilitaItemPerStock-step1].size, Sum(IIf([cat]="sales",[qty],0)) AS SalesQty, Sum(IIf([cat]="sales",[pairs],0)) AS SalesPairs, Sum(IIf([cat]="Purch",[qty],0)) AS PurchasedQty, Sum(IIf([cat]="Purch",[pairs],0)) AS PurchasedPairs, Sum(IIf([cat]="Trans",[qty],0)) AS TransQty, Sum(IIf([cat]="Trans",[pairs],0)) AS TransPairs, Sum(IIf([cat]="inv",[qty],0)) AS InvQty, Sum(IIf([cat]="inv",[pairs],0)) AS InvPairs
FROM [CalcoloDisponibilitaItemPerStock-step1] LEFT JOIN DatiCarryOverESMU ON ([CalcoloDisponibilitaItemPerStock-step1].Color = DatiCarryOverESMU.[Variable Code 01]) AND ([CalcoloDisponibilitaItemPerStock-step1].Article = DatiCarryOverESMU.[Model Item No_])
GROUP BY [CalcoloDisponibilitaItemPerStock-step1].Trademark, [CalcoloDisponibilitaItemPerStock-step1].[selling season code], [CalcoloDisponibilitaItemPerStock-step1].[LINE CODE], [CalcoloDisponibilitaItemPerStock-step1].Article, [CalcoloDisponibilitaItemPerStock-step1].[Description 2], DatiCarryOverESMU.[Sales_Purchase Status - Item], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Potential Sold Out], [CalcoloDisponibilitaItemPerStock-step1].Color, [CalcoloDisponibilitaItemPerStock-step1].size;

GO

-- [376] CalcoloDisponibilitaItem-step0-AcquistiNetti
SELECT "PURCH" AS Cat, [Purchase Header].[Shortcut Dimension 2 Code] AS Trademark, [Purchase Header].[selling season code], Item.[LINE CODE], [Purchase Line].[model item No_] AS Article, Item.[Description 2], [Purchase Line].[variable code 01] AS Color, [Purchase Line].[variable code 02] AS [Size], Sum(Val([outstanding quantity])) AS Qty, Sum(IIf(Val([quantity])>0,Val([no_ of pairs])*Val([outstanding quantity])/Val([QUANTITY]),0)) AS Pairs
FROM (Item INNER JOIN [Purchase Line] ON Item.No_ = [Purchase Line].No_) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_
WHERE ((([Purchase Line].[delete reason])="") AND (([Purchase Line].Type)=2) AND ((Item.[advertising material])=0))
GROUP BY "PURCH", [Purchase Header].[Shortcut Dimension 2 Code], [Purchase Header].[selling season code], Item.[LINE CODE], [Purchase Line].[model item No_], Item.[Description 2], [Purchase Line].[variable code 01], [Purchase Line].[variable code 02]
HAVING ((([Purchase Header].[Shortcut Dimension 2 Code])=[forms]![principale]![FiltroMarchioSourcing]) AND (([Purchase Header].[selling season code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([outstanding quantity])))>0));

GO

-- [377] CalcoloDisponibilitaItem-step0-GiacenzaItem
SELECT "INV" AS Cat, Item.[Trademark Code] AS Trademark, Item.[Season Code] AS [Selling season code], Item.[LINE CODE], [Item Ledger Entry].[Model Item No_] AS Article, Item.[Description 2], [Item Ledger Entry].[variable code 01] AS Color, [Item Ledger Entry].[variable code 02] AS [size], Sum(Val([Quantity])) AS qty, Sum(0) AS pairs
FROM ([Item Ledger Entry] INNER JOIN Location ON [Item Ledger Entry].[Location Code] = Location.Code) INNER JOIN Item ON [Item Ledger Entry].[Model Item No_] = Item.No_
WHERE (((Item.[ADVERTISING MATERIAL])=0) AND ((Location.[Enable to Purchase Run])=1))
GROUP BY "INV", Item.[Trademark Code], Item.[Season Code], Item.[LINE CODE], [Item Ledger Entry].[Model Item No_], Item.[Description 2], [Item Ledger Entry].[variable code 01], [Item Ledger Entry].[variable code 02]
HAVING (((Item.[Trademark Code])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[Season Code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([Quantity])))<>0));

GO

-- [378] CalcoloDisponibilitaItem-step0-MasterData
SELECT "MasterData" AS Cat, Item.[trademark code] AS Trademark, Item.[season code] AS [selling season code], Item.[line code], Item.[Model Item No_] AS Article, Item.[Description 2], Item.[Variable code 01] AS Color, Item.[variable code 02] AS [size], 0 AS qty, 0 AS Pairs
FROM Item
WHERE (((Item.[configurator relation])=3) AND ((Item.[advertising material])=0))
GROUP BY Item.[trademark code], Item.[season code], Item.[line code], Item.[Model Item No_], Item.[Description 2], Item.[Variable code 01], Item.[variable code 02]
HAVING (((Item.[trademark code])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[season code])=[forms]![principale]![FiltroStagioneSourcing]));

GO

-- [379] CalcoloDisponibilitaItem-step0-TrasferimentiNetti
SELECT "TRANS" AS Cat, Item.[TRADEMARK CODE] AS Trademark, Item.[SEASON CODE] AS [selling season code], Item.[LINE CODE], [Transfer Line].[MODEL ITEM No_] AS Article, Item.[Description 2], [Transfer Line].[variable code 01] AS Color, [Transfer Line].[variable code 02] AS [size], Sum(Val([QUANTITY])-Val([QUANTITY RECEIVED])) AS Qty, Sum(IIf(Val([quantity])>0,Val([no_ of pairs])*(Val([QUANTITY])-Val([QUANTITY RECEIVED]))/Val([QUANTITY]),0)) AS Pairs
FROM (([Transfer Line] INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_) INNER JOIN Item ON [Transfer Line].[Item No_] = Item.No_) INNER JOIN Location ON [Transfer Header].[Transfer-to Code] = Location.Code
WHERE ((([Transfer Line].[ITEM Type])=0) AND ((Item.[advertising material])=0) AND ((Location.[Enable to Purchase Run])=1) AND (([Transfer Line].[Derived From Line No_])=0))
GROUP BY "TRANS", Item.[TRADEMARK CODE], Item.[SEASON CODE], Item.[LINE CODE], [Transfer Line].[MODEL ITEM No_], Item.[Description 2], [Transfer Line].[variable code 01], [Transfer Line].[variable code 02]
HAVING (((Item.[TRADEMARK CODE])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[SEASON CODE])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([QUANTITY])-Val([QUANTITY RECEIVED])))>0));

GO

-- [380] CalcoloDisponibilitaItem-step0-VenditeNette
SELECT "Sales" AS Cat, [Sales Header].[Shortcut Dimension 2 Code] AS Trademark, [Sales Line].[selling season code], Item.[LINE CODE], [Sales Line].[model item No_] AS Article, Item.[Description 2], [Sales Line].[variable code 01] AS Color, [Sales Line].[variable code 02] AS [size], Sum(Val([outstanding quantity])) AS Qty, Sum(IIf(Val([quantity])>0,Val([no_ of pairs])*Val([outstanding quantity])/Val([QUANTITY]),0)) AS Pairs
FROM ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_
WHERE ((([Sales Line].[delete reason])="") AND (([Sales Line].Type)=2) AND ((Item.[advertising material])=0))
GROUP BY "Sales", [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[selling season code], Item.[LINE CODE], [Sales Line].[model item No_], Item.[Description 2], [Sales Line].[variable code 01], [Sales Line].[variable code 02]
HAVING ((([Sales Header].[Shortcut Dimension 2 Code])=[forms]![principale]![FiltroMarchioSourcing]) AND (([Sales Line].[selling season code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([outstanding quantity])))>0));

GO

