-- [382] CalcoloDisponibilitaItem-step2
SELECT [CalcoloDisponibilitaItem-step1].Trademark, [CalcoloDisponibilitaItem-step1].[selling season code], [CalcoloDisponibilitaItem-step1].[LINE CODE], [CalcoloDisponibilitaItem-step1].Article, [CalcoloDisponibilitaItem-step1].[Description 2], DatiCarryOverESMU.[Sales_Purchase Status - Item], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Potential Sold Out], [CalcoloDisponibilitaItem-step1].Color, [CalcoloDisponibilitaItem-step1].size, Sum(IIf([cat]="sales",[qty],0)) AS SalesQty, Sum(IIf([cat]="sales",[pairs],0)) AS SalesPairs, Sum(IIf([cat]="Purch",[qty],0)) AS PurchasedQty, Sum(IIf([cat]="Purch",[pairs],0)) AS PurchasedPairs, Sum(IIf([cat]="Trans",[qty],0)) AS TransQty, Sum(IIf([cat]="Trans",[pairs],0)) AS TransPairs, Sum(IIf([cat]="inv",[qty],0)) AS InvQty, Sum(IIf([cat]="inv",[pairs],0)) AS InvPairs
FROM [CalcoloDisponibilitaItem-step1] LEFT JOIN DatiCarryOverESMU ON ([CalcoloDisponibilitaItem-step1].Color = DatiCarryOverESMU.[Variable Code 01]) AND ([CalcoloDisponibilitaItem-step1].Article = DatiCarryOverESMU.[Model Item No_])
GROUP BY [CalcoloDisponibilitaItem-step1].Trademark, [CalcoloDisponibilitaItem-step1].[selling season code], [CalcoloDisponibilitaItem-step1].[LINE CODE], [CalcoloDisponibilitaItem-step1].Article, [CalcoloDisponibilitaItem-step1].[Description 2], DatiCarryOverESMU.[Sales_Purchase Status - Item], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Potential Sold Out], [CalcoloDisponibilitaItem-step1].Color, [CalcoloDisponibilitaItem-step1].size;

GO

-- [383] CalcoloDisponibilita-step0-AcquistiNetti
SELECT "PURCH" AS Cat, [Purchase Header].[Shortcut Dimension 2 Code] AS Trademark, [Purchase Header].[selling season code], Item.[LINE CODE], [Purchase Line].No_ AS Article, Item.[Description 2], [Purchase Line].[Constant variable code] AS Color, [Purchase Line].[assortment code] AS Assortment, Sum(Val([outstanding quantity])) AS Qty, Sum(IIf(Val([quantity])>0,Val([no_ of pairs])*Val([outstanding quantity])/Val([QUANTITY]),0)) AS Pairs
FROM (Item INNER JOIN [Purchase Line] ON Item.No_ = [Purchase Line].No_) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_
WHERE ((([Purchase Line].[delete reason])="") AND (([Purchase Line].Type)=20) AND ((Item.[advertising material])=0))
GROUP BY "PURCH", [Purchase Header].[Shortcut Dimension 2 Code], [Purchase Header].[selling season code], Item.[LINE CODE], [Purchase Line].No_, Item.[Description 2], [Purchase Line].[Constant variable code], [Purchase Line].[assortment code]
HAVING ((([Purchase Header].[Shortcut Dimension 2 Code])=[forms]![principale]![FiltroMarchioSourcing]) AND (([Purchase Header].[selling season code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([outstanding quantity])))>0));

GO

-- [384] CalcoloDisponibilita-step0-GiacenzaAssortimenti
SELECT "INV" AS Cat, Item.[Trademark Code] AS Trademark, Item.[Season Code] AS [Selling season code], Item.[LINE CODE], [Assortment Ledger Entry].[Model Item No_] AS Article, Item.[Description 2], [Assortment Ledger Entry].[Constant Variable Code] AS Color, [Assortment Ledger Entry].[Assortment Code] AS Assortiment, Sum(Val([Quantity])) AS qty, Sum([AssortmentQuantity]*Val([quantity])) AS pairs
FROM (([Assortment Ledger Entry] INNER JOIN Item ON [Assortment Ledger Entry].[Model Item No_] = Item.No_) INNER JOIN AssortimentiQuantita ON ([Assortment Ledger Entry].[Assortment Code] = AssortimentiQuantita.[Assortment Code]) AND ([Assortment Ledger Entry].[Assortment Variable Group] = AssortimentiQuantita.[Variable Group])) INNER JOIN Location ON [Assortment Ledger Entry].[Location Code] = Location.Code
WHERE (((Item.[ADVERTISING MATERIAL])=0) AND ((Location.[Enable to Purchase Run])=1))
GROUP BY "INV", Item.[Trademark Code], Item.[Season Code], Item.[LINE CODE], [Assortment Ledger Entry].[Model Item No_], Item.[Description 2], [Assortment Ledger Entry].[Constant Variable Code], [Assortment Ledger Entry].[Assortment Code]
HAVING (((Item.[Trademark Code])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[Season Code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([Quantity])))<>0));

GO

-- [385] CalcoloDisponibilita-step0-MasterData
SELECT "MasterData" AS Cat, Item.[trademark code] AS Trademark, Item.[season code] AS [selling season code], Item.[line code], Item.[Model Item No_] AS Article, Item.[Description 2], Item.[Variable code 01] AS Color, [Valid Model Item Assortments].[assortment code] AS Assortment, 0 AS qty, 0 AS Pairs
FROM Item INNER JOIN [Valid Model Item Assortments] ON Item.[Model Item No_] = [Valid Model Item Assortments].[Model Item No_]
WHERE (((Item.[configurator relation])=3) AND ((Item.[advertising material])=0))
GROUP BY Item.[trademark code], Item.[season code], Item.[line code], Item.[Model Item No_], Item.[Description 2], Item.[Variable code 01], [Valid Model Item Assortments].[assortment code]
HAVING (((Item.[trademark code])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[season code])=[forms]![principale]![FiltroStagioneSourcing]));

GO

-- [386] CalcoloDisponibilita-step0-TrasferimentiNetti
SELECT "TRANS" AS Cat, Item.[TRADEMARK CODE] AS Trademark, Item.[SEASON CODE] AS [selling season code], Item.[LINE CODE], [Transfer Line].[ITEM No_] AS Article, Item.[Description 2], [Transfer Line].[Constant variable code] AS Color, [Transfer Line].[assortment code] AS Assortment, Sum(Val([QUANTITY])-Val([QUANTITY RECEIVED])) AS Qty, Sum(IIf(Val([quantity])>0,Val([no_ of pairs])*(Val([QUANTITY])-Val([QUANTITY RECEIVED]))/Val([QUANTITY]),0)) AS Pairs
FROM (([Transfer Line] INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_) INNER JOIN Item ON [Transfer Line].[Item No_] = Item.No_) INNER JOIN Location ON [Transfer Header].[Transfer-to Code] = Location.Code
WHERE ((([Transfer Line].[ITEM Type])=20) AND ((Item.[advertising material])=0) AND ((Location.[Enable to Purchase Run])=1) AND (([Transfer Line].[Derived From Line No_])=0))
GROUP BY "TRANS", Item.[TRADEMARK CODE], Item.[SEASON CODE], Item.[LINE CODE], [Transfer Line].[ITEM No_], Item.[Description 2], [Transfer Line].[Constant variable code], [Transfer Line].[assortment code]
HAVING (((Item.[TRADEMARK CODE])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[SEASON CODE])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Sum(Val([QUANTITY])-Val([QUANTITY RECEIVED])))>0));

GO

-- [387] CalcoloDisponibilita-step0-VenditeNette
SELECT "Sales" AS Cat, [Sales Header].[Shortcut Dimension 2 Code] AS Trademark, [Sales Line].[selling season code], Item.[LINE CODE], [Sales Line].No_ AS Article, Item.[Description 2], [Sales Line].[Constant variable code] AS Color, [Sales Line].[assortment code] AS Assortment, Sum(Val([outstanding quantity])) AS Qty, Sum(IIf(Val([quantity])>0,Val([no_ of pairs])*Val([outstanding quantity])/Val([QUANTITY]),0)) AS Pairs
FROM ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_
