GROUP BY "Sales", [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[selling season code], Item.[LINE CODE], [Sales Line].No_, Item.[Description 2], [Sales Line].[Constant variable code], [Sales Line].[assortment code]
