-- [389] CalcoloDisponibilita-step2
SELECT [CalcoloDisponibilita-step1].Trademark, [CalcoloDisponibilita-step1].[selling season code], [CalcoloDisponibilita-step1].[LINE CODE], [CalcoloDisponibilita-step1].Article, [CalcoloDisponibilita-step1].[Description 2], DatiCarryOverESMU.[Sales_Purchase Status - Item], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Potential Sold Out], [CalcoloDisponibilita-step1].Color, [CalcoloDisponibilita-step1].Assortment, Sum(IIf([cat]="sales",[qty],0)) AS SalesQty, Sum(IIf([cat]="sales",[pairs],0)) AS SalesPairs, Sum(IIf([cat]="Purch",[qty],0)) AS PurchasedQty, Sum(IIf([cat]="Purch",[pairs],0)) AS PurchasedPairs, Sum(IIf([cat]="Trans",[qty],0)) AS TransQty, Sum(IIf([cat]="Trans",[pairs],0)) AS TransPairs, Sum(IIf([cat]="inv",[qty],0)) AS InvQty, Sum(IIf([cat]="inv",[pairs],0)) AS InvPairs
FROM [CalcoloDisponibilita-step1] LEFT JOIN DatiCarryOverESMU ON ([CalcoloDisponibilita-step1].Color = DatiCarryOverESMU.[Variable Code 01]) AND ([CalcoloDisponibilita-step1].Article = DatiCarryOverESMU.[Model Item No_])
GROUP BY [CalcoloDisponibilita-step1].Trademark, [CalcoloDisponibilita-step1].[selling season code], [CalcoloDisponibilita-step1].[LINE CODE], [CalcoloDisponibilita-step1].Article, [CalcoloDisponibilita-step1].[Description 2], DatiCarryOverESMU.[Sales_Purchase Status - Item], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Potential Sold Out], [CalcoloDisponibilita-step1].Color, [CalcoloDisponibilita-step1].Assortment;

