-- [390] CarichiAllaData
SELECT [Purch_ Rcpt_ Header].[Posting Date], Item.[Trademark Code], Item.[Season Code], Sum(Val([Purch_ Rcpt_ Line.no_ of pairs])) AS PairsReceived, [Purchase Line].[Document No_], [Purchase Line].[Line No_], [Purch_ Rcpt_ Line].Type, Vendor.Name, [datalimite] AS dataGiacenza
FROM ((([Purch_ Rcpt_ Line] INNER JOIN ([Purchase Line] INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_) ON ([Purch_ Rcpt_ Line].[Order Line No_] = [Purchase Line].[Line No_]) AND ([Purch_ Rcpt_ Line].[Order No_] = [Purchase Line].[Document No_])) INNER JOIN Item ON [Purch_ Rcpt_ Line].No_ = Item.No_) INNER JOIN [Purch_ Rcpt_ Header] ON [Purch_ Rcpt_ Line].[Document No_] = [Purch_ Rcpt_ Header].No_) INNER JOIN Vendor ON [Purchase Header].[Buy-from Vendor No_] = Vendor.No_
GROUP BY [Purch_ Rcpt_ Header].[Posting Date], Item.[Trademark Code], Item.[Season Code], [Purchase Line].[Document No_], [Purchase Line].[Line No_], [Purch_ Rcpt_ Line].Type, Vendor.Name, [datalimite]
HAVING ((([Purch_ Rcpt_ Header].[Posting Date])<=[datalimite]) AND ((Item.[Season Code])=[stagione]) AND ((Sum(Val([Purch_ Rcpt_ Line.no_ of pairs])))<>0) AND (([Purch_ Rcpt_ Line].Type)=19 Or ([Purch_ Rcpt_ Line].Type)=20));

GO

-- [391] CarichiNegozioOutletDaDdt
SELECT "Carico" AS TipoMovimento, [DDT_Picking Header].No_ AS NoDocumento, [DDT_Picking Header].[Posted Date] AS DataVendita, EANCodes.[Cross-Reference No_] AS EANCode, Val([quantity]) AS quantita, [DDT_Picking Line].[Model Item No_] AS Articolo, [DDT_Picking Line].[Variable Code 01] AS Colore, [DDT_Picking Line].[Variable Code 02] AS Taglia, Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione
FROM (([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) LEFT JOIN EANCodes ON [DDT_Picking Line].No_ = EANCodes.[Item No_]) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_
WHERE ((([DDT_Picking Header].No_)=[Forms]![Principale]![FiltroDDTPerNegozioOutlet]) AND (([DDT_Picking Line].Type)=2));

GO

-- [392] CarichiNegozioOutletDaResoTrasferimento
SELECT "ResoCarico" AS TipoMovimento, [Transfer Shipment Header].No_ AS NoDocumento, [Transfer Shipment Header].[Posting Date] AS DataVendita, EANCodes.[Cross-Reference No_] AS EANCode, -Val([quantity]) AS quantita, [Transfer Shipment Line].[Model Item No_] AS Articolo, [Transfer Shipment Line].[Variable Code 01] AS Colore, [Transfer Shipment Line].[Variable Code 02] AS Taglia, Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione
FROM (([Transfer Shipment Header] INNER JOIN [Transfer Shipment Line] ON [Transfer Shipment Header].No_ = [Transfer Shipment Line].[Document No_]) LEFT JOIN EANCodes ON [Transfer Shipment Line].[Item No_] = EANCodes.[Item No_]) INNER JOIN Item ON [Transfer Shipment Line].[Item No_] = Item.No_
WHERE ((([Transfer Shipment Header].No_)=[Forms]![Principale]![FiltroOdtPerNegozioOutlet]) AND (([Transfer Shipment Line].[Item Type])=0) AND ((Item.[advertising material])=0) AND (([Transfer Shipment Header].[Transfer-from Code])="VENEZIA" Or ([Transfer Shipment Header].[Transfer-from Code])="VENEZIA 2"));

GO

-- [393] CarichiNegozioOutletDaTrasferimento
SELECT "Carico" AS TipoMovimento, [Transfer Shipment Header].No_ AS NoDocumento, [Transfer Shipment Header].[Posting Date] AS DataVendita, EANCodes.[Cross-Reference No_] AS EANCode, Val([quantity]) AS quantita, [Transfer Shipment Line].[Model Item No_] AS Articolo, [Transfer Shipment Line].[Variable Code 01] AS Colore, [Transfer Shipment Line].[Variable Code 02] AS Taglia, Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione
FROM (([Transfer Shipment Header] INNER JOIN [Transfer Shipment Line] ON [Transfer Shipment Header].No_ = [Transfer Shipment Line].[Document No_]) LEFT JOIN EANCodes ON [Transfer Shipment Line].[Item No_] = EANCodes.[Item No_]) INNER JOIN Item ON [Transfer Shipment Line].[Item No_] = Item.No_
WHERE ((([Transfer Shipment Header].No_)=[Forms]![Principale]![FiltroOdtPerNegozioOutlet]) AND (([Transfer Shipment Line].[Item Type])=0) AND ((Item.[advertising material])=0) AND (([Transfer Shipment Header].[Transfer-TO Code])="VENEZIA" Or ([Transfer Shipment Header].[Transfer-TO Code])="VENEZIA 2"));

GO

-- [394] ClientiConVenduto
SELECT [ClientiConVenduto-Step0].[Delete Reason], Item.[Season Code], Item.[Trademark Code], [ClientiConVenduto-Step0].Salesperson, [ClientiConVenduto-Step0].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Address 2], Customer.City, Customer.[Post Code], Customer.County, Customer.[Country Code], Customer.[Phone No_], Customer.[Telex No_], Customer.[Fax No_], Customer.[Reservation Priority], Val([Credit Limit (LCY)]) AS LimiteCredito, Customer.[Payment Terms Code], Customer.[Payment Method Code], [ClientiConVenduto-Step0].[Ship-to Name], [ClientiConVenduto-Step0].[Ship-to Name 2], [ClientiConVenduto-Step0].[Ship-to Address], [ClientiConVenduto-Step0].[Ship-to Address 2], [ClientiConVenduto-Step0].[Ship-to City], [ClientiConVenduto-Step0].[Ship-to Post Code], [ClientiConVenduto-Step0].[Ship-to County], [ClientiConVenduto-Step0].[Ship-to Country Code], Sum(Val([No_ of Pairs])) AS PairsTotal, Sum([ClientiConVenduto-Step0].SalesValue) AS Venduto, Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[E-Mail]
FROM ([ClientiConVenduto-Step0] INNER JOIN Item ON [ClientiConVenduto-Step0].No_ = Item.No_) INNER JOIN Customer ON [ClientiConVenduto-Step0].[Sell-to Customer No_] = Customer.No_
GROUP BY [ClientiConVenduto-Step0].[Delete Reason], Item.[Season Code], Item.[Trademark Code], [ClientiConVenduto-Step0].Salesperson, [ClientiConVenduto-Step0].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Address 2], Customer.City, Customer.[Post Code], Customer.County, Customer.[Country Code], Customer.[Phone No_], Customer.[Telex No_], Customer.[Fax No_], Customer.[Reservation Priority], Val([Credit Limit (LCY)]), Customer.[Payment Terms Code], Customer.[Payment Method Code], [ClientiConVenduto-Step0].[Ship-to Name], [ClientiConVenduto-Step0].[Ship-to Name 2], [ClientiConVenduto-Step0].[Ship-to Address], [ClientiConVenduto-Step0].[Ship-to Address 2], [ClientiConVenduto-Step0].[Ship-to City], [ClientiConVenduto-Step0].[Ship-to Post Code], [ClientiConVenduto-Step0].[Ship-to County], [ClientiConVenduto-Step0].[Ship-to Country Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[E-Mail]
HAVING ((([ClientiConVenduto-Step0].[Delete Reason])=""));

GO

-- [395] ClientiConVendutoCalcoloEsposizione
SELECT [ClientiConVenduto-Step0].[Delete Reason], Item.[Season Code], Item.[Trademark Code], [ClientiConVenduto-Step0].Salesperson, [ClientiConVenduto-Step0].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Address 2], Customer.City, Customer.[Post Code], Customer.County, Customer.[Country Code], Customer.[Phone No_], Customer.[Telex No_], Customer.[Fax No_], Customer.[Reservation Priority], Val([Credit Limit (LCY)]) AS LimiteCredito, Customer.[Payment Terms Code], Customer.[Payment Method Code], Sum(Val([No_ of Pairs])) AS PairsTotal, Sum([ClientiConVenduto-Step0].SalesValue) AS Venduto, IIf([venduto]-[limitecredito]>0,[venduto]-[limitecredito],0) AS Esposizione, NoteOrdiniVenditaGlobaleZFinale.listacommenti, Customer.[Blocked For Assignement], Customer.[E-Mail]
FROM (([ClientiConVenduto-Step0] INNER JOIN Item ON [ClientiConVenduto-Step0].No_ = Item.No_) INNER JOIN Customer ON [ClientiConVenduto-Step0].[Sell-to Customer No_] = Customer.No_) INNER JOIN NoteOrdiniVenditaGlobaleZFinale ON [ClientiConVenduto-Step0].[Sell-to Customer No_] = NoteOrdiniVenditaGlobaleZFinale.CodiceCliente
GROUP BY [ClientiConVenduto-Step0].[Delete Reason], Item.[Season Code], Item.[Trademark Code], [ClientiConVenduto-Step0].Salesperson, [ClientiConVenduto-Step0].[Sell-to Customer No_], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Address 2], Customer.City, Customer.[Post Code], Customer.County, Customer.[Country Code], Customer.[Phone No_], Customer.[Telex No_], Customer.[Fax No_], Customer.[Reservation Priority], Val([Credit Limit (LCY)]), Customer.[Payment Terms Code], Customer.[Payment Method Code], NoteOrdiniVenditaGlobaleZFinale.listacommenti, Customer.[Blocked For Assignement], Customer.[E-Mail]
HAVING ((([ClientiConVenduto-Step0].[Delete Reason])=""));

GO

-- [396] ClientiConVenduto-Step0
SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Line].No_, [Sales Line].Quantity, [Sales Line].[Unit of Measure], [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], [Sales Line].[No_ of Pairs], Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Order Date], [Sales Header].[Salesperson Code], [Sales Line].[Constant Variable Code] AS ColorCode, [Sales Header].[Sell-to Customer No_], Val([Line Amount])-Val([Inv_ Discount Amount]) AS SalesValue, [Sales Line].[Quantity Shipped], [Sales Line].[Quantity Invoiced], [Sales Line].[Document No_], [Sales Line].[Line No_], [Sales Header].[Ship-to Name], [Sales Header].[Ship-to Name 2], [Sales Header].[Ship-to Address], [Sales Header].[Ship-to Address 2], [Sales Header].[Ship-to City], [Sales Header].[Ship-to Post Code], [Sales Header].[Ship-to County], [Sales Header].[Ship-to Country Code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19));

