FROM ((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = [Salesperson_Purchaser].Code) INNER JOIN Item ON [Sales Line].No_ = [Item].No_) INNER JOIN Customer ON [Sales Line].[Sell-to Customer No_] = [Customer].No_
