FROM [ControlloSalesHeaderEExtension-step0];

UNION ALL SELECT Check, SH_DocType, No_, SHE_DocType, [Document No_], [Selling Season Code]
FROM [ControlloSalesHeaderEExtension-step1];

UNION ALL SELECT Check, SH_DocType, No_, SHE_DocType, [Document No_], [Selling Season Code]
FROM [ControlloSalesHeaderEExtension-step2];

GO

-- [429] ControlloSalesHeaderEExtension-step0
SELECT "BOTH" AS [Check], [Sales Header].[Document Type] AS SH_DocType, [Sales Header].No_, [Sales Header Extension].[Document Type] AS SHE_DocType, [Sales Header Extension].[Document No_], [Sales Header].[Selling Season Code]
FROM [Sales Header] INNER JOIN [Sales Header Extension] ON ([Sales Header].No_ = [Sales Header Extension].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type]);

GO

-- [430] ControlloSalesHeaderEExtension-step1
SELECT "Header Only" AS [Check], [Sales Header].[Document Type] AS SH_DocType, [Sales Header].No_, [Sales Header Extension].[Document Type] AS SHE_DocType, [Sales Header Extension].[Document No_], [Sales Header].[Selling Season Code]
FROM [Sales Header] LEFT JOIN [Sales Header Extension] ON ([Sales Header].No_ = [Sales Header Extension].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type])
WHERE ((([Sales Header Extension].[Document No_]) Is Null));

GO

-- [431] ControlloSalesHeaderEExtension-step2
SELECT "Extension Only" AS [Check], [Sales Header].[Document Type] AS SH_DocType, [Sales Header].No_, [Sales Header Extension].[Document Type] AS SHE_DocType, [Sales Header Extension].[Document No_], "" AS [Selling Season Code]
FROM [Sales Header] RIGHT JOIN [Sales Header Extension] ON ([Sales Header].No_ = [Sales Header Extension].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type])
WHERE ((([Sales Header].No_) Is Null));

GO

-- [432] ControlloSbilanciamentoAssegni
SELECT Customer.[Geographical Zone], [Geographical Zone].Description, [Geographical Zone].[Credit Manager], Customer.Name, Customer.No_, [ControlloSbilanciamentoAssegni-step1].[Letter No_], [ControlloSbilanciamentoAssegni-step1].DataRegistrazione, [ControlloSbilanciamentoAssegni-step1].DataScadenza, [ControlloSbilanciamentoAssegni-step1].ImportoResiduoSimulatoInValuta, [ControlloSbilanciamentoAssegni-step1].ImportoResiduoSimulatoEuro, [ControlloSbilanciamentoAssegni-step1].CodValuta, [ControlloSbilanciamentoAssegni-step0].ImportoResiduoInValuta, [ControlloSbilanciamentoAssegni-step0].ImportoResiduoEuro, Round(([importoresiduosimulatoinvaluta]+Nz([importoresiduoinvaluta]))*10000)/10000 AS deltaValuta, Round(([importoresiduosimulatoeuro]+Nz([importoresiduoeuro]))*10000)/10000 AS deltaEuro
FROM (([ControlloSbilanciamentoAssegni-step1] LEFT JOIN [ControlloSbilanciamentoAssegni-step0] ON [ControlloSbilanciamentoAssegni-step1].[Letter No_] = [ControlloSbilanciamentoAssegni-step0].[Letter No_]) INNER JOIN Customer ON [ControlloSbilanciamentoAssegni-step1].[Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code
ORDER BY Customer.No_, [ControlloSbilanciamentoAssegni-step1].[Letter No_], [ControlloSbilanciamentoAssegni-step1].DataScadenza;

GO

-- [433] ControlloSbilanciamentoAssegni-step0
SELECT [Detailed Cust_ Ledg_ Entry].[Currency Code], Sum(Val([Detailed Cust_ Ledg_ Entry.Amount])) AS ImportoResiduoInValuta, Sum(Val([Detailed Cust_ Ledg_ Entry.Amount (LCY)])) AS ImportoResiduoEuro, [Cust_ Ledger Entry].[Letter No_]
FROM [Detailed Cust_ Ledg_ Entry] INNER JOIN [Cust_ Ledger Entry] ON [Detailed Cust_ Ledg_ Entry].[Cust_ Ledger Entry No_] = [Cust_ Ledger Entry].[Entry No_]
GROUP BY [Detailed Cust_ Ledg_ Entry].[Currency Code], [Cust_ Ledger Entry].[Letter No_]
HAVING (((Sum(Val([Detailed Cust_ Ledg_ Entry.Amount])))<>0) AND ((Sum(Val([Detailed Cust_ Ledg_ Entry.Amount (LCY)])))<>0));

GO

-- [434] ControlloSbilanciamentoAssegni-step1
SELECT [Sim_Detailed Cust_ Ledg_ Entry].[Currency Code] AS CodValuta, Sum(Val([Sim_Detailed Cust_ Ledg_ Entry.Amount])) AS ImportoResiduoSimulatoInValuta, Sum(Val([Sim_Detailed Cust_ Ledg_ Entry.Amount (LCY)])) AS ImportoResiduoSimulatoEuro, [Sim_ Cust_ Ledger Entry].[Letter No_], [Sim_ Cust_ Ledger Entry].[Customer No_], [Sim_Detailed Cust_ Ledg_ Entry].[Posting Date] AS DataRegistrazione, [Sim_ Cust_ Ledger Entry].[Due Date] AS DataScadenza
FROM [Sim_Detailed Cust_ Ledg_ Entry] INNER JOIN [Sim_ Cust_ Ledger Entry] ON [Sim_Detailed Cust_ Ledg_ Entry].[Cust_ Ledger Entry No_] = [Sim_ Cust_ Ledger Entry].[Entry No_]
GROUP BY [Sim_Detailed Cust_ Ledg_ Entry].[Currency Code], [Sim_ Cust_ Ledger Entry].[Letter No_], [Sim_ Cust_ Ledger Entry].[Customer No_], [Sim_Detailed Cust_ Ledg_ Entry].[Posting Date], [Sim_ Cust_ Ledger Entry].[Due Date]
HAVING (((Sum(Val([Sim_Detailed Cust_ Ledg_ Entry.Amount])))<>0) AND ((Sum(Val([Sim_Detailed Cust_ Ledg_ Entry.Amount (LCY)])))<>0));

GO

-- [435] ControlloSoggettiRoyalties
SELECT NSP_Subject1, NSP_Subject2, [Document No_], [Season Code], [Trademark Code], "INVOICE" AS TipoDoc
FROM [ControlloSoggettiRoyalties-step1-Fatture];

UNION ALL SELECT NSP_Subject1, NSP_Subject2, [Document No_], [Season Code], [Trademark Code], "CREDIT NOTE" AS TipoDoc
FROM [ControlloSoggettiRoyalties-step2-NoteCredito];

GO

-- [436] ControlloSoggettiRoyalties-step1-Fatture
SELECT [Sales Invoice Header].NSP_Subject1, [Sales Invoice Header].NSP_Subject2, [Sales Invoice Line].[Document No_], Item.[Season Code], Item.[Trademark Code]
FROM ([Sales Invoice Line] INNER JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_) INNER JOIN Item ON [Sales Invoice Line].No_ = Item.No_
GROUP BY [Sales Invoice Header].NSP_Subject1, [Sales Invoice Header].NSP_Subject2, [Sales Invoice Line].[Document No_], Item.[Season Code], Item.[Trademark Code]
HAVING (((Item.[Season Code])=[forms]![principale]![filtroStagioneareaamministrativa]) AND ((Item.[Trademark Code])=[forms]![principale]![filtromarchiotempipagamento]));

GO

-- [437] ControlloSoggettiRoyalties-step2-NoteCredito
SELECT [Sales Cr_Memo Header].NSP_Subject1, [Sales Cr_Memo Header].NSP_Subject2, [Sales Cr_Memo Line].[Document No_], Item.[Season Code], Item.[Trademark Code]
FROM ([Sales Cr_Memo Line] INNER JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_) INNER JOIN Item ON [Sales Cr_Memo Line].No_ = Item.No_
GROUP BY [Sales Cr_Memo Header].NSP_Subject1, [Sales Cr_Memo Header].NSP_Subject2, [Sales Cr_Memo Line].[Document No_], Item.[Season Code], Item.[Trademark Code]
HAVING (((Item.[Season Code])=[forms]![principale]![FiltroStagioneAreaAmministrativa]) AND ((Item.[Trademark Code])=[forms]![principale]![filtromarchiotempipagamento]));

GO

-- [438] CoperturaAssortimenti
SELECT [CoperturaAssortimenti-step2].[Trademark Code], [CoperturaAssortimenti-step2].[Season Code], [CoperturaAssortimenti-step2].[Product Sex], [CoperturaAssortimenti-step2].[Line Code], [CoperturaAssortimenti-step2].No_, [CoperturaAssortimenti-step2].Color, [CoperturaAssortimenti-step2].LineTyoe, [CoperturaAssortimenti-step2].[Assortment Code], [CoperturaAssortimenti-step2].[Variable Code 02], [CoperturaAssortimenti-step2].[Sales_Purchase Status - Item]
FROM [CoperturaAssortimenti-step2]
WHERE ((([CoperturaAssortimenti-step2].[Season Code])=[forms]![principale]![FiltroStagioneEAN]))
ORDER BY [CoperturaAssortimenti-step2].[Trademark Code], [CoperturaAssortimenti-step2].[Season Code], [CoperturaAssortimenti-step2].[Product Sex], [CoperturaAssortimenti-step2].[Line Code], [CoperturaAssortimenti-step2].LineTyoe, [CoperturaAssortimenti-step2].[Assortment Code], [CoperturaAssortimenti-step2].[Variable Code 02];

GO

-- [439] CoperturaAssortimenti-step0
SELECT Item.[Trademark Code], Item.[Season Code], Item.[Product Sex], Item.[Line Code], Item.No_, Item.[Variable Code 01] AS Color, "" AS [Assortment Code], Item.[Variable Code 02], Item.[Sales_Purchase Status - Item]
FROM Item
WHERE (((Item.[Configurator Relation])=3))
GROUP BY Item.[Trademark Code], Item.[Season Code], Item.[Product Sex], Item.[Line Code], Item.No_, Item.[Variable Code 01], Item.[Variable Code 02], Item.[Sales_Purchase Status - Item]
HAVING (((Item.[Line Code])<>""))
ORDER BY Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.No_, Item.[Variable Code 01], Item.[Variable Code 02];

GO

-- [440] CoperturaAssortimenti-step1
SELECT Item.[trademark code], Item.[season code], Item.[product sex], Item.[line code], Item.No_, Item.[Variable Code 01] AS Color, [CoperturaAssortimenti-step1-pre].[Assortment Code], [CoperturaAssortimenti-step1-pre].[Variable Code], Item.[Sales_Purchase Status - Item]
FROM Item INNER JOIN [CoperturaAssortimenti-step1-pre] ON (Item.[Assortment Variable Group] = [CoperturaAssortimenti-step1-pre].[Variable Group]) AND (Item.No_ = [CoperturaAssortimenti-step1-pre].[Model Item No_])
GROUP BY Item.[trademark code], Item.[season code], Item.[product sex], Item.[line code], Item.No_, Item.[Variable Code 01], [CoperturaAssortimenti-step1-pre].[Assortment Code], [CoperturaAssortimenti-step1-pre].[Variable Code], Item.[Sales_Purchase Status - Item]
HAVING (((Item.[line code])<>""))
ORDER BY Item.[trademark code], Item.[season code], Item.[line code], Item.[Variable Code 01], [CoperturaAssortimenti-step1-pre].[Variable Code];

GO

-- [441] CoperturaAssortimenti-step1-pre
SELECT [Valid Model Item Assortments].[Model Item No_], [Assortment Quantity].[Variable Group], [Assortment Quantity].[Assortment Code], [Assortment Quantity].[Variable Code], [Assortment Quantity].quantity
FROM [Valid Model Item Assortments] INNER JOIN [Assortment Quantity] ON [Valid Model Item Assortments].[Assortment Code] = [Assortment Quantity].[Assortment Code]
WHERE ((([Assortment Quantity].quantity)>"0"))
ORDER BY [Assortment Quantity].[Variable Code];

GO

-- [442] CoperturaAssortimenti-step2
SELECT  "ITEM" as LineTyoe, *
FROM [CoperturaAssortimenti-step0];

UNION ALL SELECT  "ASSORTMENT" as LineTyoe, *
FROM [CoperturaAssortimenti-step1];

GO

-- [443] CostiAcquisti
SELECT [Purchase Price].[Item No_], Avg(Val([Direct Unit Cost])) AS Costo, Item.[Model Item No_], Item.[Variable Code 01], Item.[Variable Code 02], [Purchase Price].[Currency Code]
FROM ([CostiAcquisti-step1] INNER JOIN [Purchase Price] ON [CostiAcquisti-step1].[Item No_] = [Purchase Price].[Item No_]) INNER JOIN Item ON [Purchase Price].[Item No_] = Item.No_
GROUP BY [Purchase Price].[Item No_], Item.[Model Item No_], Item.[Variable Code 01], Item.[Variable Code 02], [Purchase Price].[Currency Code], [Purchase Price].[Vendor No_]
HAVING ((([Purchase Price].[Vendor No_])<>"VAL A" And ([Purchase Price].[Vendor No_])<>"VAL B"));

GO

-- [444] CostiAcquisti-step1
SELECT [Purchase Price].[Item No_], Max([Purchase Price].[Starting Date]) AS [MaxDiStarting Date]
FROM [Purchase Price]
GROUP BY [Purchase Price].[Item No_];

