-- [446] CreaClientiDaAggiornare
SELECT Customer.No_, Customer.Name, Customer.[Country_Region Code], Customer.[Geographical Zone 2], IIf([country_region code]="ES" Or [country_region code]="XB","134",IIf([country_region code]="SM","1","135")) AS [NEW Customer Price Group], Customer.[Customer Price Group] INTO ClientiDaAggiornare
FROM Customer
WHERE (((Customer.[Geographical Zone 2])="34"));

GO

-- [447] CreaCrossReferenceFGF
INSERT INTO [Cross-Reference Model Item] ( [Model Item No_], [Cross-Reference Type], [Cross-Reference Type No_], [Constant Variable Code], [Cross-Reference No_], [Constant Assortment Var_Grp_], [Variable Code 01], [Variable Code 02], [Variable Group 01], [Variable Group 02] )
SELECT TranscodificaFGF.No_, 1 AS Espr1, "C02960" AS Espr2, TranscodificaFGF.ColorCode, [mODELLO] & "_" & [PARTE] & "_" & [COLORE_FGF] AS Espr3, Item.[Constant Assortment Var_Grp_], "" AS Espr4, "" AS Espr5, "" AS Espr6, "" AS Espr7
FROM TranscodificaFGF INNER JOIN Item ON TranscodificaFGF.No_ = Item.No_;

GO

-- [448] CreaOrdiniDaModificareTrasportatoreEServizioPerStagione
SELECT Customer.[Geographical Zone 2], [Sales Header].NO_ AS [Document No_], [Sales Header].[Selling Season Code], [Sales Header].[Shortcut Dimension 1 Code] AS CCR, [Sales Header].[Shortcut Dimension 2 Code] AS Trademark, IIf([trademark]="TH" Or [trademark]="NAPA" Or [trademark]="THK","1","2") AS CodSpedizioniere, IIf([trademark]="TH" Or [trademark]="NAPA" Or [trademark]="THK","C",IIf([geographical zone 2]="34","48N","NC")) AS CodServizio INTO OrdiniDaModificare
FROM [Sales Header] INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_
WHERE ((([Sales Header].[Selling Season Code])="I1819"));

GO

-- [449] CreaRigheSalesLineTMPFiltroClienteStagione
INSERT INTO SalesLineTMP ( [Document NO_], [Line NO_], [Customer NO_], NO_, qty, [Customer Name] )
SELECT [Sales Line].[Document No_], [Sales Line].[Line No_], [Sales Line].[Sell-to Customer No_], [Sales Line].No_, Val([quantity]) AS Espr1, [Sales Header].[Sell-to Customer Name]
FROM ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Sales Header] ON ([Sales Header].[Document Type] = [Sales Line].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)
WHERE ((([Sales Line].[Sell-to Customer No_])=[Forms]![Principale]![FiltroClienteEan]) AND (([Sales Line].[Delete Reason])='') AND ((Item.[Season Code])=[Forms]![Principale]![FiltroStagioneEan2]));

GO

-- [450] CreaRigheSalesLineTMPFiltroFatt
INSERT INTO SalesLineTMP ( [Document NO_], [Line NO_], [Customer NO_], NO_, qty, [Customer Name] )
SELECT [Sales Invoice Line].[Document No_], [Sales Invoice Line].[Line No_], [Sales Invoice Line].[Sell-to Customer No_], [Sales Invoice Line].No_, Val([quantity]) AS Espr1, [Sales Invoice Header].[Sell-to Customer Name]
FROM [Sales Invoice Header] INNER JOIN [Sales Invoice Line] ON [Sales Invoice Header].No_ = [Sales Invoice Line].[Document No_]
WHERE ((([Sales Invoice Line].[Document No_])=[Forms]![Principale]![FiltroEanFatt]) AND (([Sales Invoice Line].[Delete Reason])=''));

GO

-- [451] CreaRigheSalesLineTMPFiltroODA
INSERT INTO SalesLineTMP ( [Document NO_], [Line NO_], [Customer NO_], NO_, qty, [Customer Name] )
SELECT [Purchase Line].[Document No_], [Purchase Line].[Line No_], [Purchase Header].[Buy-from Vendor No_], [Purchase Line].No_, Val([quantity]) AS Espr1, [Purchase Header].[Pay-to Name]
