WHERE ((([Purchase Line].[Document No_])=[Forms]![Principale]![FiltroODAEan]) AND (([Purchase Line].[Delete Reason])=''));

GO

-- [452] CreaRigheSalesLineTMPFiltroODT
INSERT INTO SalesLineTMP ( [Document NO_], [Line NO_], [Customer NO_], NO_, qty )
SELECT [Transfer Line].[Document No_], [Transfer Line].[Line No_], [Transfer Header].[Transfer-to Code], [Transfer Line].[Item No_], Val([quantity]) AS Espr1
FROM [Transfer Header] INNER JOIN [Transfer Line] ON [Transfer Header].No_ = [Transfer Line].[Document No_]
WHERE ((([Transfer Line].[Document No_])=[Forms]![Principale]![FiltroODTEan]));

GO

-- [453] CreaRigheSalesLineTMPFiltroODV
INSERT INTO SalesLineTMP ( [Document NO_], [Line NO_], [Customer NO_], NO_, qty, [Customer Name] )
SELECT [Sales Line].[Document No_], [Sales Line].[Line No_], [Sales Line].[Sell-to Customer No_], [Sales Line].No_, Val([quantity]) AS Espr1, [Sales Header].[Sell-to Customer Name]
FROM [Sales Line] INNER JOIN [Sales Header] ON ([Sales Header].No_ = [Sales Line].[Document No_]) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])
WHERE ((([Sales Line].[Document No_])=[Forms]![Principale]![FiltroODVEan]) AND (([Sales Line].[Delete Reason])=''));

GO

-- [454] creazioneDocumentiImmaginiMediumBook
SELECT 4 AS [Source Type], Item.[Model Item No_] AS [Source No_], 0 AS [Source Line No_], 10000 AS [Line No_], 2 AS [Document Type], "_" AS Description, "X:\febos\foto\" & IIf(IsNull([marchio])=False,[marchiocartella],"MARCHIO_UNK") & "\" & [season code] & "\Foto Navision\" & IIf([trademark code]="BLAUER" Or [trademark code]="BLK" Or [trademark code]="BLAC" Or [trademark code]="BEPOSITIVE" Or [trademark code]="AP" Or [trademark code]="CPH" Or [trademark code]="FOAMERS" Or [trademark code]="AQVA ALTA",UCase(SubstSlashDash([Item.model item no_]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg"),IIf([trademark code]="NAPA",SubstSlashDash([Description 2]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg",[LINE CODE] & "_" & [Model Item No_] & "_" & [Item.Variable Code 01] & "-medium.jpg")) AS [Linked Document], 0 AS Priority, 0 AS [File Not Found], "_" AS [Picture CapTion], Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01] AS [Constant Variable CodE]
FROM Item LEFT JOIN RelazioniMarchiCartelle ON Item.[Trademark Code] = RelazioniMarchiCartelle.Marchio
GROUP BY 4, Item.[Model Item No_], 10000, 2, "X:\febos\foto\" & IIf(IsNull([marchio])=False,[marchiocartella],"MARCHIO_UNK") & "\" & [season code] & "\Foto Navision\" & IIf([trademark code]="BLAUER" Or [trademark code]="BLK" Or [trademark code]="BLAC" Or [trademark code]="BEPOSITIVE" Or [trademark code]="AP" Or [trademark code]="CPH" Or [trademark code]="FOAMERS" Or [trademark code]="AQVA ALTA",UCase(SubstSlashDash([Item.model item no_]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg"),IIf([trademark code]="NAPA",SubstSlashDash([Description 2]) & "_" & SubstSlashDash([Item.Variable Code 01]) & "-medium.jpg",[LINE CODE] & "_" & [Model Item No_] & "_" & [Item.Variable Code 01] & "-medium.jpg")), 0, "_", Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01], 0, Item.[Configurator Relation], Item.[Trademark Code], Item.[Season Code], 0, 0, ""
HAVING (((Item.[Configurator Relation])=[Configurator relation Filter]) AND ((Item.[Trademark Code])=[forms]![principale]![filtromarchiopergeneralinks]) AND ((Item.[Season Code])=[forms]![principale]![filtrostagionepergeneralinks]));

GO

-- [455] creazioneDocumentiImmaginiMediumBook_OneShot Copenhagen
SELECT 4 AS [Source Type], Item.[Model Item No_] AS [Source No_], 0 AS [Source Line No_], 10000 AS [Line No_], 2 AS [Document Type], "_" AS Description, "X:\febos\foto\" & [marchiocartella] & "\" & [season code] & "\Foto Navision\" & [nome effettivo (incolla valori)] AS [Linked Document], 0 AS Priority, 0 AS [File Not Found], "_" AS [Picture CapTion], Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01] AS [Constant Variable CodE]
FROM (Item LEFT JOIN RelazioniMarchiCartelle ON Item.[Trademark Code] = RelazioniMarchiCartelle.Marchio) INNER JOIN [LINELIST FW24 CPH] ON (Item.[Variable Code 01] = [LINELIST FW24 CPH].[COLOR CODE]) AND (Item.[Model Item No_] = [LINELIST FW24 CPH].[STYLE CODE])
GROUP BY 4, Item.[Model Item No_], 10000, 2, "X:\febos\foto\" & [marchiocartella] & "\" & [season code] & "\Foto Navision\" & [nome effettivo (incolla valori)], 0, "_", Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01], 0, Item.[Configurator Relation], Item.[Trademark Code], Item.[Season Code], 0, 0, ""
HAVING (((Item.[Configurator Relation])=[Configurator relation Filter]) AND ((Item.[Trademark Code])=[forms]![principale]![filtromarchiopergeneralinks]) AND ((Item.[Season Code])=[forms]![principale]![filtrostagionepergeneralinks]));

GO

