-- [476] dam_aggiorna customer service da zona geograficxa
UPDATE Customer INNER JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code SET Customer.[commercial Manager] = [Geographical Zone.commercial Manager];

