-- [478] dam_aggiorna data consegna richiesta articoli pre buy_1_artmod
UPDATE ([Sales Line] INNER JOIN ArticoliPreBuy ON ([Sales Line].[Constant Variable Code] = ArticoliPreBuy.Colore) AND ([Sales Line].No_ = ArticoliPreBuy.Articolo)) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_ SET [Sales Line].[requested delivery date] = #7/20/2022#
WHERE ((([Sales Line].[requested delivery date])=#8/15/2022#) AND (([Sales Header].[ORDER Date])<=[datacutoff]));

GO

-- [479] dam_aggiorna data consegna richiesta articoli pre buy_2_item
UPDATE ([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN ArticoliPreBuy ON ([Sales Line].[Variable Code 01] = ArticoliPreBuy.Colore) AND ([Sales Line].[Model Item No_] = ArticoliPreBuy.Articolo) SET [Sales Line].[requested delivery date] = #7/20/2022#
WHERE ((([Sales Line].[requested delivery date])=#8/15/2022#) AND (([Sales Header].[oRDER Date])<=[datacutoff]));

GO

-- [480] dam_aggiorna data consegna richiesta articoli pre buy_3_ver_old
SELECT [Sales Header].[Order Date], [Sales Line].[requested delivery date], [Sales Header].No_, [Sales Header].[Sell-to Customer No_], [Sales Header].[Sell-to Customer Name], [Sales Line].No_, [Sales Line].Type, [Sales Line].[Constant Variable Code], [Sales Line].[variable code 01], [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[SELLING SEASON CODE], Sum(Val([NO_ OF PAIRS])) AS PAIA1, Sum(Val([QUANTITY])) AS PAIA2
FROM [Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_
GROUP BY [Sales Header].[Order Date], [Sales Line].[requested delivery date], [Sales Header].No_, [Sales Line].[Line No_], [Sales Header].[Sell-to Customer No_], [Sales Header].[Sell-to Customer Name], [Sales Line].No_, [Sales Line].Type, [Sales Line].[Constant Variable Code], [Sales Line].[variable code 01], [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[SELLING SEASON CODE]
HAVING ((([Sales Header].[Shortcut Dimension 2 Code])="BLAUER") AND (([Sales Line].[SELLING SEASON CODE])="I22"))
ORDER BY [Sales Header].No_, [Sales Line].[Line No_];

GO

-- [481] dam_aggiorna data consegna richiesta articoli pre buy_3_verificA
SELECT [Sales Header].[Order Date], [Sales Line].[requested delivery date], [Sales Header].No_, [Sales Header].[Sell-to Customer No_], [Sales Header].[Sell-to Customer Name], [Sales Line].No_, [Sales Line].Type, [Sales Line].[Constant Variable Code], [Sales Line].[variable code 01], [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[SELLING SEASON CODE], Sum(Val([NO_ OF PAIRS])) AS PAIA1, Sum(Val([QUANTITY])) AS PAIA2
FROM [Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_
GROUP BY [Sales Header].[Order Date], [Sales Line].[requested delivery date], [Sales Header].No_, [Sales Header].[Sell-to Customer No_], [Sales Header].[Sell-to Customer Name], [Sales Line].No_, [Sales Line].Type, [Sales Line].[Constant Variable Code], [Sales Line].[variable code 01], [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[SELLING SEASON CODE], [Sales Line].[Line No_]
HAVING ((([Sales Line].Type)<>2) AND (([Sales Header].[Shortcut Dimension 2 Code])="BLAUER") AND (([Sales Line].[SELLING SEASON CODE])="I22"))
ORDER BY [Sales Header].No_, [Sales Line].[Line No_];

GO

