-- [499] dam_categorie provvigionali adb_anagrafica con errori
SELECT Item.[Commission Group Code], Item.[Trademark Code], Item.[Season Code], Item.No_, Item.[Configurator Relation]
FROM Item
WHERE (((Item.[Commission Group Code])<>"BL0" And (Item.[Commission Group Code])<>"BLADB") AND ((Item.[Trademark Code])="BLAUER") AND ((Item.[Season Code])="E21" Or (Item.[Season Code])="I21") AND ((Item.[Configurator Relation])=1)) OR (((Item.[Commission Group Code])<>"BLK0" And (Item.[Commission Group Code])<>"BLKDB") AND ((Item.[Trademark Code])="BLK") AND ((Item.[Season Code])="E21" Or (Item.[Season Code])="I21") AND ((Item.[Configurator Relation])=1));

GO

-- [500] dam_categorie provvigionali adb_RICERCA SU ODV DIFFERENZE
SELECT [Sales Line].[commission group code], [Sales Header].[Commission Group Code], Item.[commission group code], [Sales Line].type, [Sales Header].No_, [Sales Line].No_, [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], [Sales Line].[Subject 2 Commission _]
FROM ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_
WHERE ((([Sales Line].[commission group code])<>[item.commission group code]) AND (([Sales Line].type)=19 Or ([Sales Line].type)=20 Or ([Sales Line].type)=2) AND (([Sales Header].[selling season code])="I21") AND (([Sales Header].[Shortcut Dimension 2 Code])="BLAUER" Or ([Sales Header].[Shortcut Dimension 2 Code])="BLK"));

GO

-- [501] dam_categorie provvigionali adb_SISTEMAZIONE RIGHE ORDINE
UPDATE ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_ SET [Sales Line].[commission group code] = [item.commission group code], [Sales Line].[Subject 2 Commission _] = IIf([item.commission group code]="BLK0" Or [item.commission group code]="BL0","0.00000000000000000000",IIf([item.commission group code]="BLADB","2.00000000000000000000","1.50000000000000000000"))
WHERE ((([Sales Line].[commission group code])<>[item.commission group code]) AND (([Sales Line].type)=19 Or ([Sales Line].type)=20 Or ([Sales Line].type)=2) AND (([Sales Header].[selling season code])="I21") AND (([Sales Header].[Shortcut Dimension 2 Code])="BLAUER" Or ([Sales Header].[Shortcut Dimension 2 Code])="BLK"));

GO

-- [502] dam_controllo coerenza righe kimo budget e portafoglio ordini
SELECT [Sales Header].[Document Type], [Sales Header].No_, [Sales Header].[Bill-to Name], [Sales Header].[Budget No_], [Budget Line].[Budget No_], [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 1 Code], [Sales Header].[Shortcut Dimension 2 Code]
FROM [Sales Header] LEFT JOIN [Budget Line] ON ([Sales Header].[Sell-to Customer No_] = [Budget Line].[Source No_]) AND ([Sales Header].[Budget No_] = [Budget Line].[Budget No_])
WHERE ((([Sales Header].[Budget No_])<>"") AND (([Budget Line].[Budget No_]) Is Null) AND (([Sales Header].[selling season code])="E22"));

GO

-- [503] dam_ItemMasterData_PER VF
SELECT Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Line Code], Item_1.No_, ListinoVenditaWholesale.[Sales Code] AS ListinoWholesale, Avg(IIf(IsNull([ListinoVenditaWholesale].[Item NO_])=False,[ListinoVenditaWholesale.Listino],0)) AS PrezzoWholesale, ListinoVenditaRetail.[Sales Code] AS ListinoRetail, Avg(IIf(IsNull([ListinoVenditaRetail].[Item NO_])=False,[ListinoVenditaRetail.Listino],0)) AS PrezzoRetail, Item_1.Description, Item_1.[Description 2], Item.[Description 6], Item.[Variable Code 01] AS ColorCode, Item.[Variable Code 02] AS [Size], [Variable Code].Description AS ColorDescription, Item.[Carry Over], Item.Smu, Item.[Location Code], Item.[Delivery Period], Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Tariff No_], Val([Item.Unit Volume]) AS UnitVolume, Val([Item.Gross Weight]) AS [GrossWeight(g)], Val([Item.Net Weight]) AS [NetWeight(g)], Val([Item.Height]) AS [Height(cm)], Val([Item.Width]) AS [Width(cm)], Val([Item.Depth]) AS [Depth(cm)], Val([Item.Standard Cost]) AS StandardCost, Item.[Country_Region of Origin Code], Item.[Vendor No_], Vendor.Name, Item.[Sold Out], Item.[Sold Out Date], Item.[Commission Group Code], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Upper Composition], Item.[Lining Composition], Item.[Outsole Composition], EANCodes.[Cross-Reference No_]
FROM (((((Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN ListinoVenditaWholesale ON Item.No_ = ListinoVenditaWholesale.[Item No_]) LEFT JOIN EANCodes ON Item.No_ = EANCodes.[Item No_]) LEFT JOIN ListinoVenditaRetail ON Item.No_ = ListinoVenditaRetail.[Item No_]
GROUP BY Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Line Code], Item_1.No_, ListinoVenditaWholesale.[Sales Code], ListinoVenditaRetail.[Sales Code], Item_1.Description, Item_1.[Description 2], Item.[Description 6], Item.[Variable Code 01], Item.[Variable Code 02], [Variable Code].Description, Item.[Carry Over], Item.Smu, Item.[Location Code], Item.[Delivery Period], Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Tariff No_], Val([Item.Unit Volume]), Val([Item.Gross Weight]), Val([Item.Net Weight]), Val([Item.Height]), Val([Item.Width]), Val([Item.Depth]), Val([Item.Standard Cost]), Item.[Country_Region of Origin Code], Item.[Vendor No_], Vendor.Name, Item.[Sold Out], Item.[Sold Out Date], Item.[Commission Group Code], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Upper Composition], Item.[Lining Composition], Item.[Outsole Composition], Item.[Configurator Relation], EANCodes.[Cross-Reference No_]
HAVING (((Item.[Season Code])="E18") AND ((Item.[Trademark Code])="NAPA") AND ((Item.[Configurator Relation])=3))
ORDER BY Item.[Trademark Code], Item.[Collection Code], Item.[Line Code], Item_1.No_;

GO

-- [504] dam_lista clienti con cross reference per stagione_detail
SELECT Item.[Trademark Code], Item.[season code], Item.[product sex] AS Gender, Item.[line code], [Cross-Reference Model Item].[Model Item No_], [Cross-Reference Model Item].[Constant Variable Code] AS Color, Item.[Description 2], [Cross-Reference Model Item].[Cross-Reference Type No_] AS [Customer Code], Customer.Name, [Cross-Reference Model Item].[Cross-Reference No_]
FROM ([Cross-Reference Model Item] INNER JOIN Item ON [Cross-Reference Model Item].[Model Item No_] = Item.No_) INNER JOIN Customer ON [Cross-Reference Model Item].[Cross-Reference Type No_] = Customer.No_
WHERE (((Item.[season code])=[forms]![principale]![FiltroStagioneEAN]) AND (([Cross-Reference Model Item].[Cross-Reference No_])<>""))
ORDER BY Item.[Trademark Code], Item.[product sex], Item.[line code], [Cross-Reference Model Item].[Model Item No_], Customer.Name;

GO

-- [505] dam_lista clienti con cross reference per stagione_summary
SELECT Item.[trademark code], Item.[season code], [Cross-Reference Model Item].[Cross-Reference Type No_], Customer.Name
FROM ([Cross-Reference Model Item] INNER JOIN Item ON [Cross-Reference Model Item].[Model Item No_] = Item.No_) INNER JOIN Customer ON [Cross-Reference Model Item].[Cross-Reference Type No_] = Customer.No_
WHERE ((([Cross-Reference Model Item].[Cross-Reference No_])<>""))
GROUP BY Item.[trademark code], Item.[season code], [Cross-Reference Model Item].[Cross-Reference Type No_], Customer.Name
HAVING (((Item.[season code])=[forms]![principale]![FiltroStagioneEAN]))
ORDER BY Item.[trademark code], Item.[season code], Customer.Name;

GO

-- [506] dam_ricerca per cambio dati massivo ordini
SELECT [Sales Line].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[Sell-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].No_, [Sales Line].[Line No_], [Sales Header].[Requested Delivery Date], [Sales Line].[Requested Delivery Date], [Sales Line].[delete reason]
FROM [Sales Header] INNER JOIN [Sales Line] ON [Sales Header].No_ = [Sales Line].[Document No_]
WHERE ((([Sales Line].[selling season code])="I20"));

GO

-- [507] dam_ricerca per cambio dati massivo ordini_modifica
UPDATE [Sales Header] INNER JOIN [Sales Line] ON [Sales Header].No_ = [Sales Line].[Document No_] SET [Sales Header].[Requested Delivery Date] = #8/12/2020#, [Sales Line].[Requested Delivery Date] = #8/12/2020#
WHERE ((([Sales Header].[Requested Delivery Date])=#7/20/2020#) AND (([Sales Line].[Requested Delivery Date])=#7/20/2020#) AND (([Sales Line].[selling season code])="I20") AND (([Sales Header].[Shortcut Dimension 2 Code])="NAPA"));

GO

-- [508] dam_WMS_PBM_RIGHE ACQUISTO
UPDATE [000_WMS_PBM_table_RIGHE CARICO DA CANCELLARE] INNER JOIN [Purchase Line] ON ([000_WMS_PBM_table_RIGHE CARICO DA CANCELLARE].[Order Line No_] = [Purchase Line].[Line No_]) AND ([000_WMS_PBM_table_RIGHE CARICO DA CANCELLARE].[Order No_] = [Purchase Line].[Document No_]) SET [Purchase Line].[Outstanding Quantity] = [Quantity], [Purchase Line].[qty_ to receive] = "0", [Purchase Line].[qty_ to invoice] = "0", [Purchase Line].[Qty_ Rcd_ Not Invoiced] = "0", [Purchase Line].[Quantity Received] = "0", [Purchase Line].[Quantity Invoiced] = "0", [Purchase Line].[Receipt No_] = "", [Purchase Line].[Receipt Line No_] = 0, [Purchase Line].[Outstanding Qty_ (Base)] = [Quantity (base)], [Purchase Line].[Qty_ to Invoice (Base)] = "0", [Purchase Line].[Qty_ to Receive (Base)] = "0", [Purchase Line].[Qty_ Rcd_ Not Invoiced (Base)] = "0", [Purchase Line].[Qty_ Received (Base)] = "0", [Purchase Line].[Qty_ Invoiced (Base)] = "0", [Purchase Line].[Amt_ Rcd_ Not Invoiced] = "0", [Purchase Line].[Outstanding Amount] = [Amount], [Purchase Line].[Outstanding Amount (LCY)] = [Amount], [Purchase Line].[Amt_ Rcd_ Not Invoiced (LCY)] = "0", [Purchase Line].[Outstanding Amt_ Ex_ VAT (LCY)] = [Amount], [Purchase Line].[A_ Rcd_ Not Inv_ Ex_ VAT (LCY)] = "0";

