-- [515] Data mining
SELECT Customer.[Store Image], Customer.[Store Distribution], Customer.[Store Type], Item.[product family], Val([no_ of pairs]) AS qty, Customer.[geographical zone], Customer.[geographical zone 2]
FROM (Item INNER JOIN [Sales Line] ON Item.No_ = [Sales Line].No_) INNER JOIN ([Sales Header] INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) ON [Sales Line].[Document No_] = [Sales Header].No_
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].[delete reason])="") AND (([Sales Header].[selling season code])="E20") AND (([Sales Header].[Shortcut Dimension 2 Code])="AP") AND ((Item.[advertising material])=0));

GO

-- [516] dateprenotazionipervendite
SELECT [Reserv__Assign_ Link].[Sales Document No_], [Reserv__Assign_ Link].[Sales Line No_], [Reserv__Assign_ Link].[Reserv__Assign_ Type], Max([Reserv__Assign_ Link].[Date Reservation]) AS [Date Reservation]
FROM [Reserv__Assign_ Link]
GROUP BY [Reserv__Assign_ Link].[Sales Document No_], [Reserv__Assign_ Link].[Sales Line No_], [Reserv__Assign_ Link].[Reserv__Assign_ Type]
HAVING ((([Reserv__Assign_ Link].[Reserv__Assign_ Type])=1));

GO

-- [517] DatiCarryOverESMU
SELECT Item.[Model Item No_], Item.[Variable Code 01], Item.Smu, Item.[Carry Over], Item.[Future Carry Over], Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Potential Sold Out], Val([Minimum Order Quantity]) AS MOQ
FROM Item
WHERE (((Item.[Configurator Relation])=3))
GROUP BY Item.[Model Item No_], Item.[Variable Code 01], Item.Smu, Item.[Carry Over], Item.[Future Carry Over], Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Potential Sold Out], Val([Minimum Order Quantity])
ORDER BY Item.[Model Item No_];

GO

-- [518] DatiCarryOverESMU-Completi
SELECT Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Product Sex], Item.[Model Item No_], Item.[Variable Group 01], Item.[Variable Code 01], Item.Smu, Item.[Carry Over], Item.[Future Carry Over], Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Potential Sold Out], Item.[Advertising Material]
FROM Item
WHERE (((Item.[Configurator Relation])=3))
GROUP BY Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Product Sex], Item.[Model Item No_], Item.[Variable Group 01], Item.[Variable Code 01], Item.Smu, Item.[Carry Over], Item.[Future Carry Over], Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Potential Sold Out], Item.[Advertising Material]
ORDER BY Item.[Season Code], Item.[Trademark Code], Item.[Model Item No_];

GO

-- [519] datiLince-SelezioneUltimoRilievo-step0
SELECT datiLince.[Rif#], Max(datiLince.[Evaso il]) AS DataEvasione, datiLince.Servizio
FROM datiLince
WHERE (((datiLince.[Rischio Oggi])<>""))
GROUP BY datiLince.[Rif#], datiLince.Servizio
HAVING (((datiLince.[Rif#])<>"") AND ((datiLince.Servizio)="global risk"))
ORDER BY datiLince.[Rif#];

GO

-- [520] datiLince-SelezioneUltimoRilievo-stepfinal
SELECT [datiLince-SelezioneUltimoRilievo-step0].[Rif#], [datiLince-SelezioneUltimoRilievo-step0].DataEvasione AS LinceDataEvasione, Max(datiLince.[Rischio Oggi]) AS LinceRischioOggi
FROM [datiLince-SelezioneUltimoRilievo-step0] INNER JOIN datiLince ON ([datiLince-SelezioneUltimoRilievo-step0].[Rif#] = datiLince.[Rif#]) AND ([datiLince-SelezioneUltimoRilievo-step0].DataEvasione = datiLince.[Evaso il])
GROUP BY [datiLince-SelezioneUltimoRilievo-step0].[Rif#], [datiLince-SelezioneUltimoRilievo-step0].DataEvasione
HAVING (((Max(datiLince.[Rischio Oggi]))<>""));

GO

-- [521] DatiSap
SELECT Format$([SHIp-TO],"00000") AS shipto, Left([PO number],12) AS Ordine, Left$([Material],Len([material])-3) AS Articolo, aggiungizerisucolore(Format$([Col])) AS colore, Format$([Assortment],"0000") AS assortimento, Sap.[Asst#Qty] AS quantita, Sap.[Order qty] AS Paia
FROM Sap;

GO

-- [522] DatiSap_OLD
SELECT Format$([SHIp-TO],"00000") AS shipto, Left([PO number],12) AS Ordine, Sap.Material AS Articolo, aggiungizerisucolore(Format$([Col])) AS colore, Format$([Assortment],"0000") AS assortimento, First(Sap.[Asst#Qty]) AS quantita, Sap.Item, Sum(Sap.[Order qty]) AS Paia
FROM Sap
GROUP BY Format$([SHIp-TO],"00000"), Left([PO number],12), Sap.Material, aggiungizerisucolore(Format$([Col])), Format$([Assortment],"0000"), Sap.Item;

