-- [523] dbgroup anagrafica sfuso
SELECT Item.[Season Code], Item.[Trademark Code], [NavisionEan-step0].[Cross-Reference No_] AS SKU, [Item.Model Item No_] & "_" & [Item.Variable Code 01] & "_" & [Item.Variable Code 02] & " " & [item_1.Description] AS Description, Val([item.net weight]) AS weight
FROM (Item INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]
WHERE (((Item.[Season Code])=[forms]![principale]![FiltroStagioneSourcing]) AND ((Item.[Trademark Code])=[forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[Sales_Purchase Status - Item])=""));

GO

-- [524] dbgroup inbound sfuso
SELECT [Transfer Shipment Header].No_ AS [Order Number], 0 AS Line, [Transfer Shipment Header].[Posting Date] AS [Document Date], Vendor.No_ AS [Supplier Code], Vendor.Name AS [Supplier Name], "" AS [Order Reference], [NavisionEan-step0].[Cross-Reference No_] AS SKU, Sum(Val([quantity])) AS qty
FROM ((([Transfer Shipment Header] INNER JOIN [Transfer Shipment Line] ON [Transfer Shipment Header].No_ = [Transfer Shipment Line].[Document No_]) INNER JOIN Item ON [Transfer Shipment Line].[Item No_] = Item.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN [NavisionEan-step0] ON [Transfer Shipment Line].[Item No_] = [NavisionEan-step0].[Item No_]
WHERE ((([Transfer Shipment Line].[Item Type])=0))
GROUP BY [Transfer Shipment Header].No_, 0, [Transfer Shipment Header].[Posting Date], Vendor.No_, Vendor.Name, "", [NavisionEan-step0].[Cross-Reference No_]
HAVING ((([Transfer Shipment Header].No_)=[Numero Spedizone Trasferimento Registrata]));

GO

-- [525] DDTApertiPerVerificaSblocchiDaIncassi
SELECT Item.[trademark code], [DDT_Picking Line].[season code], [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name, [DDT_Picking Header].No_, Sum(Val([no_ of pairs])) AS paia, [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Bill-to Customer No_], [CommentiOrdiniDiVendita-step1].Comment, [CommentiOrdiniDiVendita-step1].Code, [CommentiOrdiniDiVendita-step1].Date
FROM (((([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Line].[Document Type] = [DDT_Picking Header].[Document Type])) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) LEFT JOIN [CommentiOrdiniDiVendita-step1] ON [DDT_Picking Line].[Order No_] = [CommentiOrdiniDiVendita-step1].No_) LEFT JOIN [Sales Header] ON [CommentiOrdiniDiVendita-step1].No_ = [Sales Header].No_) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code
WHERE ((([DDT_Picking Line].Type)=19 Or ([DDT_Picking Line].Type)=20))
GROUP BY [DDT_Picking Header].[Document Type], [DDT_Picking Header].status, Item.[trademark code], [DDT_Picking Line].[season code], [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name, [DDT_Picking Header].No_, [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Bill-to Customer No_], [CommentiOrdiniDiVendita-step1].Comment, [CommentiOrdiniDiVendita-step1].Code, [CommentiOrdiniDiVendita-step1].Date
HAVING ((([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Header].status)=0))
ORDER BY Item.[trademark code], [DDT_Picking Line].[season code], Sum(Val([no_ of pairs])) DESC;

GO

-- [526] DDTPerDataCreazione
SELECT [DDT_Picking Header].Status, [DDT_Picking Line].[Document No_], [DDT_Picking Header].[Posting Date] AS DataCreazione, [DDT_Picking Header].[Posted No_], [DDT_Picking Header].[Posted Date] AS DataRegistrazione, [DDT_Picking Header].[Sell-to Customer No_], Customer.Name, [DDT_Picking Line].Type, [DDT_Picking Line].No_, IIf(InStr([ddt_picking line.no_],"MES")<>0,"Y","N") AS testMes, Val([quantity]) AS qty, Val([no_ of pairs]) AS paia, Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Advertising Material]
FROM ((([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) INNER JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN Customer ON [DDT_Picking Header].[Sell-to Customer No_] = Customer.No_
WHERE ((([DDT_Picking Header].[Posting Date]) Between [forms]![principale]![datainizialeexportddt] And [forms]![principale]![datafinaleexportddt]) AND (([DDT_Picking Line].Type)=19 Or ([DDT_Picking Line].Type)=20) AND (([DDT_Picking Header].[Document Type])=0));

GO

-- [527] DDTPerDataRegistrazione
SELECT [DDT_Picking Header].Status, [DDT_Picking Line].[Document No_], [DDT_Picking Header].[Posting Date] AS DataCreazione, [DDT_Picking Header].[Posted No_], [DDT_Picking Header].[Posted Date] AS DataRegistrazione, [DDT_Picking Header].[Sell-to Customer No_], Customer.Name, [DDT_Picking Line].Type, [DDT_Picking Line].No_, [DDT_Picking Line].[Constant Variable Code] AS Color, [Variable Code].Description AS ColorDescription, [DDT_Picking Line].[Assortment Code], Val([DDT_Picking Line.quantity]) AS qty, Val([DDT_Picking Line.no_ of pairs]) AS paia, Vendor.Name, Item.[Trademark Code], Item.[Season Code], IIf([paiaordine]<>0,[paia]/[paiaordine]*[valorenetto]) AS ValoreNettoDDT, Item.[Advertising Material], DDTPerDataRegistrazione_support.[Document No_] AS OrderNO, DDTPerDataRegistrazione_support.Reference, DDTPerDataRegistrazione_support.[Customer Order Ref_]
FROM ((((([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) INNER JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN Customer ON [DDT_Picking Header].[Sell-to Customer No_] = Customer.No_) INNER JOIN DDTPerDataRegistrazione_support ON ([DDT_Picking Line].[Order Line No_] = DDTPerDataRegistrazione_support.[Line No_]) AND ([DDT_Picking Line].[Order No_] = DDTPerDataRegistrazione_support.[Document No_])) INNER JOIN [Variable Code] ON ([DDT_Picking Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([DDT_Picking Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])
WHERE ((([DDT_Picking Header].[Posted Date]) Between [forms]![principale]![datainizialeexportddt] And [forms]![principale]![datafinaleexportddt]) AND (([DDT_Picking Line].Type)=19 Or ([DDT_Picking Line].Type)=20) AND (([DDT_Picking Header].[Document Type])=0));

GO

-- [528] DDTPerDataRegistrazione_OLD
SELECT [DDT_Picking Header].Status, [DDT_Picking Line].[Document No_], [DDT_Picking Header].[Posting Date] AS DataCreazione, [DDT_Picking Header].[Posted No_], [DDT_Picking Header].[Posted Date] AS DataRegistrazione, [DDT_Picking Header].[Sell-to Customer No_], Customer.Name, [DDT_Picking Line].Type, [DDT_Picking Line].No_, IIf(InStr([ddt_picking line.no_],"MES")<>0,"Y","N") AS testMes, Val([quantity]) AS qty, Val([no_ of pairs]) AS paia, Vendor.Name, Item.[Trademark Code], Item.[Season Code]
FROM ((([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) INNER JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN Customer ON [DDT_Picking Header].[Sell-to Customer No_] = Customer.No_
WHERE ((([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Header].[Posted Date]) Between [forms]![principale]![datainizialeexportddt] And [forms]![principale]![datafinaleexportddt]) AND (([DDT_Picking Line].Type)=19 Or ([DDT_Picking Line].Type)=20));

GO

-- [529] DDTPerDataRegistrazione_support
SELECT [Sales Line].[Document No_], [Sales Line].[Line No_], (Val([Sales Line.Line Amount])-Val([Sales Line.inv_ Discount Amount])) AS ValoreNetto, [Sales Line].[Document Type], [Sales Line].Reference, [Sales Line].[Customer Order Ref_], Val([No_ of pairs]) AS PaiaOrdine
