-- [530] DDTPeriodoAgente
SELECT [DDT_Picking Header].[posted no_], [DDT_Picking Header].[Posted Date], [Sales Header].[Shortcut Dimension 2 Code] AS Trademark, [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Ship-to City], [Sales Header].No_, [Sales Header].[KIMO_FASHION SO No_], Sum(Val([no_ of pairs])) AS Pairs, Salesperson_Purchaser.Name, [DDT_Picking Header].[Salesperson Code]
FROM (([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON ([DDT_Picking Line].[Document Type] = [DDT_Picking Header].[Document Type]) AND ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_)) INNER JOIN [Sales Header] ON [DDT_Picking Line].[Order No_] = [Sales Header].No_) INNER JOIN Salesperson_Purchaser ON [DDT_Picking Header].[Salesperson Code] = Salesperson_Purchaser.Code
GROUP BY [DDT_Picking Header].[posted no_], [DDT_Picking Header].[Posted Date], [Sales Header].[Shortcut Dimension 2 Code], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Ship-to City], [Sales Header].No_, [Sales Header].[KIMO_FASHION SO No_], Salesperson_Purchaser.Name, [DDT_Picking Header].[Salesperson Code]
HAVING ((([DDT_Picking Header].[Posted Date]) Between [forms]![principale]![datainizialeexportddt] And [forms]![principale]![datafinaleexportddt]) AND (([DDT_Picking Header].[Salesperson Code])=[forms]![principale]![filtroagenteexportddt]));

GO

-- [531] def01-ANALISINOTEDICREDITO-PIVOT
SELECT [qAnalisiNoteDiCreditoEResi-step1].*, [Item].[Trademark Code], [Item].[Season Code], [Item].[Collection Code], [Item].[Line Code], [Geographical Zone].Description AS GeographicalZoneDescription, [Item].[Season Typology], [Item].[Product Family], [Item].[Product Sex], [Item].[Shipment Priority], [Item].[Innovation Degree], [Item].[Heel Height], [Item].[End Customer Price Gap], [Item].[Market Segment], [Item].[Product Typology], [Item].[Main Material], [Item].[Sole Material]
