-- [532] def01-ANALISIVENDUTO-ConfrontoStagioni
SELECT IIf(([Season Code]=[forms]![principale]![filtroconfrontostagione1] And [Order Date]<=[forms]![principale]![datacutoffstagione1] And ([Delete Date]=#1/1/1753# Or [Delete Date]>[forms]![principale]![datacutoffstagione1])) Or ([Season Code]=[forms]![principale]![filtroconfrontostagione2] And [Order Date]<=[forms]![principale]![datacutoffstagione2] And ([Delete Date]=#1/1/1753# Or [Delete Date]>[forms]![principale]![datacutoffstagione2])),"ATTIVO","") AS TestOrdineAttivoAllaDataCutOff, IIf(([Season Code]=[forms]![principale]![filtroconfrontostagione1]) Or ([Season Code]=[forms]![principale]![filtroconfrontostagione2]),"ATTIVO","") AS TestStagione, IIf(([Season Code]=[forms]![principale]![filtroconfrontostagione1] And [Order Date]<=[forms]![principale]![datacutoffstagione1]) Or ([Season Code]=[forms]![principale]![filtroconfrontostagione2] And [Order Date]<=[forms]![principale]![datacutoffstagione2]),"ATTIVO","") AS TestDataOrdine, [forms]![principale]![filtroconfrontostagione1] AS StagioneConfronto1, [forms]![principale]![datacutoffstagione1] AS DataCutOffS1, [forms]![principale]![filtroconfrontostagione2] AS StagioneConfronto2, [forms]![principale]![datacutoffstagione2] AS DataCutOffS2, [def01-ANALISIVENDUTO-PIVOT].*
FROM [def01-ANALISIVENDUTO-PIVOT];

GO

-- [533] def01-ANALISIVENDUTO-ConfrontoStagioni-COLONNE DI TEST PARZIALE
SELECT IIf(([Season Code]=[forms]![principale]![filtroconfrontostagione1] And [Order Date]<=[forms]![principale]![datacutoffstagione1] And ([Delete Date]=#1/1/1753# Or [Delete Date]>[forms]![principale]![datacutoffstagione1])) Or ([Season Code]=[forms]![principale]![filtroconfrontostagione2] And [Order Date]<=[forms]![principale]![datacutoffstagione2] And ([Delete Date]=#1/1/1753# Or [Delete Date]>[forms]![principale]![datacutoffstagione2])),"ATTIVO","") AS TestOrdineAttivoAllaDataCutOff, IIf(([Season Code]=[forms]![principale]![filtroconfrontostagione1]) Or ([Season Code]=[forms]![principale]![filtroconfrontostagione2]),"ATTIVO","") AS TestStagione, IIf(([Season Code]=[forms]![principale]![filtroconfrontostagione1] And [Order Date]<=[forms]![principale]![datacutoffstagione1]) Or ([Season Code]=[forms]![principale]![filtroconfrontostagione2] And [Order Date]<=[forms]![principale]![datacutoffstagione2]),"ATTIVO","") AS TestDataOrdine, [forms]![principale]![filtroconfrontostagione1] AS StagioneConfronto1, [forms]![principale]![datacutoffstagione1] AS DataCutOffS1, [forms]![principale]![filtroconfrontostagione2] AS StagioneConfronto2, [forms]![principale]![datacutoffstagione2] AS DataCutOffS2, [def01-ANALISIVENDUTO-PIVOT].*
FROM [def01-ANALISIVENDUTO-PIVOT];

GO

-- [534] def01-ANALISIVENDUTOITEM-ConfrontoStagioni
SELECT IIf(([Season Code]=[forms]![principale]![filtroconfrontostagione1] And [Order Date]<=[forms]![principale]![datacutoffstagione1] And ([Delete Date]=#1/1/1753# Or [Delete Date]>[forms]![principale]![datacutoffstagione1])) Or ([Season Code]=[forms]![principale]![filtroconfrontostagione2] And [Order Date]<=[forms]![principale]![datacutoffstagione2] And ([Delete Date]=#1/1/1753# Or [Delete Date]>[forms]![principale]![datacutoffstagione2])),"ATTIVO","") AS TestOrdineAttivoAllaDataCutOff, [forms]![principale]![filtroconfrontostagione1] AS StagioneConfonto1, [forms]![principale]![datacutoffstagione1] AS DataCutOffS1, [forms]![principale]![filtroconfrontostagione2] AS StagioneConfonto2, [forms]![principale]![datacutoffstagione2] AS DataCutOffS2, [def01-ANALISIVENDUTOITEM-PIVOT].*
