FROM (([def01-qAcqEVend-Item-Union] INNER JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [def01-qAcqEVend-Item-Union].Article = Item.No_) INNER JOIN DatiCarryOverESMU ON ([def01-qAcqEVend-Item-Union].ColorCode = DatiCarryOverESMU.[Variable Code 01]) AND ([def01-qAcqEVend-Item-Union].Article = DatiCarryOverESMU.[Model Item No_])) LEFT JOIN CostiAcquisti ON ([def01-qAcqEVend-Item-Union].taglia = CostiAcquisti.[Variable Code 02]) AND ([def01-qAcqEVend-Item-Union].Article = CostiAcquisti.[Model Item No_]) AND ([def01-qAcqEVend-Item-Union].ColorCode = CostiAcquisti.[Variable Code 01]);

