-- [550] def01-qAcqEVend-ZFinal-PerAnalisi
SELECT [def01-qAcqEVend-Union].*, Item.[Description 2], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.Smu, Item.[Vendor No_] AS VendorCode, Vendor.Name AS Vendor, [Variable Code].Description AS Color, Item.[Trademark Code], Item.[Collection Code], Item.[Season Code], Item.[Line Code], IIf([PairsSold]-[PairsPurchased]<0,[PairsSold]-[PairsPurchased],0) AS deltaPiazzarePairs, IIf([PairsSold]-[PairsPurchased]<0,[Valuepurchased]/[PairsPurchased]*[deltaPiazzarePairs],0) AS deltaPiazzareValueOLD, IIf([PairsSold]-[PairsPurchased]<0,[costo]*[deltaPiazzarePairs],0) AS deltaPiazzareValue, IIf([QuantitySold]-[QuantityPurchased]>0,[QuantitySold]-[QuantityPurchased],0) AS deltaComprareAssortments, IIf([QuantitySold]-[QuantityPurchased]<0,[QuantitySold]-[QuantityPurchased],0) AS deltaPiazzareAssortments, IIf([PairsSold]-[PairsPurchased]>0,[PairsSold]-[PairsPurchased],0) AS deltaComprarePairs, IIf([PairsSold]-[PairsPurchased]>0,[Valuepurchased]/[PairsPurchased]*[deltaComprarePairs],0) AS deltaComprareValueOLD, IIf([PairsSold]-[PairsPurchased]>0,[costo]*[deltaComprarePairs],0) AS deltaComprareValue, [forms]![principale]![fattorecorrettivo]*[PairsSold] AS SalesForecastPairs, Round([forms]![principale]![fattorecorrettivo]*[QuantitySold]) AS SalesForecastAssortment, IIf([quantitysold]<>0,Round([forms]![principale]![fattorecorrettivo]*[Quantitysold])*[pairssold]/[quantitysold],0) AS SalesForecastAssortmentPairs, Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Must Buy], [QuantitySold]-[deltaComprareAssortments] AS SellableAssortment, [pairssold]-[deltacomprarepairs] AS SellablePairs, IIf([valuesold]<>0,[Valuesold]*[sellablePairs]/[pairssold],0) AS SellableValue, IIf([pairssold]<>0,[Valuesold]*[SalesForecastAssortmentPairs]/[PairsSold],0) AS SalesForecastAssortmentPairsValue, IIf([pairssold]<>0,[grossSalesValue]*[sellablePairs]/[pairssold],0) AS SellableGrossValue, IIf([pairssold]<>0,[AreaManagerCommissionValue]*[sellablePairs]/[pairssold],0) AS SellableAreaManagerCommissionValue, IIf([pairssold]<>0,[SalesPersonCommissionValue]*[sellablePairs]/[pairssold],0) AS SellableSalesPersonCommissionValue, IIf([pairssold]<>0,[DiscountValue]*[sellablePairs]/[pairssold],0) AS SellableDiscountValue, DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Sold Out Date], DatiCarryOverESMU.[Sales_Purchase Status Date], DatiCarryOverESMU.[Potential Sold Out], Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((((([def01-qAcqEVend-Union] INNER JOIN Item ON [def01-qAcqEVend-Union].Article = Item.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN [Variable Code] ON (Item.[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([def01-qAcqEVend-Union].ColorCode = [Variable Code].[Variable Code])) INNER JOIN DatiCarryOverESMU ON ([def01-qAcqEVend-Union].ColorCode = DatiCarryOverESMU.[Variable Code 01]) AND ([def01-qAcqEVend-Union].Article = DatiCarryOverESMU.[Model Item No_])) LEFT JOIN [CostoAcquisti-ModelItem] ON ([def01-qAcqEVend-Union].ColorCode = [CostoAcquisti-ModelItem].[Variable Code 01]) AND ([def01-qAcqEVend-Union].Article = [CostoAcquisti-ModelItem].[Model Item No_])) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE (((Item.[Advertising Material])=0));

GO

-- [551] def01-qAcqEVend-ZFinal-PerAnalisi-MoreData
SELECT [def01-qAcqEVend-ZFinal-PerAnalisi].*, IIf([SalesForecastAssortmentPairs]-[PairsPurchased]>0,[SalesForecastAssortmentPairs]-[PairsPurchased],0) AS deltaComprareForcastAssortmentPairs, IIf([SalesForecastAssortmentPairs]-[PairsPurchased]<0,[SalesForecastAssortmentPairs]-[PairsPurchased],0) AS deltaPiazzareforecastAssortmentPairs, [SalesForecastAssortmentPairs]-[deltaComprareForcastAssortmentPairs] AS SellableForecastAssortmentPairs, IIf([SalesForecastAssortmentPairs]<>0,[SalesForecastAssortmentPairsValue]*[SellableForecastAssortmentPairs]/[SalesForecastAssortmentPairs],0) AS SellableForecastAssortmentPairsValue
FROM [def01-qAcqEVend-ZFinal-PerAnalisi];

GO

-- [552] def01-StimaRedditivitaFineStagioneVendite
SELECT [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].[Season Code], [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].[Trademark Code], [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].Article, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].ColorCode, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].Assortment, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].PurchasesPairs, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].SellablePairs, -[deltaPiazzarePairs] AS StockPairs, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].PurchasesValueEuro AS AmmontareCostoAcquisto, [PercentualeCommissioniDiAcquisto]*[PurchasesValueEuro] AS AmmontareCommissioniAcquisto, [PercentualeOneriControlloProduzione]*[purchasesValueEuro] AS AmmontareOneriControlloProduzione, [ammontarecostoacquisto]+[ammontarecommissioniacquisto]+[ammontareonericontrolloproduzione] AS TotaleCostoAcquisto, [TrasportoAcquistoEstero]*[purchasesPairs] AS AmmontareTrasportoAcquistoEstero, [PercentualeDazio]*[PurchasesValueEuro] AS AmmontareDazio, [Spesedoganali]*[PurchasesPairs] AS AmmontareSpeseDoganali, [TrasportoAcquistoItalia]*[purchasesPairs] AS AmmontareTrasportoAcquistoItalia, [Campionario]*[PurchasesPairs] AS AmmontareCampionario, [SviluppoCollezione]*[PurchasesPairs] AS AmmontareSviluppoCollezione, [percentualeperditeperfallati]*[sellablevalue] AS AmmontarePerditePerFallati, [PercentualeVariIndustriali]*[SellableValue] AS AmmontareVariIndustriali, [TotaleCostoAcquisto]+[AmmontareTrasportoAcquistoEstero]+[AmmontareDazio]+[AmmontareSpeseDoganali]+[AmmontareTrasportoAcquistoItalia]+[AmmontareCampionario]+[AmmontareSviluppoCOllezione]+[AmmontarePerditePerFallati]+[AmmontareVariIndustriali] AS TotaleCostoIndustriale, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].SellableDiscountValue AS AmmontareSconti, 0 AS AmmontareScontiStock, [PercentualeResi]*[SellableValue] AS AmmontareResi, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].SellableSalesPersonCommissionValue AS AmmontareProvvigioniAgenti, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].SellableAreaManagerCommissionValue AS AmmontareProvvigioniCapozona, [PercentualeEnasarco]*[SellableValue] AS AmmontareEnasarco, [PercentualeRoyalties]*[SellableValue] AS AmmontareRoyalties, [PercentualeInformazioniCommerciali]*[SellableValue] AS AmmontareInformazioniCommerciali, [TrasportoVendite]*[SellablePairs] AS AmmontareTrasportoVendite, [PercentualePerditeSulCredito]*[SellableValue] AS AmmontarePerditeSulCredito, [PercentualeOneriFinanziari]*[SellableValue] AS AmmontareOneriFinanziari, [SellablePairs]*[AltreSpeseFisse] AS AmmontareAltreSpeseFisse, [TotaleCostoIndustriale]+[AmmontareSconti]+[AmmontareScontiStock]+[AmmontareResi]+[AmmontareProvvigioniCapozona]+[ammontareprovvigioniagenti]+[ammontareenasarco]+[AmmontareRoyalties]+[AmmontareInformazioniCommerciali]+[AmmontareTrasportoVendite]+[AmmontarePerditeSulCredito]+[AmmontareOneriFinanziari]+[AmmontareAltreSpeseFisse] AS TotaleCostoVenduto, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].SellableGrossValue AS TotaleRicaviLordoSconti, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].SellableValue AS TotaleRicavi, [TotaleRicaviLordoSconti]-[TotaleCostoAcquisto] AS MargineSUAcquisto, [TotaleRicaviLordoSconti]-[TotaleCostoIndustriale] AS MargineSuIndustriale, [TotaleRicaviLordoSconti]-[TotaleCostoVenduto] AS MargineSuVenduto, IIf([purchasespairs]<>0,[StockPairs]*[totalecostoAcquisto]/[PurchasesPairs],0) AS ValoreStockACostoAcquisto, IIf([purchasespairs]<>0,[StockPairs]*[TotaleCostoIndustriale]/[PurchasesPairs],0) AS ValoreStockACostoIndustriale, [TotaleRicaviLordoSconti]-[AmmontareSconti]-[AmmontareScontiStock]-[AmmontareResi]-[AmmontareProvvigioniAgenti]-[ammontareprovvigionicapozona]-[ammontareenasarco]-[AmmontareRoyalties]-[AmmontareTrasportoVendite]-[AmmontareInformazioniCommerciali] AS TotaleRicaviNetti, [AmmontareCostoAcquisto]+[AmmontareCommissioniAcquisto]+[AmmontareOneriControlloProduzione]+[AmmontareTrasportoAcquistoEstero]+[AmmontareDazio]+[AmmontareSpeseDoganali]+[AmmontareTrasportoAcquistoItalia]+[AmmontareCampionario]+[AmmontareSviluppoCollezione]+[AmmontarePerditePerFallati]+[AmmontareVariIndustriali] AS TotaleGestioneAcquisto, [TotaleRicaviNetti]-[TotaleGestioneAcquisto] AS ROGC, [AmmontareAltreSpeseFisse] AS TotaleSpeseStruttura, [rogc]-[totalespesestruttura] AS RisultatoOperativo, [ammontareperditesulcredito]+[ammontareonerifinanziari] AS TotaleGestioneFinanziaria, [risultatooperativo]-[totalegestionefinanziaria] AS MarginePreImposteSenzaStock, [ValoreStockACostoIndustriale] AS ValoreStock, [MarginePreImposteSenzaStock]+[valorestock] AS MarginePreImposteConStock, [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].[Line Code]
FROM ([def01-qAcqEVend-ZFinal-PerAnalisi-MoreData] LEFT JOIN Fornitori ON [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].VendorCode = Fornitori.CodiceFornitore) LEFT JOIN Marchi ON [def01-qAcqEVend-ZFinal-PerAnalisi-MoreData].[Trademark Code] = Marchi.Marchio;

GO

-- [553] def01-StimaRedditivitaFineStagioneVendite-PIVOT
SELECT [def01-StimaRedditivitaFineStagioneVendite].[Season Code], [def01-StimaRedditivitaFineStagioneVendite].[Trademark Code], [def01-StimaRedditivitaFineStagioneVendite].[Line Code], [def01-StimaRedditivitaFineStagioneVendite].Article, [def01-StimaRedditivitaFineStagioneVendite].ColorCode, [def01-StimaRedditivitaFineStagioneVendite].Assortment, Sum([def01-StimaRedditivitaFineStagioneVendite].PurchasesPairs) AS SommaDiPurchasesPairs, Sum([def01-StimaRedditivitaFineStagioneVendite].SellablePairs) AS SommaDiSellablePairs, Sum([def01-StimaRedditivitaFineStagioneVendite].StockPairs) AS SommaDiStockPairs, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareCostoAcquisto) AS SommaDiAmmontareCostoAcquisto, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareCommissioniAcquisto) AS SommaDiAmmontareCommissioniAcquisto, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareOneriControlloProduzione) AS SommaDiAmmontareOneriControlloProduzione, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleCostoAcquisto) AS SommaDiTotaleCostoAcquisto, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareTrasportoAcquistoEstero) AS SommaDiAmmontareTrasportoAcquistoEstero, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareDazio) AS SommaDiAmmontareDazio, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareSpeseDoganali) AS SommaDiAmmontareSpeseDoganali, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareTrasportoAcquistoItalia) AS SommaDiAmmontareTrasportoAcquistoItalia, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareCampionario) AS SommaDiAmmontareCampionario, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareSviluppoCollezione) AS SommaDiAmmontareSviluppoCollezione, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontarePerditePerFallati) AS SommaDiAmmontarePerditePerFallati, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareVariIndustriali) AS SommaDiAmmontareVariIndustriali, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleCostoIndustriale) AS SommaDiTotaleCostoIndustriale, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareSconti) AS SommaDiAmmontareSconti, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareScontiStock) AS SommaDiAmmontareScontiStock, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareResi) AS SommaDiAmmontareResi, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareProvvigioniAgenti) AS SommaDiAmmontareProvvigioniAgenti, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareProvvigioniCapozona) AS SommaDiAmmontareProvvigioniCapozona, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareEnasarco) AS SommaDiAmmontareEnasarco, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareRoyalties) AS SommaDiAmmontareRoyalties, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareInformazioniCommerciali) AS SommaDiAmmontareInformazioniCommerciali, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareTrasportoVendite) AS SommaDiAmmontareTrasportoVendite, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontarePerditeSulCredito) AS SommaDiAmmontarePerditeSulCredito, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareOneriFinanziari) AS SommaDiAmmontareOneriFinanziari, Sum([def01-StimaRedditivitaFineStagioneVendite].AmmontareAltreSpeseFisse) AS SommaDiAmmontareAltreSpeseFisse, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleCostoVenduto) AS SommaDiTotaleCostoVenduto, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleRicaviLordoSconti) AS SommaDiTotaleRicaviLordoSconti, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleRicavi) AS SommaDiTotaleRicavi, Sum([def01-StimaRedditivitaFineStagioneVendite].MargineSUAcquisto) AS SommaDiMargineSUAcquisto, Sum([def01-StimaRedditivitaFineStagioneVendite].MargineSuIndustriale) AS SommaDiMargineSuIndustriale, Sum([def01-StimaRedditivitaFineStagioneVendite].MargineSuVenduto) AS SommaDiMargineSuVenduto, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleRicaviNetti) AS SommaDiTotaleRicaviNetti, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleGestioneAcquisto) AS SommaDiTotaleGestioneAcquisto, Sum([def01-StimaRedditivitaFineStagioneVendite].ROGC) AS SommaDiROGC, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleSpeseStruttura) AS SommaDiTotaleSpeseStruttura, Sum([def01-StimaRedditivitaFineStagioneVendite].RisultatoOperativo) AS SommaDiRisultatoOperativo, Sum([def01-StimaRedditivitaFineStagioneVendite].TotaleGestioneFinanziaria) AS SommaDiTotaleGestioneFinanziaria, Sum([def01-StimaRedditivitaFineStagioneVendite].MarginePreImposteSenzaStock) AS SommaDiMarginePreImposteSenzaStock, Sum([def01-StimaRedditivitaFineStagioneVendite].ValoreStock) AS SommaDiValoreStock, Sum([def01-StimaRedditivitaFineStagioneVendite].MarginePreImposteConStock) AS SommaDiMarginePreImposteConStock
FROM [def01-StimaRedditivitaFineStagioneVendite]
