-- [557] DimensioniVendite
SELECT [Document Dimension].[Table ID], Max(IIf([dimension code]="linea",[dimension value code],"")) AS dimLinea, Max(IIf([dimension code]="marchio",[dimension value code],"")) AS dimMarchio, Max(IIf([dimension code]="CCR",[dimension value code],"")) AS dimCCR, Max(IIf([dimension code]="Stagione",[dimension value code],"")) AS dimStagione, [Document Dimension].[Document Type], [Document Dimension].[Document No_], [Document Dimension].[Line No_]
FROM [Document Dimension]
GROUP BY [Document Dimension].[Table ID], [Document Dimension].[Document Type], [Document Dimension].[Document No_], [Document Dimension].[Line No_]
HAVING ((([Document Dimension].[Table ID])=37));

GO

-- [558] DimensioniVenditeControllo
SELECT DimensioniVendite.[Table ID], DimensioniVendite.dimLinea, DimensioniVendite.dimMarchio, DimensioniVendite.dimCCR, DimensioniVendite.dimStagione, DimensioniVendite.[Document Type], DimensioniVendite.[Document No_], DimensioniVendite.[Line No_], Item.[Line Code], Item.[Trademark Code], Item.[Cost Centre Code], Item.[Season Code], [Sales Line].No_
FROM DimensioniVendite INNER JOIN ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) ON (DimensioniVendite.[Line No_] = [Sales Line].[Line No_]) AND (DimensioniVendite.[Document No_] = [Sales Line].[Document No_]) AND (DimensioniVendite.[Document Type] = [Sales Line].[Document Type]);

GO

