WHERE (((Item.[Season code])=[forms]![principale]![FiltroStagioneControlliLettureResi]));

GO

-- [570] EANCodes_CleanDoubled_PerSovraccolli
SELECT EANCodes.[Cross-Reference No_], EANCodes.[Cross-Reference Type No_], EANCodes.[Cross-Reference Type], EANCodes.[Item No_], Item.[Season code]
FROM EANCodes INNER JOIN Item ON EANCodes.[Item No_] = Item.No_
WHERE (((Item.[Season code])=[forms]![principale]![filtrostagionesovraccolli]));

GO

-- [571] EANCodes_CleanDoubled_PerSovraccolli_N
SELECT UPCCodes.[Cross-Reference No_], UPCCodes.[Cross-Reference Type No_], UPCCodes.[Cross-Reference Type], UPCCodes.[Item No_], Item.[Season code]
FROM UPCCodes INNER JOIN Item ON UPCCodes.[Item No_] = Item.No_
WHERE (((Item.[Season code])=[forms]![principale]![filtrostagionesovraccolli]));

GO

-- [572] EANtoImport
SELECT [EAN Codes].Material, [EAN Codes].[Material number], [EAN Codes].Colore, [EAN Codes].taglia, [EAN Codes].[EAN/UPC]
FROM [EAN Codes]
GROUP BY [EAN Codes].Material, [EAN Codes].[Material number], [EAN Codes].Colore, [EAN Codes].taglia, [EAN Codes].[EAN/UPC];

GO

-- [573] EANUPC_CleanDoubled_PerSovraccolli
SELECT [Cross-Reference No_], [Cross-Reference Type No_], [Cross-Reference Type], [Item No_], [Season code]
FROM EANCodes_CleanDoubled_PerSovraccolli;

