FROM UPCCodes_CleanDoubled_PerSovraccolli;

GO

-- [574] EANUPCCodes
SELECT [Item Cross Reference].[Item No_], [Item Cross Reference].[Cross-Reference Type], [Item Cross Reference].[Cross-Reference No_], [Item Cross Reference].[Cross-Reference Type No_]
FROM [Item Cross Reference]
WHERE ((([Item Cross Reference].[Cross-Reference Type])=3) AND (([Item Cross Reference].[Cross-Reference Type No_])="EAN13" Or ([Item Cross Reference].[Cross-Reference Type No_])="UPC"));

GO

-- [575] EstraiDatiCoin
SELECT Item.[Model Item No_] AS CodArt, Left$([Item_1.Description 2] & " " & [Item_1.Description],36) AS DescrLunga, Left$([Item_1.Description 2] & " " & [Item_1.Description],25) AS DescrBreve, Left$([Item_1.Description 2] & " " & [Item_1.Description],13) AS DescrPos, EANCodes.[Cross-Reference No_] AS EanCode, "S" AS FlagEANPrincipale, SuggestedRetailPrices.SRP AS PrezzoVendita, 22 AS IVA, "" AS [Classificazione 1], "" AS [Classificazione 2], "" AS [Classificazione 3], "" AS DataDecorrenza
FROM (((([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN SuggestedRetailPrices ON [Sales Line].No_ = SuggestedRetailPrices.[Item No_]) INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) LEFT JOIN EANCodes ON Item.No_ = EANCodes.[Item No_]
WHERE ((([Sales Header].No_)=[forms]![principale]![filtroodvean]) AND (([Sales Line].Type)=2) AND (([Sales Line].[Delete Reason])=""))
ORDER BY Item.[Model Item No_], EANCodes.[Cross-Reference No_];

GO

-- [576] EstraiDatiCoinBolla
SELECT "XXXX - INSERIRE" AS CodiceNegozioOVS, [Transfer Shipment Header].[DDT No_] AS [Numero Bolla], [Transfer Shipment Header].[Date DDT] AS [data bolla], EANCodes.[Cross-Reference No_] AS EAN, Val([quantity]) AS quantita
FROM ([Transfer Shipment Header] INNER JOIN [Transfer Shipment Line] ON [Transfer Shipment Header].No_ = [Transfer Shipment Line].[Document No_]) INNER JOIN ((Item INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) LEFT JOIN EANCodes ON Item.No_ = EANCodes.[Item No_]) ON [Transfer Shipment Line].[Item No_] = Item.No_
WHERE ((([Transfer Shipment Header].[DDT No_])=[forms]![principale]![FiltroDDTDaTrasferimento]))
ORDER BY "XXXX - INSERIRE";

GO

-- [577] EstrazioneDatiLince
SELECT [Customer].No_ AS NoCliente, [Customer].Name, [Customer].[Name 2], [Customer].Address, [Customer].City, [Customer].[Post Code] AS PostCode, [Customer].County, [Customer].[Country Code] AS CountryCode, [Customer].[Fiscal Code] AS FiscalCode, [Customer].[VAT Registration No_] AS VATRegistrationNo, Sum([def01-ANALISIVENDUTO-PIVOT].salesvalue) AS ValoreVenditaNetto
FROM [def01-ANALISIVENDUTO-PIVOT] INNER JOIN Customer ON [def01-ANALISIVENDUTO-PIVOT].CustomerCode = [Customer].No_
WHERE ((([def01-ANALISIVENDUTO-PIVOT].[Season Code])=[stagione]) AND (([def01-ANALISIVENDUTO-PIVOT].[Delete Reason])="") AND (([def01-ANALISIVENDUTO-PIVOT].DocumentType)="sales"))
GROUP BY [Customer].No_, [Customer].Name, [Customer].[Name 2], [Customer].Address, [Customer].City, [Customer].[Post Code], [Customer].County, [Customer].[Country Code], [Customer].[Fiscal Code], [Customer].[VAT Registration No_];

GO

-- [578] EstrazioneDatiPerCompilazioneTemplateNapa
SELECT [UPC] & [Purchase Line_1.assortment code] AS chiave, [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].[Model Item No_], [Purchase Line].[Description 2], [Purchase Line].[Variable Code 01], [Purchase Line].[Variable Code 02], Str$(Val([purchase line.quantity])) AS qty_txt, Val([purchase line.quantity]) AS qty_val, [Purchase Line_1].[Assortment Code], UPCCodes.[Cross-Reference No_] AS UPC, Val([purchase line.amount]) AS Amt
FROM ([Purchase Line] AS [Purchase Line_1] INNER JOIN [Purchase Line] ON ([Purchase Line].[Original Line No_] = [Purchase Line_1].[Line No_]) AND ([Purchase Line_1].[Document No_] = [Purchase Line].[Document No_])) INNER JOIN UPCCodes ON [Purchase Line].No_ = UPCCodes.[Item No_]
WHERE ((([Purchase Line].[Document No_])=[forms]![principale]![FiltroODAEstrazioneTemplateNapa]) AND (([Purchase Line].Type)=2));

GO

-- [579] EstrazioneDatiPerCompilazioneTemplateNapa_Grouped
SELECT EstrazioneDatiPerCompilazioneTemplateNapa.upc AS chiave_, EstrazioneDatiPerCompilazioneTemplateNapa.[Document No_], EstrazioneDatiPerCompilazioneTemplateNapa.No_, EstrazioneDatiPerCompilazioneTemplateNapa.[Model Item No_], EstrazioneDatiPerCompilazioneTemplateNapa.[Description 2], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 01], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 02], Str$(Sum([qty_val])) AS qty_txt_, Sum(EstrazioneDatiPerCompilazioneTemplateNapa.qty_val) AS qty_val_, EstrazioneDatiPerCompilazioneTemplateNapa.UPC, Sum(EstrazioneDatiPerCompilazioneTemplateNapa.Amt) AS Amt_
FROM EstrazioneDatiPerCompilazioneTemplateNapa
GROUP BY EstrazioneDatiPerCompilazioneTemplateNapa.upc, EstrazioneDatiPerCompilazioneTemplateNapa.[Document No_], EstrazioneDatiPerCompilazioneTemplateNapa.No_, EstrazioneDatiPerCompilazioneTemplateNapa.[Model Item No_], EstrazioneDatiPerCompilazioneTemplateNapa.[Description 2], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 01], EstrazioneDatiPerCompilazioneTemplateNapa.[Variable Code 02], EstrazioneDatiPerCompilazioneTemplateNapa.UPC;

GO

-- [580] EstrazioneDatiVenditeBridgeSpaccioFebos
SELECT [Sales Line].Type, [Sales Line].[Document Type], [Sales Line].[Document No_], [Sales Line].[Sell-to Customer No_], Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione, Item.[Line Code] AS Linea, Item.[Model Item No_] AS Articolo, Item_1.Description, Item_1.[Description 2], [Sales Line].[Variable Code 01] AS Colore, [Sales Line].[Variable Code 02] AS taglia, Val([quantity]) AS quantita
FROM ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_
WHERE ((([Sales Line].Type)=2) AND (([Sales Line].[Document Type])=1) AND (([Sales Line].[Document No_])=[Numero ODV]))
ORDER BY Item.[Trademark Code], Item.[Season Code], Item.[Model Item No_], [Sales Line].[Variable Code 01], [Sales Line].[Variable Code 02];

GO

-- [581] EstrazioneDatiVenditeBridgeSpaccioFebosDaBolla
SELECT [DDT_Picking Line].Type, [DDT_Picking Line].[Document No_], [DDT_Picking Line].[Sell-to Customer No_], Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione, Item.[Line Code] AS Linea, Item.[Model Item No_] AS Articolo, Item_1.Description, Item_1.[Description 2], [DDT_Picking Line].[Variable Code 01] AS Colore, [DDT_Picking Line].[Variable Code 02] AS taglia, Val([quantity]) AS quantita
FROM (Item INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN [DDT_Picking Line] ON Item.No_ = [DDT_Picking Line].No_
WHERE ((([DDT_Picking Line].Type)=2) AND (([DDT_Picking Line].[Document No_])=[Numero SPD]))
ORDER BY Item.[Trademark Code], Item.[Season Code], Item.[Model Item No_], [DDT_Picking Line].[Variable Code 01], [DDT_Picking Line].[Variable Code 02];

GO

-- [582] Estrazione-Final
SELECT EstrazioneStep4.store, EstrazioneStep4.website, EstrazioneStep4.attribute_set, EstrazioneStep4.type, EstrazioneStep4.sku, EstrazioneStep4.config_attributes, EstrazioneStep5.associated_calc AS associated, EstrazioneStep4.super_attribute_pricing, EstrazioneStep4.Color, EstrazioneStep4.Size, EstrazioneStep4.has_option, EstrazioneStep4.name, EstrazioneStep4.Category_ids, EstrazioneStep4.meta_title, EstrazioneStep4.meta_description, EstrazioneStep4.Image, EstrazioneStep4.image_label, EstrazioneStep4.small_image, EstrazioneStep4.small_image_label, EstrazioneStep4.thumbnail, EstrazioneStep4.thumnail_label, EstrazioneStep4.media_gallery, EstrazioneStep4.tax_class_id, EstrazioneStep4.price, EstrazioneStep4.special_price, EstrazioneStep4.weight, EstrazioneStep4.decription, EstrazioneStep4.short_description, EstrazioneStep4.[""], EstrazioneStep4.related, EstrazioneStep4.manufacturer, EstrazioneStep4.[" "], EstrazioneStep4.qty, EstrazioneStep4.is_in_stock, EstrazioneStep4.backorders, EstrazioneStep4.manage_stock, EstrazioneStep4.status, EstrazioneStep4.visibiliity, EstrazioneStep4.materiale_suola_interna, EstrazioneStep4.materiale_suola, EstrazioneStep4.materiale_fodera, EstrazioneStep4.gender, EstrazioneStep4.collezone, EstrazioneStep4.codice_materiale_colore, EstrazioneStep4.ean_code, EstrazioneStep4.materiale, EstrazioneStep4.tipologia_scarpa, EstrazioneStep4.[paese produzione]
