-- [583] EstrazioneShooseAndCo
SELECT [def01-ANALISIVENDUTOITEM-PIVOT].[Country Code], [def01-ANALISIVENDUTOITEM-PIVOT].Salesperson, [def01-ANALISIVENDUTOITEM-PIVOT].CustomerName, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione AS ShipToCustomer, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione2 AS ShipToCustomer2, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione AS ShipToAddress, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione2 AS ShipToAddress2, [def01-ANALISIVENDUTOITEM-PIVOT].CittaSpedizione AS ShipToCity, [def01-ANALISIVENDUTOITEM-PIVOT].CodicePostaleSpedizione AS ShipToCap, [def01-ANALISIVENDUTOITEM-PIVOT].CountySpedizione AS ShipToCounty, [def01-ANALISIVENDUTOITEM-PIVOT].Article, [def01-ANALISIVENDUTOITEM-PIVOT].ColorCode, [def01-ANALISIVENDUTOITEM-PIVOT].[Assortment Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Description 2], [def01-ANALISIVENDUTOITEM-PIVOT].[Requested Delivery Date], Sum(IIf([documenttype]="SALES",[QuantitySold],0)) AS QuantitySoldGross, Sum(IIf([documenttype]="SALES",[ValueSold],0)) AS valueSoldGross, Sum(IIf([delete reason]<>"" And [documenttype]="sales",[quantitysold],0)) AS QuantityCancelled, Sum(IIf([delete reason]<>"" And [documenttype]="sales",[valuesold],0)) AS ValueCancelled, Sum(IIf([delete reason]="" And [documenttype]="sales",[quantitysold],0)) AS QuantitySoldNet, Sum(IIf([delete reason]="" And [documenttype]="sales",[valuesold],0)) AS ValueSoldNet, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityShipped) AS QuantityShipped1, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueShipped) AS ValueShipped1, Sum(IIf([delete reason]="" And [documenttype]="sales",[quantitysold],0))-Sum([QuantityShipped]) AS QuantityOutstanding, Sum(IIf([delete reason]="" And [documenttype]="sales",[valuesold],0))-Sum([ValueShipped]) AS ValueOutstanding, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityReadyForShippingRilasciate) AS QuantityReadyForShippingValidated, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueReadyForShippingRilasciate) AS ValueReadyForShippingValidated, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityReadyForShippingAperte) AS QuantityReadyForShippingBlocked, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueReadyForShippingAperte) AS ValueReadyForShippingBlocked, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityReturned) AS QuantityReturned, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueReturned) AS ValueReturned, [def01-ANALISIVENDUTOITEM-PIVOT].[Season Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Trademark Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Order Date] AS OrderDate
FROM [def01-ANALISIVENDUTOITEM-PIVOT]
GROUP BY [def01-ANALISIVENDUTOITEM-PIVOT].[Country Code], [def01-ANALISIVENDUTOITEM-PIVOT].Salesperson, [def01-ANALISIVENDUTOITEM-PIVOT].CustomerName, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione2, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione2, [def01-ANALISIVENDUTOITEM-PIVOT].CittaSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].CodicePostaleSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].CountySpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].Article, [def01-ANALISIVENDUTOITEM-PIVOT].ColorCode, [def01-ANALISIVENDUTOITEM-PIVOT].[Assortment Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Description 2], [def01-ANALISIVENDUTOITEM-PIVOT].[Requested Delivery Date], [def01-ANALISIVENDUTOITEM-PIVOT].[Season Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Trademark Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Order Date];

GO

-- [584] EstrazioneStep1
SELECT "admin" AS store, "base" AS website, "Default" AS attribute_set, "simple" AS type, [Item.model item no_] & "-" & [Item.variable code 01] & "-" & [item.variable code 02] AS sku, "" AS configurable_attributes, "" AS associated, "" AS super_attribute_pricing, [Variable Code].description AS color_description, Item.[Variable Code 02] AS [size], 0 AS has_option, Item_1.[Description 2] AS name, "" AS category_ids, "" AS meta_title, "" AS meta_description, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS [image], "" AS image_label, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS small_image, "" AS small_image_label, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS thumbnail, "" AS thumnail_label, UCase("/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_02") & ".jpg,/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_03") & ".jpg" & UCase(",/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_04") & ".jpg" AS media_gallery, 5 AS tax_class_id, SuggestedRetailPrices.SRP AS price, "" AS special_price, Val([Item.Gross Weight])*1000 AS weight, Item_1.Description AS description, Item_1.Description AS short_description, "" AS [""], "" AS related, "" AS manufacturer, "" AS [" "], Sum(Val([Quantity])) AS Qty, 1 AS is_in_stock, 0 AS backorders, 1 AS manage_stock, "Abilitato" AS status, "Non visibile individualmente" AS visibility, "" AS materiale_suola_interna, "" AS materiale_suola, "" AS materiale_fodera, Item.[product sex] AS gender, Item.[collection code] AS collezione, [Item.model item no_] & "-" & [Item.variable code 01] AS codice_materiale_colore, EanCodes.[Cross-Reference No_] AS ean_code, "" AS materiale, Item.[product family] AS tipologia_scarpa, Item.[Country_Region of Origin Code] AS [paese produzione], LCase([item.description 2] & "-" & Right$([item.model item no_],Len([ITEM.MODEL ITEM NO_])-InStr([item.model item no_],"/")) & "-" & SubstSlashDash([Item.variable code 01]) & "-" & [item.variable code 02]) AS url_key, [item.tariff no_] AS tariffa_doganale, [item.upper composition] AS upper_composition, [item.lining composition] AS lining_composition, [item.outsole composition] AS outsole_composition, [item.insole composition] AS insole_composition
FROM ([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN ((((Item INNER JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN SuggestedRetailPrices ON Item.No_ = SuggestedRetailPrices.[Item No_]) LEFT JOIN EanCodes ON Item.No_ = EanCodes.[Item No_]) ON [Sales Line].No_ = Item.No_
WHERE (((Item.[Advertising Material])=0))
GROUP BY "admin", "base", "Default", "simple", [Item.model item no_] & "-" & [Item.variable code 01] & "-" & [item.variable code 02], [Variable Code].description, Item.[Variable Code 02], Item_1.[Description 2], "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", UCase("/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_02") & ".jpg,/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_03") & ".jpg" & UCase(",/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_04") & ".jpg", 5, SuggestedRetailPrices.SRP, Val([Item.Gross Weight])*1000, Item_1.Description, 0, 1, "Abilitato", "Non visibile individualmente", Item.[product sex], Item.[collection code], [Item.model item no_] & "-" & [Item.variable code 01], EanCodes.[Cross-Reference No_], "", Item.[product family], Item.[Country_Region of Origin Code], LCase([item.description 2] & "-" & Right$([item.model item no_],Len([ITEM.MODEL ITEM NO_])-InStr([item.model item no_],"/")) & "-" & SubstSlashDash([Item.variable code 01]) & "-" & [item.variable code 02]), [item.tariff no_], [item.upper composition], [item.lining composition], [item.outsole composition], [item.insole composition], "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", "", "", "", "", "", "", "", "", "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", "", "", Item_1.Description, "", "", "", "", 0, 1, "", "", "", "", "", "", [Sales Line].Type, [Sales Header].No_, [Sales Line].[Delete Reason]
HAVING ((([Sales Line].Type)=2) AND (([Sales Header].No_)=[forms]![principale]![FiltroODVEAN]) AND (([Sales Line].[Delete Reason])=""));

GO

-- [585] EstrazioneStep2-Configurabile
SELECT "admin" AS store, "base" AS website, "Default" AS attribute_set, "configurable" AS type, [Item.model item no_] & "-" & [Item.variable code 01] AS sku, "size" AS configurable_attributes, "" AS associated, "" AS super_attribute_pricing, [Variable Code].description AS color_description, "" AS [size], 1 AS has_option, Item_1.[Description 2] AS name, "" AS category_ids, "" AS meta_title, "" AS meta_description, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS [image], "" AS image_label, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS small_image, "" AS small_image_label, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS thumbnail, "" AS thumnail_label, UCase("/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_02") & ".jpg,/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_03") & ".jpg" & UCase(",/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_04") & ".jpg" AS media_gallery, 5 AS tax_class_id, SuggestedRetailPrices.SRP AS price, "" AS special_price, Val([Item.Gross Weight])*1000 AS weight, Item_1.Description AS description, Item_1.Description AS short_description, "" AS [""], "" AS related, "" AS manufacturer, "" AS [" "], 0 AS qty, 1 AS is_in_stock, 0 AS backorders, 1 AS manage_stock, "Abilitato" AS status, "Catalogo,Ricerca" AS visibility, "" AS materiale_suola_interna, "" AS materiale_suola, "" AS materiale_fodera, Item.[product sex] AS gender, Item.[collection code] AS collezione, [Item.model item no_] & "-" & [Item.variable code 01] AS codice_materiale_colore, "" AS ean_code, "" AS materiale, Item.[product family] AS tipologia_scarpa, Item.[Country_Region of Origin Code] AS [paese produzione], LCase([item.description 2] & "-" & Right$([item.model item no_],Len([ITEM.MODEL ITEM NO_])-InStr([item.model item no_],"/")) & "-" & SUBSTSLASHDASH([Item.variable code 01])) AS url_key, [item.tariff no_] AS tariffa_doganale, [item.upper composition] AS upper_composition, [item.lining composition] AS lining_composition, [item.outsole composition] AS outsole_composition, [item.insole composition] AS insole_composition
FROM (([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN (((Item INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN SuggestedRetailPrices ON Item.No_ = SuggestedRetailPrices.[Item No_]) LEFT JOIN EanCodes ON Item.No_ = EanCodes.[Item No_]) ON [Sales Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([Sales Line].[Variable Group 01] = [Variable Code].[Variable Group])
WHERE (((Item.[Advertising Material])=0))
GROUP BY "admin", "base", "Default", "configurable", "size", [Variable Code].description, Item_1.[Description 2], "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", UCase("/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_02") & ".jpg,/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_03") & ".jpg" & UCase(",/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_04") & ".jpg", 5, SuggestedRetailPrices.SRP, Val([Item.Gross Weight])*1000, Item_1.Description, 0, 1, "Abilitato", "Catalogo,Ricerca", Item.[product sex], Item.[collection code], [Item.model item no_] & "-" & [Item.variable code 01], "", Item.[product family], Item.[Country_Region of Origin Code], LCase([item.description 2] & "-" & Right$([item.model item no_],Len([ITEM.MODEL ITEM NO_])-InStr([item.model item no_],"/")) & "-" & SUBSTSLASHDASH([Item.variable code 01])), [item.tariff no_], [item.upper composition], [item.lining composition], [item.outsole composition], [item.insole composition], "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", "", "", "", "", "", "", "", "", "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", "", "", Item_1.Description, "", "", "", "", 1, 0, 1, "", "", "", [Item.model item no_] & "-" & [Item.variable code 01], "", "", "", "", "", "", [Item.model item no_] & "-" & [Item.variable code 01], "", [Sales Line].Type, [Sales Header].No_, [Sales Line].[Delete Reason]
HAVING ((([Sales Line].Type)=2) AND (([Sales Header].No_)=[forms]![principale]![FiltroODVEAN]) AND (([Sales Line].[Delete Reason])=""));

GO

-- [586] EstrazioneStep3
SELECT *
FROM [EstrazioneStep2-Configurabile];

