FROM (((([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Header].[Document Type] = [DDT_Picking Line].[Document Type])) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) INNER JOIN [Sales Line] ON ([DDT_Picking Line].[Order Line No_] = [Sales Line].[Line No_]) AND ([DDT_Picking Line].[Order No_] = [Sales Line].[Document No_])) LEFT JOIN [NavisionEan-step0] ON [DDT_Picking Line].No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN [NavisionEan-step0-UPC] ON [DDT_Picking Line].No_ = [NavisionEan-step0-UPC].[Item No_]
WHERE ((([DDT_Picking Line].[season code])=[FORMS]![PRINCIPALE]![FiltroStagioneEAN2]) AND (([DDT_Picking Header].[Sell-to Customer No_])=[FORMS]![PRINCIPALE]![FILTROCLIENTEEAN]) AND (([DDT_Picking Header].[Document Type])=0) AND ((Item.[advertising material])=0) AND (([DDT_Picking Line].Type)=2));

