-- [609] FattureRegistrateEDDt
SELECT [Sales Shipment Header].No_, Sum(Val([Sales Shipment Line.Quantity])) AS qtyShipped, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Quantity]))) AS qtyInvoiced, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([sales invoice line.Amount]))) AS Amount_, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Line Discount Amount]))) AS LineDiscountAmount, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Line Amount]))) AS LineAmount, Sum(IIf(IsNull([sales invoice line.document no_]),0,Val([Sales Invoice Line.Inv_ Discount Amount]))) AS InvoiceDiscountAmountu, [Sales Shipment Header].[Bill-to Customer No_], [Sales Shipment Header].[Bill-to Name], [Sales Shipment Header].[Posting Date] AS DataSpedzione, [Sales Shipment Line].[DDT No_], [FattureRegistrateEDdt-step0].[posted no_], [FattureRegistrateEDdt-step0].TransportDescription, [FattureRegistrateEDdt-step0].OnlyTransfer, [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header].[No_]) AS InvoiceNo_, IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header.Posting Date]) AS DataFattura, [Geographical Zone].Description AS GeoZone1, [Geographical Zone_1].Description AS GeoZone2
FROM (((([Sales Invoice Line] LEFT JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_) RIGHT JOIN (([Sales Shipment Line] LEFT JOIN [Sales Shipment Header] ON [Sales Shipment Line].[Document No_] = [Sales Shipment Header].No_) LEFT JOIN [Sales Header] ON [Sales Shipment Line].[Order No_] = [Sales Header].No_) ON ([Sales Invoice Line].[Shipment Line No_] = [Sales Shipment Line].[Line No_]) AND ([Sales Invoice Line].[Shipment No_] = [Sales Shipment Line].[Document No_])) LEFT JOIN (Customer LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) ON [Sales Shipment Line].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code) RIGHT JOIN [FattureRegistrateEDdt-step0] ON [Sales Shipment Line].[DDT No_] = [FattureRegistrateEDdt-step0].No_
GROUP BY [Sales Shipment Header].No_, [Sales Shipment Header].[Bill-to Customer No_], [Sales Shipment Header].[Bill-to Name], [Sales Shipment Header].[Posting Date], [Sales Shipment Line].[DDT No_], [FattureRegistrateEDdt-step0].[posted no_], [FattureRegistrateEDdt-step0].TransportDescription, [FattureRegistrateEDdt-step0].OnlyTransfer, [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header].[No_]), IIf(IsNull([sales invoice header].[no_]),"",[Sales invoice header.Posting Date]), [Geographical Zone].Description, [Geographical Zone_1].Description, [Sales Shipment Line].Type
HAVING (((Sum(Val([Sales Shipment Line.Quantity])))<>0) AND (([Sales Shipment Line].Type)=2));

GO

-- [610] FattureRegistrateEDdt-SoloNonFatturato
SELECT FattureRegistrateEDDt.*
FROM FattureRegistrateEDDt
WHERE (((FattureRegistrateEDDt.qtyShipped)<>[qtyinvoiced]));

GO

-- [611] FattureRegistrateEDdt-step0
SELECT [DDT_Picking Header].*, [Transport Reason Code].Description AS TransportDescription, IIf([Enable Transfer-to Location]=1,"YES","NO") AS OnlyTransfer
FROM [DDT_Picking Header] LEFT JOIN [Transport Reason Code] ON [DDT_Picking Header].[Transport Reason Code] = [Transport Reason Code].Code
WHERE ((([DDT_Picking Header].[Posted Date]) Between [Forms]![Principale]![DataIniziale] And [Forms]![Principale]![DataFinale]));

GO

-- [612] FattureRegistrateENDC-PerFatturazioneElettronica
SELECT IIf(IsNull([FattureRegistrateENDC-PerFatturazioneElettronica-step5.N# Documento])=False,"TROVATA","NON TROVATA") AS CheckIndicom, [FattureRegistrateENDC-PerFatturazioneElettronica-step5].SDI, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[SELL-TO CUSTOMER NO_], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].NAME, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].DocumentNo_, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].DataFattura, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].AmountWithVAT, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[Document Type], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[Recipient Code], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[File Name XML], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[Date-Time Extraction XML File], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[User ID Extraction XML File], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Data emissione], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Tipo documento], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Cedente/prestatore], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Cessionario/committente], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[PIVA Cessionario/committente], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Codice ufficio], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].ValoreIndicom, [FattureRegistrateENDC-PerFatturazioneElettronica-step5].Valuta, [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Codice flusso], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Data creazione]
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step3] LEFT JOIN [FattureRegistrateENDC-PerFatturazioneElettronica-step5] ON [FattureRegistrateENDC-PerFatturazioneElettronica-step3].DocumentNo_ = [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[N# documento];

GO

-- [613] FattureRegistrateENDC-PerFatturazioneElettronica-ControlloSDILog
SELECT [FattureRegistrateENDC-PerFatturazioneElettronica-step3].*, [FE SDI Log].[Indicom Received Date], [FE SDI Log].[SDI Send Date and Time], [FE SDI Log].[SDI Get Date and Time], [FE SDI Log].[Technical Status], [FE SDI Log].[Error Message], [FE SDI Log].[Document Status]
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step3] LEFT JOIN [FE SDI Log] ON [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[File Name XML] = [FE SDI Log].[XML File Name];

GO

-- [614] FattureRegistrateENDC-PerFatturazioneElettronica-step0
SELECT [Sales Invoice Header].[Sell-to Customer No_], Customer.Name, ([Sales invoice header].[No_]) AS DocumentNo_, [Sales invoice header.Posting Date] AS DataFattura, Sum(Val([Sales Invoice Line.Quantity])) AS qtyInvoiced, Sum(Val([sales invoice line.Amount])) AS Amount_, Sum(Val([Sales Invoice Line.Line Discount Amount])) AS LineDiscountAmount, Sum(Val([Sales Invoice Line.Line Amount])) AS LineAmount, Sum(Val([Sales Invoice Line.Inv_ Discount Amount])) AS InvoiceDiscountAmountu, Sum(Val([Amount Including VAT])) AS AmountWithVAT
FROM ([Sales Invoice Line] RIGHT JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_) LEFT JOIN Customer ON [Sales Invoice Header].[Sell-to Customer No_] = Customer.No_
WHERE ((([Sales Invoice Line].Type)=2 Or ([Sales Invoice Line].Type)=1))
GROUP BY [Sales Invoice Header].[Sell-to Customer No_], Customer.Name, ([Sales invoice header].[No_]), [Sales invoice header.Posting Date]
HAVING ((([Sales invoice header.Posting Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]));

GO

-- [615] FattureRegistrateENDC-PerFatturazioneElettronica-step1
SELECT [Sales Cr_Memo Header].[Sell-to Customer No_], Customer.Name, ([Sales Cr_memo header].[No_]) AS DocumentNo_, [Sales Cr_Memo header.Posting Date] AS DataFattura, Sum(Val([Sales Cr_Memo Line.Quantity])) AS qtyInvoiced, Sum(Val([sales Cr_memo line.Amount])) AS Amount_, Sum(Val([Sales Cr_memo Line.Line Discount Amount])) AS LineDiscountAmount, Sum(Val([Sales Cr_memo Line.Line Amount])) AS LineAmount, Sum(Val([Sales Cr_Memo Line.Inv_ Discount Amount])) AS InvoiceDiscountAmountu, Sum(Val([Amount Including VAT])) AS AmountWithVAT
FROM ([Sales Cr_Memo Header] LEFT JOIN Customer ON [Sales Cr_Memo Header].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [Sales Cr_Memo Line] ON [Sales Cr_Memo Header].No_ = [Sales Cr_Memo Line].[Document No_]
WHERE ((([Sales Cr_Memo Line].TYPE)=2 Or ([Sales Cr_Memo Line].TYPE)=1))
GROUP BY [Sales Cr_Memo Header].[Sell-to Customer No_], Customer.Name, ([Sales Cr_memo header].[No_]), [Sales Cr_Memo header.Posting Date]
HAVING ((([Sales Cr_Memo header.Posting Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]));

GO

-- [616] FattureRegistrateENDC-PerFatturazioneElettronica-step2
SELECT [SELL-TO CUSTOMER NO_], NAME, DocumentNo_, DataFattura, qtyInvoiced, Amount_, LineDiscountAmount, LineAmount, InvoiceDiscountAmountu,  AmountWithVAT
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step0];

UNION ALL SELECT [SELL-TO CUSTOMER NO_], NAME, DocumentNo_, DataFattura,qtyInvoiced, Amount_, LineDiscountAmount, LineAmount, InvoiceDiscountAmountu, AmountWithVAT
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step1];

GO

-- [617] FattureRegistrateENDC-PerFatturazioneElettronica-step3
SELECT [FattureRegistrateENDC-PerFatturazioneElettronica-step2].*, [FE Document].*
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step2] LEFT JOIN [FE Document] ON [FattureRegistrateENDC-PerFatturazioneElettronica-step2].DocumentNo_ = [FE Document].[Document No_];

GO

-- [618] FattureRegistrateENDC-PerFatturazioneElettronica-step4
SELECT FattureInviateIndicom.[N# documento], Max(FattureInviateIndicom.[Data creazione]) AS UtlimaDataCreazione
FROM FattureInviateIndicom
GROUP BY FattureInviateIndicom.[N# documento];

GO

-- [619] FattureRegistrateENDC-PerFatturazioneElettronica-step5
SELECT FattureInviateIndicom.SDI, FattureInviateIndicom.[N# documento], FattureInviateIndicom.[Data emissione], FattureInviateIndicom.[Tipo documento], FattureInviateIndicom.[Cedente/prestatore], FattureInviateIndicom.[PIVA Cedente/prestatore], FattureInviateIndicom.[Cessionario/committente], FattureInviateIndicom.[PIVA Cessionario/committente], FattureInviateIndicom.[Codice ufficio], Val([Totale documento]) AS ValoreIndicom, Val([Totale da pagare]) AS DaPagareIndicom, FattureInviateIndicom.Valuta, FattureInviateIndicom.[Codice flusso], FattureInviateIndicom.[Data creazione]
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step4] INNER JOIN FattureInviateIndicom ON ([FattureRegistrateENDC-PerFatturazioneElettronica-step4].UtlimaDataCreazione = FattureInviateIndicom.[Data creazione]) AND ([FattureRegistrateENDC-PerFatturazioneElettronica-step4].[N# documento] = FattureInviateIndicom.[N# documento]);

GO

-- [620] FattureTemporaneeEDdt
SELECT [Sales Shipment Header].[Operation Type], FattureTemporaneeEDdtSteo1.No_, FattureTemporaneeEDdtSteo1.[DDT No_], [Sales Shipment Header].[Bill-to Customer No_], [Sales Shipment Header].[Bill-to Name], [DDT_Picking Header].[Posted No_], [DDT_Picking Header].[Posted Date]
FROM ((FattureTemporaneeEDdtSteo1 INNER JOIN [Sales Line] ON FattureTemporaneeEDdtSteo1.No_ = [Sales Line].[Document No_]) INNER JOIN [Sales Shipment Header] ON [Sales Line].[Shipment No_] = [Sales Shipment Header].No_) INNER JOIN [DDT_Picking Header] ON [Sales Shipment Header].[DDT No_] = [DDT_Picking Header].No_
GROUP BY [Sales Shipment Header].[Operation Type], FattureTemporaneeEDdtSteo1.No_, FattureTemporaneeEDdtSteo1.[DDT No_], [Sales Shipment Header].[Bill-to Customer No_], [Sales Shipment Header].[Bill-to Name], [DDT_Picking Header].[Posted No_], [DDT_Picking Header].[Posted Date], FattureTemporaneeEDdtSteo1.[MinDiPosted No_]
ORDER BY [Sales Shipment Header].[Operation Type], FattureTemporaneeEDdtSteo1.[DDT No_], FattureTemporaneeEDdtSteo1.[MinDiPosted No_];

GO

-- [621] FattureTemporaneeEDdtSteo1
SELECT FattureTemporaneeEDdtStep0.No_, Count(FattureTemporaneeEDdtStep0.[DDT No_]) AS [DDT No_], Min(FattureTemporaneeEDdtStep0.[Posted No_]) AS [MinDiPosted No_]
FROM FattureTemporaneeEDdtStep0
GROUP BY FattureTemporaneeEDdtStep0.No_
ORDER BY Count(FattureTemporaneeEDdtStep0.[DDT No_]), Min(FattureTemporaneeEDdtStep0.[Posted No_]);

GO

-- [622] FattureTemporaneeEDdtStep0
SELECT [Sales Header].No_, [Sales Shipment Header].[DDT No_], [Sales Shipment Header].[Posting Date], [DDT_Picking Header].[Posted Date], [DDT_Picking Header].[Posted No_]
FROM (([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN [Sales Shipment Header] ON [Sales Line].[Shipment No_] = [Sales Shipment Header].No_) INNER JOIN [DDT_Picking Header] ON [Sales Shipment Header].[DDT No_] = [DDT_Picking Header].No_
WHERE ((([Sales Line].Type)=2) AND (([Sales Header].[Document Type])=2))
GROUP BY [Sales Header].No_, [Sales Shipment Header].[DDT No_], [Sales Shipment Header].[Posting Date], [DDT_Picking Header].[Posted Date], [DDT_Picking Header].[Posted No_];

GO

-- [623] ForecastBudget
SELECT [Budget Header].No_, [Budget Line].[Source Type], [Budget Line].[Source No_], [Budget Header].Description, IIf(InStr([budget header.description],"SPORT")<>0,"SPORT",IIf(InStr([budget header.description],"MAIN")<>0,"MAIN","FULL")) AS BudgetType, [Budget Header].[Average Unit Price], [Budget Header].[Posting Date], [Budget Header].[Trademark Code], [Budget Header].[Selling Season Code], [Budget Header].[Budget Type], [Budget Header].[Budget Area], [Budget Header].[Geographical Zone Description], [Budget Header].[Salesperson Code], Salesperson_Purchaser.Name AS SalesPersonName, Val([budget header.Budget Quantity]) AS TotalBudgetQuantity, Val([budget header.Budget Amount]) AS TotalBudgetAmount, Val([Area Manager Qty]) AS CorrectedQty, Val([Area Manager Amount]) AS CorrectedAmount, [Budget Header].[Area Manager Note], [Budget Header].[Geographical Zone], [Budget Header].[Last Date Modified Actual], [Budget Header].[Last Date Modified Forecast], [Budget Line].[Source No_] AS CustomerCode, Customer.Name AS CustomerName, Customer.[Geographical Zone] AS CustomerGeorgraficalZone, [Geographical Zone].Description AS CustomerGeorgraficalZoneDescription, Customer.[Geographical Zone 2] AS CustomerGeorgraficalZone2, [Geographical Zone_1].Description AS CustomerGeorgraficalZone2Description, [Budget Line].City, Customer.[Current Risk], Customer.[Authorized Stores Number], Val([Budget Line Quantity]) AS LineBudgetQty, Val([Budget Line Amount]) AS LineBudgetAmount, Val([Revisited Quantity]) AS LineRevisedBudgetQty, Val([Revisited Amount]) AS LineRevisedBudtetAmount, Val([Curr_ Bdg_ Quantity]) AS CurrentBudgetQuanity, Val([Curr_ Bdg_ Amount]) AS CurrentBudgetAmount, Val([Previous Season Quantity]) AS PreviousSeasonQty, Val([Previous Season Amount]) AS PreviousSeasonAmount, Val([Previous Corr_ Season Quantity]) AS PreviousCorrSeasonQty, Val([Previous Corr_ Season Amount]) AS PreviousCorrSeasonAmount, Val([Budget Actual Quantity]) AS ActualQty, Val([Budget Actual Amount]) AS ActualAmount, [No Buy Reason Code].Description AS NoBuyReaon, Val([Forecast Quantity]) AS ForecastQty, Val([Forecast Amount]) AS ForecastAmount, IIf([Line Status]=0,"",IIf([Line Status]=1,"LFL",IIf([Line Status]=2,"LOST",IIf([Line Status]=3,"OPEN",IIf([Line Status]=4,"NEW",IIf([Line Status]=5,"???",IIf([Line Status]=6,"UNACHIEVED",IIf([line status]=7,"LFL_UP",IIf([line status]=8,"LFL_DOWN","unk"))))))))) AS BudgetLineStatus, Val([Adjustment Forecast Qty_]) AS AdjustedForecastQuantity, Val([Adjustment Forecast Amt_]) AS AdjustedForecastAmount, [Budget Line].Note
FROM ((((([Budget Line] LEFT JOIN [Budget Header] ON [Budget Line].[Budget No_] = [Budget Header].No_) LEFT JOIN Customer ON [Budget Line].[Source No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Budget Header].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN [No Buy Reason Code] ON [Budget Line].[No Buy Reason Code] = [No Buy Reason Code].Code) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].[CODE]) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].[CODE];

GO

-- [624] ForecastBudgetApeE17
SELECT ForecastBudget.No_, ForecastBudget.Description, ForecastBudget.BudgetType, ForecastBudget.[Average Unit Price], ForecastBudget.[Posting Date], ForecastBudget.[Trademark Code], ForecastBudget.[Sales Season Code], ForecastBudget.[Salesperson Code], ForecastBudget.SalesPersonName, ForecastBudget.[Geographical Zone], ForecastBudget.CustomerCode, ForecastBudget.CustomerName, ForecastBudget.CustomerGeorgraficalZone, ForecastBudget.CustomerGeorgraficalZoneDescription, ForecastBudget.CustomerGeorgraficalZone2, ForecastBudget.CustomerGeorgraficalZone2Description, ForecastBudget.City, ForecastBudget.[Current Risk], ForecastBudget.[Authorized Stores Number], IIf([budgettype]="MAIN",[linebudgetqty],[actualqty]) AS NewLineBudgetQty, IIf([budgettype]="MAIN",[linebudgetamount],[actualamount]) AS NewLineBudgetAmount, IIf([budgettype]="MAIN",[linebudgetqty],[actualqty]) AS NewLineRevisedBudgetQty, IIf([budgettype]="MAIN",[linebudgetamount],[actualamount]) AS NewLineRevisedBudgetAmount, IIf([budgettype]="MAIN",[linebudgetqty],[actualqty]) AS NewCurrentBudgetQty, IIf([budgettype]="MAIN",[linebudgetamount],[actualamount]) AS NewCurrentBudgetAmount, IIf([budgettype]="MAIN",[previouscorrseasonqty],0) AS NewPreviousCorrSeasonQty, IIf([budgettype]="MAIN",[previousCorrseasonamount],0) AS NewPreviousCorrSeasonAmount, ForecastBudget.ActualQty, ForecastBudget.ActualAmount, ForecastBudget.NoBuyReaon, IIf([budgettype]="MAIN",[forecastqty],[actualqty]) AS NewForecastQty, IIf([budgettype]="MAIN",[forecastamount],[actualamount]) AS NewForecastAmount, ForecastBudget.BudgetLineStatus, IIf([budgettype]="MAIN",[forecastqty],[actualqty]) AS NewAdjustedForecastQty, IIf([budgettype]="MAIN",[forecastamount],[actualamount]) AS NewAdjustedForecastAmount, ForecastBudget.[Appointment Date], ForecastBudget.Note
FROM ForecastBudget
WHERE (((ForecastBudget.[Trademark Code])="AP") AND ((ForecastBudget.[Sales Season Code])="E17"));

GO

-- [625] ForecastBudgetApeE17-Globale
SELECT ForecastBudgetApeE17.[Trademark Code], ForecastBudgetApeE17.[Sales Season Code], ForecastBudgetApeE17.[Salesperson Code], ForecastBudgetApeE17.SalesPersonName, ForecastBudgetApeE17.[Geographical Zone], ForecastBudgetApeE17.CustomerCode, ForecastBudgetApeE17.CustomerName, ForecastBudgetApeE17.CustomerGeorgraficalZone, ForecastBudgetApeE17.CustomerGeorgraficalZoneDescription, ForecastBudgetApeE17.CustomerGeorgraficalZone2, ForecastBudgetApeE17.CustomerGeorgraficalZone2Description, ForecastBudgetApeE17.City, ForecastBudgetApeE17.[Current Risk], ForecastBudgetApeE17.[Authorized Stores Number], Sum(ForecastBudgetApeE17.NewLineBudgetQty) AS NewLineBudgetQty, ForecastBudgetApeE17.NewLineBudgetAmount AS NewLineBudgetAmount, ForecastBudgetApeE17.NewLineRevisedBudgetQty AS NewLineRevisedBudgetQty, ForecastBudgetApeE17.NewLineRevisedBudgetAmount AS NewLineRevisedBudgetAmount, ForecastBudgetApeE17.NewCurrentBudgetQty AS NewCurrentBudgetQty, ForecastBudgetApeE17.NewPreviousCorrSeasonQty AS NewPreviousCorrSeasonQty, ForecastBudgetApeE17.NewPreviousCorrSeasonAmount AS NewPreviousCorrSeasonAmount, ForecastBudgetApeE17.ActualQty AS ActualQty, ForecastBudgetApeE17.ActualAmount AS ActualAmount, ForecastBudgetApeE17.NewForecastQty AS NewForecastQty, ForecastBudgetApeE17.NewForecastAmount AS NewForecastAmount, ForecastBudgetApeE17.NewAdjustedForecastQty AS NewAdjustedForecastQty, ForecastBudgetApeE17.NewAdjustedForecastAmount AS NewAdjustedForecastAmount, Min(ForecastBudgetApeE17.BudgetLineStatus) AS BudgetLineStatus, Max(ForecastBudgetApeE17.NoBuyReaon) AS NoBuyReaon
FROM ForecastBudgetApeE17
GROUP BY ForecastBudgetApeE17.[Trademark Code], ForecastBudgetApeE17.[Sales Season Code], ForecastBudgetApeE17.[Salesperson Code], ForecastBudgetApeE17.SalesPersonName, ForecastBudgetApeE17.[Geographical Zone], ForecastBudgetApeE17.CustomerCode, ForecastBudgetApeE17.CustomerName, ForecastBudgetApeE17.CustomerGeorgraficalZone, ForecastBudgetApeE17.CustomerGeorgraficalZoneDescription, ForecastBudgetApeE17.CustomerGeorgraficalZone2, ForecastBudgetApeE17.CustomerGeorgraficalZone2Description, ForecastBudgetApeE17.City, ForecastBudgetApeE17.[Current Risk], ForecastBudgetApeE17.[Authorized Stores Number], ForecastBudgetApeE17.NewLineBudgetAmount, ForecastBudgetApeE17.NewLineRevisedBudgetQty, ForecastBudgetApeE17.NewLineRevisedBudgetAmount, ForecastBudgetApeE17.NewCurrentBudgetQty, ForecastBudgetApeE17.NewPreviousCorrSeasonQty, ForecastBudgetApeE17.NewPreviousCorrSeasonAmount, ForecastBudgetApeE17.ActualQty, ForecastBudgetApeE17.ActualAmount, ForecastBudgetApeE17.NewForecastQty, ForecastBudgetApeE17.NewForecastAmount, ForecastBudgetApeE17.NewAdjustedForecastQty, ForecastBudgetApeE17.NewAdjustedForecastAmount;

GO

