-- [628] ForecastBudget-PerEstrazione-step0
SELECT ForecastBudget.No_, ForecastBudget.Description, ForecastBudget.BudgetType AS BudgetType_old, ForecastBudget.[Budget Type], ForecastBudget.[Budget Area], ForecastBudget.[Geographical Zone Description], ForecastBudget.[Average Unit Price], ForecastBudget.[Posting Date], ForecastBudget.[Trademark Code], ForecastBudget.[Selling Season Code] AS [Season Code], ForecastBudget.[Salesperson Code], ForecastBudget.SalesPersonName, ForecastBudget.TotalBudgetQuantity, ForecastBudget.TotalBudgetAmount, ForecastBudget.CorrectedQty, ForecastBudget.CorrectedAmount, ForecastBudget.[Area Manager Note], ForecastBudget.[Geographical Zone], ForecastBudget.[Last Date Modified Actual], ForecastBudget.[Last Date Modified Forecast], ForecastBudget.CustomerCode, ForecastBudget.CustomerName, ForecastBudget.CustomerGeorgraficalZone, ForecastBudget.CustomerGeorgraficalZoneDescription, ForecastBudget.CustomerGeorgraficalZone2, ForecastBudget.CustomerGeorgraficalZone2Description, ForecastBudget.City, ForecastBudget.[Current Risk], ForecastBudget.[Authorized Stores Number], ForecastBudget.LineBudgetQty, ForecastBudget.LineBudgetAmount, ForecastBudget.LineRevisedBudgetQty, ForecastBudget.LineRevisedBudtetAmount, ForecastBudget.CurrentBudgetQuanity, ForecastBudget.CurrentBudgetAmount, ForecastBudget.PreviousSeasonQty, ForecastBudget.PreviousSeasonAmount, ForecastBudget.PreviousCorrSeasonQty, ForecastBudget.PreviousCorrSeasonAmount, ForecastBudget.ActualQty, ForecastBudget.ActualAmount, ForecastBudget.NoBuyReaon, ForecastBudget.ForecastQty, ForecastBudget.ForecastAmount, ForecastBudget.BudgetLineStatus, ForecastBudget.AdjustedForecastQuantity, ForecastBudget.AdjustedForecastAmount, [ForecastBudget-Appuntamenti].Appuntamento AS [Appointment Date], ForecastBudget.Note
FROM ForecastBudget LEFT JOIN [ForecastBudget-Appuntamenti] ON (ForecastBudget.[Source No_] = [ForecastBudget-Appuntamenti].[Source No_]) AND (ForecastBudget.[Source Type] = [ForecastBudget-Appuntamenti].[Source Type]) AND (ForecastBudget.No_ = [ForecastBudget-Appuntamenti].[Budget No_])
ORDER BY ForecastBudget.No_;

GO

-- [629] GestioneDisponibilitPreRun_01_Acquisti
SELECT [Purchase Line].No_, [Purchase Line].[constant variable code], [Purchase Line].[assortment code], Sum(Val([quantity])) AS buy_qty
FROM [Purchase Line] INNER JOIN [Purchase Header] ON ([Purchase Line].[Document No_] = [Purchase Header].No_) AND ([Purchase Line].[Document Type] = [Purchase Header].[Document Type])
WHERE ((([Purchase Line].[Document No_])="ODA-25-00040" Or ([Purchase Line].[Document No_])="ODA-25-00041" Or ([Purchase Line].[Document No_])="ODA-25-00042" Or ([Purchase Line].[Document No_])="ODA-25-00043") AND (([Purchase Line].Type)=20) AND (([Purchase Line].[DELETE REASON])=""))
GROUP BY [Purchase Line].No_, [Purchase Line].[constant variable code], [Purchase Line].[assortment code]
HAVING ((([Purchase Line].[assortment code])="BM01" Or ([Purchase Line].[assortment code])="BM04" Or ([Purchase Line].[assortment code])="BM05" Or ([Purchase Line].[assortment code])="BM06" Or ([Purchase Line].[assortment code])="BM07" Or ([Purchase Line].[assortment code])="BM08" Or ([Purchase Line].[assortment code])="BW02" Or ([Purchase Line].[assortment code])="BW03" Or ([Purchase Line].[assortment code])="BW04" Or ([Purchase Line].[assortment code])="BW05" Or ([Purchase Line].[assortment code])="BW06" Or ([Purchase Line].[assortment code])="BW08"));

GO

-- [630] GestioneDisponibilitPreRun_02_Vendite
SELECT [Sales Line].No_, [Sales Line].[constant variable code], [Sales Line].[assortment code], Sum(Val([quantity])) AS sal_qty
FROM [Sales Line] INNER JOIN ([Sales Header] INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)
WHERE ((([Sales Header].[selling season code])="E26") AND (([Sales Line].type)=20) AND (([Sales Header].[fast shipping])=1) AND (([Sales Line].[DELETE REASON])=""))
GROUP BY [Sales Line].No_, [Sales Line].[constant variable code], [Sales Line].[assortment code];

GO

-- [631] GestioneDisponibilitPreRun_03_Final
SELECT GestioneDisponibilitPreRun_01_Acquisti.No_, GestioneDisponibilitPreRun_01_Acquisti.[constant variable code], GestioneDisponibilitPreRun_01_Acquisti.[assortment code], GestioneDisponibilitPreRun_01_Acquisti.buy_qty, GestioneDisponibilitPreRun_02_Vendite.sal_qty, [buy_qty]-Nz([sal_qty]) AS disp_qty, IIf([buy_qty]-Nz([sal_qty])>0,"","XXX") AS TST
FROM GestioneDisponibilitPreRun_02_Vendite RIGHT JOIN GestioneDisponibilitPreRun_01_Acquisti ON (GestioneDisponibilitPreRun_02_Vendite.[assortment code] = GestioneDisponibilitPreRun_01_Acquisti.[assortment code]) AND (GestioneDisponibilitPreRun_02_Vendite.[constant variable code] = GestioneDisponibilitPreRun_01_Acquisti.[constant variable code]) AND (GestioneDisponibilitPreRun_02_Vendite.No_ = GestioneDisponibilitPreRun_01_Acquisti.No_);

GO

-- [632] GestioneDisponibilitPreRun_03_Final_PerAgenti
SELECT GestioneDisponibilitPreRun_01_Acquisti.No_, GestioneDisponibilitPreRun_01_Acquisti.[constant variable code] AS Color, GestioneDisponibilitPreRun_01_Acquisti.[assortment code], [buy_qty]-Nz([sal_qty]) AS disp_qty
FROM GestioneDisponibilitPreRun_02_Vendite RIGHT JOIN GestioneDisponibilitPreRun_01_Acquisti ON (GestioneDisponibilitPreRun_02_Vendite.[assortment code] = GestioneDisponibilitPreRun_01_Acquisti.[assortment code]) AND (GestioneDisponibilitPreRun_02_Vendite.[constant variable code] = GestioneDisponibilitPreRun_01_Acquisti.[constant variable code]) AND (GestioneDisponibilitPreRun_02_Vendite.No_ = GestioneDisponibilitPreRun_01_Acquisti.No_)
WHERE (((IIf([buy_qty]-Nz([sal_qty])>0,"","XXX"))=""));

GO

-- [633] giac-01-AssortimentiInBolla-step01
SELECT [Item].*, [DDT_Picking Line].[Constant Variable Code], [DDT_Picking Line].[Assortment Code], [DDT_Picking Line].Quantity
FROM ([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON ([DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) AND ([DDT_Picking Header].[Document Type] = [DDT_Picking Line].[Document Type])) INNER JOIN Item ON [DDT_Picking Line].No_ = [Item].No_
WHERE ((([DDT_Picking Header].Status)=0 Or ([DDT_Picking Header].Status)=1) AND (([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Line].Type)=20));

GO

-- [634] giac-01-AssortimentiInBolla-step02
SELECT [giac-01-AssortimentiInBolla-step01].No_, [giac-01-AssortimentiInBolla-step01].[Constant Variable Code], [giac-01-AssortimentiInBolla-step01].[Assortment Code], Sum(Val([Quantity])) AS AssortimentiInBolla, [giac-01-AssortimentiInBolla-step01].[Constant Assortment Var_Grp_], [giac-01-AssortimentiInBolla-step01].[Assortment Variable Group]
FROM [giac-01-AssortimentiInBolla-step01]
GROUP BY [giac-01-AssortimentiInBolla-step01].No_, [giac-01-AssortimentiInBolla-step01].[Constant Variable Code], [giac-01-AssortimentiInBolla-step01].[Assortment Code], [giac-01-AssortimentiInBolla-step01].[Constant Assortment Var_Grp_], [giac-01-AssortimentiInBolla-step01].[Assortment Variable Group];

GO

-- [635] giac-02-AssortimentiInGiacenza-step01
SELECT [Assortment Ledger Entry].[Model Item No_], [Assortment Ledger Entry].[Constant Variable Code], [Assortment Ledger Entry].[Assortment Code], [Assortment Ledger Entry].Quantity, [Assortment Ledger Entry].[Constant Assortment Var_Grp_], [Assortment Ledger Entry].[Assortment Variable Group]
FROM [Assortment Ledger Entry];

GO

-- [636] giac-02-AssortimentiInGiacenza-step02
SELECT [giac-02-AssortimentiInGiacenza-step01].[Model Item No_], [giac-02-AssortimentiInGiacenza-step01].[Constant Variable Code], [giac-02-AssortimentiInGiacenza-step01].[Assortment Code], Sum(Val([Quantity])) AS AssortimentiInGiacenza, [giac-02-AssortimentiInGiacenza-step01].[Constant Assortment Var_Grp_], [giac-02-AssortimentiInGiacenza-step01].[Assortment Variable Group]
FROM [giac-02-AssortimentiInGiacenza-step01]
GROUP BY [giac-02-AssortimentiInGiacenza-step01].[Model Item No_], [giac-02-AssortimentiInGiacenza-step01].[Constant Variable Code], [giac-02-AssortimentiInGiacenza-step01].[Assortment Code], [giac-02-AssortimentiInGiacenza-step01].[Constant Assortment Var_Grp_], [giac-02-AssortimentiInGiacenza-step01].[Assortment Variable Group]
HAVING (((Sum(Val([Quantity])))>0));

GO

-- [637] giac-02-CalcoloPaiassortimenti
SELECT [Assortment Variable Group].[Assortment Code], [Assortment Variable Group].[Variable Group], Sum([Assortment Quantity].Quantity) AS PaiaPerAssortimento
FROM [Assortment Quantity] INNER JOIN [Assortment Variable Group] ON ([Assortment Quantity].[Variable Group] = [Assortment Variable Group].[Variable Group]) AND ([Assortment Quantity].[Assortment Code] = [Assortment Variable Group].[Assortment Code])
GROUP BY [Assortment Variable Group].[Assortment Code], [Assortment Variable Group].[Variable Group];

GO

-- [638] giac-03
SELECT [giac-02-AssortimentiInGiacenza-step02].[Model Item No_] AS Article, [giac-02-AssortimentiInGiacenza-step02].[Constant Variable Code] AS Color, [giac-02-AssortimentiInGiacenza-step02].[Assortment Code] AS Assortment, [giac-02-AssortimentiInGiacenza-step02].AssortimentiInGiacenza, [giac-01-AssortimentiInBolla-step02].AssortimentiInBolla, [AssortimentiInGiacenza]-nz([AssortimentiInBolla]) AS AssortimentiLiberi, [Variable Code].Description AS ColorDescription, [AssortimentiInGiacenza]*[PaiaPerAssortimento] AS PaiaiInGiacenza, [AssortimentiInBolla]*[PaiaPerAssortimento] AS PaiaInBolla, [AssortimentiLiberi]*[PaiaPerAssortimento] AS PaiaLibere
FROM (([giac-01-AssortimentiInBolla-step02] RIGHT JOIN [giac-02-AssortimentiInGiacenza-step02] ON ([giac-01-AssortimentiInBolla-step02].[Constant Variable Code] = [giac-02-AssortimentiInGiacenza-step02].[Constant Variable Code]) AND ([giac-01-AssortimentiInBolla-step02].[Assortment Code] = [giac-02-AssortimentiInGiacenza-step02].[Assortment Code]) AND ([giac-01-AssortimentiInBolla-step02].No_ = [giac-02-AssortimentiInGiacenza-step02].[Model Item No_])) LEFT JOIN [Variable Code] ON ([giac-02-AssortimentiInGiacenza-step02].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([giac-02-AssortimentiInGiacenza-step02].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])) LEFT JOIN [giac-02-CalcoloPaiassortimenti] ON ([giac-02-AssortimentiInGiacenza-step02].[Assortment Code] = [giac-02-CalcoloPaiassortimenti].[Assortment Code]) AND ([giac-02-AssortimentiInGiacenza-step02].[Assortment Variable Group] = [giac-02-CalcoloPaiassortimenti].[Variable Group]);

GO

-- [639] giac-04-giacenzaAssortimentiLibera
SELECT [giac-03].Article, [giac-03].Color, [giac-03].Assortment, [giac-03].AssortimentiInGiacenza, [giac-03].AssortimentiInBolla, [giac-03].AssortimentiLiberi, [giac-03].ColorDescription, [giac-03].PaiaiInGiacenza, [giac-03].PaiaInBolla, [giac-03].PaiaLibere, [Item].[Trademark Code], [Item].[Collection Code], [Item].[Season Code], [Item].[Line Code], [Item].[Season Typology], [Item].[Product Family], [Item].[Product Sex], [Item].[Shipment Priority], [Item].[Innovation Degree], [Item].[Heel Height], [Item].[End Customer Price Gap], [Item].[Market Segment], [Item].[Product Typology], [Item].[Main Material], [Item].[Sole Material]
FROM [giac-03] INNER JOIN Item ON [giac-03].Article = [Item].No_;

GO

-- [640] giacenza collocazioni
SELECT [Warehouse Entry].[Location Code], [Warehouse Entry].[Bin Code], Item.[model item no_], Item.[variable code 01], Item.[variable code 02], Sum(Val([quantity])) AS qty
FROM [Warehouse Entry] INNER JOIN Item ON [Warehouse Entry].[Item No_] = Item.No_
GROUP BY [Warehouse Entry].[Location Code], [Warehouse Entry].[Bin Code], Item.[model item no_], Item.[variable code 01], Item.[variable code 02]
HAVING (((Sum(Val([quantity])))>0));

GO

-- [641] GiacenzaAssortimenti
SELECT Item.[Trademark Code] AS Marchio_, Item.[Season Code] AS Stagione_, [Assortment Ledger Entry].[Model Item No_] AS Articolo, [Assortment Ledger Entry].[Constant Variable Code] AS Colore_, [Assortment Ledger Entry].[Assortment Code] AS assortimento, Sum(Val([Quantity])) AS qty, Sum([AssortmentQuantity]*Val([quantity])) AS pairs, [Assortment Ledger Entry].[Location Code] AS Location_
FROM ([Assortment Ledger Entry] INNER JOIN Item ON [Assortment Ledger Entry].[Model Item No_] = Item.No_) INNER JOIN AssortimentiQuantita ON ([Assortment Ledger Entry].[Assortment Code] = AssortimentiQuantita.[Assortment Code]) AND ([Assortment Ledger Entry].[Assortment Variable Group] = AssortimentiQuantita.[Variable Group])
GROUP BY Item.[Trademark Code], Item.[Season Code], [Assortment Ledger Entry].[Model Item No_], [Assortment Ledger Entry].[Constant Variable Code], [Assortment Ledger Entry].[Assortment Code], [Assortment Ledger Entry].[Location Code]
HAVING (((Sum(Val([Quantity])))<>0));

GO

-- [642] GiacenzaAssortimenti_ORIG
SELECT Item.[Trademark Code] AS Marchio_, Item.[Season Code] AS Stagione_, [Assortment Ledger Entry].[Model Item No_] AS Articolo, [Assortment Ledger Entry].[Constant Variable Code] AS Colore_, [Assortment Ledger Entry].[Assortment Code] AS assortimento, Sum(Val([Quantity])) AS qty, Sum([AssortmentQuantity]*Val([quantity])) AS pairs, [Assortment Ledger Entry].[Location Code] AS Location_
FROM ([Assortment Ledger Entry] INNER JOIN Item ON [Assortment Ledger Entry].[Model Item No_] = Item.No_) INNER JOIN AssortimentiQuantita ON ([Assortment Ledger Entry].[Assortment Code] = AssortimentiQuantita.[Assortment Code]) AND ([Assortment Ledger Entry].[Assortment Variable Group] = AssortimentiQuantita.[Variable Group])
GROUP BY Item.[Trademark Code], Item.[Season Code], [Assortment Ledger Entry].[Model Item No_], [Assortment Ledger Entry].[Constant Variable Code], [Assortment Ledger Entry].[Assortment Code], [Assortment Ledger Entry].[Location Code]
HAVING (((Item.[Trademark Code])=[FiltroMarchio]) AND ((Item.[Season Code])=[FiltroStagione]) AND ((Sum(Val([Quantity])))<>0));

GO

-- [643] GiacenzaLiberaVeloce
SELECT [GiacenzaLiberaVeloce-preExport].[Trademark code], [GiacenzaLiberaVeloce-preExport].[Season code], [GiacenzaLiberaVeloce-preExport].[Item No_], [GiacenzaLiberaVeloce-preExport].[Location Code], [GiacenzaLiberaVeloce-preExport].[model item no_], [GiacenzaLiberaVeloce-preExport].color, [GiacenzaLiberaVeloce-preExport].size, [GiacenzaLiberaVeloce-preExport].EAN, [GiacenzaLiberaVeloce-preExport].CAT_1, [GiacenzaLiberaVeloce-preExport].CAT_2, Sum(IIf([CAT_1]="GIAC",[QTY],0)) AS qGiac, Sum(IIf([CAT_1]="BOLLA",[QTY],0)) AS qBOLLA, Sum(IIf([CAT_1]="GIAC" Or [cat_1]="BOLLA",[QTY],0)) AS qGiacLibera
FROM [GiacenzaLiberaVeloce-preExport]
GROUP BY [GiacenzaLiberaVeloce-preExport].[Trademark code], [GiacenzaLiberaVeloce-preExport].[Season code], [GiacenzaLiberaVeloce-preExport].[Item No_], [GiacenzaLiberaVeloce-preExport].[Location Code], [GiacenzaLiberaVeloce-preExport].[model item no_], [GiacenzaLiberaVeloce-preExport].color, [GiacenzaLiberaVeloce-preExport].size, [GiacenzaLiberaVeloce-preExport].EAN, [GiacenzaLiberaVeloce-preExport].CAT_1, [GiacenzaLiberaVeloce-preExport].CAT_2
HAVING ((([GiacenzaLiberaVeloce-preExport].CAT_1)="GIAC" Or ([GiacenzaLiberaVeloce-preExport].CAT_1)="BOLLA"));

GO

-- [644] GiacenzaLiberaVeloce_step0_GiacenzaTotale
SELECT [Item Ledger Entry].[Item No_], [Item Ledger Entry].[Location Code], Sum(Val([quantity])) AS qty, Item.[Trademark code], Item.[Season code], "GIAC_TOT" AS CAT_1, "" AS CAT_2
FROM [Item Ledger Entry] INNER JOIN Item ON [Item Ledger Entry].[Item No_] = Item.No_
GROUP BY [Item Ledger Entry].[Item No_], [Item Ledger Entry].[Location Code], Item.[Trademark code], Item.[Season code], "GIAC_TOT", ""
HAVING (((Sum(Val([quantity])))>0) AND ((Item.[Trademark code])=[Forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[Season code])=[Forms]![principale]![FiltroStagioneSourcing]));

GO

-- [645] GiacenzaLiberaVeloce_step1_GiacenzaAssortita
SELECT [Assortment Ledger Entry Item].[Location Code], [Assortment Ledger Entry Item].[Item No_], Sum(Val([quantity])) AS qty, Item.[trademark code], [Assortment Ledger Entry Item].[season code], "GIAC" AS CAT_1, "ASSORTITO" AS CAT_2
FROM [Assortment Ledger Entry Item] INNER JOIN Item ON [Assortment Ledger Entry Item].[Item No_] = Item.No_
GROUP BY [Assortment Ledger Entry Item].[Location Code], [Assortment Ledger Entry Item].[Item No_], Item.[trademark code], [Assortment Ledger Entry Item].[season code], "GIAC", "ASSORTITO"
HAVING (((Sum(Val([quantity])))>0) AND ((Item.[trademark code])=[Forms]![principale]![FiltroMarchioSourcing]) AND (([Assortment Ledger Entry Item].[season code])=[Forms]![principale]![FiltroStagioneSourcing]));

GO

-- [646] GiacenzaLiberaVeloce_step1a_GiacenzaSfusa
SELECT GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Item No_], GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Location Code], GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Trademark code], GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Season code], "GIAC" AS CAT_1, IIf(IsNull([GiacenzaLiberaVeloce_step1_GiacenzaAssortita.location code])=True,[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty],[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty]-[GiacenzaLiberaVeloce_step1_GiacenzaAssortita].[qty]) AS qty, "SFUSO" AS CAT_2
FROM GiacenzaLiberaVeloce_step0_GiacenzaTotale LEFT JOIN GiacenzaLiberaVeloce_step1_GiacenzaAssortita ON (GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Location Code] = GiacenzaLiberaVeloce_step1_GiacenzaAssortita.[Location Code]) AND (GiacenzaLiberaVeloce_step0_GiacenzaTotale.[Item No_] = GiacenzaLiberaVeloce_step1_GiacenzaAssortita.[Item No_])
WHERE (((IIf(IsNull([GiacenzaLiberaVeloce_step1_GiacenzaAssortita.location code])=True,[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty],[GiacenzaLiberaVeloce_step0_GiacenzaTotale].[qty]-[GiacenzaLiberaVeloce_step1_GiacenzaAssortita].[qty]))>0));

GO

-- [647] GiacenzaLiberaVeloce_step2_bolla
SELECT [DDT_Picking Header].status, [DDT_Picking Line].No_, [DDT_Picking Line].Type, [DDT_Picking Line].[Location Code], Val([DDT_Picking Line].[Quantity]) AS qty, Item.[trademark code], Item.[season code], IIf([DDT_Picking Line_1.Type]=20,"ASSORTITO","SFUSO") AS CAT_2, "BOLLA" AS CAT_1, [DDT_Picking Header].[Document Type], [DDT_Picking Line_1].Type
FROM (([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON [DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) INNER JOIN [DDT_Picking Line] AS [DDT_Picking Line_1] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Line_1].[Document No_]) AND ([DDT_Picking Line].[Document Type] = [DDT_Picking Line_1].[Document Type]) AND ([DDT_Picking Line].[Original Line No_] = [DDT_Picking Line_1].[Line No_])
WHERE ((([DDT_Picking Header].status)<>20) AND (([DDT_Picking Line].Type)=2) AND ((Item.[trademark code])=[Forms]![principale]![FiltroMarchioSourcing]) AND ((Item.[season code])=[Forms]![principale]![FiltroStagioneSourcing]) AND (([DDT_Picking Header].[Document Type])=0));

GO

-- [648] GiacenzaLiberaVeloce_step3_prenotazioni
SELECT Item.No_, [Reserv__Assign_ Link].[Location Code], Item.[season code], [Reserv__Assign_ Link].[Source Type], "PREN" AS CAT_1, Val([Reserv__Assign_ Link.reserved_assigned quantity]) AS qty, [Reserv__Assign_ Link].[Reserv__Assign_ Type], Item.[trademark code], [Sales Line_1].Type, [Reserv__Assign_ Link].Type, [Reserv__Assign_ Link].[Batch Name], IIf([sALES Line_1.Type]=20,"ASSORTITO","SFUSO") AS CAT_2
FROM ((Item INNER JOIN [Reserv__Assign_ Link] ON Item.No_ = [Reserv__Assign_ Link].No_) INNER JOIN [Sales Line] ON ([Reserv__Assign_ Link].[Sales Line No_] = [Sales Line].[Line No_]) AND ([Reserv__Assign_ Link].[Sales Document No_] = [Sales Line].[Document No_])) INNER JOIN [Sales Line] AS [Sales Line_1] ON ([Sales Line].[Original Line No_] = [Sales Line_1].[Line No_]) AND ([Sales Line].[Document No_] = [Sales Line_1].[Document No_])
GROUP BY Item.No_, [Reserv__Assign_ Link].[Location Code], Item.[season code], [Reserv__Assign_ Link].[Source Type], "PREN", Val([Reserv__Assign_ Link.reserved_assigned quantity]), [Reserv__Assign_ Link].[Reserv__Assign_ Type], Item.[trademark code], [Sales Line_1].Type, [Reserv__Assign_ Link].Type, [Reserv__Assign_ Link].[Batch Name], IIf([sALES Line_1.Type]=20,"ASSORTITO","SFUSO")
HAVING (((Item.[season code])=[Forms]![principale]![FiltroStagioneSourcing]) AND (([Reserv__Assign_ Link].[Source Type])=0) AND ((Val([Reserv__Assign_ Link.reserved_assigned quantity]))>0) AND (([Reserv__Assign_ Link].[Reserv__Assign_ Type])=1) AND ((Item.[trademark code])=[Forms]![principale]![FiltroMarchioSourcing]) AND (([Reserv__Assign_ Link].Type)=2));

GO

-- [649] GiacenzaLiberaVeloce_step4_union
SELECT CAT_1, CAT_2, [Trademark code], [Season code], [Item No_], [Location Code], qty
FROM GiacenzaLiberaVeloce_step0_GiacenzaTotale;

UNION ALL SELECT CAT_1, CAT_2, [Trademark code], [Season code], [Item No_], [Location Code], qty
FROM GiacenzaLiberaVeloce_step1_GiacenzaAssortita;

UNION ALL SELECT CAT_1, CAT_2, [Trademark code], [Season code], [Item No_], [Location Code], qty
FROM GiacenzaLiberaVeloce_step1a_GiacenzaSfusa;

UNION ALL SELECT CAT_1, CAT_2, [Trademark code], [Season code], [No_], [Location Code], -qty
FROM GiacenzaLiberaVeloce_step2_bolla;

GO

-- [650] GiacenzaLiberaVeloce-preExport
SELECT GiacenzaLiberaVeloce_step4_union.*, Item.[model item no_], Item.[variable code 01] AS color, Item.[variable code 02] AS [size], EANCodes.[Cross-Reference No_] AS EAN
FROM (GiacenzaLiberaVeloce_step4_union INNER JOIN Item ON GiacenzaLiberaVeloce_step4_union.[Item No_] = Item.No_) LEFT JOIN EANCodes ON Item.No_ = EANCodes.[Item No_];

GO

-- [651] GraficoMiglioriArticoliVenduti
SELECT [GraficoMiglioriArticoliVenduti-step0].*, [DatiCarryOverESMU-Completi].[Carry Over], Immagini.[Linked Document], Immagini_mediaRis.[Linked Document] AS LinkedDocumentMediaRis, [GraficoMiglioriArticoliVenduti-step1].PaiaPerLinea, [GraficoMiglioriArticoliVenduti-step2].PaiaPerArticolo, ListinoVenditaWholesaleRaggruppato.ListinoWholesale, ListinoVenditaRetailRaggruppato.ListinoRetail
FROM (((((([GraficoMiglioriArticoliVenduti-step0] LEFT JOIN Immagini ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = Immagini.[Constant Variable Code]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = Immagini.[Source No_])) LEFT JOIN [GraficoMiglioriArticoliVenduti-step1] ON ([GraficoMiglioriArticoliVenduti-step0].VendorName = [GraficoMiglioriArticoliVenduti-step1].VendorName) AND ([GraficoMiglioriArticoliVenduti-step0].Linea = [GraficoMiglioriArticoliVenduti-step1].Linea)) LEFT JOIN [GraficoMiglioriArticoliVenduti-step2] ON [GraficoMiglioriArticoliVenduti-step0].Articolo = [GraficoMiglioriArticoliVenduti-step2].Articolo) LEFT JOIN ListinoVenditaRetailRaggruppato ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = ListinoVenditaRetailRaggruppato.[variable code 01]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = ListinoVenditaRetailRaggruppato.[model item no_])) LEFT JOIN ListinoVenditaWholesaleRaggruppato ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = ListinoVenditaWholesaleRaggruppato.[variable code 01]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = ListinoVenditaWholesaleRaggruppato.[model item no_])) LEFT JOIN [DatiCarryOverESMU-Completi] ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = [DatiCarryOverESMU-Completi].[Variable Code 01]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = [DatiCarryOverESMU-Completi].[Model Item No_])) LEFT JOIN Immagini_mediaRis ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = Immagini_mediaRis.[Constant Variable Code]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = Immagini_mediaRis.[Source No_])
WHERE ((([GraficoMiglioriArticoliVenduti-step0].PaiaConfermate)<>0));

GO

-- [652] GraficoMiglioriArticoliVendutiEstrazione
SELECT [GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code] AS Marchio, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code] AS Stagione, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Line Code] AS Linea, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_] AS Articolo, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01] AS CodiceColore, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status - Item] AS StatusArticolo, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status Date], [GraficoMiglioriArticoliVendutiEstrazione-step0].[Delete Reason] AS DeleteReasonVendite, Sum(Val(Nz([no_ of pairs]))) AS Paia, [GraficoMiglioriArticoliVendutiEstrazione-step1].Description AS Descrizione, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Description 2] AS Descrizione2, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Family] AS FamigliaProdotto, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Sex] AS GenereProdotto, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Collection Code] AS [Collection Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Vendor No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].VendorName, [GraficoMiglioriArticoliVendutiEstrazione-step1].Manufacturer, [GraficoMiglioriArticoliVendutiEstrazione-step1].ManufacturerName, [GraficoMiglioriArticoliVendutiEstrazione-step1].[advertising material], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Currency Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Country_Region of Origin Code] AS Espr1
FROM [GraficoMiglioriArticoliVendutiEstrazione-step1] LEFT JOIN [GraficoMiglioriArticoliVendutiEstrazione-step0] ON ([GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01] = [GraficoMiglioriArticoliVendutiEstrazione-step0].[Constant Variable Code]) AND ([GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_] = [GraficoMiglioriArticoliVendutiEstrazione-step0].No_)
GROUP BY [GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Line Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status - Item], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status Date], [GraficoMiglioriArticoliVendutiEstrazione-step0].[Delete Reason], [GraficoMiglioriArticoliVendutiEstrazione-step1].Description, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Description 2], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Family], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Sex], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Collection Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Vendor No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].VendorName, [GraficoMiglioriArticoliVendutiEstrazione-step1].Manufacturer, [GraficoMiglioriArticoliVendutiEstrazione-step1].ManufacturerName, [GraficoMiglioriArticoliVendutiEstrazione-step1].[advertising material], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Currency Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Country_Region of Origin Code]
HAVING ((([GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code])=[Maschere]![principale]![filtroStagione]))
ORDER BY [GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Line Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01];

GO

-- [653] GraficoMiglioriArticoliVendutiEstrazione-step0
SELECT [Sales Line].*
FROM [Sales Line]
WHERE ((([Sales Line].Type)=19 Or ([Sales Line].Type)=20) AND (([Sales Line].[Document Type])=1));

GO

-- [654] GraficoMiglioriArticoliVendutiEstrazione-step1
SELECT Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Model Item No_], Item.[Variable Code 01], Item.[Configurator Relation], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Description 2], Item_1.Description, Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, Vendor.[Currency Code], Item.[Country_region of Origin Code], Item.[advertising material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((Item INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
GROUP BY Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Model Item No_], Item.[Variable Code 01], Item.[Configurator Relation], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Description 2], Item_1.Description, Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, Vendor.[Currency Code], Item.[Country_region of Origin Code], Item.[advertising material], Item.Manufacturer, Vendor_1.Name
HAVING (((Item.[Model Item No_]) Not Like "temp%") AND ((Item.[Configurator Relation])=3))
ORDER BY Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Model Item No_], Item.[Variable Code 01];

GO

-- [655] GraficoMiglioriArticoliVenduti-Fornitore
SELECT [GraficoMiglioriArticoliVenduti-step0].*, [DatiCarryOverESMU-Completi].[Carry Over], Immagini.[Linked Document], [GraficoMiglioriArticoliVenduti-step1].PaiaPerLinea, [GraficoMiglioriArticoliVenduti-step2].PaiaPerArticolo, ListinoVenditaWholesaleRaggruppato.ListinoWholesale, ListinoVenditaRetailRaggruppato.ListinoRetail
FROM ((((([GraficoMiglioriArticoliVenduti-step0] LEFT JOIN Immagini ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = Immagini.[Constant Variable Code]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = Immagini.[Source No_])) LEFT JOIN [GraficoMiglioriArticoliVenduti-step1] ON ([GraficoMiglioriArticoliVenduti-step0].VendorName = [GraficoMiglioriArticoliVenduti-step1].VendorName) AND ([GraficoMiglioriArticoliVenduti-step0].Linea = [GraficoMiglioriArticoliVenduti-step1].Linea)) LEFT JOIN [GraficoMiglioriArticoliVenduti-step2] ON [GraficoMiglioriArticoliVenduti-step0].Articolo = [GraficoMiglioriArticoliVenduti-step2].Articolo) LEFT JOIN ListinoVenditaWholesaleRaggruppato ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = ListinoVenditaWholesaleRaggruppato.[variable code 01]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = ListinoVenditaWholesaleRaggruppato.[model item no_])) LEFT JOIN ListinoVenditaRetailRaggruppato ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = ListinoVenditaRetailRaggruppato.[variable code 01]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = ListinoVenditaRetailRaggruppato.[model item no_])) LEFT JOIN [DatiCarryOverESMU-Completi] ON ([GraficoMiglioriArticoliVenduti-step0].CodiceColore = [DatiCarryOverESMU-Completi].[Variable Code 01]) AND ([GraficoMiglioriArticoliVenduti-step0].Articolo = [DatiCarryOverESMU-Completi].[Model Item No_])
WHERE ((([GraficoMiglioriArticoliVenduti-step0].[Vendor No_])=[Maschere]![principale]![filtroFornitore]) AND (([GraficoMiglioriArticoliVenduti-step0].PaiaConfermate)<>0));

GO

-- [656] GraficoMiglioriArticoliVenduti-step0
SELECT [Sales Line].[Document Type], Item.[Line Code] AS Linea, [Sales Line].No_ AS Articolo, [Sales Line].[Constant Variable Code] AS CodiceColore, [Variable Code].Description AS Colore, Item.[Trademark Code] AS Marchio, [Sales Header].[Selling Season Code] AS Stagione, Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) AS PaiaConfermateREAL, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, IIf([moltiplicatore]<>1,Round([PaiaconfermateREAL]*[MOLTIPLICATORE]/10,0)*10,[paiaconfermatereal]) AS PaiaConfermate, Vendor_1.No_ AS Manufacturer, Vendor_1.Name AS ManufacturerName
FROM (((([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE (((Item.[advertising material])=0))
GROUP BY [Sales Line].[Document Type], Item.[Line Code], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Variable Code].Description, Item.[Trademark Code], [Sales Header].[Selling Season Code], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, Vendor_1.No_, Vendor_1.Name
HAVING ((([Sales Line].[Document Type])=1) AND ((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([Sales Header].[Selling Season Code])=[Maschere]![principale]![filtroStagione]))
ORDER BY Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) DESC;

GO

-- [657] GraficoMiglioriArticoliVenduti-step0-SoloStagionaleEPronto
SELECT [Sales Line].[Document Type], Item.[Line Code] AS Linea, [Sales Line].No_ AS Articolo, [Sales Line].[Constant Variable Code] AS CodiceColore, [Variable Code].Description AS Colore, Item.[Trademark Code] AS Marchio, [Sales Header].[Selling Season Code] AS Stagione, Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) AS PaiaConfermateREAL, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, IIf([moltiplicatore]<>1,Round([PaiaconfermateREAL]*[MOLTIPLICATORE]/10,0)*10,[paiaconfermatereal]) AS PaiaConfermate, Vendor_1.No_ AS Manufacturer, Vendor_1.Name AS ManufacturerName
FROM (((([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE ((([Sales Header].[Order Type])=0 Or ([Sales Header].[Order Type])=2 Or ([Sales Header].[Order Type])=5) AND ((Item.[advertising material])=0))
GROUP BY [Sales Line].[Document Type], Item.[Line Code], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Variable Code].Description, Item.[Trademark Code], [Sales Header].[Selling Season Code], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, Vendor_1.No_, Vendor_1.Name
HAVING ((([Sales Line].[Document Type])=1) AND ((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([Sales Header].[Selling Season Code])=[Maschere]![principale]![filtroStagione]))
ORDER BY Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) DESC;

GO

-- [658] GraficoMiglioriArticoliVenduti-step0-SQL PER TOP40
SELECT TOP 40 Item.[Line Code] AS Linea, [Sales Line].No_ AS Articolo, [Sales Line].[Constant Variable Code] AS CodiceColore, [Variable Code].Description AS Colore, Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione, Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,Val([no_ of pairs]),0)) AS PaiaConfermate, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code]
FROM ([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])
GROUP BY Item.[Line Code], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Variable Code].Description, Item.[Trademark Code], Item.[Season Code], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code]
HAVING (((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND ((Item.[Season Code])=[Maschere]![principale]![filtroStagione]))
ORDER BY Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,Val([no_ of pairs]),0)) DESC;

GO

-- [659] GraficoMiglioriArticoliVenduti-step0-TuttiGliOrdini
SELECT [Sales Line].[Document Type], Item.[Line Code] AS Linea, [Sales Line].No_ AS Articolo, [Sales Line].[Constant Variable Code] AS CodiceColore, [Variable Code].Description AS Colore, Item.[Trademark Code] AS Marchio, [Sales Header].[Selling Season Code] AS Stagione, Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) AS PaiaConfermateREAL, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, IIf([moltiplicatore]<>1,Round([PaiaconfermateREAL]*[MOLTIPLICATORE]/10,0)*10,[paiaconfermatereal]) AS PaiaConfermate, Vendor_1.No_ AS Manufacturer, Vendor_1.Name AS ManufacturerName
FROM (((([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE (((Item.[advertising material])=0))
GROUP BY [Sales Line].[Document Type], Item.[Line Code], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Variable Code].Description, Item.[Trademark Code], [Sales Header].[Selling Season Code], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, Vendor_1.No_, Vendor_1.Name
HAVING ((([Sales Line].[Document Type])=1) AND ((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([Sales Header].[Selling Season Code])=[Maschere]![principale]![filtroStagione]))
ORDER BY Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) DESC;

GO

-- [660] GraficoMiglioriArticoliVenduti-step1
SELECT [GraficoMiglioriArticoliVenduti-step0].VendorName, [GraficoMiglioriArticoliVenduti-step0].Linea, Sum([GraficoMiglioriArticoliVenduti-step0].PaiaConfermate) AS PaiaPerLinea
FROM [GraficoMiglioriArticoliVenduti-step0]
GROUP BY [GraficoMiglioriArticoliVenduti-step0].VendorName, [GraficoMiglioriArticoliVenduti-step0].Linea;

GO

-- [661] GraficoMiglioriArticoliVenduti-step2
SELECT [GraficoMiglioriArticoliVenduti-step0].Articolo, Sum([GraficoMiglioriArticoliVenduti-step0].PaiaConfermate) AS PaiaPerArticolo
FROM [GraficoMiglioriArticoliVenduti-step0]
GROUP BY [GraficoMiglioriArticoliVenduti-step0].Articolo;

GO

-- [662] GraficoVenditePerAgente
SELECT [Item].[Trademark Code] AS Marchio, [Item].[Season Code] AS Stagione, [Salesperson_Purchaser].Name AS Agente, [Geographical Zone].Description AS ZonaGeografica, Sum(IIf([Sales Line.delete reason]='' Or IsNull([Sales Line.delete reason])=True,Val([no_ of pairs]),0)) AS PaiaConfermate
FROM (((([Sales Line] INNER JOIN Item ON [Sales Line].No_ = [Item].No_) INNER JOIN Customer ON [Sales Line].[Sell-to Customer No_] = [Customer].No_) INNER JOIN [Geographical Zone] ON [Customer].[Geographical Zone] = [Geographical Zone].[Geographical Zone]) INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) INNER JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = [Salesperson_Purchaser].Code
GROUP BY [Item].[Trademark Code], [Item].[Season Code], [Salesperson_Purchaser].Name, [Geographical Zone].Description, [Sales Line].[Document Type], [Sales Line].Type
HAVING ((([Item].[Trademark Code])=[parametroMarchio]) AND (([Item].[Season Code])=[parametroStagione]) AND (([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20))
ORDER BY Sum(IIf([Sales Line.delete reason]='' Or IsNull([Sales Line.delete reason])=True,Val([no_ of pairs]),0)) DESC;

GO

-- [663] GraficoVenditePerLinea
SELECT Item.[Line Code] AS Linea, Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione, Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,Val([no_ of pairs]),0)) AS PaiaConfermate
FROM [Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_
GROUP BY Item.[Line Code], Item.[Trademark Code], Item.[Season Code], [Sales Line].[Document Type], [Sales Line].Type
HAVING (((Item.[Trademark Code])=[parametroMarchio]) AND ((Item.[Season Code])=[parametroStagione]) AND (([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=19 Or ([Sales Line].Type)=20))
ORDER BY Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,Val([no_ of pairs]),0)) DESC;

GO

