-- [735] NavisionEAN-Cliente
SELECT [NavisionEan-step0].[Cross-Reference No_] AS EANCode, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCCode, Item.No_ AS Item, Item.[Model Item No_] AS Article, Item.[Description 2], Item.[Variable Code 01] AS Color, [Variable Code].Description AS ColorDesc, Item.[Variable Code 02] AS [Size], Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Sales_Purchase Status - Item], Sum(SalesLineTMP.qty) AS TotalQuantity, SalesLineTMP.[Customer NO_], First(SalesLineTMP.[Customer Name]) AS [Customer Name]
FROM ((SalesLineTMP LEFT JOIN (Item LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) ON SalesLineTMP.NO_ = Item.No_) LEFT JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN [NavisionEan-step0-UPC] ON Item.No_ = [NavisionEan-step0-UPC].[Item No_]
WHERE (((Item.[Advertising Material])=0) AND ((Item.[Configurator Relation])=3))
GROUP BY [NavisionEan-step0].[Cross-Reference No_], [NavisionEan-step0-UPC].[Cross-Reference No_], Item.No_, Item.[Model Item No_], Item.[Description 2], Item.[Variable Code 01], [Variable Code].Description, Item.[Variable Code 02], Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Sales_Purchase Status - Item], SalesLineTMP.[Customer NO_];

GO

-- [736] NavisionEAN-EtichetteFGF_SPD
SELECT [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_] AS EANCode, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCCode, Item.No_ AS Item, Item.[Model Item No_] AS Article, Item.[Variable Code 01] AS Color, Item.[Variable Code 02] AS [Size], Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [DDT_Picking Line].[Document No_], Sum(Val([quantity])) AS qty, Item.[Description 2], [Variable Code].Description AS ColorDescription, CrossReferenceFGF_PerEtichette.[Cross-Reference No_]
FROM ([DDT_Picking Header] LEFT JOIN ((((Item LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN [Variable Code] ON (Item.[Variable Group 01] = [Variable Code].[Variable Group]) AND (Item.[Variable Code 01] = [Variable Code].[Variable Code])) LEFT JOIN [NavisionEan-step0-UPC] ON Item.No_ = [NavisionEan-step0-UPC].[Item No_]) RIGHT JOIN [DDT_Picking Line] ON Item.No_ = [DDT_Picking Line].No_) ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]) LEFT JOIN CrossReferenceFGF_PerEtichette ON ([DDT_Picking Line].[Variable Code 01] = CrossReferenceFGF_PerEtichette.[Constant Variable Code]) AND ([DDT_Picking Line].[Model Item No_] = CrossReferenceFGF_PerEtichette.[Model Item No_])
GROUP BY [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_], [NavisionEan-step0-UPC].[Cross-Reference No_], Item.No_, Item.[Model Item No_], Item.[Variable Code 01], Item.[Variable Code 02], Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [DDT_Picking Line].[Document No_], Item.[Description 2], [Variable Code].Description, CrossReferenceFGF_PerEtichette.[Cross-Reference No_], [DDT_Picking Header].No_
