-- [752] NDCRegistrateEResi
SELECT [NDCRegistrateEResi-step0].No_, Sum(Val([Return Receipt Line.Quantity])) AS qtyShipped, Sum(IIf(IsNull([Sales Cr_Memo Line.document no_]),0,Val([Sales Cr_Memo Line.Quantity]))) AS qtyInvoiced, Sum(IIf(IsNull([sales cr_memo line.document no_]),0,Val([sales cr_memo line.Amount]))) AS Amount_, Sum(IIf(IsNull([sales cr_memo line.document no_]),0,Val([Sales cr_memo Line.Line Discount Amount]))) AS LineDiscountAmount, Sum(IIf(IsNull([sales cr_memo line.document no_]),0,Val([Sales cr_memo Line.Line Amount]))) AS LineAmount, Sum(IIf(IsNull([sales cr_memo line.document no_]),0,Val([Sales cr_memo Line.Inv_ Discount Amount]))) AS InvoiceDiscountAmountu, [NDCRegistrateEResi-step0].[Bill-to Customer No_], [NDCRegistrateEResi-step0].[Bill-to Name], [NDCRegistrateEResi-step0].[Posting Date] AS DataSpedzione, [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], IIf(IsNull([Sales Cr_Memo Header].[no_]),"",[Sales Cr_Memo Header].[No_]) AS CrMemoNo_, IIf(IsNull([Sales Cr_Memo Header].[no_]),"",[Sales Cr_Memo Header.Posting Date]) AS DataNDC, [Return Receipt Line].Type, [Geographical Zone].Description AS GeoZone1, [Geographical Zone_1].Description AS GeoZone2
FROM [NDCRegistrateEResi-step0] LEFT JOIN ((((([Sales Cr_Memo Line] LEFT JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_) RIGHT JOIN ([Return Receipt Line] LEFT JOIN [Sales Header] ON [Return Receipt Line].[Return Order No_] = [Sales Header].No_) ON ([Sales Cr_Memo Line].[Return Receipt Line No_] = [Return Receipt Line].[Line No_]) AND ([Sales Cr_Memo Line].[Return Receipt No_] = [Return Receipt Line].[Document No_])) LEFT JOIN Customer ON [Return Receipt Line].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code) ON [NDCRegistrateEResi-step0].No_ = [Return Receipt Line].[Document No_]
GROUP BY [NDCRegistrateEResi-step0].No_, [NDCRegistrateEResi-step0].[Bill-to Customer No_], [NDCRegistrateEResi-step0].[Bill-to Name], [NDCRegistrateEResi-step0].[Posting Date], [Sales Header].[selling season code], [Sales Header].[Shortcut Dimension 2 Code], IIf(IsNull([Sales Cr_Memo Header].[no_]),"",[Sales Cr_Memo Header].[No_]), IIf(IsNull([Sales Cr_Memo Header].[no_]),"",[Sales Cr_Memo Header.Posting Date]), [Return Receipt Line].Type, [Geographical Zone].Description, [Geographical Zone_1].Description
HAVING (((Sum(Val([Return Receipt Line.Quantity])))<>0) AND (([Return Receipt Line].Type)=2));

GO

