-- [782] ProspettoProvvigioniStagioneMarchio
SELECT [Cust_ Invoices Per Salesperson].[Item_Serv_ Comm_ Group], [Cust_ Invoices Per Salesperson].[Salesperson Code], Salesperson_Purchaser.Name AS Agente, [Cust_ Invoices Per Salesperson].[Customer No_], Customer.Name AS Cliente, [Cust_ Invoices Per Salesperson].[Document Type], [Cust_ Invoices Per Salesperson].[Document No_], [ProspettoProvvigioniStagioneMarchio-TipiOrdineEResi].[Order Types], [Cust_ Invoices Per Salesperson].[Posting Date] AS DataDocumento, First(Val([Cust_ Invoices Per Salesperson.Invoice Aumount])) AS ImportFatturaConIva, First(Val([Cust_ Invoices Per Salesperson.Invoice Remaining Amount])) AS ResiduoFatturaConIva, First(Val([Cust_ Invoices Per Salesperson.Comm_ Base Gross Amt_])) AS ImponibileFattura, First(Val([Cust_ Invoices Per Salesperson.Amount Commission _])) AS ImportoProvvigioneTotale, Sum(Val(Nz([Invoiced Comm_ Amt_]))) AS importopagato, Sum(Val((Nz([Charged Comm_ Amt_])))) AS ImportoRFecuperato, [Cust_ Invoices Per Salesperson].[Trademark Code], [Cust_ Invoices Per Salesperson].[Season Code], [Cust_ Invoices Per Salesperson].[Dimension Set ID], [PaiedOff Commission].[Entry No_], [PaiedOff Commission].[Payment Date], Val([Cust_ Invoices Per Salesperson.Commission _]) AS PercentualeProvvigione
FROM ((([Cust_ Invoices Per Salesperson] LEFT JOIN [PaiedOff Commission] ON [Cust_ Invoices Per Salesperson].[Entry No_] = [PaiedOff Commission].[Entry No_]) LEFT JOIN Customer ON [Cust_ Invoices Per Salesperson].[Customer No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Cust_ Invoices Per Salesperson].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN [ProspettoProvvigioniStagioneMarchio-TipiOrdineEResi] ON [Cust_ Invoices Per Salesperson].[Document No_] = [ProspettoProvvigioniStagioneMarchio-TipiOrdineEResi].[Document No_]
GROUP BY [Cust_ Invoices Per Salesperson].[Item_Serv_ Comm_ Group], [Cust_ Invoices Per Salesperson].[Salesperson Code], Salesperson_Purchaser.Name, [Cust_ Invoices Per Salesperson].[Customer No_], Customer.Name, [Cust_ Invoices Per Salesperson].[Document Type], [Cust_ Invoices Per Salesperson].[Document No_], [ProspettoProvvigioniStagioneMarchio-TipiOrdineEResi].[Order Types], [Cust_ Invoices Per Salesperson].[Posting Date], [Cust_ Invoices Per Salesperson].[Trademark Code], [Cust_ Invoices Per Salesperson].[Season Code], [Cust_ Invoices Per Salesperson].[Dimension Set ID], [PaiedOff Commission].[Entry No_], [PaiedOff Commission].[Payment Date], Val([Cust_ Invoices Per Salesperson.Commission _]);

GO

-- [783] ProspettoProvvigioniStagioneMarchio-Sistemazione2018
SELECT [Cust_ Invoices Per Salesperson].[Salesperson Code], Salesperson_Purchaser.Name AS Agente, [Cust_ Invoices Per Salesperson].[Customer No_], Customer.Name AS Cliente, [Cust_ Invoices Per Salesperson].[Document Type], [Cust_ Invoices Per Salesperson].[Document No_], [Cust_ Invoices Per Salesperson].[Posting Date] AS DataDocumento, First(Val([Cust_ Invoices Per Salesperson.Invoice Aumount])) AS ImportFatturaConIva, First(Val([Cust_ Invoices Per Salesperson.Invoice Remaining Amount])) AS ResiduoFatturaConIva, First(Val([Cust_ Invoices Per Salesperson.Comm_ Base Gross Amt_])) AS ImponibileFattura, First(Val([Cust_ Invoices Per Salesperson.Amount Commission _])) AS ImportoProvvigioneTotale, [Cust_ Invoices Per Salesperson].[Trademark Code], [Cust_ Invoices Per Salesperson].[Season Code], Max(Val([Cust_ Invoices Per Salesperson.Commission _])) AS PercentualeProvvigione
FROM ([Cust_ Invoices Per Salesperson] LEFT JOIN Customer ON [Cust_ Invoices Per Salesperson].[Customer No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Cust_ Invoices Per Salesperson].[Salesperson Code] = Salesperson_Purchaser.Code
GROUP BY [Cust_ Invoices Per Salesperson].[Salesperson Code], Salesperson_Purchaser.Name, [Cust_ Invoices Per Salesperson].[Customer No_], Customer.Name, [Cust_ Invoices Per Salesperson].[Document Type], [Cust_ Invoices Per Salesperson].[Document No_], [Cust_ Invoices Per Salesperson].[Posting Date], [Cust_ Invoices Per Salesperson].[Trademark Code], [Cust_ Invoices Per Salesperson].[Season Code]
HAVING ((([Cust_ Invoices Per Salesperson].[Posting Date])>=#1/1/2018#));

