-- [787] ProvvigioniPerStagione-DettaglioLiquidazioni
SELECT NSP_FattureClientiAgenti.CodDimensione1, NSP_FattureClientiAgenti.CodDimensione2, [ProvvigioniPerStagione-step2].CodiceCCR, [ProvvigioniPerStagione-step1].CodiceMarchio, [ProvvigioniPerStagione-step0].CodiceStagione, NSP_FattureClientiAgenti.CodiceAgente, Salesperson_Purchaser.Name AS NomeAgente, NSP_FattureClientiAgenti.TipoAgente, NSP_FattureClientiAgenti.NrCliente, Customer.Name AS NomeCliente, NSP_FattureClientiAgenti.SourceCode, NSP_FattureClientiAgenti.TipoDocumento, NSP_FattureClientiAgenti.DataRegistrazione, NSP_FattureClientiAgenti.NrDocumento, NSP_FattureClientiAgenti.MovimentoManuale, NSP_FattureClientiAgenti.RaggrStampe, NSP_FattureClientiAgenti.[Nr_ Movimento], NSP_FattureClientiAgenti.Descrizione, NSP_FattureClientiAgenti.CodValuta, Val([NSP_FattureClientiAgenti.PercentualeProvvigione]) AS PercProvvigione, NSP_FattureClientiAgenti.[Escludi da liquidazione], [ProvvigioniPerStagione-DettaglioLiqudazioni-step3].DataLiquidazione, [ProvvigioniPerStagione-DettaglioLiqudazioni-step3].ImpProvvFatturato
FROM (((((NSP_FattureClientiAgenti LEFT JOIN [ProvvigioniPerStagione-step0] ON NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-step0].[Document No_]) LEFT JOIN Salesperson_Purchaser ON NSP_FattureClientiAgenti.CodiceAgente = Salesperson_Purchaser.Code) LEFT JOIN Customer ON NSP_FattureClientiAgenti.NrCliente = Customer.No_) LEFT JOIN [ProvvigioniPerStagione-step1] ON NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-step1].[Document No_]) LEFT JOIN [ProvvigioniPerStagione-step2] ON NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-step2].[Document No_]) LEFT JOIN [ProvvigioniPerStagione-DettaglioLiqudazioni-step3] ON (NSP_FattureClientiAgenti.RaggrStampe = [ProvvigioniPerStagione-DettaglioLiqudazioni-step3].RaggrStampe) AND (NSP_FattureClientiAgenti.PercentualeProvvigione = [ProvvigioniPerStagione-DettaglioLiqudazioni-step3].PercentualeProvvigione) AND (NSP_FattureClientiAgenti.CodiceAgente = [ProvvigioniPerStagione-DettaglioLiqudazioni-step3].CodiceAgente) AND (NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-DettaglioLiqudazioni-step3].NrDocumento) AND (NSP_FattureClientiAgenti.TipoDocumento = [ProvvigioniPerStagione-DettaglioLiqudazioni-step3].TipoDocumento)
WHERE (((NSP_FattureClientiAgenti.DataRegistrazione) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]));

GO

-- [788] ProvvigioniPerStagione-Orig
SELECT NSP_FattureClientiAgenti.CodDimensione1, NSP_FattureClientiAgenti.CodDimensione2, [ProvvigioniPerStagione-step2].CodiceCCR, [ProvvigioniPerStagione-step1].CodiceMarchio, [ProvvigioniPerStagione-step0].CodiceStagione, NSP_FattureClientiAgenti.CodiceAgente, Salesperson_Purchaser.Name AS NomeAgente, NSP_FattureClientiAgenti.TipoAgente, NSP_FattureClientiAgenti.NrCliente, Customer.Name AS NomeCliente, NSP_FattureClientiAgenti.SourceCode, NSP_FattureClientiAgenti.TipoDocumento, NSP_FattureClientiAgenti.DataRegistrazione, NSP_FattureClientiAgenti.NrDocumento, NSP_FattureClientiAgenti.MovimentoManuale, NSP_FattureClientiAgenti.RaggrStampe, NSP_FattureClientiAgenti.[Nr_ Movimento], NSP_FattureClientiAgenti.Descrizione, NSP_FattureClientiAgenti.CodValuta, Val([ImponibileProvvigione]) AS ImponiProvv, Val([ImportoProvvigione]) AS ImportoProvv, Val([NSP_FattureClientiAgenti.PercentualeProvvigione]) AS PercProvvigione, Val([ImpProvvDaFatturare]) AS ImpProvDaFatt, [ProvvigioniPerStagione-step3].ImpProvvFatturato, Val([ImpProvvDaRecuperare]) AS ImpProvvDaRec, Val([ImportoFattura]) AS ImpFatt, Val([ResiduoFattura]) AS ResFatt, Val([QuotaPagata]) AS QPagata, Val([QuotaProvv]) AS QProvv, NSP_FattureClientiAgenti.[Escludi da liquidazione]
FROM (((((NSP_FattureClientiAgenti LEFT JOIN [ProvvigioniPerStagione-step0] ON NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-step0].[Document No_]) LEFT JOIN Salesperson_Purchaser ON NSP_FattureClientiAgenti.CodiceAgente = Salesperson_Purchaser.Code) LEFT JOIN Customer ON NSP_FattureClientiAgenti.NrCliente = Customer.No_) LEFT JOIN [ProvvigioniPerStagione-step1] ON NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-step1].[Document No_]) LEFT JOIN [ProvvigioniPerStagione-step2] ON NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-step2].[Document No_]) LEFT JOIN [ProvvigioniPerStagione-step3] ON (NSP_FattureClientiAgenti.RaggrStampe = [ProvvigioniPerStagione-step3].RaggrStampe) AND (NSP_FattureClientiAgenti.PercentualeProvvigione = [ProvvigioniPerStagione-step3].PercentualeProvvigione) AND (NSP_FattureClientiAgenti.CodiceAgente = [ProvvigioniPerStagione-step3].CodiceAgente) AND (NSP_FattureClientiAgenti.NrDocumento = [ProvvigioniPerStagione-step3].NrDocumento) AND (NSP_FattureClientiAgenti.TipoDocumento = [ProvvigioniPerStagione-step3].TipoDocumento)
WHERE (((NSP_FattureClientiAgenti.DataRegistrazione) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]));

GO

-- [789] ProvvigioniPerStagione-step0
SELECT [Posted Document Dimension].[Table ID], [Posted Document Dimension].[Document No_], [Posted Document Dimension].[Dimension Code], First([Posted Document Dimension].[Dimension Value Code]) AS CodiceStagione
FROM [Posted Document Dimension]
GROUP BY [Posted Document Dimension].[Table ID], [Posted Document Dimension].[Document No_], [Posted Document Dimension].[Dimension Code]
HAVING ((([Posted Document Dimension].[Table ID])=113 Or ([Posted Document Dimension].[Table ID])=115) AND (([Posted Document Dimension].[Dimension Code])="STAGIONE"));

GO

-- [790] ProvvigioniPerStagione-step1
SELECT [Posted Document Dimension].[Table ID], [Posted Document Dimension].[Document No_], [Posted Document Dimension].[Dimension Code], First([Posted Document Dimension].[Dimension Value Code]) AS CodiceMarchio
FROM [Posted Document Dimension]
GROUP BY [Posted Document Dimension].[Table ID], [Posted Document Dimension].[Document No_], [Posted Document Dimension].[Dimension Code]
HAVING ((([Posted Document Dimension].[Table ID])=113 Or ([Posted Document Dimension].[Table ID])=115) AND (([Posted Document Dimension].[Dimension Code])="MARCHIO"));

GO

-- [791] ProvvigioniPerStagione-step2
SELECT [Posted Document Dimension].[Table ID], [Posted Document Dimension].[Document No_], [Posted Document Dimension].[Dimension Code], First([Posted Document Dimension].[Dimension Value Code]) AS CodiceCCR
FROM [Posted Document Dimension]
GROUP BY [Posted Document Dimension].[Table ID], [Posted Document Dimension].[Document No_], [Posted Document Dimension].[Dimension Code]
HAVING ((([Posted Document Dimension].[Table ID])=113 Or ([Posted Document Dimension].[Table ID])=115) AND (([Posted Document Dimension].[Dimension Code])="CCR"));

GO

-- [792] ProvvigioniPerStagione-step3
SELECT Sum(NSP_StoricoFattClientiAgenti.ImpProvvFatturato) AS ImpProvvFatturato, NSP_StoricoFattClientiAgenti.TipoDocumento, NSP_StoricoFattClientiAgenti.NrDocumento, NSP_StoricoFattClientiAgenti.CodiceAgente, NSP_StoricoFattClientiAgenti.PercentualeProvvigione, NSP_StoricoFattClientiAgenti.RaggrStampe
FROM NSP_StoricoFattClientiAgenti
GROUP BY NSP_StoricoFattClientiAgenti.TipoDocumento, NSP_StoricoFattClientiAgenti.NrDocumento, NSP_StoricoFattClientiAgenti.CodiceAgente, NSP_StoricoFattClientiAgenti.PercentualeProvvigione, NSP_StoricoFattClientiAgenti.RaggrStampe;

GO

-- [793] q1
SELECT [Sales Line].No_, [Sales Line].[Document No_], [Sales Line].[Line No_], [Sales Line].[Sell-to Customer No_], Val([Quantity]) AS comprato, Val([Qty_ Shipped Not Invoiced]) AS quantitaspeditanonfatt, Val([Quantity Shipped]) AS quantitaspedita, Val([Quantity Invoiced]) AS quantitafatt
FROM [Sales Line]
WHERE ((([Sales Line].No_)="fm8sn02044" Or ([Sales Line].No_)="fm8sn02045"));

GO

-- [794] q2
SELECT q1.[Sell-to Customer No_], q1.No_
FROM q1
GROUP BY q1.[Sell-to Customer No_], q1.No_;

GO

-- [795] q3
SELECT q2.[Sell-to Customer No_], Count(q2.No_) AS ConteggioDiNo_
FROM q2
GROUP BY q2.[Sell-to Customer No_]
HAVING (((Count(q2.No_))>1));

GO

-- [796] q4
SELECT q1.*
