GO

-- [797] qAcq
SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].[Unit of Measure], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Line].[Delete Reason], [Purchase Line].[Av_ Net Unit Cost], Val([Quantity]) AS QuantityPurchased, Val([No_ of Pairs]) AS PairsPurchased, Val([av_ net unit cost])*Val([no_ of pairs]) AS ValuePurchased, [Purchase Line].[Currency Code], IIf([currency code]="USD",(Val([av_ net unit cost])*Val([no_ of pairs]))/[forms]![principale]![cambioeurodollaro],IIf(IsNull([currency code]) Or [currency code]="",(Val([av_ net unit cost])*Val([no_ of pairs])),"ERROR CURRENCY NOT AVAILABLE")) AS ValuePurchasedEur, Val([Purchase Line.Quantity Received]) AS QuantityReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueReceived, Val([Purchase Line.Quantity Invoiced]) AS QuantityInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueInvoicedPurchases
FROM [Purchase Line]
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=20) AND (([Purchase Line].[Delete Reason])=""));

GO

-- [798] qAcqGrouped
SELECT qAcq.No_ AS PurchasesArt, qAcq.[Constant Variable Code] AS PurchasesColorCode, qAcq.[Assortment Code] AS PurchasesAssortment, Sum(qAcq.QuantityPurchased) AS QuantityPurchased, Sum(qAcq.PairsPurchased) AS PairsPurchased, qAcq.[Currency Code] AS CurrencyCodePurchase, Sum(qAcq.ValuePurchased) AS ValuePurchased, Sum(qAcq.ValuePurchasedEur) AS ValuePurchasedEur, Sum(qAcq.QuantityReceived) AS QuantityReceived, Sum(qAcq.PairsReceived) AS PairsReceived, Sum(qAcq.ValueReceived) AS ValueReceived, Sum(qAcq.QuantityInvoicedPurchases) AS QuantityInvoicedPurchases, Sum(qAcq.PairsInvoicedPurchases) AS PairsInvoicedPurchases, Sum(qAcq.ValueInvoicedPurchases) AS ValueInvoicedPurchases
FROM qAcq
GROUP BY qAcq.No_, qAcq.[Constant Variable Code], qAcq.[Assortment Code], qAcq.[Currency Code];

GO

-- [799] qAcqItem
SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].[Model Item No_], [Purchase Line].No_, [Purchase Line].[Unit of Measure], [Purchase Line].[Variable Code 01], [Purchase Line].[Variable Code 02], [Purchase Line].[Currency Code], [Purchase Line].[Delete Reason], [Purchase Line].[Av_ Net Unit Cost], [Variable Code].[Order Variable Code], IIf(IsNull([Purchase Line_1.Assortment Code]) Or [Purchase Line_1.Assortment Code]="","XXX",[Purchase Line_1.Assortment Code]) AS AssortmentCode, Val([purchase line.Quantity]) AS QuantityPurchased, Val([purchase line.No_ of pairs]) AS PairsPurchased, Val([purchase line.line amount]) AS ValuePurchased, Val([Purchase Line.Quantity Received]) AS QuantityReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueReceived, Val([Purchase Line.Quantity Invoiced]) AS QuantityInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueInvoicedPurchases
FROM ([Purchase Line] INNER JOIN [Variable Code] ON ([Purchase Line].[Variable Code 02] = [Variable Code].[Variable Code]) AND ([Purchase Line].[Variable Group 02] = [Variable Code].[Variable Group])) INNER JOIN [Purchase Line] AS [Purchase Line_1] ON ([Purchase Line].[Document No_] = [Purchase Line_1].[Document No_]) AND ([Purchase Line].[Original Line No_] = [Purchase Line_1].[Line No_])
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=2) AND (([Purchase Line].[Delete Reason])=""));

GO

-- [800] qAcqItemGrouped
SELECT qAcqItem.[Model Item No_] AS PurchasesArt, qAcqItem.[Variable Code 01] AS PurchasesColorCode, qAcqItem.No_, qAcqItem.[Variable Code 02] AS taglia, qAcqItem.[Order Variable Code], qAcqItem.AssortmentCode, qAcqItem.[Currency Code] AS CurrencyCodePurchase, Sum(qAcqItem.QuantityPurchased) AS QuantityPurchased, Sum(qAcqItem.PairsPurchased) AS PairsPurchased, Sum(qAcqItem.ValuePurchased) AS ValuePurchased, Sum(qAcqItem.QuantityReceived) AS QuantityReceived, Sum(qAcqItem.PairsReceived) AS PairsReceived, Sum(qAcqItem.ValueReceived) AS ValueReceived, Sum(qAcqItem.QuantityInvoicedPurchases) AS QuantityInvoicedPurchases, Sum(qAcqItem.PairsInvoicedPurchases) AS PairsInvoicedPurchases, Sum(qAcqItem.ValueInvoicedPurchases) AS ValueInvoicedPurchases
FROM qAcqItem
GROUP BY qAcqItem.[Model Item No_], qAcqItem.[Variable Code 01], qAcqItem.No_, qAcqItem.[Variable Code 02], qAcqItem.[Order Variable Code], qAcqItem.AssortmentCode, qAcqItem.[Currency Code];

GO

-- [801] qAcq-PerAnalisiConsegne-step01
SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].No_ AS Article, [Purchase Line].Quantity, [Purchase Line].[Unit of Measure], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], Val([No_ of Pairs]) AS Pairs, [Purchase Line].[Delete Reason], [Purchase Line].[Av_ Net Unit Cost], Val([Av_ Net Unit Cost])*[Pairs] AS PurchaseCost, [Purchase Line].[Requested Receipt Date], [Purchase Line].[Promised Receipt Date], [Purchase Line].[Planned Receipt Date], IIf([currency code]="USD",[PurchaseCost]/[forms]![principale]![cambioeurodollaro],[PurchaseCost]) AS PurchaseCostInEuro
FROM [Purchase Line]
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=20) AND (([Purchase Line].[Delete Reason])=""));

GO

-- [802] qAcq-PerAnalisiConsegne-step02
SELECT [qAcq-PerAnalisiConsegne-step01].*, [Item].[Trademark Code], [Item].[Season Code], [Item].[Line Code], [Vendor].Name AS Vendor, Year([Requested Receipt Date]) & "/" & Format(Month([Requested Receipt Date]),"00") AS PeriodRequestedReceiptDate, Year([Promised Receipt Date]) & "/" & Format(Month([Promised Receipt Date]),"00") AS PeriodPromisedReceiptDate, Year([Planned Receipt Date]) & "/" & Format(Month([Planned Receipt Date]),"00") AS PeriodPlannedReceiptDate
FROM [qAcq-PerAnalisiConsegne-step01] INNER JOIN (Item INNER JOIN Vendor ON [Item].[Vendor No_] = [Vendor].No_) ON [qAcq-PerAnalisiConsegne-step01].Article = [Item].No_;

GO

-- [803] qAcqPerPaiaRicevute-step0
SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].Quantity, [Purchase Line].[Unit of Measure], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Line].[No_ of Pairs], [Purchase Line].[Delete Reason], [Purchase Line].[Av_ Net Unit Cost], Val([av_ net unit cost])*Val([no_ of pairs]) AS PurchaseValue, [Purchase Line].[Currency Code], IIf([currency code]="USD",(Val([av_ net unit cost])*Val([no_ of pairs]))/[forms]![principale]![cambioeurodollaro],IIf(IsNull([currency code]) Or [currency code]="",(Val([av_ net unit cost])*Val([no_ of pairs])),"ERROR CURRENCY NOT AVAILABLE")) AS PurchaseValueEur, [Purchase Line].[Outstanding Quantity], (Val([quantity])-Val([outstanding quantity]))/Val([quantity])*Val([no_ of pairs]) AS ReceivedPairs
FROM [Purchase Line]
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=20) AND (([Purchase Line].[Delete Reason])=""));

GO

-- [804] qAcqPerPaiaRicevute-step1
SELECT [qAcqPerPaiaRicevute-step0].No_ AS PurchasesArt, [qAcqPerPaiaRicevute-step0].[Constant Variable Code] AS PurchasesColorCode, [qAcqPerPaiaRicevute-step0].[Assortment Code] AS PurchasesAssortment, Sum(Val([Quantity])) AS PurchasesAssortimentQuantity, Sum(Val([No_ of Pairs])) AS PurchasesPairs, Sum([qAcqPerPaiaRicevute-step0].ReceivedPairs) AS ReceivedPairs
FROM [qAcqPerPaiaRicevute-step0]
GROUP BY [qAcqPerPaiaRicevute-step0].No_, [qAcqPerPaiaRicevute-step0].[Constant Variable Code], [qAcqPerPaiaRicevute-step0].[Assortment Code];

GO

-- [805] qAcqPerPaiaRicevute-step3
SELECT [qAcqPerPaiaRicevute-step1].*, [Item].[Trademark Code], [Item].[Season Code], [Item].[Line Code], [Vendor].Name AS Vendor
FROM ([qAcqPerPaiaRicevute-step1] INNER JOIN Item ON [qAcqPerPaiaRicevute-step1].PurchasesArt = [Item].No_) INNER JOIN Vendor ON [Item].[Vendor No_] = [Vendor].No_;

GO

-- [806] qAnalisiNoteDiCreditoEResi
SELECT [Sales Cr_Memo Line].Type, [Sales Cr_Memo Line].No_, [Sales Cr_Memo Line].Quantity, [Sales Cr_Memo Line].[Unit of Measure], [Sales Cr_Memo Line].[Constant Variable Code], [Sales Cr_Memo Line].[Assortment Code], [Sales Cr_Memo Line].[No_ of Pairs], [Salesperson_Purchaser].Name AS Salesperson, [Sales Cr_Memo Line].[Return Reason Code], [Sales Cr_Memo Line].[Customer Price Group], [Sales Cr_Memo Line].[Average Unit Price], [Sales Cr_Memo Header].[Document Date], [Sales Cr_Memo Header].[Salesperson Code], [Sales Cr_Memo Line].[Constant Variable Code] AS ColorCode, [Sales Cr_Memo Header].[Sell-to Customer No_], Val([Line Amount])-Val([Inv_ Discount Amount]) AS SalesValue
FROM [Sales Cr_Memo Line] INNER JOIN ([Sales Cr_Memo Header] LEFT JOIN Salesperson_Purchaser ON [Sales Cr_Memo Header].[Salesperson Code] = [Salesperson_Purchaser].Code) ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_
WHERE ((([Sales Cr_Memo Line].Type)=19)) OR ((([Sales Cr_Memo Line].Type)=20));

GO

-- [807] qAnalisiNoteDiCreditoEResi-step1
SELECT qAnalisiNoteDiCreditoEResi.No_ AS Article, qAnalisiNoteDiCreditoEResi.[Constant Variable Code], qAnalisiNoteDiCreditoEResi.Salesperson, qAnalisiNoteDiCreditoEResi.[Return Reason Code], qAnalisiNoteDiCreditoEResi.[Assortment Code], Sum(Val([Quantity])) AS AssortmentQuantity, Sum((Val([No_ of Pairs]))) AS PairsQuantity, qAnalisiNoteDiCreditoEResi.[Document Date], qAnalisiNoteDiCreditoEResi.[Salesperson Code], qAnalisiNoteDiCreditoEResi.ColorCode, qAnalisiNoteDiCreditoEResi.[Sell-to Customer No_] AS CustomerCode, [Customer].[Geographical Zone], [Customer].Name AS CustomerName, Sum(qAnalisiNoteDiCreditoEResi.SalesValue) AS ValoreNoteDiCredito
FROM qAnalisiNoteDiCreditoEResi INNER JOIN Customer ON qAnalisiNoteDiCreditoEResi.[Sell-to Customer No_] = [Customer].No_
GROUP BY qAnalisiNoteDiCreditoEResi.No_, qAnalisiNoteDiCreditoEResi.[Constant Variable Code], qAnalisiNoteDiCreditoEResi.Salesperson, qAnalisiNoteDiCreditoEResi.[Return Reason Code], qAnalisiNoteDiCreditoEResi.[Assortment Code], qAnalisiNoteDiCreditoEResi.[Document Date], qAnalisiNoteDiCreditoEResi.[Salesperson Code], qAnalisiNoteDiCreditoEResi.ColorCode, qAnalisiNoteDiCreditoEResi.[Sell-to Customer No_], [Customer].[Geographical Zone], [Customer].Name;

GO

-- [808] QC_1
SELECT "F" & Mid$([purchase header.no_],5,2) & Right$([purchase header.no_],5) & Format$([document packaging header.package no_],"0000") AS PackageNr, "Napa_I20_1R" AS [Buy Group], [Document Packaging Header].[Document No_], [Document Packaging Line].[Item No_], [Document Packaging Line].[Colour Code], [Purchase Header].[Shortcut Dimension 2 Code] AS TrademarkCode, [Purchase Header].[Selling Season Code], Sum(Val([Document Packaging Line.Quantity])) AS BoxQty, Item.[Description 2], [Variable Code].Description AS febos_color_desc, [Purchase Line].[Assortment Code], [Document Packaging Header].[package no_] AS febos_box_no
FROM (((([Document Packaging Line] INNER JOIN [Document Packaging Header] ON ([Document Packaging Line].[Document Type] = [Document Packaging Header].[Document Type]) AND ([Document Packaging Line].[Document No_] = [Document Packaging Header].[Document No_]) AND ([Document Packaging Line].[Package No_] = [Document Packaging Header].[Package No_])) INNER JOIN [Purchase Header] ON [Document Packaging Header].[Document No_] = [Purchase Header].No_) INNER JOIN Item ON [Document Packaging Line].[Item No_] = Item.No_) INNER JOIN [Variable Code] ON ([Document Packaging Line].[Colour Code] = [Variable Code].[Variable Code]) AND ([Document Packaging Line].[Colour Group] = [Variable Code].[Variable Group])) INNER JOIN [Purchase Line] ON ([Document Packaging Line].[Document Line No_] = [Purchase Line].[Line No_]) AND ([Document Packaging Line].[Document No_] = [Purchase Line].[Document No_])
GROUP BY "F" & Mid$([purchase header.no_],5,2) & Right$([purchase header.no_],5) & Format$([document packaging header.package no_],"0000"), "Napa_I20_1R", [Document Packaging Header].[Document No_], [Document Packaging Line].[Item No_], [Document Packaging Line].[Colour Code], [Purchase Header].[Shortcut Dimension 2 Code], [Purchase Header].[Selling Season Code], Item.[Description 2], [Variable Code].Description, [Purchase Line].[Assortment Code], [Document Packaging Header].[package no_]
HAVING ((([Purchase Header].[Shortcut Dimension 2 Code])=[forms]![principale]![filtromarchiosourcing]) AND (([Purchase Header].[Selling Season Code])=[forms]![principale]![filtroStagionesourcing]));

GO

-- [809] QC_2
SELECT [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].[Constant Variable Code], Sum(Val([no_ of pairs])) AS TotQty
FROM [Purchase Line]
WHERE ((([Purchase Line].[Document Type])=1))
GROUP BY [Purchase Line].[Delete Reason], [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].[Constant Variable Code]
HAVING ((([Purchase Line].[Delete Reason])="") AND ((Sum(Val([no_ of pairs])))>0));

GO

-- [810] QC_3
SELECT [Document Packaging Line].[Document No_], Max([Document Packaging Line].[Package No_]) AS febos_box_all
FROM [Document Packaging Line]
GROUP BY [Document Packaging Line].[Document No_];

GO

-- [811] QC_Final
SELECT QC_1.PackageNr, QC_1.[Document No_], QC_1.[Item No_], QC_1.[Colour Code], QC_1.TrademarkCode, QC_1.[Selling Season Code], QC_1.BoxQty, QC_2.TotQty
FROM (QC_1 INNER JOIN QC_2 ON (QC_1.[Colour Code] = QC_2.[Constant Variable Code]) AND (QC_1.[Item No_] = QC_2.No_) AND (QC_1.[Document No_] = QC_2.[Document No_])) INNER JOIN QC_3 ON QC_2.[Document No_] = QC_3.[Document No_]
ORDER BY QC_1.[Document No_], QC_1.PackageNr;

GO

-- [812] QC_Final_CPH BOXES
SELECT QC_1.PackageNr AS febos_box_id, QC_1.[Document No_] AS febos_po_id, QC_1.[Item No_] AS febos_article_id, QC_1.[Description 2] AS febos_article_name, QC_1.[Colour Code] AS febos_color_code, QC_1.febos_color_desc, QC_1.[Assortment Code] AS febos_assortment, QC_1.BoxQty AS febos_assortment_no, QC_1.febos_box_no, QC_3.febos_box_all
FROM (QC_1 INNER JOIN QC_2 ON (QC_1.[Colour Code] = QC_2.[Constant Variable Code]) AND (QC_1.[Item No_] = QC_2.No_) AND (QC_1.[Document No_] = QC_2.[Document No_])) INNER JOIN QC_3 ON QC_2.[Document No_] = QC_3.[Document No_]
ORDER BY QC_1.[Document No_], QC_1.febos_box_no;

