antitainbollaDaInviareWMSps])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingDaInviareWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaInviatoWMSps]) AS PairsReadyForShippingInviatoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollaInviatoWMSps]) AS QuantityReadyForShippingInviatoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollaInviatoWMSps])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingInviatoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaEvasoWMSps]) AS PairsReadyForShippingEvasoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollaEvasoWMSps]) AS QuantityReadyForShippingEvasoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollaEvasoWMSps])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingEvasoWMSps, [Sales Header].[Payment Terms Code], [Sales Header].[Payment Method Code], [Sales Header].[Invoice Discount Calculation] AS CalcoloScontoFattura, Val([Sales Header.Invoice Discount Value]) AS ScontoFattura, IIf([Consignment]=True,"SI","NO") AS ContoVendita, Val([Right on Return _]) AS PercentualeDirittoAlReso, [Sales Header].Note, [Sales Header].[Campaign No_], [Sales Header].[event code], Val([Sales Line.Line Discount _]) AS ScontoRiga, Val([Sales Line.Discount 1 _]) AS Sconto1Riga, Val([Sales Line.Discount 2 _]) AS Sconto2Riga, Val([Sales Line.Discount 3 _]) AS Sconto3Riga, IIf([Anomalous]=1,"X","") AS Anomalo, IIf([Not Anomalous]=1,"X","") AS NonAnomalo, [Sales Header].[Anomalous Date], IIf([Checked]=1,"X","") AS Verificato, [Sales Header].[Checked Date], [Sales Header].[Budget No_], [Sales Header].[Course Date] AS DataDecorrenza, [Sales Header].[KIMO_FASHION SO No_] AS KimoOrder, [Sales Header].[Shipment Method Code] AS ShipmentMethodCode, [Shipment Method].Description AS ShipmentMethodDescription, [Sales Header].[Selling Season Code] AS [SEASON CODE], [Sales Header].[Transport Reason Code], [Transport Reason Code].Description AS TransportReasonCodeDescription, [Sales Line].[Location Code], [Sales Header].[Shipping Agent Code], [Sales Header].[Shipping Agent Service Code], dateprenotazionipervendite.[Date Reservation], [Sales Header].[Fast Shipping], [Sales Header].[Commission Group Code] AS CommissionGroupCodeOrder, [Sales Header].[Geographical Zone] AS GeographicalZoneFromOrder, [Geographical Zone].Description AS GeographicalZoneDescriptionFromOrder, [Budget Header].[Budget Area], [Sales Line].[Model Cross Reference], [Sales Header].[shortcut dimension 2 code] AS [trademark code]
