-- [840] quantitaAssortimento
SELECT Sum(Val([Quantity])) AS quantitaassortimento, [Assortment Quantity].[Assortment Code]
FROM [Assortment Quantity]
GROUP BY [Assortment Quantity].[Assortment Code];

GO

-- [841] qVend
SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Header].No_ AS OrderNo, [Sales Line].[Line No_], [Sales Line].No_, Val([Quantity]) AS QuantitySold, [Sales Line].[Unit of Measure], [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], Val([No_ of Pairs]) AS PairsSold, Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Salesperson Code], [Sales Line].[Av_ Net Unit Price], [Sales Line].[Currency Code], Val([Line Amount])-Val([Inv_ Discount Amount]) AS ValueSold, Val([Average Unit Price]) AS GrossUnitPrice, Val([average unit price])*Val([no_ of pairs]) AS GrossSalesValue, [GrossSalesValue]-[ValueSold] AS DiscountValue, Val(Nz([Area Manager Commission _]))*[valuesold]/10 AS AreaManagerCommissionValue, Val(Nz([Salesperson Commission _]))*[valuesold]/100 AS SalesPersonCommissionValue, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsShipped, Val([Sales Line.Quantity Shipped]) AS QuantityShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueInvoiced, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS Pairsinvoiced, Val([Sales Line.Quantity invoiced]) AS QuantityInvoiced
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20) AND (([Sales Line].[Delete Reason])=""))
ORDER BY [Sales Header].No_;

GO

-- [842] qVendGrouped
SELECT qVend.No_ AS SalesArt, qVend.[Constant Variable Code] AS SalesColorCode, qVend.[Assortment Code] AS SalesAssortment, Sum(qVend.GrossSalesValue) AS GrossSalesValue, Sum(qVend.DiscountValue) AS DiscountValue, Sum(qVend.AreaManagerCommissionValue) AS AreaManagerCommissionValue, Sum(qVend.SalesPersonCommissionValue) AS SalesPersonCommissionValue, Sum(qVend.QuantitySold) AS QuantitySold, Sum(qVend.PairsSold) AS PairsSold, Sum(qVend.ValueSold) AS ValueSold, Sum(qVend.QuantityShipped) AS QuantityShipped, Sum(qVend.PairsShipped) AS PairsShipped, Sum(qVend.ValueShipped) AS ValueShipped, Sum(qVend.QuantityInvoiced) AS QuantityInvoiced, Sum(qVend.Pairsinvoiced) AS Pairsinvoiced, Sum(qVend.ValueInvoiced) AS ValueInvoiced
FROM qVend
GROUP BY qVend.No_, qVend.[Constant Variable Code], qVend.[Assortment Code];

GO

-- [843] qVendItem
SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Header].No_ AS OrderNo, [Sales Line].[Line No_], [Sales Line].[Model Item No_], [Sales Line].No_, [Sales Line].[Unit of Measure], [Sales Line].[Variable Code 01], [Sales Line].[Variable Code 02], Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Salesperson Code], [Sales Line].[Av_ Net Unit Price], Val([sales line.Average Unit Price]) AS GrossUnitPrice, Val([sales line.average unit price])*Val([sales line.no_ of pairs]) AS GrossSalesValue, [GrossSalesValue]-[ValueSold] AS DiscountValue, Val(nz([sales line.Area Manager Commission _]))*[valuesold]/100 AS AreaManagerCommissionValue, Val(nz([Sales Line.Salesperson Commission _]))*[valuesold]/100 AS SalesPersonCommissionValue, [Variable Code].[Order Variable Code], IIf(IsNull([Sales Line_1.Assortment Code]) Or [Sales Line_1.Assortment Code]="","XXX",[Sales Line_1.Assortment Code]) AS AssortmentCode, Val([sales line.Quantity]) AS QuantitySold, [Sales Line].[Currency Code], Val([sales line.No_ of pairs]) AS PairsSold, Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount]) AS ValueSold, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsShipped, Val([Sales Line.Quantity Shipped]) AS QuantityShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueInvoiced, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsInvoiced, Val([Sales Line.Quantity Invoiced]) AS QuantityInvoiced
FROM ((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Code 02] = [Variable Code].[Variable Code]) AND ([Sales Line].[Variable Group 02] = [Variable Code].[Variable Group])) INNER JOIN [Sales Line] AS [Sales Line_1] ON ([Sales Line].[Document No_] = [Sales Line_1].[Document No_]) AND ([Sales Line].[Original Line No_] = [Sales Line_1].[Line No_])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=2) AND (([Sales Line].[Delete Reason])=""))
ORDER BY [Sales Header].No_;

GO

-- [844] qVendItemGrouped
SELECT qVendItem.[Model Item No_] AS SalesArt, qVendItem.[Variable Code 01] AS SalesColorCode, qVendItem.[Variable Code 02] AS Taglia, qVendItem.[Order Variable Code], qVendItem.No_, qVendItem.AssortmentCode, Sum(qVendItem.QuantitySold) AS QuantitySold, Sum(qVendItem.PairsSold) AS PairsSold, Sum(qVendItem.ValueSold) AS ValueSold, Sum(qVendItem.GrossSalesValue) AS GrossSalesValue, Sum(qVendItem.DiscountValue) AS DiscountValue, Sum(qVendItem.AreaManagerCommissionValue) AS AreaManagerCommissionValue, Sum(qVendItem.SalesPersonCommissionValue) AS SalesPersonCommissionValue, Sum(qVendItem.QuantityShipped) AS QuantityShipped, Sum(qVendItem.PairsShipped) AS PairsShipped, Sum(qVendItem.ValueShipped) AS ValueShipped, Sum(qVendItem.QuantityInvoiced) AS QuantityInvoiced, Sum(qVendItem.PairsInvoiced) AS PairsInvoiced, Sum(qVendItem.ValueInvoiced) AS ValueInvoiced
FROM qVendItem
GROUP BY qVendItem.[Model Item No_], qVendItem.[Variable Code 01], qVendItem.[Variable Code 02], qVendItem.[Order Variable Code], qVendItem.No_, qVendItem.AssortmentCode;

GO

-- [845] RDADaRicevere
SELECT [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[trademark code], Sum([qSoloVend-PerGriglieAgenti].PairsSold) AS PairsSold, Sum([qSoloVend-PerGriglieAgenti].ValueSoldVAT) AS ValueSoldVAT, [qSoloVend-PerGriglieAgenti].[Sales Line].[requested delivery date] AS [Req Delivery Date], "" AS [NOTE]
FROM [qSoloVend-PerGriglieAgenti]
WHERE ((([qSoloVend-PerGriglieAgenti].OrderType)="Progr" Or ([qSoloVend-PerGriglieAgenti].OrderType)="Pronto") AND (([qSoloVend-PerGriglieAgenti].[Securities Received])=False))
GROUP BY [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[Sales Line].[requested delivery date], "", [qSoloVend-PerGriglieAgenti].[season code], [qSoloVend-PerGriglieAgenti].[Payment Method Code]
HAVING ((([qSoloVend-PerGriglieAgenti].[Salesperson Code])=[forms]![principale]![filtroAgentePerGrigliaAgenti]) AND (([qSoloVend-PerGriglieAgenti].[season code])=[forms]![principale]![creditofiltrostagione2]) AND (([qSoloVend-PerGriglieAgenti].[Payment Method Code])="RDA"))
ORDER BY [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[trademark code];

GO

-- [846] RDADaRicevere_Riepilogo
SELECT [qSoloVend-PerGriglieAgenti].[Credit Manager], [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[Purchase Group], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[risk rating], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[Sales Line].[requested delivery date] AS [Req Delivery Date], Sum([qSoloVend-PerGriglieAgenti].PairsSold) AS PairsSold, Sum([qSoloVend-PerGriglieAgenti].ValueSold) AS ValueSold, Sum([qSoloVend-PerGriglieAgenti].ValueSoldVAT) AS ValueSoldVAT, Sum([qSoloVend-PerGriglieAgenti].PairsReadyForShipping) AS SommaDiPairsReadyForShipping, Sum([qSoloVend-PerGriglieAgenti].ValueReadyForShipping) AS SommaDiValueReadyForShipping, IIf([Securities Received]=1,"Y","N") AS [Securities Received_], IIf([Blocked for Assignments]=1,"Y","N") AS [Blocked for Assignments_], [qSoloVend-PerGriglieAgenti].[Reason Block Code], "" AS [NOTE]
FROM [qSoloVend-PerGriglieAgenti]
WHERE ((([qSoloVend-PerGriglieAgenti].OrderType)="Progr" Or ([qSoloVend-PerGriglieAgenti].OrderType)="Pronto"))
GROUP BY [qSoloVend-PerGriglieAgenti].[Credit Manager], [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[Purchase Group], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[risk rating], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[Sales Line].[requested delivery date], IIf([Securities Received]=1,"Y","N"), IIf([Blocked for Assignments]=1,"Y","N"), [qSoloVend-PerGriglieAgenti].[Reason Block Code], "", [qSoloVend-PerGriglieAgenti].[season code]
HAVING ((([qSoloVend-PerGriglieAgenti].[Payment Method Code])="RDA") AND ((IIf([Securities Received]=1,"Y","N"))="N") AND (([qSoloVend-PerGriglieAgenti].[season code])=[forms]![principale]![creditofiltrostagione2])) OR (((IIf([Blocked for Assignments]=1,"Y","N"))="Y") AND (([qSoloVend-PerGriglieAgenti].[season code])=[forms]![principale]![creditofiltrostagione2]))
ORDER BY [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[trademark code];

GO

