-- [856] ReportVendutoComprato-NonProiettato-Vendite
SELECT [Sales Line].[Document Type], Item.[Line Code] AS Linea, [Sales Line].[Model Item No_] AS Articolo, [Sales Line].[Variable Code 01] AS CodiceColore, [Variable Code].Description AS Colore, Item.[Trademark Code] AS Marchio, [Sales Header].[Selling Season Code] AS Stagione, [Sales Line].[delete reason], Sum(Val([quantity])) AS PaiaVendute, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([Sales Line].[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [Sales Line].[Model Item No_] = Item.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE (((Item.[Advertising Material])=0))
GROUP BY [Sales Line].[Document Type], Item.[Line Code], [Sales Line].[Model Item No_], [Sales Line].[Variable Code 01], [Variable Code].Description, Item.[Trademark Code], [Sales Header].[Selling Season Code], [Sales Line].[delete reason], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, Item.Manufacturer, Vendor_1.Name
HAVING ((([Sales Line].[Document Type])=1) AND ((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([Sales Header].[Selling Season Code])=[Maschere]![principale]![filtroStagione]) AND (([Sales Line].[delete reason])=""))
ORDER BY Sum(Val([quantity])) DESC;

GO

