-- [884] SituazioneRicevimenti_step2
SELECT [SituazioneRicevimenti-step0-Acq].*, IIf(IsNull([SituazioneRicevimenti-step1-Trs.ARTICLE])=False,[PairsTravelling],0) AS PairsTravelling_, IIf(IsNull([SituazioneRicevimenti-step1-Trs.ARTICLE])=False,[PairsReceived]-[PairsTravelling],[pAIRSrECEIVED]) AS PairsInHouse
FROM [SituazioneRicevimenti-step0-Acq] LEFT JOIN [SituazioneRicevimenti-step1-Trs] ON ([SituazioneRicevimenti-step0-Acq].[Assortment Code] = [SituazioneRicevimenti-step1-Trs].[Assortment Code]) AND ([SituazioneRicevimenti-step0-Acq].Color = [SituazioneRicevimenti-step1-Trs].Color) AND ([SituazioneRicevimenti-step0-Acq].Article = [SituazioneRicevimenti-step1-Trs].Article);

GO

-- [885] SituazioneRicevimenti-step0-Acq
SELECT [Purchase Header].[Buy-from Vendor No_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Purchase Line].No_ AS Article, Item.[Description 2] AS Description, [Purchase Line].[Constant Variable Code] AS Color, [Purchase Line].[Assortment Code], [Purchase Header].[Document Type], Sum(Val([Purchase Line.No_ of Pairs])) AS PairsPurchased, Sum(IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0)) AS PairsReceived, Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((([Purchase Header] INNER JOIN [Purchase Line] ON ([Purchase Header].No_ = [Purchase Line].[Document No_]) AND ([Purchase Header].[Document Type] = [Purchase Line].[Document Type])) INNER JOIN Item ON [Purchase Line].No_ = Item.No_) INNER JOIN Vendor ON [Purchase Header].[Buy-from Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
GROUP BY [Purchase Header].[Buy-from Vendor No_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Purchase Line].No_, Item.[Description 2], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Header].[Document Type], [Purchase Line].[Delete Reason], [Purchase Line].Type, Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name
HAVING ((([Purchase Header].[Document Type])=1) AND (([Purchase Line].[Delete Reason])="") AND (([Purchase Line].Type)=19 Or ([Purchase Line].Type)=20) AND ((Item.[Advertising Material])=0));

GO

-- [886] SituazioneRicevimenti-step1-Trs
SELECT Item.[vendor no_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Transfer Line].[Item No_] AS Article, Item.[Description 2] AS Description, [Transfer Line].[Constant Variable Code] AS Color, [Transfer Line].[Assortment Code], Sum(IIf(Val([transfer line.quantity])>0,Val([Transfer Line.No_ of Pairs])/Val([transfer line.quantity])*(Val([quantity shipped])-Val([quantity received])),0)) AS PairsTravelling, Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((([Transfer Line] INNER JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_) INNER JOIN Item ON [Transfer Line].[Item No_] = Item.No_) INNER JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
GROUP BY Item.[vendor no_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Transfer Line].[Item No_], Item.[Description 2], [Transfer Line].[Constant Variable Code], [Transfer Line].[Assortment Code], [Transfer Line].[item Type], Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name
HAVING (((Sum(IIf(Val([transfer line.quantity])>0,Val([Transfer Line.No_ of Pairs])/Val([transfer line.quantity])*(Val([quantity shipped])-Val([quantity received])),0)))<>0) AND (([Transfer Line].[item Type])=19 Or ([Transfer Line].[item Type])=20) AND ((Item.[Advertising Material])=0));

GO

-- [887] SituazioneSpedizioni
SELECT [Sales Header].[Shortcut Dimension 2 Code] AS Trademark, [Sales Header].[selling season code] AS Season, [Geographical Zone_1].Description AS [GeoZone 2 Description], Salesperson_Purchaser.Name AS [Salesperson Name], [Geographical Zone].Description AS [GeoZone 1 Description], [Sales Header].[Sell-to Customer No_] AS [Customer Code], [Sales Header].[Sell-to Customer Name] AS [Customer Name], [Sales Header].[Ship-to City], [Sales Header].No_ AS [Order No_], [Sales Line].[Customer Order Ref_], IIf([Customer.Blocked for Assignments]=1,"Y","N") AS [Credit Block], [Sales Header].[payment method code], IIf([securities received]=1,"Y","N") AS [Securities Received/Titoli Ricevuti], Item.[Collection Code], Item.[product family], Max(dateprenotazionipervendite.[date reservation]) AS [Expected Arrival Date In Febos], Item.[product sex] AS Gender, [Sales Line].No_ AS Article, Item.[Description 2], [Sales Line].[Constant Variable Code] AS [Color Code], [Variable Code].Description AS [Color Description], Sum(IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs]))) AS PairsSold, Sum(IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount])))) AS ValueSold, Sum(IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*Val([no_ of pairs]),0)) AS PairsShipped, Sum(IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaRilasciate])) AS DeliveryInProgress, Sum(IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaAperte])) AS [Pairs Reserved to Ship]
FROM ((((((((([Sales Header] INNER JOIN [Sales Line] ON ([Sales Header].No_ = [Sales Line].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Line].[Document Type])) INNER JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN dateprenotazionipervendite ON ([Sales Line].[Line No_] = dateprenotazionipervendite.[Sales Line No_]) AND ([Sales Line].[Document No_] = dateprenotazionipervendite.[Sales Document No_])) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN [qsoloVend-DatiBolleAperteRilasciate] ON ([Sales Line].[Line No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order Line No_]) AND ([Sales Line].[Document No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order No_])) INNER JOIN [Sales Header Extension] ON ([Sales Header].No_ = [Sales Header Extension].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type])) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON [Sales Header Extension].[Geographical Zone 2] = [Geographical Zone_1].Code) LEFT JOIN [Geographical Zone] ON [Sales Header].[Geographical Zone] = [Geographical Zone].Code
WHERE ((([Sales Line].[document type])=1) AND (([Sales Line].[delete reason])="") AND (([Sales Header].[order type])=0 Or ([Sales Header].[order type])=2) AND (([Sales Line].Type)=19 Or ([Sales Line].Type)=20))
GROUP BY [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[selling season code], [Geographical Zone_1].Description, Salesperson_Purchaser.Name, [Geographical Zone].Description, [Sales Header].[Sell-to Customer No_], [Sales Header].[Sell-to Customer Name], [Sales Header].[Ship-to City], [Sales Header].No_, [Sales Line].[Customer Order Ref_], IIf([Customer.Blocked for Assignments]=1,"Y","N"), [Sales Header].[payment method code], IIf([securities received]=1,"Y","N"), Item.[Collection Code], Item.[product family], Item.[product sex], [Sales Line].No_, Item.[Description 2], [Sales Line].[Constant Variable Code], [Variable Code].Description
HAVING ((([Sales Header].[selling season code])=[FORMS]![PRINCIPALE]![FiltroStagioneEAN2]))
ORDER BY [Sales Header].[Shortcut Dimension 2 Code], [Geographical Zone_1].Description, Salesperson_Purchaser.Name, [Geographical Zone].Description, [Sales Header].[Sell-to Customer Name], [Sales Header].No_, Item.[Collection Code], Item.[product family], Item.[product sex], [Sales Line].No_, [Sales Line].[Constant Variable Code];

GO

-- [888] SituazioneSpedizioniAgenti
SELECT [Sales Header].[Shortcut Dimension 2 Code] AS Trademark, [Sales Header].[selling season code] AS Season, Salesperson_Purchaser.Name AS [Salesperson Name], [Sales Header].[Sell-to Customer No_] AS [Customer Code], [Sales Header].[Sell-to Customer Name] AS [Customer Name], [Sales Header].[Ship-to City], [Sales Header].No_ AS [Order No_], [Sales Line].[Customer Order Ref_], IIf([Customer.Blocked for Assignments]=1,"Y","N") AS [Credit Block], [Sales Header].[payment method code], IIf([securities received]=1,"Y","N") AS [Securities Received/Titoli Ricevuti], Item.[Collection Code], Item.[product family], Max(dateprenotazionipervendite.[date reservation]) AS [Expected Arrival Date In Febos], Item.[product sex] AS Gender, [Sales Line].No_ AS Article, Item.[Description 2], [Sales Line].[Constant Variable Code] AS [Color Code], [Variable Code].Description AS [Color Description], Sum(IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs]))) AS PairsSold, Sum(IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount])))) AS ValueSold, Sum(IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*Val([no_ of pairs]),0)) AS PairsShipped, Sum(IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaRilasciate])) AS DeliveryInProgress, Sum(IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaAperte])) AS [Pairs Reserved to Ship]
FROM (((((([Sales Header] INNER JOIN [Sales Line] ON ([Sales Header].No_ = [Sales Line].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Line].[Document Type])) INNER JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN dateprenotazionipervendite ON ([Sales Line].[Line No_] = dateprenotazionipervendite.[Sales Line No_]) AND ([Sales Line].[Document No_] = dateprenotazionipervendite.[Sales Document No_])) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN [qsoloVend-DatiBolleAperteRilasciate] ON ([Sales Line].[Line No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order Line No_]) AND ([Sales Line].[Document No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order No_])
WHERE ((([Sales Header].[Salesperson Code])=[forms]![principale]![filtroagenteexportddt]) AND (([Sales Line].[document type])=1) AND (([Sales Line].[delete reason])="") AND (([Sales Header].[order type])=0 Or ([Sales Header].[order type])=2) AND (([Sales Line].Type)=19 Or ([Sales Line].Type)=20))
GROUP BY [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[selling season code], Salesperson_Purchaser.Name, [Sales Header].[Sell-to Customer No_], [Sales Header].[Sell-to Customer Name], [Sales Header].[Ship-to City], [Sales Header].No_, [Sales Line].[Customer Order Ref_], IIf([Customer.Blocked for Assignments]=1,"Y","N"), [Sales Header].[payment method code], IIf([securities received]=1,"Y","N"), Item.[Collection Code], Item.[product family], Item.[product sex], [Sales Line].No_, Item.[Description 2], [Sales Line].[Constant Variable Code], [Variable Code].Description
HAVING ((([Sales Header].[selling season code])=[FORMS]![PRINCIPALE]![FiltroStagioneEAN2]))
ORDER BY [Sales Header].[Shortcut Dimension 2 Code], Salesperson_Purchaser.Name, [Sales Header].[Sell-to Customer Name], [Sales Header].No_, Item.[Collection Code], Item.[product family], Item.[product sex], [Sales Line].No_, [Sales Line].[Constant Variable Code];

GO

