-- [906] SovraccolliDaLetture_UPC
SELECT [SovraccolliDaLetture_UPC-step0].*, Item.[Model Item No_] AS Article, Item.[Variable Code 01] AS Colore, Item.[Variable Code 02] AS taglia
FROM ([SovraccolliDaLetture_UPC-step0] LEFT JOIN UPCCodes_CleanDoubled_PerSovraccolli ON [SovraccolliDaLetture_UPC-step0].EANCODELETTORETXT = UPCCodes_CleanDoubled_PerSovraccolli.[Cross-Reference No_]) LEFT JOIN Item ON UPCCodes_CleanDoubled_PerSovraccolli.[Item No_] = Item.No_
ORDER BY [SovraccolliDaLetture_UPC-step0].CARTONE, [SovraccolliDaLetture_UPC-step0].EANCODELETTORETXT;

GO

-- [907] SovraccolliDaLetture_UPC-step0
SELECT ListaPerSovraccolluDaLetture.CARTONE, Format$([EANCODELETTORE],"000000000000") AS EANCODELETTORETXT, Count(ListaPerSovraccolluDaLetture.EANCODELETTORE) AS Pezzi
FROM ListaPerSovraccolluDaLetture
GROUP BY ListaPerSovraccolluDaLetture.CARTONE, Format$([EANCODELETTORE],"000000000000");

GO

-- [908] SovraccolliDaLetture-step0
SELECT ListaPerSovraccolluDaLetture.CARTONE, Format$([EANCODELETTORE],"0") AS EANCODELETTORETXT, Count(ListaPerSovraccolluDaLetture.EANCODELETTORE) AS Pezzi, Format$([EANCODELETTORE],"0000000000000") AS EANCODELETTORETXT_OLD
FROM ListaPerSovraccolluDaLetture
GROUP BY ListaPerSovraccolluDaLetture.CARTONE, Format$([EANCODELETTORE],"0"), Format$([EANCODELETTORE],"0000000000000");

GO

-- [909] SovraccolliDaLettureTest
SELECT Count([SovraccolliDaLettureTest-step0].Cartone) AS CartoniContati, Sum([SovraccolliDaLettureTest-step0].SommaDiPezzi) AS pezziTotali, Max(Val([cartone])) AS numeromaxcartone
FROM [SovraccolliDaLettureTest-step0];

GO

-- [910] SovraccolliDaLettureTest-step0
SELECT TabellaAppoggioSovraccolliDaLetture.Cartone, Sum(TabellaAppoggioSovraccolliDaLetture.Pezzi) AS SommaDiPezzi
FROM TabellaAppoggioSovraccolliDaLetture
GROUP BY TabellaAppoggioSovraccolliDaLetture.Cartone;

GO

-- [911] SovraccolliDaLettureTJX
SELECT SovraccolliDaLetture.CARTONE, Sum(SovraccolliDaLetture.Pezzi) AS Pezzi, SovraccolliDaLetture.Article, SovraccolliDaLetture.Colore
FROM SovraccolliDaLetture
GROUP BY SovraccolliDaLetture.CARTONE, SovraccolliDaLetture.Article, SovraccolliDaLetture.Colore;

GO

-- [912] SovraccolliMaterialePubblicitario
SELECT [Document Packaging Header].[Document Type], [Document Packaging Header].[Document No_], [Document Packaging Header].[Package No_], [Purchase Line].No_, [Purchase Line].[constant variable code], "F" & Mid$([purchase line.document no_],5,2) & Right$([purchase line.document no_],5) & Format$([document packaging header.package no_],"0000") AS CartonLabel
FROM ([Purchase Line] INNER JOIN [Document Packaging Line] ON ([Purchase Line].[Document No_] = [Document Packaging Line].[Document No_]) AND ([Purchase Line].[Line No_] = [Document Packaging Line].[Document Line No_])) INNER JOIN [Document Packaging Header] ON ([Document Packaging Line].[Document Type] = [Document Packaging Header].[Document Type]) AND ([Document Packaging Line].[Document No_] = [Document Packaging Header].[Document No_]) AND ([Document Packaging Line].[Package No_] = [Document Packaging Header].[Package No_])
GROUP BY [Document Packaging Header].[Document Type], [Document Packaging Header].[Document No_], [Document Packaging Header].[Package No_], [Purchase Line].No_, [Purchase Line].[constant variable code], "F" & Mid$([purchase line.document no_],5,2) & Right$([purchase line.document no_],5) & Format$([document packaging header.package no_],"0000")
HAVING ((([Document Packaging Header].[Document No_])=[forms]![principale]![filtroodaean]));

GO

-- [913] SovraccolliTjx
SELECT [Sales Header].[Customer Order Ref_] AS RiferimentoOrdineCliente, [Sales Line].Reference AS ReferenzaOrdineCliente, [Sales Header].[Delete Reason], [Sales Line].Type, [Sales Line].[Document No_] AS OrdineNr, [Sales Line].[Line No_] AS LineaNr, Val([quantity]) AS quantita, [Sales Line].No_ AS articolo, [Sales Line].[Description 2] AS Descrizione2, [Variable Code].[Variable Code] AS Colore, [Variable Code].Description AS DescrizioneColore, Val([no_ of pairs]) AS paia, [Sales Line].[Assortment Code] AS Assortimento
FROM ([Sales Header] INNER JOIN [Sales Line] ON ([Sales Header].No_ = [Sales Line].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Line].[Document Type])) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]);

GO

-- [914] SovraccolliTjxDettaglioTaglie
SELECT [Sales Line].[Document No_] AS OrdineNr, [Sales Line].[Line No_] AS LineaNr, [Sales Line].[Variable Code 02] AS taglia, Val([quantity]) AS quantitaTaglia, [Sales Line].[Original Line No_] AS LineaOriginaleNr
FROM [Sales Line];

GO

-- [915] StampaMassivaSovraccolliDaAnagrafica
SELECT [DDT_Picking Line].[Document No_], [DDT_Picking Line].[Document Type], [DDT_Picking Line].Type, Sum(Val([quantity])) AS qty, Int(Sum(Val([quantity])/[forms]![principale]![numeropezzipercartone])) AS cartoni, [DDT_Picking Header].status, [DDT_Picking Header].[Shortcut Dimension 2 Code], [DDT_Picking Header].[Bill-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Bill-to Name 2], [DDT_Picking Header].[Bill-to Address], [DDT_Picking Header].[Bill-to Address 2], [DDT_Picking Header].[Bill-to Post Code], [DDT_Picking Header].[Bill-to City], [DDT_Picking Header].[Bill-to County], [DDT_Picking Header].[Bill-to Country_Region Code], [DDT_Picking Header].[Ship-to Code], [DDT_Picking Header].[Ship-to Name], [DDT_Picking Header].[Ship-to Name 2], [DDT_Picking Header].[Ship-to Address], [DDT_Picking Header].[Ship-to Address 2], [DDT_Picking Header].[Ship-to Post Code], [DDT_Picking Header].[Ship-to City], [DDT_Picking Header].[Ship-to County], [DDT_Picking Header].[Ship-to Country_Region Code]
FROM [DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]
GROUP BY [DDT_Picking Line].[Document No_], [DDT_Picking Line].[Document Type], [DDT_Picking Line].Type, [DDT_Picking Header].status, [DDT_Picking Header].[Shortcut Dimension 2 Code], [DDT_Picking Header].[Bill-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].[Bill-to Name 2], [DDT_Picking Header].[Bill-to Address], [DDT_Picking Header].[Bill-to Address 2], [DDT_Picking Header].[Bill-to Post Code], [DDT_Picking Header].[Bill-to City], [DDT_Picking Header].[Bill-to County], [DDT_Picking Header].[Bill-to Country_Region Code], [DDT_Picking Header].[Ship-to Code], [DDT_Picking Header].[Ship-to Name], [DDT_Picking Header].[Ship-to Name 2], [DDT_Picking Header].[Ship-to Address], [DDT_Picking Header].[Ship-to Address 2], [DDT_Picking Header].[Ship-to Post Code], [DDT_Picking Header].[Ship-to City], [DDT_Picking Header].[Ship-to County], [DDT_Picking Header].[Ship-to Country_Region Code]
HAVING ((([DDT_Picking Line].[Document Type])=0) AND (([DDT_Picking Line].Type)=2) AND (([DDT_Picking Header].status)=1) AND (([DDT_Picking Header].[Shortcut Dimension 2 Code])="BLAC"));

GO

-- [916] StatisticheEcommerce
SELECT Export_Sales_Report.order_date, Export_Sales_Report.order_number, Export_Sales_Report.product_qty_ordered, Export_Sales_Report.product_ean, [Item_1.No_] & "_" & [Color] AS ArtCol, Item_1.No_, Item.[variable code 01] AS Color, Item.[variable code 02] AS [Size], Item.[season code], Item.[trademark code], Item.[collection code]
FROM Export_Sales_Report LEFT JOIN (([NavisionEan-step0] LEFT JOIN Item ON [NavisionEan-step0].[Item No_] = Item.No_) LEFT JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) ON Export_Sales_Report.product_ean = [NavisionEan-step0].[Cross-Reference No_];

GO

-- [917] SuggestedRetailPrices
SELECT [Sales Price].[Item No_], [Sales Price].[Sales Type], [Sales Price].[Sales Code], Val([Unit Price]) AS SRP
FROM [Sales Price]
WHERE ((([Sales Price].[Sales Code])=[Listino]));

GO

-- [918] tempiPag_CervedPayline_DeterminazioniImporti
SELECT tempiPagBaseDocumentiDaVerificareQueryGenerale.ChiaveMovimentoFatturaNotaCredito, Sum([importopagato]) AS importototalePagatoPerEntry, First(tempiPagDocumentiCalcoloDelloImporto.Importo) AS ImportoOriginalePerEntry
FROM tempiPagBaseDocumentiDaVerificareQueryGenerale INNER JOIN tempiPagDocumentiCalcoloDelloImporto ON tempiPagBaseDocumentiDaVerificareQueryGenerale.ChiaveMovimentoFatturaNotaCredito = tempiPagDocumentiCalcoloDelloImporto.[Entry No_]
GROUP BY tempiPagBaseDocumentiDaVerificareQueryGenerale.ChiaveMovimentoFatturaNotaCredito;

GO

-- [919] tempiPag_CervedPayline_DeterminazioniImportiEStatus
SELECT tempiPag_CervedPayline_DeterminazioniImporti.ChiaveMovimentoFatturaNotaCredito, tempiPag_CervedPayline_DeterminazioniImporti.importototalePagatoPerEntry, tempiPag_CervedPayline_DeterminazioniImporti.ImportoOriginalePerEntry, IIf([importototalePagatoPerEntry]=0,"FullOpen",IIf(Abs([importototalePagatoPerEntry]-[importooriginaleperentry])>0.0001,"Partial","Payed")) AS status
FROM tempiPag_CervedPayline_DeterminazioniImporti;

GO

-- [920] tempiPag_New_step0_CollegamentoDaFattura
SELECT [Cust_ Ledger Entry].[Entry No_] AS ChiaveMovimentoFatturaNotaCredito, IIf(IsNull([Cust_ Ledger Entry_1.entry no_])=False,[Cust_ Ledger Entry_1.entry no_],0) AS ChiaveMovimentoPagamento, Round(Val([Cust_ Ledger Entry.Closed by Amount])*10000)/10000 AS ImportoAbbinato, "N Fatt/NC a 1 Pag" AS collegamento, [Cust_ Ledger Entry].[Document Type], IIf([Cust_ Ledger Entry_1.document type]=2 Or [Cust_ Ledger Entry_1.document type]=3,"Y","N") AS testComp
FROM [Cust_ Ledger Entry] INNER JOIN [Cust_ Ledger Entry] AS [Cust_ Ledger Entry_1] ON [Cust_ Ledger Entry].[Closed by Entry No_] = [Cust_ Ledger Entry_1].[Entry No_]
WHERE ((([Cust_ Ledger Entry].[Document Type])=2 Or ([Cust_ Ledger Entry].[Document Type])=3));

GO

-- [921] tempiPag_New_step1_CollegamentoDaPagamento
SELECT [Cust_ Ledger Entry_1].[Entry No_] AS ChiaveMovimentoFatturaNotaCredito, [Cust_ Ledger Entry].[Entry No_] AS ChiaveMovimentoPagamento, Round(-Val([Cust_ Ledger Entry.Closed by Amount])*10000)/10000 AS ImportoAbbinato, "1 Fatt/NC a N Pag" AS collegamento, [Cust_ Ledger Entry_1].[Document Type], [Cust_ Ledger Entry_1].[dimension set id], IIf([Cust_ Ledger Entry.document type]=2 Or [Cust_ Ledger Entry.document type]=3,"Y","N") AS testComp
FROM [Cust_ Ledger Entry] INNER JOIN [Cust_ Ledger Entry] AS [Cust_ Ledger Entry_1] ON [Cust_ Ledger Entry].[Closed by Entry No_] = [Cust_ Ledger Entry_1].[Entry No_]
WHERE ((([Cust_ Ledger Entry_1].[Document Type])=2 Or ([Cust_ Ledger Entry_1].[Document Type])=3));

GO

-- [922] tempiPag_New_step2_UnionCollegamenti
SELECT ChiaveMovimentoFatturaNotaCredito, ChiaveMovimentoPagamento, ImportoAbbinato, collegamento, testComp
FROM tempiPag_New_step0_CollegamentoDaFattura

UNION ALL SELECT ChiaveMovimentoFatturaNotaCredito, ChiaveMovimentoPagamento, ImportoAbbinato, collegamento, testComp
FROM tempiPag_New_step1_CollegamentoDaPagamento;

GO

-- [923] tempiPag_New_Step3_TotalePagatoPerEntryNo
SELECT tempiPag_New_step2_UnionCollegamenti.ChiaveMovimentoFatturaNotaCredito, Sum(tempiPag_New_step2_UnionCollegamenti.ImportoAbbinato) AS totalePagatoPerEntryNo
FROM tempiPag_New_step2_UnionCollegamenti
GROUP BY tempiPag_New_step2_UnionCollegamenti.ChiaveMovimentoFatturaNotaCredito;

GO

-- [924] tempiPag_New_step4_CalcoloDelloImportoPerEnrtyNo
SELECT [Cust_ Ledger Entry].[Document Type], [Cust_ Ledger Entry].[Entry No_], Round(Sum(IIf([entry type]=1 Or [entry type]=3 Or [entry type]=4 Or [entry type]=5 Or [entry type]=6 Or [entry type]=7 Or [entry type]=8 Or [entry type]=9 Or [entry type]=12 Or [entry type]=13 Or [entry type]=14 Or [entry type]=15 Or [entry type]=16 Or [entry type]=17,Val([Amount]),0))*10000)/10000 AS Importo, Round(Sum(Val([Amount]))*10000)/10000 AS ImportoResiduo
FROM [Cust_ Ledger Entry] INNER JOIN [Detailed Cust_ Ledg_ Entry] ON [Cust_ Ledger Entry].[Entry No_] = [Detailed Cust_ Ledg_ Entry].[Cust_ Ledger Entry No_]
GROUP BY [Cust_ Ledger Entry].[Document Type], [Cust_ Ledger Entry].[Entry No_]
HAVING ((([Cust_ Ledger Entry].[Document Type])=2 Or ([Cust_ Ledger Entry].[Document Type])=3));

GO

-- [925] tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo
SELECT tempiPag_New_step4_CalcoloDelloImportoPerEnrtyNo.[Entry No_], tempiPag_New_step4_CalcoloDelloImportoPerEnrtyNo.Importo, tempiPag_New_step4_CalcoloDelloImportoPerEnrtyNo.ImportoResiduo, [importo]-[importoresiduo] AS importototalePagatoPerEntryNo, IIf([importototalePagatoPerEntryNo]=0,"FullOpen",IIf([importoresiduo]<>0,"Partial","Payed")) AS status
FROM tempiPag_New_step4_CalcoloDelloImportoPerEnrtyNo;

GO

-- [926] tempiPag_New_step6_Residui
SELECT tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo.[Entry No_] AS ChiaveMovimentoFatturaNotaCredito, tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo.importoresiduo AS importoabbinato, "Residuo" AS collegamento
FROM tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo
WHERE (((tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo.importoresiduo)<>0));

GO

-- [927] tempiPag_New_step7_TuttiIMovimenti
SELECT ChiaveMovimentoFatturaNotaCredito, ChiaveMovimentoPagamento, ImportoAbbinato, collegamento, testComp
FROM tempiPag_New_step0_CollegamentoDaFattura;

union all SELECT ChiaveMovimentoFatturaNotaCredito, ChiaveMovimentoPagamento, ImportoAbbinato, collegamento, testComp
FROM tempiPag_New_step1_CollegamentoDaPagamento;

UNION ALL SELECT ChiaveMovimentoFatturaNotaCredito, 0, ImportoAbbinato, collegamento, ""
FROM tempiPag_New_step6_Residui;

GO

-- [928] tempiPag_New_step8a_Generale
SELECT [Geographical Zone].Description AS Geo1, [Geographical Zone_1].Description AS Geo2, Customer.No_ AS CodiceCliente, Customer.Name AS Cliente, Salesperson_Purchaser.Code AS CodiceAgente, Salesperson_Purchaser.Name AS Agente, [Cust_ Ledger Entry].[Document Type] AS TipoDocumentoFattura, IIf([tipodocumentofattura]=2,"FATT",IIf([tipodocumentofattura]=3,"NDC","???")) AS DescrTipo, [Cust_ Ledger Entry].[Document No_] AS NumeroDocumentoFattura, tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoFatturaNotaCredito, [Cust_ Ledger Entry_1].[Document Type] AS TipoDocumentoPagamento, [Cust_ Ledger Entry_1].[Document No_] AS NumeroDocumentoPagamento, tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoPagamento, tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo.status, tempiPag_New_step7_TuttiIMovimenti.collegamento, tempiPag_New_step7_TuttiIMovimenti.Importoabbinato, tempiPag_New_step7_TuttiIMovimenti.testComp, [Cust_ Ledger Entry].[Document Date] AS DataFattura, [Cust_ Ledger Entry].[Due Date] AS DataScadenzaPagamento, IIf([collegamento]<>"Residuo",IIf([Cust_ Ledger Entry_1.Document type]<>3,[Cust_ Ledger Entry_1.due date],[Cust_ Ledger Entry_1.document date]),[forms]![principale]![datapagamentoposizioniscoperte]) AS DataPagamento, [Cust_ Ledger Entry].[Dimension Set ID], Customer.[SKIP CREDIT INFO UPDATE], [Cust_ Ledger Entry].[Payment Method Code] AS [Payment Method Code_CustLedgEnrty], Customer.[Payment Method Code], Customer.[Payment Terms Code], [Cust_ Ledger Entry].[Managed by Lawyer] AS [Managed by Lawyer_FatturaNDC], [Cust_ Ledger Entry_1].[Managed by Lawyer] AS [Managed by Lawyer_Pagamento]
FROM ((((tempiPag_New_step7_TuttiIMovimenti LEFT JOIN [Cust_ Ledger Entry] AS [Cust_ Ledger Entry_1] ON tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoPagamento = [Cust_ Ledger Entry_1].[Entry No_]) INNER JOIN (([Cust_ Ledger Entry] INNER JOIN Customer ON [Cust_ Ledger Entry].[Customer No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Cust_ Ledger Entry].[Salesperson Code] = Salesperson_Purchaser.Code) ON tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoFatturaNotaCredito = [Cust_ Ledger Entry].[Entry No_]) INNER JOIN tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo ON tempiPag_New_step7_TuttiIMovimenti.ChiaveMovimentoFatturaNotaCredito = tempiPag_New_step5_CalcoloDelloImportoEStatusPerEntryNo.[Entry No_]) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code;

GO

-- [929] tempiPag_New_step8b_GeneralePriimiCalcoli
SELECT tempiPag_New_step8a_Generale.*, DateDiff("d",[datafattura],[datapagamento]) AS giorniPagamento, DateDiff("d",[datascadenzapagamento],[datapagamento]) AS giorniritardoPagamento, DateDiff("d",[datafattura],[datapagamento])*[importoabbinato] AS giorniPagamentoXImporto, DateDiff("d",[datascadenzapagamento],[datapagamento])*[importoabbinato] AS giorniritardoPagamentoximporto
FROM tempiPag_New_step8a_Generale;

GO

-- [930] tempiPag_New_step8c_GeneraleFinal
SELECT tempiPag_New_step8b_GeneralePriimiCalcoli.*, IIf([giorniPagamento]<=[forms]![principale]![NumeroGiorniSoglia],[importoabbinato],0) AS importoEntroSoglia, IIf([giorniritardoPagamento]<=[forms]![principale]![NumeroGiorniSogliaRitardo],[importoabbinato],0) AS importoEntroSogliaRitardo, [cliente]+" ("+[codicecliente]+")" AS clienteecodice, [agente]+" ("+[codiceagente]+")" AS agenteecodice, Dimensioni_NE.CCR, Dimensioni_NE.MARCHIO, Dimensioni_NE.STAGIONE, Dimensioni_NE.LINEA
FROM tempiPag_New_step8b_GeneralePriimiCalcoli LEFT JOIN Dimensioni_NE ON tempiPag_New_step8b_GeneralePriimiCalcoli.[Dimension Set ID] = Dimensioni_NE.[Dimension Set ID];

GO

-- [931] tempiPag_New_step9a_CervedPayline_Aperte
INSERT INTO Payline_Export_Structure_Partite ( status, Geo2, Cod_Cliente, Data_doc, n_doc, data_reg, n_reg, data_scad, importo, dare_avere, causale, [Data Pagamento] )
SELECT tempiPag_New_step9a_CervedPayline_Aperte_pre.status, tempiPag_New_step9a_CervedPayline_Aperte_pre.Geo2, tempiPag_New_step9a_CervedPayline_Aperte_pre.Cod_Cliente, tempiPag_New_step9a_CervedPayline_Aperte_pre.Data_doc, tempiPag_New_step9a_CervedPayline_Aperte_pre.n_doc, tempiPag_New_step9a_CervedPayline_Aperte_pre.data_reg, tempiPag_New_step9a_CervedPayline_Aperte_pre.n_reg, tempiPag_New_step9a_CervedPayline_Aperte_pre.data_scad, Sum(tempiPag_New_step9a_CervedPayline_Aperte_pre.importo) AS importo, tempiPag_New_step9a_CervedPayline_Aperte_pre.dare_avere, tempiPag_New_step9a_CervedPayline_Aperte_pre.causale, "" AS [Data Pagamento]
