GROUP BY tempiPag_New_step9a_CervedPayline_Aperte_pre.status, tempiPag_New_step9a_CervedPayline_Aperte_pre.Geo2, tempiPag_New_step9a_CervedPayline_Aperte_pre.Cod_Cliente, tempiPag_New_step9a_CervedPayline_Aperte_pre.Data_doc, tempiPag_New_step9a_CervedPayline_Aperte_pre.n_doc, tempiPag_New_step9a_CervedPayline_Aperte_pre.data_reg, tempiPag_New_step9a_CervedPayline_Aperte_pre.n_reg, tempiPag_New_step9a_CervedPayline_Aperte_pre.data_scad, tempiPag_New_step9a_CervedPayline_Aperte_pre.dare_avere, tempiPag_New_step9a_CervedPayline_Aperte_pre.causale, "";

GO

-- [932] tempiPag_New_step9a_CervedPayline_Aperte_pre
SELECT tempiPag_New_step8a_Generale.status, tempiPag_New_step8a_Generale.Geo2, tempiPag_New_step8a_Generale.CodiceCliente AS Cod_Cliente, tempiPag_New_step8a_Generale.DataFattura AS Data_doc, tempiPag_New_step8a_Generale.NumeroDocumentoFattura AS n_doc, tempiPag_New_step8a_Generale.DataFattura AS data_reg, tempiPag_New_step8a_Generale.ChiaveMovimentoFatturaNotaCredito AS n_reg, tempiPag_New_step8a_Generale.DataScadenzaPagamento AS data_scad, tempiPag_New_step8a_Generale.importoabbinato AS importo, IIf([tipodocumentofattura]=2,"D","A") AS dare_avere, IIf([tipodocumentofattura]=2,"EF1#","EF2#") AS causale
FROM tempiPag_New_step8a_Generale INNER JOIN Customer ON tempiPag_New_step8a_Generale.CodiceCliente = Customer.No_
WHERE (((tempiPag_New_step8a_Generale.status)<>"Payed") AND ((tempiPag_New_step8a_Generale.Geo2)="ITALIA") AND ((Customer.[skip credit info update])=False));

GO

-- [933] tempiPag_New_step9b_CervedPayline_Chiuse
INSERT INTO Payline_Export_Structure_Partite ( status, Geo2, Cod_Cliente, Data_doc, n_doc, data_reg, n_reg, data_scad, importo, dare_avere, causale, [Data Pagamento] )
SELECT tempiPag_New_step8a_Generale.status, tempiPag_New_step8a_Generale.Geo2, tempiPag_New_step8a_Generale.CodiceCliente AS Cod_Cliente, tempiPag_New_step8a_Generale.DataFattura AS Data_doc, tempiPag_New_step8a_Generale.NumeroDocumentoFattura AS n_doc, tempiPag_New_step8a_Generale.DataFattura AS data_reg, tempiPag_New_step8a_Generale.ChiaveMovimentoFatturaNotaCredito AS n_reg, tempiPag_New_step8a_Generale.DataScadenzaPagamento AS data_scad, tempiPag_New_step8a_Generale.importoabbinato AS importo, IIf([tipodocumentofattura]=2,"D","A") AS dare_avere, IIf([tipodocumentofattura]=2,"EF1#","EF2#") AS causale, tempiPag_New_step8a_Generale.DataPagamento AS [Data Pagamento]
FROM tempiPag_New_step8a_Generale INNER JOIN Customer ON tempiPag_New_step8a_Generale.CodiceCliente = Customer.No_
WHERE (((tempiPag_New_step8a_Generale.status)="Payed") AND ((tempiPag_New_step8a_Generale.Geo2)="ITALIA") AND ((tempiPag_New_step8a_Generale.DataPagamento) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]) AND ((Customer.[skip credit info update])=False));

GO

-- [934] tempiPag_New_step9c_CervedPayline_Clienti
INSERT INTO Payline_Export_Structure_Clienti ( Codice_Cliente, Ragione_Sociale, indirizzo, cap, localita, provincia, nazione, partita_iva, codice_fiscale, legale, bloccati )
SELECT tempiPag_New_step8a_Generale.CodiceCliente AS Codice_Cliente, [Name] & " " & [Name 2] AS Ragione_Sociale, [Address] & " " & [Address 2] AS indirizzo, Customer.[post code] AS cap, Customer.city AS localita, Customer.county AS provincia, Customer.[country_region code] AS nazione, Customer.[vat registration no_] AS partita_iva, Customer.[fiscal code] AS codice_fiscale, "" AS legale, "" AS bloccati
FROM tempiPag_New_step8a_Generale INNER JOIN Customer ON tempiPag_New_step8a_Generale.CodiceCliente = Customer.No_
WHERE (((Customer.[Skip Credit Info Update])=False) AND ((tempiPag_New_step8a_Generale.Geo2)="ITALIA") AND ((tempiPag_New_step8a_Generale.status)="Payed") AND ((tempiPag_New_step8a_Generale.DataPagamento) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale])) OR (((Customer.[Skip Credit Info Update])=False) AND ((tempiPag_New_step8a_Generale.Geo2)="ITALIA") AND ((tempiPag_New_step8a_Generale.collegamento)="Residuo"))
GROUP BY tempiPag_New_step8a_Generale.CodiceCliente, [Name] & " " & [Name 2], [Address] & " " & [Address 2], Customer.[post code], Customer.city, Customer.county, Customer.[country_region code], Customer.[vat registration no_], Customer.[fiscal code], "";

GO

