-- [937] tempiPagBaseDocumentiDaVerificareQueryGenerale-step1
SELECT Customer.No_ AS CodiceCliente, Customer.Name AS Cliente, Salesperson_Purchaser.Code AS CodiceAgente, Salesperson_Purchaser.Name AS Agente, [Cust_ Ledger Entry].[Document Type] AS TipoDocumentoFattura, [Cust_ Ledger Entry].[Document No_] AS NumeroDocumentoFattura, tempiPagBaseDocumentiDaVerificareSenzaDoppi.ChiaveMovimentoFatturaNotaCredito, [Cust_ Ledger Entry_1].[Document Type] AS TipoDocumentoPagamento, [Cust_ Ledger Entry_1].[Document No_] AS NumeroDocumentoPagamento, tempiPagBaseDocumentiDaVerificareSenzaDoppi.ChiaveMovimentoPagamento, tempiPagBaseDocumentiDaVerificareSenzaDoppi.collegamento, tempiPagDocumentiCalcoloDelloImporto.Importo, IIf([Cust_ Ledger Entry_1.document date]<>#1/1/1753#,[importoabbinato],[importo]) AS importoabbinatocalcolato, IIf([Cust_ Ledger Entry_1.document date]<>#1/1/1753#,[importoabbinato],0) AS importopagato, [Cust_ Ledger Entry].[Document Date] AS DataFattura, [Cust_ Ledger Entry].[Due Date] AS DataScadenzaPagamento, IIf([Cust_ Ledger Entry_1.document date]<>#1/1/1753#,IIf([Cust_ Ledger Entry_1.Document type]<>3,[Cust_ Ledger Entry_1.due date],[Cust_ Ledger Entry_1.document date]),[forms]![principale]![datapagamentoposizioniscoperte]) AS DataPagamento
FROM ((tempiPagBaseDocumentiDaVerificareSenzaDoppi INNER JOIN (([Cust_ Ledger Entry] INNER JOIN Customer ON [Cust_ Ledger Entry].[Customer No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Cust_ Ledger Entry].[Salesperson Code] = Salesperson_Purchaser.Code) ON tempiPagBaseDocumentiDaVerificareSenzaDoppi.ChiaveMovimentoFatturaNotaCredito = [Cust_ Ledger Entry].[Entry No_]) LEFT JOIN [Cust_ Ledger Entry] AS [Cust_ Ledger Entry_1] ON tempiPagBaseDocumentiDaVerificareSenzaDoppi.ChiaveMovimentoPagamento = [Cust_ Ledger Entry_1].[Entry No_]) LEFT JOIN tempiPagDocumentiCalcoloDelloImporto ON tempiPagBaseDocumentiDaVerificareSenzaDoppi.ChiaveMovimentoFatturaNotaCredito = tempiPagDocumentiCalcoloDelloImporto.[Entry No_];

GO

