-- [940] tempiPagDocumentiCalcoloDelloImporto
SELECT [Cust_ Ledger Entry].[Entry No_], Sum(IIf([entry type]=1 Or [entry type]=3 Or [entry type]=4 Or [entry type]=5 Or [entry type]=6 Or [entry type]=7 Or [entry type]=8 Or [entry type]=9 Or [entry type]=12 Or [entry type]=13 Or [entry type]=14 Or [entry type]=15 Or [entry type]=16 Or [entry type]=17,Val([Amount]),0)) AS Importo, Sum(Val([Amount])) AS ImportoResiduo
FROM [Cust_ Ledger Entry] INNER JOIN [Detailed Cust_ Ledg_ Entry] ON [Cust_ Ledger Entry].[Entry No_]=[Detailed Cust_ Ledg_ Entry].[Cust_ Ledger Entry No_]
GROUP BY [Cust_ Ledger Entry].[Entry No_];

GO

-- [941] tempiPagDocumentiConCollegamentoDaFatturaNotaCredito
SELECT [Cust_ Ledger Entry].[Document Type], [Cust_ Ledger Entry].[Entry No_] AS ChiaveMovimentoFatturaNotaCredito, IIf(IsNull([Cust_ Ledger Entry_1.entry no_])=False,[Cust_ Ledger Entry_1.entry no_],0) AS ChiaveMovimentoPagamento, Val([Cust_ Ledger Entry.Closed by Amount]) AS ImportoAbbinato, IIf(IsNull([Cust_ Ledger Entry_1.entry no_])=False,Val([Cust_ Ledger Entry_1.Closed by Amount]),0) AS ImportoAbbinato1, "N Fatt/NC a 1 Pag" AS collegamento
FROM [Cust_ Ledger Entry] LEFT JOIN [Cust_ Ledger Entry] AS [Cust_ Ledger Entry_1] ON [Cust_ Ledger Entry].[Closed by Entry No_] = [Cust_ Ledger Entry_1].[Entry No_]
WHERE ((([Cust_ Ledger Entry].[Document Type])=2));

GO

-- [942] tempiPagDocumentiConCollegamentoDaPagamento
SELECT [Cust_ Ledger Entry_1].[Document Type], [Cust_ Ledger Entry_1].[Entry No_] AS ChiaveMovimentoFatturaNotaCredito, [Cust_ Ledger Entry].[Entry No_] AS ChiaveMovimentoPagamento, -Val([Cust_ Ledger Entry.Closed by Amount]) AS ImportoAbbinato, -Val([Cust_ Ledger Entry_1.Closed by Amount]) AS ImportoAbbinato1, "1 Fatt/NC a N Pag" AS collegamento
FROM [Cust_ Ledger Entry] INNER JOIN [Cust_ Ledger Entry] AS [Cust_ Ledger Entry_1] ON [Cust_ Ledger Entry].[Closed by Entry No_]=[Cust_ Ledger Entry_1].[Entry No_]
WHERE ((([Cust_ Ledger Entry_1].[Document Type])=2));

GO

