-- [966] ValutazioneMagazzino_GenerazioneVALB_ModelItem
INSERT INTO [Purch_ Price Model Item] ( [Model Item No_], [Vendor No_], [Starting Date], [Currency Code], [Unit of Measure Code], [Minimum Quantity], [Constant Variable Code], [Variable Code 01], [Variable Code 02], [selling season code], [Ending Date], [Constant Assortment Var_Grp_], [Variable Group 01], [Variable Group 02], [Direct Unit Cost] )
SELECT [Purch_ Price Model Item].[Model Item No_], "VAL B" AS NewVendor, [forms]![principale]![DataCreazioneValoriMagazzino] AS NewDate, "" AS NewCurrency, [Purch_ Price Model Item].[Unit of Measure Code], [Purch_ Price Model Item].[Minimum Quantity], [Purch_ Price Model Item].[Constant Variable Code], [Purch_ Price Model Item].[Variable Code 01], [Purch_ Price Model Item].[Variable Code 02], "" AS [Selling Season Code], [Purch_ Price Model Item].[Ending Date], [Purch_ Price Model Item].[Constant Assortment Var_Grp_], [Purch_ Price Model Item].[Variable Group 01], [Purch_ Price Model Item].[Variable Group 02], IIf([Currency Code]="USD",Round(Val([Direct Unit Cost])/[forms]![principale]![tassodicambiovalutazionemagazzino]*(1-[forms]![principale]![PercentualeSvalutazioneVALB]),2),Round(Val([Direct Unit Cost])*(1-[forms]![principale]![PercentualeSvalutazioneVALB]),2)) AS NewDirectUnitCost
