FROM ((((((((VenditeEPrenotazioniUnioneStatus LEFT JOIN [Sales Line] ON (VenditeEPrenotazioniUnioneStatus.ordineNumero = [Sales Line].[Document No_]) AND (VenditeEPrenotazioniUnioneStatus.OrdineRiga = [Sales Line].[Line No_])) LEFT JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].[Code]) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].[Code]) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_;

