WHERE ((([Reserv__Assign_ Link].[Reserv__Assign_ Type])=1) AND ((Val([Reserved_Assigned Quantity]))<>0) AND (([Reserv__Assign_ Link].Type)=20) AND (([Reserv__Assign_ Link].[Source Type])=5) AND (([Reserv__Assign_ Link].[Selling Season Code])=[forms]![principale]![filtroStagioneprenotazioni]));

