-- [992] VenditeEPrenotazioniUnioneStatus
SELECt statusRiga, ordineNumero, OrdineRiga, [Source Document No_] AS ordineAcquistoTrasferimentoNumero, [Source Line No_] as OrdineAcquistoTrasferimentoRiga,  assortmentQty, pairsQty, [Date Reservation], [Requested Receipt Date], [Promised Receipt Date], [Planned Receipt Date], [Expected Receipt Date], #01/01/1980#  as TransferReceiptDate, SourceLocation, SalesLocation, [Season Code]
FROM [VenditeEPrenotazioni-PrenotatoAcquisto]


union all SELECt statusRiga, ordineNumero, OrdineRiga, "" ,0 , assortmentQty, pairsQty, #01/01/1980#,   #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#, #01/01/1980#, SalesLocation, SalesLocation, [Season Code] 
FROM [VenditeEPrenotazioni-PrenotatoGiacenza]

UNION ALL SELECt statusRiga, ordineNumero, OrdineRiga, [TO Document No_], [TO Line No_], assortmentQty, pairsQty, [Date Reservation],   #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#, TransferReceiptDate, SourceLocation, SalesLocation, [Season Code]
FROM [VenditeEPrenotazioni-PrenotatoTrasferimento];



union all SELECt statusRiga, ordineNumero, OrdineRiga, "" ,0 , assortmentQty, pairsQty, #01/01/1980#,   #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#, #01/01/1980#, SalesLocation, SalesLocation, [Season Code] 
FROM [VenditeEPrenotazioni-InBollaAperta]

union all SELECt statusRiga, ordineNumero, OrdineRiga, "" ,0 , assortmentQty, pairsQty, #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#, #01/01/1980#, SalesLocation, SalesLocation, [Season Code] 
FROM [VenditeEPrenotazioni-InBollaRilasciata]

union all SELECt statusRiga, ordineNumero, OrdineRiga, "" ,0 , assortmentQty, pairsQty, #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#, #01/01/1980#, SalesLocation, SalesLocation, [Season Code]
FROM [VenditeEPrenotazioni-Spedito]

UNION ALL SELECt statusRiga, ordineNumero, OrdineRiga, "" ,0 , assortmentQty, pairsQty, #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#,  #01/01/1980#, #01/01/1980#, SalesLocation, SalesLocation, [Season Code]
FROM [VenditeEPrenotazioni-Scoperto];

GO

-- [993] VenditeSpaccio
SELECT [Item Ledger Entry].[Posting Date], [Item Ledger Entry].[Document No_], [Item Ledger Entry].[Entry Type], [Item Ledger Entry].[Item No_], [VenditeSpaccio-CostiAcquisto].Costo, Item.[Trademark Code] AS marchio, Item.[Season Code] AS stagione, Item.[Model Item No_], [Item Ledger Entry].[Variable Code 01] AS colore, [Item Ledger Entry].[Variable Code 02] AS taglia, Item_1.Description, Item_1.[Description 2], Val([Quantity]) AS quantita
FROM ([Item Ledger Entry] INNER JOIN (Item LEFT JOIN [VenditeSpaccio-CostiAcquisto] ON Item.No_ = [VenditeSpaccio-CostiAcquisto].[Item No_]) ON [Item Ledger Entry].[Item No_] = Item.No_) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_
WHERE ((([Item Ledger Entry].[Posting Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]) AND (([Item Ledger Entry].[Document No_]) Like "vend%") AND (([Item Ledger Entry].[Entry Type])=1));

GO

-- [994] VenditeSpaccio-CostiAcquisto
SELECT [Purchase Price].[Item No_], Max([Purchase Price].[Starting Date]) AS [MaxDiStarting Date], Max(Val([Direct Unit Cost])) AS Costo
FROM [Purchase Price]
GROUP BY [Purchase Price].[Item No_];

GO

-- [995] VenditeTagliaVeloce
SELECT [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name AS SalespersonName, [Sales Header].[Sell-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].[Ship-to City], [Sales Header].No_ AS OrderNo, [Geographical Zone].Description AS GeographicalZone1_Description, [Geographical Zone_1].description AS GeographicalZone2Description, [Sales Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Header].[selling season code] AS Stagione, Item.[LINE CODE], Item.[COLLECTION CODE], Item.DESCRIPTION, Item.[DESCRIPTION 2], [Sales Line].[MODEL ITEM NO_], [Sales Line].[variable CODE 02] AS [size], [Sales Line].[VARIABLE CODE 01] AS COLOR, [Variable Code].Description AS ColorDecription, Item.[PRODUCT SEX], Val([quantity]) AS qty, IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount]))) AS ValueSold, [Sales Line].[DELETE REASON], [DB Suole BePositive].[CODICE SUOLA], [DB Suole BePositive].[COLORE SUOLA]
FROM (((((([Sales Header] INNER JOIN (Item INNER JOIN [Sales Line] ON Item.No_ = [Sales Line].No_) ON ([Sales Header].[Document Type] = [Sales Line].[Document Type]) AND ([Sales Header].No_ = [Sales Line].[Document No_])) LEFT JOIN [Sales Header Extension] ON [Sales Header].No_ = [Sales Header Extension].[Document No_]) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN [Geographical Zone] ON [Sales Header].[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON [Sales Header Extension].[Geographical Zone 2] = [Geographical Zone_1].Code) LEFT JOIN [Variable Code] ON ([Sales Line].[Variable Group 01] = [Variable Code].[Variable Group]) AND ([Sales Line].[Variable Code 01] = [Variable Code].[Variable Code])) LEFT JOIN [DB Suole BePositive] ON ([Sales Line].[Variable Code 01] = [DB Suole BePositive].Color) AND ([Sales Line].[Model Item No_] = [DB Suole BePositive].[Model Item No_])
WHERE ((([Sales Header].[Shortcut Dimension 2 Code])=[forms]![principale]![filtromarchiosourcing]) AND (([Sales Header].[selling season code])=[forms]![principale]![filtroStagionesourcing]) AND (([Sales Line].Type)=2));

GO

-- [996] VendutoCalcoloProiezionePerTaglia
SELECT [VendutoCalcoloProiezionePerTaglia-step1].TrademarkCode, [VendutoCalcoloProiezionePerTaglia-step1].SeasonCode, [VendutoCalcoloProiezionePerTaglia-step1].ProductGender, [VendutoCalcoloProiezionePerTaglia-step1].size, Sum([VendutoCalcoloProiezionePerTaglia-step1].PairsSold) AS PairsSold, Round(Sum([ForecastedPairsByMarket])) AS ForecastedPairsByMarket_
FROM [VendutoCalcoloProiezionePerTaglia-step1]
GROUP BY [VendutoCalcoloProiezionePerTaglia-step1].TrademarkCode, [VendutoCalcoloProiezionePerTaglia-step1].SeasonCode, [VendutoCalcoloProiezionePerTaglia-step1].ProductGender, [VendutoCalcoloProiezionePerTaglia-step1].size;

GO

-- [997] VendutoCalcoloProiezionePerTaglia-step0
SELECT [Sales Header].[Budget No_], Sum(Val([Quantity])) AS PairsSold, [Sales Line].[Variable Code 02] AS [Size], Item.[PRODUCT SEX] AS ProductGender, [Sales Header].[Shortcut Dimension 2 Code] AS [Trademark Code], [Sales Header].[Selling Season Code] AS [Season Code]
FROM ([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) INNER JOIN Item ON [Sales Line].No_ = Item.No_
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=2) AND (([Sales Line].[Delete Reason])="") AND ((Item.[advertising material])=0))
GROUP BY [Sales Header].[Budget No_], [Sales Line].[Variable Code 02], Item.[PRODUCT SEX], [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[Selling Season Code]
HAVING ((([Sales Header].[Shortcut Dimension 2 Code])=[Forms]![principale]![FiltroMarchioSourcing]) AND (([Sales Header].[Selling Season Code])=[forms]![principale]![FiltroStagioneSourcing]));

GO

-- [998] VendutoCalcoloProiezionePerTaglia-step1
SELECT VendutoComprato_FattoriDiPropiezione.TrademarkCode, VendutoComprato_FattoriDiPropiezione.SeasonCode, [VendutoCalcoloProiezionePerTaglia-step0].[Budget No_], [VendutoCalcoloProiezionePerTaglia-step0].ProductGender, [VendutoCalcoloProiezionePerTaglia-step0].size, [VendutoCalcoloProiezionePerTaglia-step0].PairsSold AS PairsSold, (([pairssold]*[fattorePROIEZIONEDIbudget])) AS ForecastedPairsByMarket
FROM VendutoComprato_FattoriDiPropiezione INNER JOIN [VendutoCalcoloProiezionePerTaglia-step0] ON VendutoComprato_FattoriDiPropiezione.BudgetNo_ = [VendutoCalcoloProiezionePerTaglia-step0].[Budget No_];

GO

