INSERT INTO VendutoCompratoProiezioneTabella
SELECT [VendutoCompratoProiezione-preexport].*
FROM [VendutoCompratoProiezione-preexport];

GO

-- [1000] VendutoCompratoProiezione_CreazioneRigheBudgetProiezione
INSERT INTO VendutoComprato_FattoriDiPropiezione ( BudgetNo_, BudgetDescrizione, SeasonCode, TrademarkCode, BudgetType )
