-- [1001] VendutoCompratoProiezioneItem
INSERT INTO VendutoCompratoProiezioneTabella
SELECT [VendutoCompratoProiezioneItem-preexport].*
FROM [VendutoCompratoProiezioneItem-preexport];

GO

-- [1002] VendutoCompratoProiezioneItem-preexport
SELECT Vendor.No_ AS VendorNo_, Vendor.Name AS VendorName, Item.[Trademark Code], Item.[Season Code], Item.[line code], Item.[collection code], Item.[product sex], Item.[product family], [VendutoCompratoProiezioneItem-step11-new-calcoli].No_, Item.Description, Item.[Description 2], [VendutoCompratoProiezioneItem-step11-new-calcoli].[Constant Variable Code] AS ColorCode, [Variable Code].Description AS Color, [VendutoCompratoProiezioneItem-step11-new-calcoli].PairsSold, [VendutoCompratoProiezioneItem-step11-new-calcoli].PairsPurchased, [VendutoCompratoProiezioneItem-step11-new-calcoli].PairsInventory, [VendutoCompratoProiezioneItem-step11-new-calcoli].toBuy, [VendutoCompratoProiezioneItem-step11-new-calcoli].toSell, [VendutoCompratoProiezioneItem-step11-new-calcoli].ForecastedPairsByMarket_, [VendutoCompratoProiezioneItem-step11-new-calcoli].ForecastedPairsByMarketCorrected_, [VendutoCompratoProiezioneItem-step11-new-calcoli].toBuyByBudgetCorrected, [VendutoCompratoProiezioneItem-step11-new-calcoli].toSellByBudgetCorrected, [VendutoCompratoProiezioneItem-step11-new-calcoli].ForecastedPairsFlat, [VendutoCompratoProiezioneItem-step11-new-calcoli].toBuyFlat, [VendutoCompratoProiezioneItem-step11-new-calcoli].toSellFlat, [VendutoCompratoProiezioneItem-Ven-step2-CalcoloIncidenzeCliente].Incidenza, [VendutoCompratoProiezioneItem-Ven-step2-CalcoloIncidenzeCliente].[Bill-to Customer No_], [VendutoCompratoProiezioneItem-Ven-step2-CalcoloIncidenzeCliente].[Bill-to Name], [VendutoCompratoProiezioneItem-Ven-step2-CalcoloIncidenzeCliente].PairsSold_, Immagini.[Linked Document], DatiCarryOverESMU.[Potential Sold Out], DatiCarryOverESMU.[Sold Out], Item.Manufacturer, Vendor_1.Name AS ManufacturerName, DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.MOQ, IIf([ForecastedPairsByMarketCorrected_]>0.95*[MOQ]," * * *",IIf([ForecastedPairsByMarketCorrected_]>0.8*[MOQ]," * * ",IIf([ForecastedPairsByMarketCorrected_]>0.6*[MOQ]," * ","X"))) AS testMOQ
FROM ((([VendutoCompratoProiezioneItem-step11-new-calcoli] LEFT JOIN DatiCarryOverESMU ON ([VendutoCompratoProiezioneItem-step11-new-calcoli].[Constant Variable Code] = DatiCarryOverESMU.[Variable Code 01]) AND ([VendutoCompratoProiezioneItem-step11-new-calcoli].No_ = DatiCarryOverESMU.[Model Item No_])) LEFT JOIN Immagini ON ([VendutoCompratoProiezioneItem-step11-new-calcoli].[Constant Variable Code] = Immagini.[Constant Variable Code]) AND ([VendutoCompratoProiezioneItem-step11-new-calcoli].No_ = Immagini.[Source No_])) INNER JOIN (((Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN [Variable Code] ON (Item.[Variable Group 01] = [Variable Code].[Variable Group]) AND (Item.[Variable Code 01] = [Variable Code].[Variable Code])) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_) ON [VendutoCompratoProiezioneItem-step11-new-calcoli].No_ = Item.No_) LEFT JOIN [VendutoCompratoProiezioneItem-Ven-step2-CalcoloIncidenzeCliente] ON ([VendutoCompratoProiezioneItem-step11-new-calcoli].[Constant Variable Code] = [VendutoCompratoProiezioneItem-Ven-step2-CalcoloIncidenzeCliente].[Constant Variable Code]) AND ([VendutoCompratoProiezioneItem-step11-new-calcoli].No_ = [VendutoCompratoProiezioneItem-Ven-step2-CalcoloIncidenzeCliente].No_);

GO

-- [1003] VendutoCompratoProiezioneItem-step10-new-pivot
SELECT [VendutoCompratoProiezioneItem-step9-new].No_, [VendutoCompratoProiezioneItem-step9-new].[Constant Variable Code], Sum(IIf([sourcetype]="SELL",[PAIRS],0)) AS PairsSold, Sum(IIf([sourcetype]="BUY",[PAIRS],0)) AS PairsPurchased, Sum(IIf([sourcetype]="INVENTORY",[PAIRS],0)) AS PairsInventory, Sum([VendutoCompratoProiezioneItem-step9-new].ForecastedPairsByMarket_) AS ForecastedPairsByMarket_, Sum([VendutoCompratoProiezioneItem-step9-new].ForecastedPairsByMarketCorrected_) AS ForecastedPairsByMarketCorrected_, Sum([VendutoCompratoProiezioneItem-step9-new].ForecastedPairsFlat) AS ForecastedPairsFlat
FROM [VendutoCompratoProiezioneItem-step9-new]
GROUP BY [VendutoCompratoProiezioneItem-step9-new].No_, [VendutoCompratoProiezioneItem-step9-new].[Constant Variable Code];

GO

-- [1004] VendutoCompratoProiezioneItem-step11-new-calcoli
SELECT [VendutoCompratoProiezioneItem-step10-new-pivot].*, IIf([pairssold]-[pairspurchased]-[pairsinventory]>0,[pairssold]-[pairspurchased]-[pairsinventory],0) AS toBuy, IIf([pairssold]-[pairspurchased]-[pairsinventory]<=0,[pairssold]-[pairspurchased]-[pairsinventory],0) AS toSell, IIf([ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory]>0,[ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory],0) AS toBuyByBudgetCorrected, IIf([ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory]<=0,[ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory],0) AS toSellByBudgetCorrected, IIf([ForecastedPairsFlat]-[pairspurchased]-[pairsinventory]>0,[ForecastedPairsFlat]-[pairspurchased]-[pairsinventory],0) AS toBuyFlat, IIf([ForecastedPairsFlat]-[pairspurchased]-[pairsinventory]<=0,[ForecastedPairsFlat]-[pairspurchased]-[pairsinventory],0) AS toSellFlat
FROM [VendutoCompratoProiezioneItem-step10-new-pivot];

GO

-- [1005] VendutoCompratoProiezioneItem-step3-ProiezioniPerBudget
SELECT [VendutoCompratoProiezioneItem-Vendite-step0].[Budget No_], [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code], Sum([VendutoCompratoProiezioneItem-Vendite-step0].PairsSold) AS PairsSold_, Sum([PairsSold])*Max([fattoreproiezionedibudget]) AS PairsForecastByBudget, Sum([PairsSold])*Max([fattoreproiezioneGlobale]) AS PairsForecastGlobal
FROM [VendutoCompratoProiezioneItem-Vendite-step0] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezioneItem-Vendite-step0].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_
GROUP BY [VendutoCompratoProiezioneItem-Vendite-step0].[Budget No_], [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code];

GO

-- [1006] VendutoCompratoProiezioneItem-step4-CalcoloFattCorrettivoGlobale
SELECT Sum([VendutoCompratoProiezioneItem-step3-ProiezioniPerBudget].PairsForecastByBudget) AS SommaDiPairsForecastByBudget, Sum([VendutoCompratoProiezioneItem-step3-ProiezioniPerBudget].PairsForecastGlobal) AS SommaDiPairsForecastGlobal, Sum([PairsForecastGlobal])/Sum([PairsForecastByBudget]) AS FattoreCorrettivoGlobale, VendutoComprato_FattoriDiPropiezione.SeasonCode, VendutoComprato_FattoriDiPropiezione.TrademarkCode, VendutoComprato_FattoriDiPropiezione.BudgetType
FROM [VendutoCompratoProiezioneItem-step3-ProiezioniPerBudget] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezioneItem-step3-ProiezioniPerBudget].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_
GROUP BY VendutoComprato_FattoriDiPropiezione.SeasonCode, VendutoComprato_FattoriDiPropiezione.TrademarkCode, VendutoComprato_FattoriDiPropiezione.BudgetType;

GO

-- [1007] VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato
SELECT [VendutoCompratoProiezioneItem-Vendite-step0].[Budget No_], [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code], Sum([VendutoCompratoProiezioneItem-Vendite-step0].PairsSold) AS PairsSold_, Sum([pairssold]*[fattorePROIEZIONEDIbudget]) AS ForecastedPairsByMarket, Sum([pairssold]*[fattorePROIEZIONEdibudget])*First([FATTORECORRETTIVOGLOBALE]) AS ForecastedPairsByMarketCorrected
FROM ([VendutoCompratoProiezioneItem-Vendite-step0] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezioneItem-Vendite-step0].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_) INNER JOIN [VendutoCompratoProiezioneItem-step4-CalcoloFattCorrettivoGlobale] ON ([VendutoCompratoProiezioneItem-step4-CalcoloFattCorrettivoGlobale].BudgetType = VendutoComprato_FattoriDiPropiezione.BudgetType) AND ([VendutoCompratoProiezioneItem-Vendite-step0].[Season Code] = [VendutoCompratoProiezioneItem-step4-CalcoloFattCorrettivoGlobale].SeasonCode) AND ([VendutoCompratoProiezioneItem-Vendite-step0].[Trademark Code] = [VendutoCompratoProiezioneItem-step4-CalcoloFattCorrettivoGlobale].TrademarkCode)
GROUP BY [VendutoCompratoProiezioneItem-Vendite-step0].[Budget No_], [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code];

GO

-- [1008] VendutoCompratoProiezioneItem-step6-VenditeProiettate
SELECT [VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato].No_, [VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato].[Constant Variable Code], Sum([VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato].PairsSold_) AS PairsSold, Round(Sum([ForecastedPairsByMarket])) AS ForecastedPairsByMarket_, Round(Sum([ForecastedPairsByMarketCorrected])) AS ForecastedPairsByMarketCorrected_, Round(Sum([pairssold_])*First([fattoreproiezioneglobale])) AS ForecastedPairsFlat
FROM [VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_
GROUP BY [VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato].No_, [VendutoCompratoProiezioneItem-step5-VendutoProiettatoPerMercato].[Constant Variable Code];

GO

-- [1009] VendutoCompratoProiezioneItem-step7-Comprato
SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].[Unit of Measure], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Line].[Delete Reason], Val([Quantity]) AS QuantityPurchased, Val([No_ of Pairs]) AS PairsPurchased, Item.[TRADEMARK CODE], [Purchase Line].[SEASON CODE]
FROM [Purchase Line] INNER JOIN Item ON [Purchase Line].No_ = Item.No_
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=19) AND (([Purchase Line].[Delete Reason])="") AND ((Item.[TRADEMARK CODE])=[FiltroMarchioVendutoComprato]) AND (([Purchase Line].[SEASON CODE])=[FiltroStagioneVendutoComprato]));

GO

-- [1010] VendutoCompratoProiezioneItem-step8-bis-giacenza
SELECT [Item Ledger Entry].[Model Item No_] AS No_, [Item Ledger Entry].[Variable Code 01], Sum(Val([quantity])) AS PairsInventory
FROM ([Item Ledger Entry] INNER JOIN Location ON [Item Ledger Entry].[Location Code] = Location.Code) INNER JOIN Item ON [Item Ledger Entry].[Model Item No_] = Item.No_
WHERE (((Location.[Enable to Purchase Run])=True) AND ((Item.[season code])=[FiltroSTAGIONEVendutoComprato]) AND ((Item.[Trademark Code])=[FiltroMarchioVendutoComprato]))
GROUP BY [Item Ledger Entry].[Model Item No_], [Item Ledger Entry].[Variable Code 01]
HAVING (((Sum(Val([quantity])))<>0));

GO

-- [1011] VendutoCompratoProiezioneItem-step8-CompratoByAricoloColore
SELECT [VendutoCompratoProiezioneItem-step7-Comprato].No_, [VendutoCompratoProiezioneItem-step7-Comprato].[Constant Variable Code], Sum([VendutoCompratoProiezioneItem-step7-Comprato].PairsPurchased) AS PairsPurchased
FROM [VendutoCompratoProiezioneItem-step7-Comprato]
GROUP BY [VendutoCompratoProiezioneItem-step7-Comprato].No_, [VendutoCompratoProiezioneItem-step7-Comprato].[Constant Variable Code];

GO

-- [1012] VendutoCompratoProiezioneItem-step9-new
SELECT "SELL" as SourceType, No_, [Constant Variable Code], PairsSold as Pairs, ForecastedPairsByMarket_, ForecastedPairsByMarketCorrected_, ForecastedPairsFlat
FROM [VendutoCompratoProiezioneItem-step6-VenditeProiettate];

Union all select "BUY" as SourceType, No_, [Constant Variable Code], PairsPurchased as Pairs, 0,0,0
FROM [VendutoCompratoProiezioneItem-step8-CompratoByAricoloColore]

UNION ALL select "INVENTORY" as SourceType, No_, [Variable Code 01], PairsInventory as Pairs, 0,0,0
FROM [VendutoCompratoProiezioneItem-step8-bis-giacenza];

GO

-- [1013] VendutoCompratoProiezioneItem-Vendite-step0
SELECT [Sales Header].[Budget No_], [Sales Header].[Sell-to Customer No_], [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Line].[Document Type], [Sales Line].Type, [Sales Header].No_ AS OrderNo, [Sales Line].[Line No_], Val([Quantity]) AS QuantitySold, [Sales Line].[Unit of Measure], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], Val([No_ of Pairs]) AS PairsSold, Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Header].[Salesperson Code], [Sales Header].[Shortcut Dimension 2 Code] AS [Trademark Code], [Sales Header].[Selling Season Code] AS [Season Code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=19) AND (([Sales Line].[Delete Reason])="") AND (([Sales Header].[Shortcut Dimension 2 Code])=[FiltroMarchioVendutoComprato]) AND (([Sales Header].[Selling Season Code])=[FiltroStagioneVendutoComprato]))
ORDER BY [Sales Header].No_;

GO

-- [1014] VendutoCompratoProiezioneItem-Vendite-step1-TotaliPerArticolo
SELECT [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code], Sum([VendutoCompratoProiezioneItem-Vendite-step0].PairsSold) AS TotalPairsByArticleColor
FROM [VendutoCompratoProiezioneItem-Vendite-step0]
GROUP BY [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code];

GO

-- [1015] VendutoCompratoProiezioneItem-Ven-step2a-CalcoloIncidenzeCliente
SELECT [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code], Sum([PairsSold])/Max([TotalPairsByArticleColor]) AS Incidenza, [VendutoCompratoProiezioneItem-Vendite-step0].[Sell-to Customer No_], [VendutoCompratoProiezioneItem-Vendite-step0].[Bill-to Customer No_], [VendutoCompratoProiezioneItem-Vendite-step0].[Bill-to Name], Sum([VendutoCompratoProiezioneItem-Vendite-step0].PairsSold) AS PairsSold_, [VendutoCompratoProiezioneItem-Vendite-step1-TotaliPerArticolo].TotalPairsByArticleColor, [VendutoCompratoProiezioneItem-Vendite-step0].[Trademark Code], [VendutoCompratoProiezioneItem-Vendite-step0].[Season Code]
FROM [VendutoCompratoProiezioneItem-Vendite-step0] INNER JOIN [VendutoCompratoProiezioneItem-Vendite-step1-TotaliPerArticolo] ON ([VendutoCompratoProiezioneItem-Vendite-step0].No_ = [VendutoCompratoProiezioneItem-Vendite-step1-TotaliPerArticolo].No_) AND ([VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code] = [VendutoCompratoProiezioneItem-Vendite-step1-TotaliPerArticolo].[Constant Variable Code])
GROUP BY [VendutoCompratoProiezioneItem-Vendite-step0].No_, [VendutoCompratoProiezioneItem-Vendite-step0].[Constant Variable Code], [VendutoCompratoProiezioneItem-Vendite-step0].[Sell-to Customer No_], [VendutoCompratoProiezioneItem-Vendite-step0].[Bill-to Customer No_], [VendutoCompratoProiezioneItem-Vendite-step0].[Bill-to Name], [VendutoCompratoProiezioneItem-Vendite-step1-TotaliPerArticolo].TotalPairsByArticleColor, [VendutoCompratoProiezioneItem-Vendite-step0].[Trademark Code], [VendutoCompratoProiezioneItem-Vendite-step0].[Season Code]
HAVING (((Sum([PairsSold])/Max([TotalPairsByArticleColor]))>0.35))
