-- [1023] VendutoCompratoProiezione-step3-ProiezioniPerBudget
SELECT [VendutoCompratoProiezione-Vendite-step0].[Budget No_], [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code], Sum([VendutoCompratoProiezione-Vendite-step0].PairsSold) AS PairsSold_, Sum([PairsSold])*Max([fattoreproiezionedibudget]) AS PairsForecastByBudget, Sum([PairsSold])*Max([fattoreproiezioneGlobale]) AS PairsForecastGlobal
FROM [VendutoCompratoProiezione-Vendite-step0] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezione-Vendite-step0].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_
GROUP BY [VendutoCompratoProiezione-Vendite-step0].[Budget No_], [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code];

GO

-- [1024] VendutoCompratoProiezione-step4-CalcoloFattoreCorrettivoGlobale
SELECT Sum([VendutoCompratoProiezione-step3-ProiezioniPerBudget].PairsForecastByBudget) AS SommaDiPairsForecastByBudget, Sum([VendutoCompratoProiezione-step3-ProiezioniPerBudget].PairsForecastGlobal) AS SommaDiPairsForecastGlobal, Sum([PairsForecastGlobal])/Sum([PairsForecastByBudget]) AS FattoreCorrettivoGlobale, VendutoComprato_FattoriDiPropiezione.SeasonCode, VendutoComprato_FattoriDiPropiezione.TrademarkCode, VendutoComprato_FattoriDiPropiezione.BudgetType
FROM [VendutoCompratoProiezione-step3-ProiezioniPerBudget] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezione-step3-ProiezioniPerBudget].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_
GROUP BY VendutoComprato_FattoriDiPropiezione.SeasonCode, VendutoComprato_FattoriDiPropiezione.TrademarkCode, VendutoComprato_FattoriDiPropiezione.BudgetType;

GO

-- [1025] VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato
SELECT [VendutoCompratoProiezione-Vendite-step0].[Budget No_], [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code], Sum([VendutoCompratoProiezione-Vendite-step0].PairsSold) AS PairsSold_, Sum([pairssold]*[fattorePROIEZIONEDIbudget]) AS ForecastedPairsByMarket, Sum([pairssold]*[fattorePROIEZIONEdibudget])*First([FATTORECORRETTIVOGLOBALE]) AS ForecastedPairsByMarketCorrected
FROM ([VendutoCompratoProiezione-Vendite-step0] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezione-Vendite-step0].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_) INNER JOIN [VendutoCompratoProiezione-step4-CalcoloFattoreCorrettivoGlobale] ON ([VendutoCompratoProiezione-step4-CalcoloFattoreCorrettivoGlobale].BudgetType = VendutoComprato_FattoriDiPropiezione.BudgetType) AND ([VendutoCompratoProiezione-Vendite-step0].[Season Code] = [VendutoCompratoProiezione-step4-CalcoloFattoreCorrettivoGlobale].SeasonCode) AND ([VendutoCompratoProiezione-Vendite-step0].[Trademark Code] = [VendutoCompratoProiezione-step4-CalcoloFattoreCorrettivoGlobale].TrademarkCode)
GROUP BY [VendutoCompratoProiezione-Vendite-step0].[Budget No_], [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code];

GO

