SELECT [VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato].No_, [VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato].[Constant Variable Code], Sum([VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato].PairsSold_) AS PairsSold, Round(Sum([ForecastedPairsByMarket])) AS ForecastedPairsByMarket_, Round(Sum([ForecastedPairsByMarketCorrected])) AS ForecastedPairsByMarketCorrected_, Round(Sum([pairssold_])*First([fattoreproiezioneglobale])) AS ForecastedPairsFlat
FROM [VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato] INNER JOIN VendutoComprato_FattoriDiPropiezione ON [VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato].[Budget No_] = VendutoComprato_FattoriDiPropiezione.BudgetNo_
GROUP BY [VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato].No_, [VendutoCompratoProiezione-step5-VendutoProiettatoPerMercato].[Constant Variable Code];

GO

-- [1027] VendutoCompratoProiezione-step7-Comprato
SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].[Unit of Measure], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Line].[Delete Reason], Val([Quantity]) AS QuantityPurchased, Val([No_ of Pairs]) AS PairsPurchased, Item.[TRADEMARK CODE], [Purchase Line].[SEASON CODE]
FROM [Purchase Line] INNER JOIN Item ON [Purchase Line].No_ = Item.No_
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=20) AND (([Purchase Line].[Delete Reason])="") AND ((Item.[TRADEMARK CODE])=[FiltroMarchioVendutoComprato]) AND (([Purchase Line].[SEASON CODE])=[FiltroStagioneVendutoComprato]));

GO

-- [1028] VendutoCompratoProiezione-step8-bis-giacenza
SELECT [Assortment Ledger Entry].[Model Item No_] AS No_, [Assortment Ledger Entry].[Constant Variable Code], Sum(Val([quantity])*[assortmentquantity]) AS PairsInventory
FROM (([Assortment Ledger Entry] INNER JOIN Location ON [Assortment Ledger Entry].[Location Code] = Location.Code) INNER JOIN AssortimentiQuantita ON ([Assortment Ledger Entry].[Assortment Code] = AssortimentiQuantita.[Assortment Code]) AND ([Assortment Ledger Entry].[Assortment Variable Group] = AssortimentiQuantita.[Variable Group])) INNER JOIN Item ON [Assortment Ledger Entry].[Model Item No_] = Item.No_
WHERE (((Location.[Enable to Purchase Run])=True) AND (([Assortment Ledger Entry].[season code])=[FiltroSTAGIONEVendutoComprato]) AND ((Item.[Trademark Code])=[FiltroMarchioVendutoComprato]))
GROUP BY [Assortment Ledger Entry].[Model Item No_], [Assortment Ledger Entry].[Constant Variable Code]
HAVING (((Sum(Val([quantity])*[assortmentquantity]))<>0));

GO

