FROM [VendutoCompratoProiezione-step6-VenditeProiettate] INNER JOIN [VendutoCompratoProiezione-step8-CompratoByAricoloColore] ON ([VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code] = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].[Constant Variable Code]) AND ([VendutoCompratoProiezione-step6-VenditeProiettate].No_ = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_);

GO

-- [1031] VendutoCompratoProiezione-step9-new
SELECT "SELL" as SourceType, No_, [Constant Variable Code], PairsSold as Pairs, ForecastedPairsByMarket_, ForecastedPairsByMarketCorrected_, ForecastedPairsFlat
