-- [1032] VendutoCompratoProiezione-step9-soloAcq_BUTTARE OBSOLETA
SELECT [VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_, [VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code], 0 AS PairsSold, [VendutoCompratoProiezione-step8-CompratoByAricoloColore].PairsPurchased, 0 AS ForecastedPairsByMarket_, 0 AS ForecastedPairsByMarketCorrected_, 0 AS ForecastedPairsFlat, 0 AS toBuy, [VendutoCompratoProiezione-step8-CompratoByAricoloColore].pairspurchased AS toSell, 0 AS toBuyByBudgetCorrected, [VendutoCompratoProiezione-step8-CompratoByAricoloColore].pairspurchased AS toSellByBudgetCorrected, 0 AS toBuyFlat, [VendutoCompratoProiezione-step8-CompratoByAricoloColore].pairspurchased AS toSellFlat
FROM [VendutoCompratoProiezione-step6-VenditeProiettate] RIGHT JOIN [VendutoCompratoProiezione-step8-CompratoByAricoloColore] ON ([VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code] = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].[Constant Variable Code]) AND ([VendutoCompratoProiezione-step6-VenditeProiettate].No_ = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_)
WHERE ((([VendutoCompratoProiezione-step6-VenditeProiettate].No_) Is Null));

GO

-- [1033] VendutoCompratoProiezione-step9-soloVend_BUTTARE OBSOLETA
SELECT [VendutoCompratoProiezione-step6-VenditeProiettate].No_, [VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code], [VendutoCompratoProiezione-step6-VenditeProiettate].PairsSold, 0 AS PairsPurchased, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsByMarket_, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsByMarketCorrected_, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsFlat, [VendutoCompratoProiezione-step6-VenditeProiettate].pairssold AS toBuy, 0 AS toSell, [VendutoCompratoProiezione-step6-VenditeProiettate].[ForecastedPairsByMarketCorrected_] AS toBuyByBudgetCorrected, 0 AS toSellByBudgetCorrected, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsFlat AS toBuyFlat, 0 AS toSellFlat
FROM [VendutoCompratoProiezione-step6-VenditeProiettate] LEFT JOIN [VendutoCompratoProiezione-step8-CompratoByAricoloColore] ON ([VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code] = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].[Constant Variable Code]) AND ([VendutoCompratoProiezione-step6-VenditeProiettate].No_ = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_)
WHERE ((([VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_) Is Null));

GO

-- [1034] VendutoCompratoProiezioneTabella_Duplicati
SELECT First(VendutoCompratoProiezioneTabella.No_) AS No_Campo, First(VendutoCompratoProiezioneTabella.ColorCode) AS ColorCodeCampo, Count(VendutoCompratoProiezioneTabella.No_) AS NumDuplicati
