-- [1035] VendutoCompratoProiezione-Vendite-step0
SELECT [Sales Header].[Budget No_], [Sales Header].[Sell-to Customer No_], [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Line].[Document Type], [Sales Line].Type, [Sales Header].No_ AS OrderNo, [Sales Line].[Line No_], Val([Quantity]) AS QuantitySold, [Sales Line].[Unit of Measure], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], Val([No_ of Pairs]) AS PairsSold, Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Header].[Salesperson Code], [Sales Header].[Shortcut Dimension 2 Code] AS [Trademark Code], [Sales Header].[Selling Season Code] AS [Season Code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20) AND (([Sales Line].[Delete Reason])="") AND (([Sales Header].[Shortcut Dimension 2 Code])=[FiltroMarchioVendutoComprato]) AND (([Sales Header].[Selling Season Code])=[FiltroStagioneVendutoComprato]))
ORDER BY [Sales Header].No_;

GO

-- [1036] VendutoCompratoProiezione-Vendite-step1-TotaliPerArticolo
SELECT [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code], Sum([VendutoCompratoProiezione-Vendite-step0].PairsSold) AS TotalPairsByArticleColor
FROM [VendutoCompratoProiezione-Vendite-step0]
GROUP BY [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code];

GO

-- [1037] VendutoCompratoProiezione-Vendite-step2a-CalcoloIncidenzeCliente
SELECT [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code], Sum([PairsSold])/Max([TotalPairsByArticleColor]) AS Incidenza, [VendutoCompratoProiezione-Vendite-step0].[Sell-to Customer No_], [VendutoCompratoProiezione-Vendite-step0].[Bill-to Customer No_], [VendutoCompratoProiezione-Vendite-step0].[Bill-to Name], Sum([VendutoCompratoProiezione-Vendite-step0].PairsSold) AS PairsSold_, [VendutoCompratoProiezione-Vendite-step1-TotaliPerArticolo].TotalPairsByArticleColor, [VendutoCompratoProiezione-Vendite-step0].[Trademark Code], [VendutoCompratoProiezione-Vendite-step0].[Season Code]
FROM [VendutoCompratoProiezione-Vendite-step0] INNER JOIN [VendutoCompratoProiezione-Vendite-step1-TotaliPerArticolo] ON ([VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code] = [VendutoCompratoProiezione-Vendite-step1-TotaliPerArticolo].[Constant Variable Code]) AND ([VendutoCompratoProiezione-Vendite-step0].No_ = [VendutoCompratoProiezione-Vendite-step1-TotaliPerArticolo].No_)
GROUP BY [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code], [VendutoCompratoProiezione-Vendite-step0].[Sell-to Customer No_], [VendutoCompratoProiezione-Vendite-step0].[Bill-to Customer No_], [VendutoCompratoProiezione-Vendite-step0].[Bill-to Name], [VendutoCompratoProiezione-Vendite-step1-TotaliPerArticolo].TotalPairsByArticleColor, [VendutoCompratoProiezione-Vendite-step0].[Trademark Code], [VendutoCompratoProiezione-Vendite-step0].[Season Code]
HAVING (((Sum([PairsSold])/Max([TotalPairsByArticleColor]))>0.35))
ORDER BY [VendutoCompratoProiezione-Vendite-step0].No_, [VendutoCompratoProiezione-Vendite-step0].[Constant Variable Code], Sum([PairsSold])/Max([TotalPairsByArticleColor]) DESC , [VendutoCompratoProiezione-Vendite-step0].[Sell-to Customer No_], Sum([VendutoCompratoProiezione-Vendite-step0].PairsSold) DESC;

GO

-- [1038] VendutoCompratoProiezione-Vendite-step2b-CalcoloIncidenzaCliente
SELECT [VendutoCompratoProiezione-Vendite-step2a-CalcoloIncidenzeCliente].No_, [VendutoCompratoProiezione-Vendite-step2a-CalcoloIncidenzeCliente].[Constant Variable Code], Max([VendutoCompratoProiezione-Vendite-step2a-CalcoloIncidenzeCliente].Incidenza) AS MaxDiIncidenza
FROM [VendutoCompratoProiezione-Vendite-step2a-CalcoloIncidenzeCliente]
GROUP BY [VendutoCompratoProiezione-Vendite-step2a-CalcoloIncidenzeCliente].No_, [VendutoCompratoProiezione-Vendite-step2a-CalcoloIncidenzeCliente].[Constant Variable Code];

GO

