SELECT Count([No_]) AS ConteggioSPD, WMS_AnalisiStatusDDT_Detail.Status, WMS_AnalisiStatusDDT_Detail.StatusWHSE, Sum(WMS_AnalisiStatusDDT_Detail.qty) AS SommaDiqty
