-- [1047] WMS_AnalisiStatusDDT_Detail
SELECT [DDT_Picking Header].No_, [DDT_Picking Header].[Bill-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].Status, IIf(IsNull([Source No_]),"WHSE_N","WHSE_Y") AS StatusWHSE, Sum((Val([ddt_picking line.no_ of pairs]))) AS qty, [DDT_Picking Header].[Selling Season Code], [DDT_Picking Header].[Shortcut Dimension 2 Code] AS TrademarkCode, WMS_AnalisiStatusDDT_step0.No_ AS WarehouseNo, WMS_AnalisiStatusDDT_step0.[Warehouse Speciality Code], WMS_AnalisiStatusDDT_step0.[Warehouse Note], WMS_AnalisiStatusDDT_step0.[Special Requests], [DDT_Picking Line].type
FROM (WMS_AnalisiStatusDDT_step0 RIGHT JOIN [DDT_Picking Header] ON WMS_AnalisiStatusDDT_step0.[Source No_] = [DDT_Picking Header].No_) LEFT JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]
GROUP BY [DDT_Picking Header].No_, [DDT_Picking Header].[Bill-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Header].Status, IIf(IsNull([Source No_]),"WHSE_N","WHSE_Y"), [DDT_Picking Header].[Selling Season Code], [DDT_Picking Header].[Shortcut Dimension 2 Code], WMS_AnalisiStatusDDT_step0.No_, WMS_AnalisiStatusDDT_step0.[Warehouse Speciality Code], WMS_AnalisiStatusDDT_step0.[Warehouse Note], WMS_AnalisiStatusDDT_step0.[Special Requests], [DDT_Picking Header].[Document Type], [DDT_Picking Line].type
HAVING ((([DDT_Picking Header].Status)=0 Or ([DDT_Picking Header].Status)=1) AND (([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Line].type)=20 Or ([DDT_Picking Line].type)=19));

GO

-- [1048] WMS_AnalisiStatusDDT_step0
SELECT [Warehouse Shipment Line].[Source No_], [Warehouse Shipment Line].No_, [Warehouse Shipment Header].[Special Requests], [Warehouse Shipment Header].[Warehouse Speciality Code], [Warehouse Shipment Header].[Warehouse Note]
FROM [Warehouse Shipment Header] INNER JOIN [Warehouse Shipment Line] ON [Warehouse Shipment Header].No_ = [Warehouse Shipment Line].No_
GROUP BY [Warehouse Shipment Line].[Source No_], [Warehouse Shipment Line].No_, [Warehouse Shipment Header].[Special Requests], [Warehouse Shipment Header].[Warehouse Speciality Code], [Warehouse Shipment Header].[Warehouse Note]
HAVING ((([Warehouse Shipment Line].[Source No_]) Like "SPD*"));

GO

-- [1049] WMS_ArticoliCosmos_RunMisti
SELECT WMS_ArticoliCosmos_RunMisti_step2.[Bill-to Customer No_], WMS_ArticoliCosmos_RunMisti_step2.[Bill-to Name], WMS_ArticoliCosmos_RunMisti_step2.[Document No_], WMS_ArticoliCosmos_RunMisti_step2.[Item No_], WMS_ArticoliCosmos_RunMisti_step2.[Constant Variable Code], WMS_ArticoliCosmos_RunMisti_step2.qualityLevel, Sum(WMS_ArticoliCosmos_RunMisti_step2.qty) AS paia
FROM WMS_ArticoliCosmos_RunMisti_step2
GROUP BY WMS_ArticoliCosmos_RunMisti_step2.[Bill-to Customer No_], WMS_ArticoliCosmos_RunMisti_step2.[Bill-to Name], WMS_ArticoliCosmos_RunMisti_step2.[Document No_], WMS_ArticoliCosmos_RunMisti_step2.[Item No_], WMS_ArticoliCosmos_RunMisti_step2.[Constant Variable Code], WMS_ArticoliCosmos_RunMisti_step2.qualityLevel;

GO

-- [1050] WMS_ArticoliCosmos_RunMisti_step0_BUTTA
SELECT [Purchase Line].[Season Code], [Purchase Line].[Buy-from Vendor No_], [Purchase Line].[Shortcut Dimension 2 Code], [Purchase Line].[Document No_], [Purchase Line].No_, Item.[Description 2], [Purchase Line].[Constant Variable Code], Sum(Val([NO_ OF PAIRS])) AS PAIA
FROM [Purchase Line] INNER JOIN Item ON [Purchase Line].No_ = Item.No_
GROUP BY [Purchase Line].[Season Code], [Purchase Line].[Buy-from Vendor No_], [Purchase Line].[Shortcut Dimension 2 Code], [Purchase Line].[Document No_], [Purchase Line].No_, Item.[Description 2], [Purchase Line].[Constant Variable Code], [Purchase Line].Type, [Purchase Line].[DELETE REASON]
HAVING ((([Purchase Line].[Season Code])="I25") AND (([Purchase Line].[Shortcut Dimension 2 Code])="NAPA") AND (([Purchase Line].[Document No_])="ODA-24-00116" Or ([Purchase Line].[Document No_])="ODA-24-00120") AND (([Purchase Line].Type)=20) AND (([Purchase Line].[DELETE REASON])=""));

GO

-- [1051] WMS_ArticoliCosmos_RunMisti_step1
SELECT [DDT_Picking Header].[Document Type], [DDT_Picking Line].[Sell-to Customer No_], [DDT_Picking Header].[Bill-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Line].[Document No_], [DDT_Picking Line].[Line No_], [DDT_Picking Line].No_, [DDT_Picking Line].[Constant Variable Code], [DDT_Picking Header].STATUS
FROM [DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON [DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_
WHERE ((([DDT_Picking Header].[Document Type])=0) AND (([DDT_Picking Line].No_)="NP0A88XV"));

GO

-- [1052] WMS_ArticoliCosmos_RunMisti_step2
SELECT WMS_ArticoliCosmos_RunMisti_step1.[Sell-to Customer No_], WMS_ArticoliCosmos_RunMisti_step1.[Bill-to Customer No_], WMS_ArticoliCosmos_RunMisti_step1.[Bill-to Name], WMS_ArticoliCosmos_RunMisti_step1.[Document No_], WMS_ArticoliCosmos_RunMisti_step1.[Line No_], [Registered Whse_ Activity Line].[Item No_], [Registered Whse_ Activity Line].[Constant Variable Code], [Unique Identifier Pst_ Docnts].Code, Val([item identifier.No_ of Pairs]) AS qty, IIf(Left$([item identifier.code],8)="F2400116" Or Left$([item identifier.code],8)="F2400120","FIRST","SECOND") AS qualityLevel
FROM (([Item Identifier] INNER JOIN ([Unique Identifier Pst_ Docnts] INNER JOIN [Registered Whse_ Activity Line] ON ([Unique Identifier Pst_ Docnts].[Line No_] = [Registered Whse_ Activity Line].[Line No_]) AND ([Unique Identifier Pst_ Docnts].No_ = [Registered Whse_ Activity Line].No_)) ON [Item Identifier].Code = [Unique Identifier Pst_ Docnts].Code) INNER JOIN [Registered Whse_ Activity Hdr_] ON [Registered Whse_ Activity Line].No_ = [Registered Whse_ Activity Hdr_].No_) INNER JOIN WMS_ArticoliCosmos_RunMisti_step1 ON ([Registered Whse_ Activity Line].[Link To Source Line No_] = WMS_ArticoliCosmos_RunMisti_step1.[Line No_]) AND ([Registered Whse_ Activity Line].[Link To Source No_] = WMS_ArticoliCosmos_RunMisti_step1.[Document No_])
WHERE ((([Registered Whse_ Activity Line].[Item No_])="NP0A88XV") AND (([Registered Whse_ Activity Hdr_].[Whse_ Phase Code])="OUT.PRE") AND (([Registered Whse_ Activity Line].[Action Type])=2));

GO

-- [1053] WMS_CheckSpedWhseDDTMultipliCliente
SELECT WMS_CheckSpedWhseDDTMultipliCliente_Step01.No_, WMS_CheckSpedWhseDDTMultipliCliente_Step01.[Warehouse Note], [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Ship-to Code], Count([DDT_Picking Header].No_) AS ConteggioDiNo_
FROM [DDT_Picking Header] INNER JOIN WMS_CheckSpedWhseDDTMultipliCliente_Step01 ON [DDT_Picking Header].No_ = WMS_CheckSpedWhseDDTMultipliCliente_Step01.[Source No_]
GROUP BY WMS_CheckSpedWhseDDTMultipliCliente_Step01.No_, WMS_CheckSpedWhseDDTMultipliCliente_Step01.[Warehouse Note], [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Ship-to Code]
HAVING (((Count([DDT_Picking Header].No_))>1));

