FROM (WMS_UltimaCollocazione_Step5 INNER JOIN [Item Identifier] ON WMS_UltimaCollocazione_Step5.Code = [Item Identifier].Code) INNER JOIN Item ON [Item Identifier].[Item No_] = Item.No_;

