-- [1082] WMS_UltimaCollocazione_Step1_Journal
SELECT "Journal" AS WELineType, [Warehouse Entry].[Item No_], [Warehouse Entry].[Constant Variable Code], [Warehouse Entry].[Assortment Code], [Warehouse Entry].[Journal Batch Name] AS TestataWE, [Warehouse Entry].[Line No_] AS RigaWE, [Unique Identifier Pst_ Docnts].Code, [Warehouse Entry].[Entry No_], [Warehouse Entry].[Location Code], [Warehouse Entry].[Bin Code]
FROM ([Unique Identifier Pst_ Docnts] INNER JOIN [Warehouse Entry] ON ([Unique Identifier Pst_ Docnts].[Line No_] = [Warehouse Entry].[Line No_]) AND ([Unique Identifier Pst_ Docnts].[Journal Batch Name] = [Warehouse Entry].[Journal Batch Name])) INNER JOIN [Item Identifier] ON ([Item Identifier].[Assortment Code] = [Warehouse Entry].[Assortment Code]) AND ([Item Identifier].[Constant Variable Code] = [Warehouse Entry].[Constant Variable Code]) AND ([Item Identifier].[Item No_] = [Warehouse Entry].[Item No_]) AND ([Unique Identifier Pst_ Docnts].Code = [Item Identifier].Code);

GO

-- [1083] WMS_UltimaCollocazione_Step2_Docs
SELECT "DOCS" AS WELineType, [Warehouse Entry].[Item No_], [Warehouse Entry].[Constant Variable Code], [Warehouse Entry].[Assortment Code], [Warehouse Entry].[Source No_] AS TestataWE, [Warehouse Entry].[Source Line No_] AS RigaWE, [Unique Identifier Pst_ Docnts_1].Code, [Warehouse Entry].[Entry No_], [Warehouse Entry].[Location Code], [Warehouse Entry].[Bin Code], Val([warehouse entry.quantity]) AS qty
FROM ([Unique Identifier Pst_ Docnts] AS [Unique Identifier Pst_ Docnts_1] INNER JOIN [Registered Whse_ Activity Line] ON ([Unique Identifier Pst_ Docnts_1].[Line No_] = [Registered Whse_ Activity Line].[Line No_]) AND ([Unique Identifier Pst_ Docnts_1].No_ = [Registered Whse_ Activity Line].No_)) INNER JOIN [Warehouse Entry] ON ([Registered Whse_ Activity Line].[Bin Code] = [Warehouse Entry].[Bin Code]) AND ([Registered Whse_ Activity Line].[Whse_ Document No_] = [Warehouse Entry].[Whse_ Document No_]) AND ([Registered Whse_ Activity Line].[Whse_ Document Type] = [Warehouse Entry].[Whse_ Document Type]) AND ([Registered Whse_ Activity Line].[Whse_ Document Line No_] = [Warehouse Entry].[Whse_ Document Line No_])
WHERE ((([Registered Whse_ Activity Line].[Action Type])=2));

GO

-- [1084] WMS_UltimaCollocazione_Step3_Union
SELECT WeLineType, [Item No_], [Constant Variable Code], [Assortment Code], TestataWE, RigaWE, Code, [Entry No_], [Location Code],  [Bin Code]
FROM WMS_UltimaCollocazione_Step1_Journal;


UNION ALL SELECT WeLineType, [Item No_], [Constant Variable Code], [Assortment Code], TestataWE, RigaWE, Code, [Entry No_], [Location Code], [Bin Code]
FROM WMS_UltimaCollocazione_Step2_Docs;

GO

-- [1085] WMS_UltimaCollocazione_Step4_LastEntry
