WHERE ((([Unique Identifier Pst_ Docnts].[Activity Type])=1) AND (([Registered Whse_ Activity Hdr_].[Whse_ Activity No_])="WSTW-2500077"))
ORDER BY [Unique Identifier Pst_ Docnts].No_ DESC;

