FROM (WMS_WarehouseEntry_Errate_step0 LEFT JOIN [Warehouse Entry] ON (WMS_WarehouseEntry_Errate_step0.[Assortment Code] = [Warehouse Entry].[Assortment Code]) AND (WMS_WarehouseEntry_Errate_step0.[Constant Variable Code] = [Warehouse Entry].[Constant Variable Code]) AND (WMS_WarehouseEntry_Errate_step0.[Item No_] = [Warehouse Entry].[Item No_]) AND (WMS_WarehouseEntry_Errate_step0.RigaWE = [Warehouse Entry].[Line No_]) AND (WMS_WarehouseEntry_Errate_step0.TestataWE = [Warehouse Entry].[Journal Batch Name])) LEFT JOIN WMS_WarehouseEntry_Errate_step1 ON ([Warehouse Entry].[Assortment Code] = WMS_WarehouseEntry_Errate_step1.[Assortment Code]) AND ([Warehouse Entry].[Constant Variable Code] = WMS_WarehouseEntry_Errate_step1.[Constant Variable Code]) AND ([Warehouse Entry].[Item No_] = WMS_WarehouseEntry_Errate_step1.[Item No_]) AND ([Warehouse Entry].[Line No_] = WMS_WarehouseEntry_Errate_step1.[Line No_]) AND ([Warehouse Entry].[Journal Batch Name] = WMS_WarehouseEntry_Errate_step1.[Journal Batch Name]);

GO

-- [1096] WMS_WarehouseEntry_Errate_step0
SELECT "Journal" AS WELineType, [Warehouse Entry].[Item No_], [Warehouse Entry].[Constant Variable Code], [Warehouse Entry].[Assortment Code], [Warehouse Entry].[Journal Batch Name] AS TestataWE, [Warehouse Entry].[Line No_] AS RigaWE, Sum(Val([QUANTITY])) AS QTY
