FROM ([Item Identifier] RIGHT JOIN [Unique Identifier Documents] ON [Item Identifier].Code = [Unique Identifier Documents].Code) RIGHT JOIN [Warehouse Journal Line] ON ([Unique Identifier Documents].[Line No_] = [Warehouse Journal Line].[Line No_]) AND ([Unique Identifier Documents].[Journal Batch Name] = [Warehouse Journal Line].[Journal Batch Name]);

