-- [1104] WMS_WarehouseSpedRegCodiciColliEPrelievi_Registrati
SELECT [DDT_Picking Header].[Salesperson Code], Salesperson_Purchaser.Name, [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Line].[Document No_], [DDT_Picking Header].[ship provider order id], [DDT_Picking Line].[Line No_], [DDT_Picking Line].No_ AS Article, [DDT_Picking Line].[Constant Variable Code] AS ColorCode, [DDT_Picking Line].[Assortment Code], [DDT_Picking Header].[Shortcut Dimension 2 Code] AS Marchio, [DDT_Picking Header].[SELLING SEASON CODE] AS StagioneVendita, Val([ddt_picking line.quantity]) AS qty, 1 AS PrelievoRegistrato, [Registered Whse_ Activity Line].No_ AS NumeroPrelievo, [Registered Whse_ Activity Line].[Whse_ Phase Code] AS FasePrelievo, [Registered Whse_ Activity Line].[Bin Code], [Unique Identifier Pst_ Docnts].Code, [Posted Whse_ Shipment Header].No_ AS SpedWarehouseNo, [Posted Whse_ Shipment Header].[Special Requests], [Posted Whse_ Shipment Header].[Warehouse Speciality Code], [Posted Whse_ Shipment Header].[Warehouse Note], [Posted Whse_ Shipment Header].[Posting Date] AS SpedWarehouseData
FROM ([Posted Whse_ Shipment Line] INNER JOIN ([Unique Identifier Pst_ Docnts] RIGHT JOIN ([Registered Whse_ Activity Line] INNER JOIN (([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON [DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) LEFT JOIN Salesperson_Purchaser ON [DDT_Picking Header].[Salesperson Code] = Salesperson_Purchaser.Code) ON ([Registered Whse_ Activity Line].[Link To Source Line No_] = [DDT_Picking Line].[Line No_]) AND ([Registered Whse_ Activity Line].[Link To Source No_] = [DDT_Picking Line].[Document No_])) ON ([Unique Identifier Pst_ Docnts].[Line No_] = [Registered Whse_ Activity Line].[Line No_]) AND ([Unique Identifier Pst_ Docnts].No_ = [Registered Whse_ Activity Line].No_)) ON ([Posted Whse_ Shipment Line].[Source Line No_] = [DDT_Picking Line].[Line No_]) AND ([Posted Whse_ Shipment Line].[Source No_] = [DDT_Picking Line].[Document No_])) INNER JOIN [Posted Whse_ Shipment Header] ON [Posted Whse_ Shipment Line].No_ = [Posted Whse_ Shipment Header].No_
WHERE ((([DDT_Picking Header].Status)=20) AND (([DDT_Picking Line].Type)=20) AND (([DDT_Picking Header].[Document Type])=0))
ORDER BY [DDT_Picking Line].[Document No_], [DDT_Picking Line].[Line No_], [Registered Whse_ Activity Line].No_, [Registered Whse_ Activity Line].[Whse_ Phase Code], [Unique Identifier Pst_ Docnts].Code;

GO

